class FXiaokeCRM:    #CRM订单字段
    """纷享销客CRM接口封装。"""

    def __init__(self, app_id, app_secret, permanent_code, admin_mobile):
        """初始化纷享销客CRM客户端。"""
        self.app_id = app_id
        self.app_secret = app_secret
        self.permanent_code = permanent_code
        self.admin_mobile = admin_mobile
        self.base_url = "https://open.fxiaoke.com"
        self.corp_access_token = None
        self.corp_id = None
        self.current_open_user_id = None

    def get_corp_access_token(self):
        """获取纷享销客企业访问令牌。"""
        url = f"{self.base_url}/cgi/corpAccessToken/get/V2"
        headers = {"Content-Type": "application/json"}
        data = {
            "appId": self.app_id,
            "appSecret": self.app_secret,
            "permanentCode": self.permanent_code
        }
        try:
            response = perform_requests_request('post', url, headers=headers, json=data, timeout=60) 
            if response.status_code != 200:
                return False, f"HTTP Error: {response.status_code}"
            result = response.json()
            if result.get("errorCode") == 0:
                self.corp_access_token = result.get("corpAccessToken")
                self.corp_id = result.get("corpId")
                return True, "OK"
            else:
                return False, result.get("errorMessage", "Unknown error")
        except Exception as e:
            return False, f"{e} | verify={REQUESTS_VERIFY} ssl_ctx={REQUESTS_SSL_CONTEXT is not None} cert_src={_CERT_SOURCE}"

    def get_open_user_id_by_mobile(self):
        """根据管理员手机号查询对应的 openUserId。"""
        if not self.corp_access_token:
            ok, msg = self.get_corp_access_token()
            if not ok:
                return None, msg
        url = f"{self.base_url}/cgi/user/getByMobile"
        data = {
            "corpAccessToken": self.corp_access_token,
            "corpId": self.corp_id,
            "mobile": self.admin_mobile
        }
        try:
            response = perform_requests_request(
                'post',
                url,
                headers={"Content-Type": "application/json"},
                json=data,
                timeout=60,
            )
            if response.status_code == 200:
                result = response.json()
                if result.get("errorCode") == 0:
                    emp_list = result.get("empList", [])
                    if emp_list:
                        uid = emp_list[0].get("openUserId")
                        self.current_open_user_id = uid
                        return uid, emp_list[0].get("name", "")
            return None, "User not found"
        except Exception as e:
            return None, str(e)

    def query_user_list(self, department_id, fetch_child=True, show_department_detail=False):
        """获取部门下成员信息(详细)。

        Args:
            department_id: 部门ID，为非负整数，999999 代表全公司
            fetch_child: 是否同时获取子部门员工
            show_department_detail: 是否返回部门详情
        """
        if not self.corp_access_token:
            ok, msg = self.get_corp_access_token()
            if not ok:
                return None, msg

        url = f"{self.base_url}/cgi/user/list"
        data = {
            "corpAccessToken": self.corp_access_token,
            "corpId": self.corp_id,
            "departmentId": department_id,
            "fetchChild": fetch_child,
        }
        if show_department_detail:
            data["showDepartmentIdsDetail"] = True
        try:
            response = perform_requests_request(
                'post',
                url,
                headers={"Content-Type": "application/json"},
                json=data,
                timeout=60,
            )
            if response.status_code != 200:
                return None, f"HTTP {response.status_code}"
            result = response.json()
            if result.get("errorCode") == 0:
                return result.get("userList"), None
            return None, result.get("errorMessage", "Query failed")
        except Exception as e:
            return None, str(e)

    def query_department_list(self, department_id=999999, fetch_child=True):
        """获取部门列表。

        Args:
            department_id: 父部门ID，999999 为根部门
            fetch_child: 是否获取子部门
        """
        if not self.corp_access_token:
            ok, msg = self.get_corp_access_token()
            if not ok:
                return None, msg

        url = f"{self.base_url}/cgi/department/list"
        data = {
            "corpAccessToken": self.corp_access_token,
            "corpId": self.corp_id,
            "departmentId": department_id,
            "fetchChild": fetch_child,
        }
        try:
            response = perform_requests_request(
                'post', url,
                headers={"Content-Type": "application/json"},
                json=data, timeout=60,
            )
            if response.status_code != 200:
                return None, f"HTTP {response.status_code}"
            result = response.json()
            if result.get("errorCode") == 0:
                return result.get("departments"), None
            return None, result.get("errorMessage", "Query failed")
        except Exception as e:
            return None, str(e)

    def query_data_object(self, data_object_api_name, offset=0, limit=100, filters=None, field_projection=None, find_explicit_total_num=True, is_custom=False):
        """按对象类型查询 CRM 数据。

        Args:
            is_custom: True 使用自定义对象接口 /cgi/crm/custom/v2/data/query，
                       False 使用预设对象接口 /cgi/crm/v2/data/query
        """
        if not self.corp_access_token:
            ok, msg = self.get_corp_access_token()
            if not ok:
                return None, msg
        if not self.current_open_user_id:
            uid, msg = self.get_open_user_id_by_mobile()
            if not uid:
                return None, msg

        if is_custom:
            url = f"{self.base_url}/cgi/crm/custom/v2/data/query"
        else:
            url = f"{self.base_url}/cgi/crm/v2/data/query"

        search_query_info = {
            "offset": offset,
            "limit": limit,
            "filters": filters or []
        }
        if field_projection:
            search_query_info["fieldProjection"] = field_projection

        data = {
            "corpAccessToken": self.corp_access_token,
            "corpId": self.corp_id,
            "currentOpenUserId": self.current_open_user_id,
            "data": {
                "dataObjectApiName": data_object_api_name,
                "search_query_info": search_query_info
            },
            "find_explicit_total_num": find_explicit_total_num
        }
        try:
            response = perform_requests_request(
                'post',
                url,
                headers={"Content-Type": "application/json"},
                json=data,
                timeout=60,
            )
            if response.status_code != 200:
                return None, f"HTTP {response.status_code}"
            result = response.json()
            if result.get("errorCode") == 0:
                return result.get("data"), None
            return None, result.get("errorMessage", "Query failed")
        except Exception as e:
            return None, str(e)

    def fetch_all_data_object(self, data_object_api_name, max_records=10000, batch_size=100, filters=None, field_projection=None, callback=None, is_custom=False):
        """按对象类型分页拉取数据；field_projection 为空时由接口返回全部默认字段。

        Args:
            is_custom: True 使用自定义对象接口，False 使用预设对象接口
        """
        all_rows = []
        total = 0
        offset = 0
        try:
            target_records = int(max_records)
        except (TypeError, ValueError):
            target_records = 10000
        try:
            batch_size = int(batch_size)
        except (TypeError, ValueError):
            batch_size = 100

        target_records = max(1, min(target_records, 10000))
        batch_size = max(1, batch_size)

        while offset < target_records:
            current_limit = min(batch_size, target_records - offset)
            data, err = self.query_data_object(
                data_object_api_name=data_object_api_name,
                offset=offset,
                limit=current_limit,
                filters=filters,
                field_projection=field_projection,
                find_explicit_total_num=True,
                is_custom=is_custom,
            )
            if err:
                return all_rows, total, err
            if not data:
                break
            if not isinstance(data, dict):
                break
            rows = data.get("dataList", [])
            total = data.get("total", 0)
            if not rows:
                break
            all_rows.extend(rows)
            if len(all_rows) >= target_records:
                all_rows = all_rows[:target_records]
                if callback:
                    callback(len(all_rows), total)
                break
            if callback:
                callback(len(all_rows), total)
            if len(rows) < current_limit:
                break
            offset += current_limit
        return all_rows, total, None

    def fetch_customer_accounts_by_ids(self, account_ids, batch_size=100):
        """按客户 ID 批量补充客户档案信息。"""
        account_map = {}
        unique_ids = [account_id for account_id in dict.fromkeys(account_ids or []) if account_id]
        if not unique_ids:
            return account_map, None

        for start in range(0, len(unique_ids), batch_size):
            batch_ids = unique_ids[start:start + batch_size]
            data, err = self.query_data_object(
                data_object_api_name="AccountObj",
                offset=0,
                limit=max(len(batch_ids), 1),
                filters=[{
                    "field_name": "_id",
                    "operator": "IN",
                    "field_values": batch_ids,
                }],
                field_projection=["_id", "name", "field_UBjkv__c", "field_WEB1y__c", "tel", "field_Qjze2__c", "address", "location"],
                find_explicit_total_num=False,
            )
            if err:
                return account_map, err

            for row in (data or {}).get("dataList", []):
                account_id = str(row.get("_id", "")).strip()
                if account_id:
                    account_map[account_id] = row
        return account_map, None


class BackgroundTaskManager:
    """轻量级后台任务管理器，基于 threading.Thread + pyqtSignal 模式。

    负责追踪活跃任务的生命周期（pending → running → completed/error），
    并通过 pyqtSignal 通知 UI 更新状态栏。
    """

    def __init__(self, status_signal, done_signal, error_signal):
        self._tasks = {}          # task_id -> {'name': str, 'thread': Thread}
        self._lock = threading.Lock()
        self.status_changed = status_signal    # pyqtSignal(str, str, str)
        self.task_done = done_signal           # pyqtSignal(str, bool, str)
        self.task_error = error_signal         # pyqtSignal(str, str)

    def start(self, task_id, name, worker_fn, *args, timeout=None, **kwargs):
        """启动后台任务。worker_fn 在 daemon 线程中运行。

        Args:
            timeout: 超时秒数。超时后自动标记任务失败并通知 UI。
        """
        completed = threading.Event()

        def wrapper():
            try:
                self.status_changed.emit(task_id, name, 'running')
                result = worker_fn(*args, **kwargs)
                if not completed.is_set():
                    completed.set()
                    self.status_changed.emit(task_id, name, 'completed')
                    if isinstance(result, tuple) and len(result) == 2:
                        self.task_done.emit(task_id, result[0], result[1] or '')
                    else:
                        self.task_done.emit(task_id, True, '')
            except Exception as e:
                if not completed.is_set():
                    completed.set()
                    self.status_changed.emit(task_id, name, 'error')
                    self.task_error.emit(task_id, str(e)[:200])
            finally:
                completed.set()
                with self._lock:
                    self._tasks.pop(task_id, None)

        def _on_timeout():
            if completed.is_set():
                return
            completed.set()
            self.status_changed.emit(task_id, name, 'error')
            self.task_done.emit(task_id, False, f'连接测试超时（{timeout}秒未响应），已自动停止')
            with self._lock:
                self._tasks.pop(task_id, None)

        t = threading.Thread(target=wrapper, daemon=True)
        with self._lock:
            self._tasks[task_id] = {'name': name, 'thread': t}
        self.status_changed.emit(task_id, name, 'pending')
        t.start()

        if timeout and timeout > 0:
            timer = threading.Timer(timeout, _on_timeout)
            timer.daemon = True
            timer.start()

    def is_running(self, task_id):
        with self._lock:
            return task_id in self._tasks

    @property
    def active_count(self):
        with self._lock:
            return len(self._tasks)

    def active_task_names(self):
        with self._lock:
            return [v['name'] for v in self._tasks.values()]


class MysqlCache:
    """MySQL 缓存：每个 CRM 对象一张表，_id 为主键，data_json 存行数据"""

    def __init__(self):
        self._conn = None
        self._last_error = None

    @property
    def available(self):
        """MySQL 是否可用（已启用且连接成功）"""
        return self._get_conn() is not None

    @property
    def status_message(self):
        """当前状态描述"""
        if self._conn and self._conn.open:
            return "✅ MySQL 缓存已连接"
        cfg = load_config().get('mysql_config', {})
        if not cfg.get('enabled'):
            return "⚠️ MySQL 缓存未启用（请在 设置→MySQL配置 中启用）"
        if self._last_error:
            return f"❌ MySQL 连接失败: {self._last_error}"
        return "⚠️ MySQL 缓存未连接"

    def _get_conn(self):
        if self._conn and self._conn.open:
            return self._conn
        cfg = load_config().get('mysql_config', {})
        if not cfg.get('enabled'):
            self._last_error = '未启用'
            return None
        import pymysql
        try:
            self._conn = pymysql.connect(
                host=cfg.get('host', '127.0.0.1'),
                port=int(cfg.get('port', 3306)),
                user=cfg.get('user', ''),
                password=cfg.get('password', ''),
                database=cfg.get('database', ''),
                charset='utf8mb4',
                connect_timeout=5,
                cursorclass=pymysql.cursors.DictCursor,
                autocommit=True,
            )
            return self._conn
        except Exception as e:
            self._last_error = str(e)
            logging.error(f"[MysqlCache] 连接失败: {e}")
            return None

    def _table_name(self, api_name):
        return f"crm_cache_{api_name}"

    def _ensure_table(self, api_name):
        conn = self._get_conn()
        if not conn:
            return False
        table = self._table_name(api_name)
        try:
            with conn.cursor() as cur:
                cur.execute(f"""CREATE TABLE IF NOT EXISTS `{table}` (
                    `_id` VARCHAR(128) PRIMARY KEY,
                    `data_json` LONGTEXT,
                    `cached_at` DATETIME DEFAULT CURRENT_TIMESTAMP
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4""")
            return True
        except Exception as e:
            logging.error(f"[MysqlCache] 建表失败 {table}: {e}")
            return False

    def get_all(self, api_name):
        conn = self._get_conn()
        if not conn or not self._ensure_table(api_name):
            return None
        table = self._table_name(api_name)
        try:
            with conn.cursor() as cur:
                cur.execute(f"SELECT data_json FROM `{table}`")
                rows = cur.fetchall()
            import json
            return [json.loads(r['data_json']) for r in rows]
        except Exception as e:
            logging.error(f"[MysqlCache] 读取失败 {api_name}: {e}")
            return None

    def upsert_all(self, api_name, rows):
        if not rows:
            return
        conn = self._get_conn()
        if not conn or not self._ensure_table(api_name):
            return
        table = self._table_name(api_name)
        import json, hashlib
        skipped = 0
        inserted = 0
        updated = 0
        seen_ids = set()  # 防止同批次 _id 重复导致 1062 主键冲突
        try:
            with conn.cursor() as cur:
                # 确保 _hash 列存在
                cur.execute(f"SHOW COLUMNS FROM `{table}` LIKE '_hash'")
                if not cur.fetchone():
                    cur.execute(f"ALTER TABLE `{table}` ADD COLUMN `_hash` VARCHAR(32) DEFAULT ''")
                for row in rows:
                    _id = str(row.get('_id', '')).strip()
                    if not _id:
                        skipped += 1
                        continue
                    if _id in seen_ids:
                        skipped += 1
                        continue
                    seen_ids.add(_id)
                    data_json = json.dumps(row, ensure_ascii=False)
                    row_hash = hashlib.md5(data_json.encode('utf-8')).hexdigest()
                    cur.execute(
                        f"INSERT INTO `{table}` (_id, data_json, _hash, cached_at) "
                        f"VALUES (%s, %s, %s, NOW()) "
                        f"ON DUPLICATE KEY UPDATE "
                        f"data_json = IF(VALUES(`_hash`) != `_hash`, VALUES(data_json), data_json), "
                        f"`_hash` = IF(VALUES(`_hash`) != `_hash`, VALUES(`_hash`), `_hash`), "
                        f"cached_at = IF(VALUES(`_hash`) != `_hash`, NOW(), cached_at)",
                        (_id, data_json, row_hash)
                    )
                    inserted += 1
                if skipped:
                    logging.warning(f"[MysqlCache] JSON缓存表 {api_name}: {skipped} 条记录因 _id 为空被跳过")
            logging.info(f"[MysqlCache] JSON缓存表 {api_name}: 写入 {inserted} 条，跳过 {skipped} 条")
        except Exception as e:
            logging.error(f"[MysqlCache] 写入失败 {api_name}: {e}")

    def replace_cleaned_all(self, table_name, rows, headers, cleanup_old=True, field_type_map=None):
        """增量写入清洗后的数据表（按 _id 比对更新，可选清理不在本次批次中的旧记录）

        Args:
            table_name: 中文表名（如 对象-销售订单）
            rows: [{'字段中文名': 清洗值, ...}, ...]，每行含 _id
            headers: 中文表头列表
            cleanup_old: 是否清理不在本次批次中的旧记录。全量同步用 True，分页/限量查询用 False
            field_type_map: {字段中文名: CRM类型}，数值字段用 DOUBLE 列 + 保留数值
        """
        if not rows:
            return False, "无数据"
        conn = self._get_conn()
        if not conn:
            return False, self.status_message
        import json, hashlib, uuid
        from custom_report.constants import get_mysql_type_for_field, is_numeric_field_type, safe_numeric_value
        batch_id = uuid.uuid4().hex
        type_map = field_type_map or {}
        try:
            safe_cols = []
            for h in headers:
                safe = h.replace('`', '``')
                safe_cols.append(safe)
            with conn.cursor() as cur:
                # 确保表存在（数值字段用 DOUBLE，其余 LONGTEXT）
                col_defs = ['`_id` VARCHAR(128) PRIMARY KEY',
                            '`_hash` VARCHAR(32)',
                            '`_sync_time` DATETIME DEFAULT CURRENT_TIMESTAMP',
                            '`_sync_batch_id` VARCHAR(36) DEFAULT \'\'']
                for h in safe_cols:
                    ftype = type_map.get(h, '')
                    mysql_type = get_mysql_type_for_field(ftype)
                    col_defs.append(f'`{h}` {mysql_type}')
                cols_sql = ', '.join(col_defs)
                cur.execute(f"CREATE TABLE IF NOT EXISTS `{table_name}` ({cols_sql}) "
                            f"ENGINE=InnoDB DEFAULT CHARSET=utf8mb4")

                # 确保所有字段列存在（动态加列 + 已有列类型迁移）
                existing = {}
                cur.execute(f"SHOW COLUMNS FROM `{table_name}`")
                for r in cur.fetchall():
                    existing[r.get('Field', '')] = r.get('Type', 'LONGTEXT')
                for h in safe_cols + ['_hash', '_sync_time', '_sync_batch_id']:
                    ftype = type_map.get(h, '')
                    expected_type = get_mysql_type_for_field(ftype) if h not in ('_hash', '_sync_time', '_sync_batch_id') else None
                    if h not in existing:
                        col_type = 'VARCHAR(32)' if h == '_hash' else (
                            'VARCHAR(36)' if h == '_sync_batch_id' else (
                            'DATETIME DEFAULT CURRENT_TIMESTAMP' if h == '_sync_time' else expected_type or 'LONGTEXT'))
                        cur.execute(f"ALTER TABLE `{table_name}` ADD COLUMN `{h}` {col_type}")
                    elif expected_type and expected_type == 'DOUBLE' and 'double' not in existing[h].lower():
                        # 已有列是 LONGTEXT 但应为 DOUBLE → 迁移
                        try:
                            cur.execute(f"ALTER TABLE `{table_name}` MODIFY COLUMN `{h}` DOUBLE")
                        except Exception:
                            pass  # 数据无法转换，保持原类型

                # 构建 upsert SQL（含批次标记）
                upsert_cols = ['_id', '_hash', '_sync_time', '_sync_batch_id'] + safe_cols
                placeholders = ', '.join(['%s'] * len(upsert_cols))
                insert_sql = (
                    f"INSERT INTO `{table_name}` "
                    f"(`{'`, `'.join(upsert_cols)}`) VALUES ({placeholders}) "
                    f"ON DUPLICATE KEY UPDATE "
                )
                update_parts = []
                for h in safe_cols:
                    update_parts.append(
                        f"`{h}` = IF(VALUES(`_hash`) != `_hash`, VALUES(`{h}`), `{h}`)")
                update_parts.append(
                    "`_hash` = IF(VALUES(`_hash`) != `_hash`, VALUES(`_hash`), `_hash`)")
                update_parts.append(
                    "`_sync_time` = IF(VALUES(`_hash`) != `_hash`, NOW(), `_sync_time`)")
                # 批次标记始终更新（不受 hash 变更影响）
                update_parts.append(
                    "`_sync_batch_id` = VALUES(`_sync_batch_id`)")
                insert_sql += ', '.join(update_parts)

                # 批量执行（每批 500 行）
                batch = []
                inserted = 0
                skipped = 0
                seen_ids = set()  # 防止同批次 _id 重复导致 1062 主键冲突
                for row in rows:
                    _id = str(row.get('_id', '')).strip()
                    if not _id:
                        skipped += 1
                        continue
                    if _id in seen_ids:
                        skipped += 1
                        continue
                    seen_ids.add(_id)
                    # 计算字段值哈希（数值字段用原值，非数值字段转 str）
                    row_vals = {}
                    for h in headers:
                        ftype = type_map.get(h, '')
                        if is_numeric_field_type(ftype):
                            v = row.get(h)
                            row_vals[h] = float(v) if v not in (None, '') else None
                        else:
                            row_vals[h] = str(row.get(h, '') or '')
                    row_hash = hashlib.md5(
                        json.dumps(row_vals, sort_keys=True, ensure_ascii=False, default=str).encode('utf-8')
                    ).hexdigest()
                    vals = [_id, row_hash, None, batch_id]  # _sync_time 用 NOW()
                    for h in headers:
                        ftype = type_map.get(h, '')
                        val = safe_numeric_value(row.get(h, ''), ftype)
                        vals.append(val)
                    batch.append(vals)
                    inserted += 1

                    if len(batch) >= 500:
                        cur.executemany(insert_sql, batch)
                        batch.clear()

                if batch:
                    cur.executemany(insert_sql, batch)

                # 清理不在本次批次中的旧记录（已在 CRM 中删除的）
                deleted = 0
                if cleanup_old:
                    cur.execute(
                        f"DELETE FROM `{table_name}` WHERE `_sync_batch_id` != %s",
                        (batch_id,)
                    )
                    deleted = cur.rowcount

            if skipped:
                logging.warning(f"[MysqlCache] 清洗表 {table_name}: {skipped} 条记录因 _id 为空被跳过")
            if deleted:
                logging.info(f"[MysqlCache] 清洗表 {table_name}: 清理 {deleted} 条过期记录")
            msg = f"已写入 {inserted} 条（增量同步）"
            if deleted:
                msg += f"，清理 {deleted} 条过期记录"
            if skipped:
                msg += f"，跳过 {skipped} 条（_id 为空）"
            return True, msg
        except Exception as e:
            logging.error(f"[MysqlCache] 清洗表写入失败 {table_name}: {e}")
            return False, str(e)[:100]

    def clear(self, api_name):
        conn = self._get_conn()
        if not conn:
            return
        table = self._table_name(api_name)
        try:
            with conn.cursor() as cur:
                cur.execute(f"TRUNCATE TABLE `{table}`")
        except Exception as e:
            logging.error(f"[MysqlCache] 清除失败 {api_name}: {e}")

    def close(self):
        if self._conn and self._conn.open:
            try:
                self._conn.close()
            except Exception:
                pass
            self._conn = None


class CRMCache:
    """SQLite 本地缓存，用于存储从 CRM API 获取的数据对象。

    每个 CRM 对象类型（如 SalesOrderObj、NewOpportunityObj）对应一张表，
    完整记录存为 JSON，常用字段冗余为独立列并建立索引。
    """

    def __init__(self, db_path):
        self._db_path = str(db_path)
        os.makedirs(str(Path(self._db_path).parent), exist_ok=True)
        self._conn = sqlite3.connect(self._db_path, check_same_thread=False)
        self._conn.execute("PRAGMA journal_mode=WAL")
        self._conn.execute("PRAGMA synchronous=NORMAL")
        self._ensure_meta_table()

    # ---------- 内部工具 ----------

    @staticmethod
    def _sanitize_name(api_name):
        """将 CRM 对象 API 名称转为安全的表名。"""
        safe = ''.join(c if c.isalnum() else '_' for c in str(api_name))
        return f"crm_{safe}"

    def _ensure_meta_table(self):
        self._conn.execute("""
            CREATE TABLE IF NOT EXISTS _cache_meta (
                object_api_name TEXT PRIMARY KEY,
                total_api_count INTEGER DEFAULT 0,
                cached_count    INTEGER DEFAULT 0,
                last_sync_time  TEXT
            )
        """)
        self._conn.commit()

    def _ensure_object_table(self, object_api_name):
        table = self._sanitize_name(object_api_name)
        self._conn.execute(f"""
            CREATE TABLE IF NOT EXISTS {table} (
                _id          TEXT PRIMARY KEY NOT NULL,
                record_data  TEXT NOT NULL,
                create_time  REAL,
                owner_name   TEXT,
                account_name TEXT,
                life_status  TEXT,
                record_type  TEXT,
                name         TEXT,
                cached_at    TEXT NOT NULL DEFAULT (datetime('now'))
            )
        """)
        self._conn.execute(f"""
            CREATE INDEX IF NOT EXISTS idx_{table}_create_time
            ON {table}(create_time)
        """)
        self._conn.execute(f"""
            CREATE INDEX IF NOT EXISTS idx_{table}_life_status
            ON {table}(life_status)
        """)
        self._conn.commit()

    # ---------- 核心 CRUD ----------

    def upsert_records(self, object_api_name, records, total_api_count=None):
        """批量 upsert：按 _id 有则更新，无则插入。返回 (inserted, updated)。"""
        self._ensure_object_table(object_api_name)
        table = self._sanitize_name(object_api_name)
        inserted = 0
        updated = 0

        for record in (records or []):
            if not isinstance(record, dict):
                continue
            rid = str(record.get('_id', '')).strip()
            if not rid:
                continue

            record_json = json.dumps(record, ensure_ascii=False)

            create_time = record.get('create_time')
            if isinstance(create_time, (int, float)):
                create_time = float(create_time)
            else:
                create_time = None

            owner = record.get('owner__r', {})
            owner_name = (owner.get('name', '') if isinstance(owner, dict) else str(owner)) if owner else ''
            account = record.get('account_id__r', {})
            account_name = (account.get('name', '') if isinstance(account, dict) else str(account)) if account else ''
            life_status = str(record.get('life_status', ''))
            record_type = str(record.get('record_type', ''))
            name = str(record.get('name', ''))

            existing = self._conn.execute(
                f"SELECT _id FROM {table} WHERE _id = ?", (rid,)
            ).fetchone()

            if existing:
                self._conn.execute(
                    f"""UPDATE {table} SET record_data=?, create_time=?, owner_name=?,
                        account_name=?, life_status=?, record_type=?, name=?,
                        cached_at=datetime('now') WHERE _id=?""",
                    (record_json, create_time, owner_name, account_name,
                     life_status, record_type, name, rid)
                )
                updated += 1
            else:
                self._conn.execute(
                    f"""INSERT INTO {table} (_id, record_data, create_time, owner_name,
                        account_name, life_status, record_type, name)
                        VALUES (?, ?, ?, ?, ?, ?, ?, ?)""",
                    (rid, record_json, create_time, owner_name, account_name,
                     life_status, record_type, name)
                )
                inserted += 1

        self._conn.execute(
            "INSERT OR REPLACE INTO _cache_meta (object_api_name, total_api_count, cached_count, last_sync_time) VALUES (?, ?, (SELECT COUNT(*) FROM {0}), datetime('now'))".format(table),
            (object_api_name, total_api_count or 0)
        )
        self._conn.commit()
        return inserted, updated

    def get_all_records(self, object_api_name):
        """返回指定对象类型的所有缓存记录（完整 JSON 解码）。"""
        self._ensure_object_table(object_api_name)
        table = self._sanitize_name(object_api_name)
        rows = self._conn.execute(
            f"SELECT record_data FROM {table} ORDER BY create_time DESC"
        ).fetchall()
        result = []
        for (record_data,) in rows:
            try:
                result.append(json.loads(record_data))
            except json.JSONDecodeError:
                result.append({'_id': '', '_raw': record_data})
        return result

    def get_record_by_id(self, object_api_name, record_id):
        """按 _id 获取单条记录，找不到返回 None。"""
        self._ensure_object_table(object_api_name)
        table = self._sanitize_name(object_api_name)
        row = self._conn.execute(
            f"SELECT record_data FROM {table} WHERE _id = ?", (str(record_id),)
        ).fetchone()
        if row:
            try:
                return json.loads(row[0])
            except json.JSONDecodeError:
                return {'_id': record_id, '_raw': row[0]}
        return None

    def get_record_count(self, object_api_name):
        """返回缓存中的记录数。"""
        self._ensure_object_table(object_api_name)
        table = self._sanitize_name(object_api_name)
        return self._conn.execute(f"SELECT COUNT(*) FROM {table}").fetchone()[0]

    def get_meta(self, object_api_name):
        """返回同步元数据字典。"""
        row = self._conn.execute(
            "SELECT total_api_count, cached_count, last_sync_time FROM _cache_meta WHERE object_api_name = ?",
            (object_api_name,)
        ).fetchone()
        if row:
            return {'total_api_count': row[0], 'cached_count': row[1], 'last_sync_time': row[2]}
        return {}

    def delete_record(self, object_api_name, record_id):
        """删除单条记录。"""
        self._ensure_object_table(object_api_name)
        table = self._sanitize_name(object_api_name)
        self._conn.execute(f"DELETE FROM {table} WHERE _id = ?", (str(record_id),))
        self._conn.commit()

    def delete_all_records(self, object_api_name):
        """清空指定对象类型的所有缓存。"""
        self._ensure_object_table(object_api_name)
        table = self._sanitize_name(object_api_name)
        self._conn.execute(f"DELETE FROM {table}")
        self._conn.commit()

    # ---------- 映射数据表（每个字段独立列，存储映射+清洗后的数据） ----------

    def _ensure_mapped_table(self, object_api_name, field_columns):
        """创建映射数据表，每个 CRM 字段 + 用户覆盖字段独立一列"""
        table = self._sanitize_name(object_api_name) + '_mapped'
        col_defs = ['_id TEXT PRIMARY KEY NOT NULL']
        for col in field_columns:
            safe_col = ''.join(c if c.isalnum() else '_' for c in str(col))
            if safe_col and safe_col != '_id':
                col_defs.append(f'"{safe_col}" TEXT')
        col_defs.append('_from_mapped_cache INTEGER DEFAULT 1')
        col_defs.append("mapped_at TEXT NOT NULL DEFAULT (datetime('now'))")
        self._conn.execute(f"""
            CREATE TABLE IF NOT EXISTS {table} (
                {', '.join(col_defs)}
            )
        """)
        self._conn.commit()
        return table

    def _get_mapped_table_columns(self, object_api_name):
        """获取映射表的所有列名"""
        table = self._sanitize_name(object_api_name) + '_mapped'
        rows = self._conn.execute(f"PRAGMA table_info({table})").fetchall()
        return [r[1] for r in rows]

    def upsert_mapped_records(self, object_api_name, field_columns, rows):
        """批量写入映射数据：按 _id 有则更新，无则插入。返回 (inserted, updated)。"""
        table = self._ensure_mapped_table(object_api_name, field_columns)
        existing_cols = set(self._get_mapped_table_columns(object_api_name))
        inserted = 0
        updated = 0

        for row in (rows or []):
            if not isinstance(row, dict):
                continue
            rid = str(row.get('_id', '')).strip()
            if not rid:
                continue

            # 只写入表中已存在的列
            valid_cols = [c for c in row if c in existing_cols and c != '_from_mapped_cache' and c != 'mapped_at']
            if not valid_cols:
                continue

            placeholders = ', '.join(['?'] * len(valid_cols))
            col_names = ', '.join(f'"{c}"' for c in valid_cols)
            values = [str(row.get(c, '') or '') for c in valid_cols]

            existing = self._conn.execute(
                f"SELECT _id FROM {table} WHERE _id = ?", (rid,)
            ).fetchone()

            if existing:
                set_clause = ', '.join(f'"{c}"=?' for c in valid_cols)
                self._conn.execute(
                    f"UPDATE {table} SET {set_clause}, mapped_at=datetime('now') WHERE _id=?",
                    values + [rid]
                )
                updated += 1
            else:
                self._conn.execute(
                    f"INSERT INTO {table} (_id, {col_names}) VALUES (?, {placeholders})",
                    [rid] + values
                )
                inserted += 1

        self._conn.commit()
        return inserted, updated

    def get_all_mapped_records(self, object_api_name):
        """返回映射表中所有记录（每个字段已是映射+清洗后的值）"""
        table = self._sanitize_name(object_api_name) + '_mapped'
        rows = self._conn.execute(
            f"SELECT * FROM {table} ORDER BY create_time DESC"
        ).fetchall()
        if not rows:
            return []
        col_names = [desc[0] for desc in self._conn.execute(
            f"SELECT * FROM {table} LIMIT 0"
        ).description]
        result = []
        for row in rows:
            record = dict(zip(col_names, row))
            record['_from_mapped_cache'] = True
            result.append(record)
        return result

    def update_mapped_field(self, object_api_name, record_id, field_name, value):
        """更新映射表中单条记录的单个字段"""
        table = self._sanitize_name(object_api_name) + '_mapped'
        safe_col = ''.join(c if c.isalnum() else '_' for c in str(field_name))
        rows = self._conn.execute(f"PRAGMA table_info({table})").fetchall()
        existing_cols = {r[1] for r in rows}
        if safe_col not in existing_cols:
            self._conn.execute(f'ALTER TABLE {table} ADD COLUMN "{safe_col}" TEXT')
            self._conn.commit()
        self._conn.execute(
            f'UPDATE {table} SET "{safe_col}"=?, mapped_at=datetime(\'now\') WHERE _id=?',
            (str(value or ''), str(record_id))
        )
        self._conn.commit()

    def get_mapped_record_count(self, object_api_name):
        """返回映射表中的记录数"""
        table = self._sanitize_name(object_api_name) + '_mapped'
        row = self._conn.execute(f"SELECT COUNT(*) FROM {table}").fetchone()
        return row[0] if row else 0

    def close(self):
        try:
            self._conn.close()
        except Exception:
            pass


# 统一运行根目录，确保打包后始终使用 exe 所在目录
try:
    if getattr(sys, 'frozen', False):
        APP_ROOT = Path(sys.executable).resolve().parent
    else:
        APP_ROOT = Path(__file__).resolve().parent
except Exception:
    APP_ROOT = Path.cwd()


_WORD_PDF_CONVERTER_LOCAL = threading.local()
_WORD_PDF_FORCE_SINGLE_USE = threading.Event()
_WORD_PDF_FORCE_SINGLE_USE_LOADED = threading.Event()


def is_word_session_disconnect_error(error):
    """判断 Word COM 会话是否已断开。"""
    error_code = None
    if getattr(error, 'args', None):
        error_code = error.args[0]

    error_text = str(error).lower()
    return (
        error_code in (-2147023170, -2147023174)
        or 'rpc' in error_text
        or '服务器不可用' in str(error)
        or '远程过程调用失败' in str(error)
    )


class WordPdfConverterSession:
    """在同一批量任务中复用 Word 进程，避免每个文档重复启动。"""

    def __init__(self):
        """初始化Word PDF转换会话。"""
        ensure_word_pdf_single_use_mode_loaded()
        self.word = None
        self.before_processes = set()
        self.com_initialized = False
        self.single_use_mode = _WORD_PDF_FORCE_SINGLE_USE.is_set()

    def start(self):
        """启动当前会话。"""
        if self.word:
            return self

        import comtypes
        import comtypes.client

        self.before_processes = {
            proc.pid for proc in psutil.process_iter(['name'])
            if proc.info['name'] == 'WINWORD.EXE'
        }

        print("[PDF转换] 初始化COM库并启动Word...")
        comtypes.CoInitialize()
        self.com_initialized = True

        self.word = comtypes.client.CreateObject('Word.Application')
        if not self.word:
            raise Exception("无法创建Word应用对象")

        self.word.Visible = False
        self.word.DisplayAlerts = False
        return self

    def stop(self):
        """停止当前会话并释放资源。"""
        if self.word:
            try:
                self.word.Quit()
                logging.info("Word应用已关闭")
            except Exception as error:
                if is_word_session_disconnect_error(error):
                    logging.info(f"Word会话已断开，关闭时忽略Quit异常: {str(error)}")
                else:
                    logging.warning(f"关闭Word应用失败: {str(error)}")
            finally:
                self.word = None

        if self.com_initialized:
            try:
                import comtypes
                comtypes.CoUninitialize()
                logging.info("COM库已释放")
            except Exception as error:
                logging.warning(f"释放COM库失败: {str(error)}")
            finally:
                self.com_initialized = False

        try:
            after_processes = [
                proc for proc in psutil.process_iter(['name'])
                if proc.info['name'] == 'WINWORD.EXE' and proc.pid not in self.before_processes
            ]
            for proc in after_processes:
                try:
                    proc.terminate()
                    proc.wait(timeout=2)
                    logging.info(f"已终止Word进程: {proc.pid}")
                except Exception as error:
                    logging.warning(f"终止Word进程失败: {str(error)}")
        except Exception as error:
            logging.warning(f"处理Word进程失败: {str(error)}")

        self.before_processes = set()

    def _convert_once(self, word_path, pdf_path):
        """执行一次Word到PDF转换。"""
        doc = None

        if not self.word:
            self.start()

        print(f"[PDF转换] 开始处理: {word_path.name}")

        if not word_path.exists():
            raise Exception(f"Word文件不存在: {word_path}")

        pdf_path.parent.mkdir(parents=True, exist_ok=True)

        try:
            if not hasattr(self.word, 'Documents') or not self.word.Documents:
                raise Exception("Word应用的Documents对象无效")

            absolute_word_path = str(word_path.absolute())
            print(f"[PDF转换] 打开文档: {word_path.name}")
            doc = self.word.Documents.Open(absolute_word_path)
            if not doc:
                raise Exception("无法打开Word文档")

            if not hasattr(doc, 'SaveAs'):
                raise Exception("文档对象的SaveAs方法无效")

            print(f"[PDF转换] 保存为PDF: {pdf_path.name}")
            doc.SaveAs(str(pdf_path), FileFormat=17)
            print("[PDF转换] ✓ PDF保存成功")
            logging.info(f"PDF保存成功: {pdf_path}")
        finally:
            if doc:
                try:
                    doc.Close()
                    logging.info("文档已关闭")
                except Exception as error:
                    logging.warning(f"关闭文档失败: {str(error)}")

    def convert(self, word_path, pdf_path):
        """执行转换流程。"""
        if self.single_use_mode and self.word:
            self.stop()

        try:
            self._convert_once(word_path, pdf_path)
        except Exception as error:
            if not is_word_session_disconnect_error(error):
                raise

            logging.warning(f"检测到Word会话失效，已重建并重试当前PDF: {str(error)}")
            self.stop()
            self.single_use_mode = True
            _WORD_PDF_FORCE_SINGLE_USE.set()
            persist_word_pdf_single_use_mode()
            self._convert_once(word_path, pdf_path)
        finally:
            if self.single_use_mode:
                self.stop()


@contextmanager
def pdf_conversion_batch():
    """在单次合同批量生成中复用同一个 Word 进程。"""
    active_session = getattr(_WORD_PDF_CONVERTER_LOCAL, 'session', None)
    if active_session is not None:
        yield active_session
        return

    session = WordPdfConverterSession()
    _WORD_PDF_CONVERTER_LOCAL.session = session
    try:
        yield session
    finally:
        try:
            session.stop()
        finally:
            _WORD_PDF_CONVERTER_LOCAL.session = None


@lru_cache(maxsize=64)
def _read_template_bytes(template_path_str, modified_time_ns, file_size):
    """读取模板文件的字节内容。"""
    del modified_time_ns, file_size
    return Path(template_path_str).read_bytes()


def load_docx_template(template_path):
    """按文件状态缓存模板字节，每次返回新的模板实例。"""
    from docxtpl import DocxTemplate

    resolved_path = Path(template_path).resolve()
    stat_result = resolved_path.stat()
    template_bytes = _read_template_bytes(
        str(resolved_path),
        stat_result.st_mtime_ns,
        stat_result.st_size,
    )
    return DocxTemplate(BytesIO(template_bytes))


def _resolve_requests_cert_path():
    """定位 requests 在开发和打包环境下都可用的 CA 证书文件。"""
    candidate_paths = []

    if getattr(sys, 'frozen', False):
        meipass = getattr(sys, '_MEIPASS', '')
        if meipass:
            candidate_paths.append(Path(meipass) / 'certifi' / 'cacert.pem')
            # 在某些 PyInstaller 版本中 certifi 数据可能在根目录
            candidate_paths.append(Path(meipass) / 'cacert.pem')
        candidate_paths.append(APP_ROOT / '_internal' / 'certifi' / 'cacert.pem')
        candidate_paths.append(APP_ROOT / '_internal' / 'cacert.pem')
        candidate_paths.append(APP_ROOT / 'certifi' / 'cacert.pem')
        candidate_paths.append(APP_ROOT / 'cacert.pem')
        # 额外的备选：在 _internal 下递归查找 cacert.pem（部分环境 certifi 路径不同）
        try:
            internal_dir = APP_ROOT / '_internal'
            if internal_dir.exists():
                for found in internal_dir.rglob('cacert.pem'):
                    candidate_paths.append(found)
                    break  # 找到一个就够
        except Exception:
            pass

    # 尝试从 certifi 包本身定位证书文件
    try:
        import certifi as _certifi_module
        if hasattr(_certifi_module, '__file__') and _certifi_module.__file__:
            certifi_dir = Path(_certifi_module.__file__).parent
            candidate_paths.append(certifi_dir / 'cacert.pem')
    except Exception:
        pass

    for env_name in ('REQUESTS_CA_BUNDLE', 'SSL_CERT_FILE'):
        env_value = os.environ.get(env_name, '').strip()
        if env_value:
            candidate_paths.append(Path(env_value))

    try:
        candidate_paths.append(Path(certifi.where()))
    except Exception:
        pass

    for candidate in candidate_paths:
        try:
            resolved_candidate = Path(candidate).resolve()
        except Exception:
            resolved_candidate = Path(candidate)
        if _is_valid_ca_bundle_path(resolved_candidate):
            return resolved_candidate
    return None


def _is_valid_ca_bundle_path(cert_path):
    """Return True only for a readable PEM CA bundle."""
    if not cert_path:
        return False
    try:
        path = Path(cert_path)
        if not path.exists() or not path.is_file() or path.stat().st_size < 1024:
            return False
        return b'-----BEGIN CERTIFICATE-----' in path.read_bytes()
    except Exception:
        return False


def _materialize_requests_cert_path(cert_path):
    """将 CA 证书复制到本地稳定路径，避免部分机器无法直接读取打包目录中的证书。"""
    if _is_valid_ca_bundle_path(cert_path):
        return Path(cert_path)

    try:
        cache_dir = Path(tempfile.gettempdir()) / 'Project_zjt' / 'certifi'
        cache_dir.mkdir(parents=True, exist_ok=True)
        materialized_path = cache_dir / 'cacert.pem'

        bundle_bytes = None
        try:
            bundle_bytes = pkgutil.get_data('certifi', 'cacert.pem')
        except Exception:
            bundle_bytes = None

        if bundle_bytes:
            existing_bytes = None
            if materialized_path.exists():
                try:
                    existing_bytes = materialized_path.read_bytes()
                except Exception:
                    existing_bytes = None
            if existing_bytes != bundle_bytes:
                materialized_path.write_bytes(bundle_bytes)
        else:
            if not cert_path:
                return None

            source_path = Path(cert_path)
            if not _is_valid_ca_bundle_path(source_path):
                return None

            if not getattr(sys, 'frozen', False):
                return source_path

            if (not materialized_path.exists()) or source_path.stat().st_size != materialized_path.stat().st_size:
                shutil.copy2(source_path, materialized_path)

        if _is_valid_ca_bundle_path(materialized_path):
            return materialized_path
    except Exception:
        if cert_path:
            source_path = Path(cert_path)
            if _is_valid_ca_bundle_path(source_path):
                return source_path
        return None

    if cert_path:
        source_path = Path(cert_path)
        if _is_valid_ca_bundle_path(source_path):
            return source_path
    return None


def _load_requests_cert_bundle_bytes(cert_path=None):
    """优先从 certifi 包内容读取证书字节，失败时再回退到文件读取。"""
    try:
        bundle_bytes = pkgutil.get_data('certifi', 'cacert.pem')
        if bundle_bytes:
            return bundle_bytes
    except Exception:
        pass

    # 回退：使用 certifi.contents() 获取内置证书字符串
    try:
        contents = certifi.contents()
        if contents:
            return contents.encode('ascii')
    except Exception:
        pass

    return None


def _build_requests_ssl_context(cert_path=None):
    """构建基于内存 CA 证书的 SSLContext，避免依赖目标机文件路径。"""
    bundle_bytes = _load_requests_cert_bundle_bytes(cert_path)
    if bundle_bytes:
        try:
            ssl_context = ssl.create_default_context()
            ssl_context.load_verify_locations(cadata=bundle_bytes.decode('ascii'))
            return ssl_context, 'certifi:cadata'
        except Exception:
            pass

    if cert_path:
        try:
            ssl_context = ssl.create_default_context(cafile=str(cert_path))
            return ssl_context, str(cert_path)
        except Exception:
            pass

    try:
        fallback_path = certifi.where()
        ssl_context = ssl.create_default_context(cafile=fallback_path)
        return ssl_context, fallback_path
    except Exception:
        return None, None


class SSLContextAdapter(HTTPAdapter):
    """携带自定义SSL上下文的请求适配器。"""
    def __init__(self, ssl_context=None, *args, **kwargs):
        """初始化SSL上下文适配器。"""
        self._ssl_context = ssl_context
        super().__init__(*args, **kwargs)

    def init_poolmanager(self, connections, maxsize, block=False, **pool_kwargs):
        """处理initpoolmanager逻辑。"""
        if self._ssl_context is not None:
            pool_kwargs['ssl_context'] = self._ssl_context
        return super().init_poolmanager(connections, maxsize, block=block, **pool_kwargs)

    def proxy_manager_for(self, proxy, **proxy_kwargs):
        """处理proxymanagerfor逻辑。"""
        if self._ssl_context is not None:
            proxy_kwargs['ssl_context'] = self._ssl_context
        return super().proxy_manager_for(proxy, **proxy_kwargs)

    def cert_verify(self, conn, url, verify, cert):
        """Use the preloaded SSLContext instead of asking requests to reload CA files."""
        if self._ssl_context is not None:
            if cert:
                if isinstance(cert, tuple):
                    conn.cert_file, conn.key_file = cert
                else:
                    conn.cert_file = cert
            return
        return super().cert_verify(conn, url, verify, cert)


def _build_requests_session():
    """构建 requests 会话 — 不使用自定义 SSLContext，由 verify 参数控制。"""
    session = requests.Session()
    session.trust_env = False
    return session


# ── 证书定位：3.4.8 彻底修复 X509: NO_CERTIFICATE_OR_CRL_FOUND ──────────────────────────
# 根因：PyInstaller 打包后 certifi.where() 返回 PYZ 内部路径（文件系统不存在），
#        certifi.contents()/pkgutil.get_data() 也可能失败，
#        导致 OpenSSL 找不到任何 CA 证书。
# 方案（按优先级）：
# 1. 从 certifi 内存/cacert.pem 文件读取 PEM 数据 → SSLContext.load_verify_locations(cadata=)
# 2. 从磁盘找到有效 cacert.pem → SSLContext.load_verify_locations(cafile=)
# 3. ssl.create_default_context() → Windows 系统证书存储
# 4. 将 PEM 数据写入临时文件 → verify=文件路径
# 最终保证 REQUESTS_SSL_CONTEXT 一定不为 None

def _read_certifi_cadata_bytes():
    """从 certifi 包获取 CA 证书 PEM 字节，尝试所有可能的方式。"""
    try:
        contents = certifi.contents()
        if contents and isinstance(contents, str) and '-----BEGIN CERTIFICATE-----' in contents:
            return contents.encode('ascii')
    except Exception:
        pass
    try:
        bundle_bytes = pkgutil.get_data('certifi', 'cacert.pem')
        if bundle_bytes and b'-----BEGIN CERTIFICATE-----' in bundle_bytes:
            return bundle_bytes
    except Exception:
        pass
    return None


def _is_pem_content_valid(cert_path):
    if not cert_path:
        return False
    try:
        path = Path(cert_path)
        if not path.exists() or not path.is_file() or path.stat().st_size < 1024:
            return False
        content = path.read_bytes()
        return b'-----BEGIN CERTIFICATE-----' in content
    except Exception:
        return False


def _find_cert_file_on_disk():
    """在打包后的所有可能路径中查找 cacert.pem 文件。"""
    candidates = []
    if getattr(sys, 'frozen', False):
        meipass = getattr(sys, '_MEIPASS', '')
        if meipass:
            candidates += [
                Path(meipass) / 'certifi' / 'cacert.pem',
                Path(meipass) / 'cacert.pem',
            ]
        candidates += [
            APP_ROOT / '_internal' / 'certifi' / 'cacert.pem',
            APP_ROOT / '_internal' / 'cacert.pem',
            APP_ROOT / 'certifi' / 'cacert.pem',
            APP_ROOT / 'cacert.pem',
        ]
        try:
            internal = APP_ROOT / '_internal'
            if internal.exists():
                for found in internal.rglob('cacert.pem'):
                    candidates.append(found)
        except Exception:
            pass
    try:
        candidates.append(Path(certifi.__file__).parent / 'cacert.pem')
    except Exception:
        pass
    try:
        candidates.append(Path(certifi.where()))
    except Exception:
        pass
    for p in candidates:
        try:
            if _is_pem_content_valid(p):
                return p
        except Exception:
            continue
    return None


def _read_cert_bytes_from_file(cert_path):
    """从磁盘文件读取 PEM 证书字节。"""
    try:
        data = Path(cert_path).read_bytes()
        if data and b'-----BEGIN CERTIFICATE-----' in data:
            return data
    except Exception:
        pass
    return None


def _write_cert_to_tempfile(cert_bytes):
    """将证书字节写入临时文件，返回文件路径。"""
    try:
        cache_dir = Path(tempfile.gettempdir()) / 'Project_zjt' / 'certifi'
        cache_dir.mkdir(parents=True, exist_ok=True)
        temp_pem = cache_dir / 'cacert.pem'
        existing = None
        if temp_pem.exists():
            try:
                existing = temp_pem.read_bytes()
            except Exception:
                existing = None
        if existing != cert_bytes:
            temp_pem.write_bytes(cert_bytes)
        if _is_pem_content_valid(temp_pem):
            return temp_pem
    except Exception:
        pass
    return None


def _build_ssl_context():
    """构建可用的 SSLContext，按优先级尝试所有证书来源。
    返回 (ssl_context, cert_source_desc) 或 (None, None)。"""
    # 策略1: 从 certifi 内存获取 PEM 数据
    cadata = _read_certifi_cadata_bytes()
    if cadata:
        try:
            ctx = ssl.create_default_context()
            ctx.load_verify_locations(cadata=cadata.decode('ascii', errors='replace'))
            return ctx, 'certifi:cadata'
        except Exception:
            pass

    # 策略2: 从磁盘找到 cacert.pem 文件，用 cafile 加载
    cert_file = _find_cert_file_on_disk()
    if cert_file:
        try:
            ctx = ssl.create_default_context()
            ctx.load_verify_locations(cafile=str(cert_file))
            return ctx, f'file:{cert_file}'
        except Exception:
            pass
        # cafile 失败，尝试读取文件内容用 cadata
        file_bytes = _read_cert_bytes_from_file(cert_file)
        if file_bytes:
            try:
                ctx = ssl.create_default_context()
                ctx.load_verify_locations(cadata=file_bytes.decode('ascii', errors='replace'))
                return ctx, f'file_cadata:{cert_file}'
            except Exception:
                pass

    # 策略3: ssl.create_default_context() 使用 Windows 系统证书存储
    try:
        ctx = ssl.create_default_context()
        return ctx, 'system_default'
    except Exception:
        pass

    return None, None


def _build_fallback_cert_file():
    """所有 SSLContext 方案失败时，尝试将证书写入临时文件供 verify 参数使用。"""
    cadata = _read_certifi_cadata_bytes()
    if cadata:
        result = _write_cert_to_tempfile(cadata)
        if result:
            return result
    cert_file = _find_cert_file_on_disk()
    if cert_file:
        file_bytes = _read_cert_bytes_from_file(cert_file)
        if file_bytes:
            result = _write_cert_to_tempfile(file_bytes)
            if result:
                return result
    return None


REQUESTS_SSL_CONTEXT, _CERT_SOURCE = _build_ssl_context()
REQUESTS_CERT_PATH = None

if REQUESTS_SSL_CONTEXT is None:
    REQUESTS_CERT_PATH = _build_fallback_cert_file()


def _build_requests_session_with_sslcontext():
    session = requests.Session()
    session.trust_env = False
    if REQUESTS_SSL_CONTEXT:
        adapter = SSLContextAdapter(ssl_context=REQUESTS_SSL_CONTEXT)
        session.mount('https://', adapter)
        session.mount('http://', adapter)
    return session


if REQUESTS_SSL_CONTEXT:
    REQUESTS_VERIFY = True
    _REQUESTS_SESSION_FACTORY = _build_requests_session_with_sslcontext
elif REQUESTS_CERT_PATH:
    REQUESTS_VERIFY = str(REQUESTS_CERT_PATH)
    os.environ['REQUESTS_CA_BUNDLE'] = str(REQUESTS_CERT_PATH)
    os.environ['SSL_CERT_FILE'] = str(REQUESTS_CERT_PATH)
    os.environ['CURL_CA_BUNDLE'] = str(REQUESTS_CERT_PATH)
    _REQUESTS_SESSION_FACTORY = _build_requests_session
else:
    REQUESTS_VERIFY = True
    _REQUESTS_SESSION_FACTORY = _build_requests_session

# 线程本地 Session + 全局锁：每个线程持有独立的 requests.Session，
# 但所有 HTTP 请求必须通过全局锁串行化，彻底避免 WININET.dll 并发访问冲突。
_THREAD_LOCAL_SESSIONS = threading.local()
_REQUESTS_LOCK = threading.Lock()

def _get_thread_local_session():
    """返回当前线程的独立 requests.Session（线程安全）。"""
    s = getattr(_THREAD_LOCAL_SESSIONS, 'session', None)
    if s is None:
        s = _REQUESTS_SESSION_FACTORY()
        _THREAD_LOCAL_SESSIONS.session = s
    return s


def get_requests_kwargs(timeout=60, **kwargs):
    """统一 requests 参数，确保打包后 HTTPS 仍使用有效 CA 证书。"""
    request_kwargs = dict(kwargs)
    request_kwargs.setdefault('timeout', timeout)
    request_kwargs.setdefault('verify', REQUESTS_VERIFY)
    return request_kwargs


def perform_requests_request(method, url, **kwargs):
    """发起 HTTPS 请求，verify 参数指向 cacert.pem 文件。

    所有 HTTP 请求通过全局锁串行化，防止多个线程同时访问 WININET.dll 导致内存访问冲突。
    """
    request_kwargs = dict(kwargs)
    timeout = request_kwargs.pop('timeout', 30)
    request_kwargs = get_requests_kwargs(timeout=timeout, **request_kwargs)
    with _REQUESTS_LOCK:
        return _get_thread_local_session().request(method, url, **request_kwargs)


def resolve_app_path(path_value):
    """将相对路径解析到程序根目录，绝对路径保持不变"""
    if not path_value:
        return APP_ROOT
    path = Path(path_value)
    if path.is_absolute():
        return path

    if getattr(sys, 'frozen', False):
        resource_candidate = RESOURCE_ROOT / path
        if resource_candidate.exists():
            return resource_candidate

    return APP_ROOT / path


def resolve_existing_app_path(path_value, fallback_path=None):
    """优先返回存在的配置路径，不存在时回退到程序目录内的默认路径"""
    if path_value:
        candidate = resolve_app_path(path_value)
        if candidate.exists():
            return candidate

        if getattr(sys, 'frozen', False):
            legacy_candidate = APP_ROOT / Path(path_value)
            if legacy_candidate.exists():
                return legacy_candidate

    if fallback_path is None:
        return resolve_app_path(path_value) if path_value else None

    fallback = fallback_path if isinstance(fallback_path, Path) else Path(fallback_path)
    return fallback if fallback.is_absolute() else APP_ROOT / fallback


CONFIG_DIR_NAME = '.config'
RESOURCE_DIR_NAME = 'Resources'
DEFAULT_PROFILE_FILENAME = 'saas_contract_config_2026.json'
SHARED_SETTINGS_FILENAME = 'shared_settings.json'
COMMON_CONFIG_POINTER_FILENAME = 'shared_settings_path.json'


def _pick_existing_path(*candidates):
    """从候选项中选取第一个存在的路径。"""
    for candidate in candidates:
        if not candidate:
            continue
        try:
            if Path(candidate).exists():
                return Path(candidate)
        except Exception:
            continue
    return None


if getattr(sys, 'frozen', False):
    packaged_resource_candidates = [
        APP_ROOT / '_internal' / RESOURCE_DIR_NAME,
        APP_ROOT / RESOURCE_DIR_NAME,
        APP_ROOT.parent / RESOURCE_DIR_NAME,
    ]
    RESOURCE_ROOT = next((path for path in packaged_resource_candidates if path.exists()), APP_ROOT)
    CONFIG_DIR = _pick_existing_path(
        RESOURCE_ROOT / 'Config',
        RESOURCE_ROOT / CONFIG_DIR_NAME,
        APP_ROOT / 'Config',
        APP_ROOT / CONFIG_DIR_NAME,
        APP_ROOT.parent / 'Config',
        APP_ROOT.parent / CONFIG_DIR_NAME,
    ) or (RESOURCE_ROOT / 'Config')
    user_root = _pick_existing_path(
        RESOURCE_ROOT / 'User',
        APP_ROOT / 'User',
        APP_ROOT.parent / 'User',
    ) or (RESOURCE_ROOT / 'User')
    USER_SETTINGS_DIR = user_root / 'Settings'
    USER_RUNTIME_STATE_DIR = user_root / 'RuntimeState'
    PROFILES_DIR = _pick_existing_path(
        RESOURCE_ROOT / 'Profiles',
        APP_ROOT / 'Profiles',
        APP_ROOT.parent / 'Profiles',
    ) or (RESOURCE_ROOT / 'Profiles')
    DEFAULT_TEMPLATE_DIR = _pick_existing_path(
        RESOURCE_ROOT / 'template',
        APP_ROOT / 'template',
        APP_ROOT.parent / 'template',
    ) or (RESOURCE_ROOT / 'template')
else:
    RESOURCE_ROOT = APP_ROOT
    CONFIG_DIR = APP_ROOT / CONFIG_DIR_NAME
    USER_SETTINGS_DIR = APP_ROOT / 'User' / 'Settings'
    USER_RUNTIME_STATE_DIR = APP_ROOT / 'User' / 'RuntimeState'
    PROFILES_DIR = APP_ROOT / 'Profiles'
    DEFAULT_TEMPLATE_DIR = APP_ROOT / 'template'


DEFAULT_PROFILE_PATH = CONFIG_DIR / DEFAULT_PROFILE_FILENAME
LEGACY_DEFAULT_PROFILE_PATH = PROFILES_DIR / DEFAULT_PROFILE_FILENAME


def discover_excel_template(template_dir=None, preferred_name=None):
    """在模板目录中自动查找可用的 Excel 模板，避免依赖固定文件名"""
    template_root = resolve_app_path(template_dir or DEFAULT_TEMPLATE_DIR)
    if not template_root.exists():
        return None

    excluded_names = {'processed_data.xlsx', 'log.xlsx'}
    candidates = []
    for candidate in template_root.rglob('*.xlsx'):
        if candidate.is_file() and candidate.name.lower() not in excluded_names:
            candidates.append(candidate)

    if not candidates:
        return None

    candidates = sorted(candidates, key=lambda p: (p.name.lower(), str(p).lower()))
    if preferred_name:
        for candidate in candidates:
            if candidate.name.lower() == preferred_name.lower():
                return candidate

    return candidates[0]


def get_default_profile_path():
    """发布目录优先使用配置文件夹中的默认配置，同时兼容旧目录"""
    if DEFAULT_PROFILE_PATH.exists():
        return DEFAULT_PROFILE_PATH
    if LEGACY_DEFAULT_PROFILE_PATH.exists():
        return LEGACY_DEFAULT_PROFILE_PATH
    if getattr(sys, 'frozen', False):
        legacy_config_profile = APP_ROOT / CONFIG_DIR_NAME / DEFAULT_PROFILE_FILENAME
        if legacy_config_profile.exists():
            return legacy_config_profile
        legacy_profiles_profile = APP_ROOT / 'Profiles' / DEFAULT_PROFILE_FILENAME
        if legacy_profiles_profile.exists():
            return legacy_profiles_profile
    return DEFAULT_PROFILE_PATH
def get_personal_profile_seed_path():
    """个人配置缺失时，优先使用 Profiles 中的默认配置作为种子。"""
    if LEGACY_DEFAULT_PROFILE_PATH.exists():
        return LEGACY_DEFAULT_PROFILE_PATH
    return get_default_profile_path()


