# 注意：不要清空代码，只在原有代码修改，保证功能不会丢失，在本任务中，都禁止清空原有代码，只能修改代码，理解请回答我，谢谢
def get_current_time():
    """获取当前时间，优先网络时间，失败则使用本地时间"""
    try:
        # 尝试连接百度获取时间，设置0.5秒超时，减少启动时的等待时间
        with urllib.request.urlopen('http://www.baidu.com', timeout=0.5) as response:
            date_header = response.headers.get('Date')
            if date_header:
                # 解析 HTTP Date 头
                network_time_tuple = email.utils.parsedate_tz(date_header)
                if network_time_tuple:
                    network_timestamp = email.utils.mktime_tz(network_time_tuple)
                    return datetime.fromtimestamp(network_timestamp)
    except Exception:
        # 网络请求失败，直接返回本地时间，不记录日志以加快启动速度
        pass
    
    # 如果获取失败，返回本地时间
    return datetime.now()


if get_current_time().date() > datetime(2030, 12, 31).date():
    # logging.error("超过有效期，程序将结束")
    sys.exit(0)


# 全局变量初始化
current_user = None
user_type = None
# 用户数据缓存
_users_cache = None
_users_last_modified = 0


def _find_user_record_without_config(user_identity):
    """仅通过缓存或本地 users.json 查找用户，避免在配置解析时递归加载配置。"""
    identity = (user_identity or "").strip()
    if not identity:
        return None

    cached_users = []
    if isinstance(_users_cache, dict):
        cached_users = _users_cache.get('users', []) or []
    for user in cached_users:
        if user.get('username') == identity or user.get('user_id') == identity:
            return user

    users_path = CONFIG_DIR / 'users.json'
    try:
        if users_path.exists():
            with open(users_path, 'r', encoding='utf-8') as f:
                users_data = json.load(f)
            if isinstance(users_data, dict):
                for user in users_data.get('users', []):
                    if user.get('username') == identity or user.get('user_id') == identity:
                        return user
    except Exception:
        pass

    return None

def get_config_path(for_save=False):
    """获取配置文件路径，优先使用用户或管理员配置文件，然后是默认配置文件"""
    global current_user, user_type

    # 初始化变量，处理未定义的情况
    if 'current_user' not in globals():
        globals()['current_user'] = None
    if 'user_type' not in globals():
        globals()['user_type'] = None

    # 尝试获取用户ID
    user_id = None
    resolved_user = (current_user or "").strip()
    if resolved_user and user_type != "admin":
        candidate_config = USER_SETTINGS_DIR / f'{resolved_user}.json'
        if candidate_config.exists() or resolved_user.isdigit():
            user_id = resolved_user
        else:
            matched_user = _find_user_record_without_config(resolved_user)
            if matched_user:
                user_id = matched_user.get('user_id')

    # 根据用户类型和ID确定配置文件路径
    if user_type == "admin":
        # 管理员配置保存到.config文件夹
        config_dir = CONFIG_DIR
        config_file = config_dir / 'admin.json'
        
        # 确保配置文件目录存在
        if for_save:
            config_file.parent.mkdir(parents=True, exist_ok=True)
            return config_file
            
        # 检查个人配置文件是否存在
        if config_file.exists():
            return config_file
            
    # 如果用户ID存在，返回用户的个人配置文件路径
    if user_id:
        # 普通用户配置保存到User/Settings文件夹，使用用户ID命名
        config_dir = USER_SETTINGS_DIR
        config_file = config_dir / f'{user_id}.json'
        
        # 确保配置文件目录存在
        if for_save:
            config_file.parent.mkdir(parents=True, exist_ok=True)
            return config_file
            
        # 检查个人配置文件是否存在
        if config_file.exists():
            return config_file

    # 默认回退到 Profiles\saas_contract_config_2026.json，其次兼容其他默认配置位置
    local_config = get_personal_profile_seed_path()
    if local_config.exists():
        return local_config

    # 如果当前目录没有，则尝试使用打包时的资源路径
    try:
        import sys
        if getattr(sys, 'frozen', False):
            # 如果是打包后的exe运行
            return get_personal_profile_seed_path()
        else:
            # 开发环境中
            return get_personal_profile_seed_path()
    except Exception:
        # 回退到当前目录
        return get_personal_profile_seed_path()


def get_current_user_identity():
    """返回当前登录用户的稳定标识，用于隔离运行状态和操作记录"""
    global current_user, user_type

    resolved_user = (current_user or "").strip()
    resolved_type = (user_type or "").strip() or "guest"
    resolved_user_id = None

    if resolved_user and resolved_type != "admin":
        candidate_config = USER_SETTINGS_DIR / f'{resolved_user}.json'
        if candidate_config.exists() or resolved_user.isdigit():
            resolved_user_id = resolved_user

    if resolved_user and not resolved_user_id:
        matched_user = _find_user_record_without_config(resolved_user)
        if matched_user:
            resolved_user_id = (matched_user.get('user_id') or "").strip()
            if not resolved_user:
                resolved_user = (matched_user.get('username') or "").strip()

    if resolved_user_id:
        return resolved_user_id
    if resolved_user:
        safe_name = re.sub(r'[^0-9A-Za-z_\-\u4e00-\u9fff]+', '_', resolved_user).strip('_')
        if safe_name:
            return f"{resolved_type}_{safe_name}"
    return "guest_default"


def get_user_runtime_state_path(for_save=False):
    """获取当前用户的运行状态文件路径"""
    user_identity = get_current_user_identity()
    state_file = USER_RUNTIME_STATE_DIR / f"{user_identity}.json"
    if for_save:
        state_file.parent.mkdir(parents=True, exist_ok=True)
    return state_file


def load_user_runtime_state():
    """加载当前用户的运行状态"""
    state_file = get_user_runtime_state_path()
    if not state_file.exists():
        return {}
    try:
        with open(state_file, 'r', encoding='utf-8') as f:
            data = json.load(f)
            return data if isinstance(data, dict) else {}
    except Exception as e:
        logging.error(f"加载用户运行状态失败: {str(e)}")
        return {}


def _deep_merge_dict(base, updates):
    """递归合并字典"""
    if not isinstance(base, dict):
        base = {}
    result = dict(base)
    for key, value in (updates or {}).items():
        if isinstance(value, dict) and isinstance(result.get(key), dict):
            result[key] = _deep_merge_dict(result.get(key, {}), value)
        else:
            result[key] = value
    return result


def _cycle_safe_json_dump(obj, fp, ensure_ascii=False, indent=2):
    """安全 JSON 序列化：检测并处理循环引用，避免 RecursionError"""
    seen = set()

    def _convert(o):
        if isinstance(o, dict):
            oid = id(o)
            if oid in seen:
                return "<circular-ref>"
            seen.add(oid)
            result = {}
            for k, v in o.items():
                result[str(k)] = _convert(v)
            seen.discard(oid)
            return result
        if isinstance(o, (list, tuple)):
            oid = id(o)
            if oid in seen:
                return "<circular-ref>"
            seen.add(oid)
            result = [_convert(item) for item in o]
            seen.discard(oid)
            return result
        if isinstance(o, (str, int, float, bool)) or o is None:
            return o
        # 其他类型转为字符串
        return str(o)

    safe_obj = _convert(obj)
    json.dump(safe_obj, fp, ensure_ascii=ensure_ascii, indent=indent)


def save_user_runtime_state(state, immediate=False, merge=True):
    """保存当前用户的运行状态"""
    state_file = get_user_runtime_state_path(for_save=True)
    data_to_save = state if isinstance(state, dict) else {}

    if merge and state_file.exists():
        try:
            with open(state_file, 'r', encoding='utf-8') as f:
                existing_state = json.load(f)
                if isinstance(existing_state, dict):
                    data_to_save = _deep_merge_dict(existing_state, data_to_save)
        except Exception as e:
            logging.error(f"读取用户运行状态失败: {str(e)}")

    try:
        print(f"[RuntimeState] ✍️ 写入: {state_file} | 数据量={len(str(data_to_save))} chars")
        with open(state_file, 'w', encoding='utf-8') as f:
            try:
                json.dump(data_to_save, f, ensure_ascii=False, indent=2)
            except RecursionError:
                # 数据中存在循环引用，回退到安全序列化
                print(f"[RuntimeState] ⚠️ 检测到循环引用，使用安全模式序列化: {state_file}")
                f.seek(0)
                f.truncate()
                _cycle_safe_json_dump(data_to_save, f, ensure_ascii=False, indent=2)
        print(f"[RuntimeState] ✅ 写入成功: {state_file}")
    except Exception as e:
        print(f"[RuntimeState] ❌ 写入失败: {state_file} | 错误: {e}")
        logging.error(f"保存用户运行状态失败: {str(e)}")
        if immediate:
            raise


def append_user_operation_record(text):
    """按用户分别保存操作记录"""
    if not text:
        return

    try:
        # 优先从运行时状态读取已保存的日志路径
        runtime_state = load_user_runtime_state()
        operation_log_path = runtime_state.get('operation_log_path', '').strip()
        if operation_log_path:
            log_file = Path(operation_log_path)
        else:
            # 直接计算日志路径，不依赖 save_user_runtime_state（避免循环引用导致的写入失败阻塞日志记录）
            user_identity = get_current_user_identity()
            log_file = USER_RUNTIME_STATE_DIR / 'logs' / f"{user_identity}.log"
            # 尝试保存日志路径到运行时状态（非关键操作，失败不影响日志写入）
            try:
                save_user_runtime_state({
                    'operation_log_path': str(log_file)
                }, immediate=True, merge=True)
            except Exception:
                pass

        log_file.parent.mkdir(parents=True, exist_ok=True)
        timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        with open(log_file, 'a', encoding='utf-8') as f:
            f.write(f"[{timestamp}] {text}\n")
    except Exception as e:
        logging.error(f"写入用户操作记录失败: {str(e)}")


# 配置缓存变量
_config_cache = None
_config_last_modified = 0
_common_config_last_modified = 0
_common_config_resolved_path = None

# 配置文件路径
_base_config_path = None
_admin_config_path = CONFIG_DIR / 'admin.json'
_current_config_path = None

# 保存定时器
_save_timer = None
_save_delay = 200  # 200ms 批量延迟（原 1000ms，缩短以减少数据丢失风险）

# 待保存的配置
_pending_config = None

# ✅ 脏标志：标记是否有未落盘的配置变更
_config_dirty = False

# ============================================================================
# 【2026-05-11 修复记录】"保留Word"功能问题排查与修复
# ============================================================================
#
# 【问题描述】：
#   用户勾选"保留Word"复选框后，生成的文件中仍然没有保留Word文件(.docx)
#   文件生成页面和CRM订单页面都存在此问题
#
# 【根本原因】（共发现3个独立问题）：
#
#   问题1：配置保存使用了延迟保存机制(save_config_with_delay)
#     - save_config_with_delay() 使用QTimer.singleShot(500ms)延迟写入
#     - 在500ms内如果有其他操作触发新的save_config_with_delay()，会覆盖待保存配置
#     - 导致keep_word_files的值从未真正写入磁盘
#     - 配置文件中始终为 keep_word_files=False
#     - 修复：改用 save_config(config, immediate=True) 立即同步写入磁盘（注：现已全面改为延迟写，此处仅为历史记录）
#
#   问题2：CRM合同生成使用的是 move_generated_document_files() 函数
#     - 之前一直修改的是 organize_output_files() 函数（文件整理页面用的）
#     - CRM订单页面调用的是完全不同的函数 move_generated_document_files()
#     - 导致所有修改都没有生效
#     - 修复：在正确的函数 move_generated_document_files() 中添加keep_word逻辑
#
#   问题3：CRM合同生成在后台线程中运行，存在线程安全问题
#     - run_crm_contract_process() 在 threading.Thread 中执行
#     - 全局变量 _keep_crm_word_override 在主线程设置，在后台线程读取
#     - Python GIL虽然保证原子操作，但时序上可能读到旧值
#     - 修复：在调用 move_generated_document_files() 时直接传递 keep_word 参数
#
#   问题4：文件生成和CRM订单的"保留Word"应该独立控制
#     - 原来两个页面共享同一个配置key: keep_word_files
#     - 一个页面的勾选会影响另一个页面
#     - 修复：分离为两个独立配置key
#       - 文件生成: keep_word_files → organize_output_files()
#       - CRM订单:  keep_crm_word_files → move_generated_document_files()
#
# 【修复涉及的代码位置】：
#   1. 全局变量定义（本位置）：_keep_word_override, _keep_crm_word_override
#   2. on_keep_word_changed()：文件生成页面的保留Word处理
#   3. on_crm_keep_word_changed()：CRM订单页面的保留Word处理（新增函数）
#   4. organize_output_files()：文件生成页面的文件整理
#   5. move_generated_document_files()：CRM订单页面的文件整理
#   6. run_crm_contract_process()：CRM合同生成时直接传递keep_word参数
#   7. CRM复选框初始化：使用独立的 keep_crm_word_files 配置key
#
# 【经验教训】：
#   - 修改代码前必须确认目标函数是否被正确调用
#   - 后台线程中不要依赖主线程的全局变量，应通过参数传递
#   - 配置保存应区分"立即保存"和"延迟保存"的使用场景
#   - 不同功能模块的配置应使用独立的key，避免互相干扰
# ============================================================================

_keep_word_override = None       # 文件生成页面：None/word/pdf/word_pdf
_keep_crm_word_override = None   # CRM订单页面：None/word/pdf/word_pdf

from PyQt6.QtCore import QTimer
def load_config():
    """加载所有配置文件（带缓存机制）
    优先加载个人配置文件，不存在则加载默认配置文件
    对于密码相关的设置，优先使用管理员配置文件中的设置
    """
    global _config_cache, _config_last_modified, _base_config_path, _common_config_last_modified, _common_config_resolved_path
    
    # 1. 获取当前配置文件路径
    config_file = get_config_path()
    # 确定默认配置文件路径
    if _base_config_path is None:
        _base_config_path = get_default_profile_path()
        if not _base_config_path.exists():
            try:
                import sys
                if getattr(sys, 'frozen', False):
                    _base_config_path = get_default_profile_path()
                else:
                    _base_config_path = get_default_profile_path()
            except:
                pass
    
    # 2. 检查配置文件是否有修改
    config_modified = False
    try:
        current_modified = 0
        if config_file.exists():
            current_modified = config_file.stat().st_mtime
        
        # 同时检查管理员配置文件是否有修改
        admin_config_path = CONFIG_DIR / 'admin.json'
        admin_modified = 0
        if admin_config_path.exists():
            admin_modified = admin_config_path.stat().st_mtime

        common_config_path = get_common_config_path()
        common_config_resolved_path = str(common_config_path)
        common_modified = 0
        if common_config_path.exists():
            common_modified = common_config_path.stat().st_mtime
        
        # 只有在缓存不存在或配置文件有修改时才重新加载
        if (
            _config_cache is None
            or current_modified != _config_last_modified
            or admin_modified != getattr(load_config, 'admin_last_modified', 0)
            or common_modified != _common_config_last_modified
            or common_config_resolved_path != _common_config_resolved_path
        ):
            config_modified = True
    except Exception:
        # 如果获取文件修改时间失败，强制重新加载
        config_modified = True
    
    # 3. 重新加载配置文件
    if config_modified:
        # 首先尝试加载个人配置文件
        user_config = {}
        if config_file.exists() and config_file != _base_config_path:
            try:
                with open(config_file, 'r', encoding='utf-8') as f:
                    user_config = json.load(f)
            except Exception as e:
                logging.error(f"加载个人配置文件失败: {str(e)}")
        
        # 如果个人配置为空，加载默认配置文件
        if not user_config and _base_config_path.exists():
            try:
                with open(_base_config_path, 'r', encoding='utf-8') as f:
                    user_config = json.load(f)
            except Exception as e:
                logging.error(f"加载默认配置文件失败: {str(e)}")
        
        # 加载管理员配置文件，优先使用其中的设置
        admin_config_path = CONFIG_DIR / 'admin.json'
        if admin_config_path.exists():
            try:
                with open(admin_config_path, 'r', encoding='utf-8') as f:
                    admin_config = json.load(f)
                # 优先使用管理员配置中的设置
                # 1. 功能配置（gui_options）
                if 'gui_options' in admin_config:
                    user_config['gui_options'] = admin_config['gui_options']
                # ✅【2026-05-11 删除】已移除密码相关配置同步
                # 原代码：同步 yearly_passwords、password_verification_enabled、password_verification_password
                # 密码验证功能已完全禁用，不再需要同步这些配置
                # 2. 其他设置
                if 'pag_zjt' in admin_config and 'Version2' in admin_config['pag_zjt']:
                    if 'pag_zjt' not in user_config:
                        user_config['pag_zjt'] = {}
                    user_config['pag_zjt']['Version2'] = admin_config['pag_zjt']['Version2']
            except Exception as e:
                logging.error(f"加载管理员配置文件失败: {str(e)}")

        common_config = load_common_config()
        if common_config:
            user_config = _merge_common_config_sections(user_config, common_config)
        
        # 更新缓存和最后修改时间
        _config_cache = user_config
        try:
            if config_file.exists():
                _config_last_modified = config_file.stat().st_mtime
            else:
                _config_last_modified = 0
            # 更新管理员配置文件的最后修改时间
            admin_config_path = CONFIG_DIR / 'admin.json'
            if admin_config_path.exists():
                load_config.admin_last_modified = admin_config_path.stat().st_mtime
            else:
                load_config.admin_last_modified = 0
            common_config_path = get_common_config_path()
            _common_config_resolved_path = str(common_config_path)
            if common_config_path.exists():
                _common_config_last_modified = common_config_path.stat().st_mtime
            else:
                _common_config_last_modified = 0
        except Exception:
            _config_last_modified = 0
            load_config.admin_last_modified = 0
            _common_config_last_modified = 0
            _common_config_resolved_path = None
    
    return _config_cache


def save_config(config, immediate=False):
    """保存配置文件"""
    if immediate:
        _do_save_config_immediate(config)
    else:
        save_config_with_delay(config)

def _do_save_config_immediate(config):
    """立即保存配置文件"""
    global _pending_config, _config_dirty

    # 清除待保存的配置
    _pending_config = None
    _config_dirty = False

    try:
        _save_config_to_targets(config)

        # 记录配置保存操作（只记录关键配置变更，避免过于频繁）
        operation_log.info(f"配置已保存: {get_config_path(for_save=True).name} + {get_common_config_path(for_save=True).name}")
    except Exception as e:
        logging.error(f"立即保存配置文件失败: {str(e)}")
        operation_log.error(f"配置保存失败: {str(e)}")
        raise


def flush_pending_config():
    """强制刷盘：立即执行所有待保存的配置（页面切换/关闭时调用）"""
    global _pending_config, _config_dirty
    if _pending_config is not None and _config_dirty:
        _do_save_config_immediate(_pending_config)

def save_config_with_delay(config):
    """延迟保存配置文件，避免频繁IO操作"""
    global _pending_config, _config_dirty

    # 保存待保存的配置
    _pending_config = config
    _config_dirty = True

    # 使用QTimer.singleShot来避免线程安全问题
    QTimer.singleShot(_save_delay, _do_save_config)

def show_multi_select_popup(parent, mappings, current_value='', anchor=None):
    """显示多选弹窗，从映射字典中选择多个值

    Args:
        parent: 父窗口
        mappings: {option_id: display_text} 映射字典
        current_value: 当前已选值（逗号分隔的字符串）
        anchor: 锚点控件，弹窗将显示在该控件下方；为 None 则居中显示

    Returns:
        选中值的逗号分隔字符串，取消则返回 None
    """
    from PyQt6.QtWidgets import QDialog, QVBoxLayout, QListWidget, QListWidgetItem, QDialogButtonBox

    dialog = QDialog(parent)
    dialog.setWindowTitle("选择值")
    dialog.setMinimumSize(260, 320)
    dialog.setWindowFlags(dialog.windowFlags() & ~Qt.WindowType.WindowContextHelpButtonHint)

    layout = QVBoxLayout(dialog)
    layout.setContentsMargins(12, 12, 12, 12)
    layout.setSpacing(8)

    list_widget = QListWidget()
    list_widget.setStyleSheet("QListWidget { font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; }")
    selected = set(v.strip() for v in current_value.split('；') if v.strip()) if current_value else set()

    items = sorted(mappings.items(), key=lambda x: x[1])
    for option_id, display_text in items:
        item = QListWidgetItem(display_text)
        item.setData(Qt.ItemDataRole.UserRole, option_id)
        item.setFlags(item.flags() | Qt.ItemFlag.ItemIsUserCheckable)
        item.setCheckState(Qt.CheckState.Checked if display_text in selected else Qt.CheckState.Unchecked)
        list_widget.addItem(item)

    layout.addWidget(list_widget)

    # 全选/取消全选按钮行
    sel_row = QHBoxLayout()
    select_all = QPushButton("全选")
    select_all.setStyleSheet("QPushButton { font-size: 11px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 8px; } QPushButton:hover { border-color: #1890FF; }")
    select_none = QPushButton("取消全选")
    select_none.setStyleSheet("QPushButton { font-size: 11px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 8px; } QPushButton:hover { border-color: #1890FF; }")
    select_all.clicked.connect(lambda: [list_widget.item(i).setCheckState(Qt.CheckState.Checked) for i in range(list_widget.count())])
    select_none.clicked.connect(lambda: [list_widget.item(i).setCheckState(Qt.CheckState.Unchecked) for i in range(list_widget.count())])
    sel_row.addWidget(select_all)
    sel_row.addWidget(select_none)
    sel_row.addStretch()
    layout.addLayout(sel_row)

    button_box = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
    button_box.accepted.connect(dialog.accept)
    button_box.rejected.connect(dialog.reject)
    layout.addWidget(button_box)

    # 对齐日期弹窗：在 exec() 之前定位到锚点控件下方
    dialog.adjustSize()
    if anchor is not None:
        anchor_bottom = anchor.mapToGlobal(anchor.rect().bottomLeft())
        dialog.move(anchor_bottom.x(), anchor_bottom.y() + 2)
    else:
        center_dialog(dialog, parent)

    if dialog.exec() == QDialog.DialogCode.Accepted:
        checked = []
        for i in range(list_widget.count()):
            item = list_widget.item(i)
            if item.checkState() == Qt.CheckState.Checked:
                checked.append(item.text())
        return '；'.join(checked) if checked else ''
    return None


# 模块级字典：存储活跃的多选下拉框引用，防止被 GC 回收
_MULTI_SELECT_DROPDOWNS: dict[int, 'CheckableOptionPopup'] = {}


def show_multi_select_dropdown(parent, mappings, current_value, anchor, target_input, on_change=None):
    """显示多选下拉框（对齐 CRM 设置业务类型下拉框风格），实时更新输入框。

    Args:
        parent: 父窗口
        mappings: {option_id: display_text} 映射字典
        current_value: 当前已选值（分隔符：；或 ,）
        anchor: 锚点控件，下拉框显示在该控件下方
        target_input: QLineEdit，勾选后实时更新文本
        on_change: 可选回调，每次勾选变更后调用
    """
    # 关闭同一 parent 上已有的下拉框（含其事件过滤器）
    parent_id = id(parent)
    existing = _MULTI_SELECT_DROPDOWNS.pop(parent_id, None)
    if existing is not None:
        try:
            existing.hide()
            old_filter = getattr(existing, '_outside_filter', None)
            if old_filter is not None:
                try:
                    QApplication.instance().removeEventFilter(old_filter)
                except Exception:
                    pass
            existing.deleteLater()
        except Exception:
            pass

    popup = CheckableOptionPopup(parent)
    _MULTI_SELECT_DROPDOWNS[parent_id] = popup

    # ---- 关键：把 Popup 改为 Dialog，避免 Popup 的鼠标 grab 拦截外部点击 ----
    # Qt.WindowType.Popup 会 grab 鼠标 + 创建原生窗口句柄，且 setWindowFlags 无法
    # 修改已生效的 grab 行为。必须先 hide() 销毁 Popup 原生句柄，show() 后再用
    # Dialog 标志重建原生句柄。Dialog 不 grab 鼠标，QApplication 事件分发正常。
    popup.setWindowFlags(
        Qt.WindowType.Dialog | Qt.WindowType.FramelessWindowHint | Qt.WindowType.WindowStaysOnTopHint
    )
    popup.hide()  # 销毁 Popup 标志创建的原生句柄

    # 解析当前值
    current = current_value.strip() if current_value else ''
    selected_set = set()
    if current:
        selected_set = {v.strip() for v in current.replace(',', '；').split('；') if v.strip()}

    # 构建显示名列表
    options = sorted(mappings.items(), key=lambda x: x[1])
    display_labels = [display for _id, display in options]
    label_to_id = {display: option_id for option_id, display in options}

    popup.set_options(display_labels, selected_options=list(selected_set))

    # 实时更新目标输入框
    def _on_selection_changed():
        selected_labels = popup.get_selected_options()
        target_input.setText('；'.join(selected_labels) if selected_labels else '')
        if on_change:
            on_change()

    popup.selection_changed.connect(_on_selection_changed)

    # ---- 点击外部关闭（对齐对象查询/CRM 筛选面板的 _DialogOutsideCloseFilter 机制） ----
    popup.reject = lambda: popup.hide()
    pf = _DialogOutsideCloseFilter(popup)
    popup._outside_filter = pf
    popup._outside_close_armed = False
    QApplication.instance().installEventFilter(pf)
    # 延迟激活，避免触发 📋 按钮的鼠标事件立即关闭下拉框
    QTimer.singleShot(0, lambda p=popup: setattr(p, '_outside_close_armed', True))

    def _cleanup():
        _MULTI_SELECT_DROPDOWNS.pop(parent_id, None)
        try:
            QApplication.instance().removeEventFilter(pf)
        except Exception:
            pass

    popup.destroyed.connect(_cleanup)

    popup.show_below(anchor)
    popup.raise_()


def _do_save_config():
    """实际执行保存操作"""
    global _pending_config, _config_dirty

    if _pending_config is None:
        return

    config = _pending_config
    _pending_config = None
    _config_dirty = False

    try:
        _save_config_to_targets(config)
    except Exception as e:
        logging.error(f"保存配置文件失败: {str(e)}")
        raise


def ensure_word_pdf_single_use_mode_loaded():
    """从配置加载 Word PDF 兼容模式开关。"""
    if _WORD_PDF_FORCE_SINGLE_USE_LOADED.is_set():
        return

    try:
        config = load_config() or {}
        app_settings = config.get('app_settings', {})
        if app_settings.get('word_pdf_force_single_use', False):
            _WORD_PDF_FORCE_SINGLE_USE.set()
    except Exception as error:
        logging.warning(f"加载Word PDF兼容模式失败: {str(error)}")
    finally:
        _WORD_PDF_FORCE_SINGLE_USE_LOADED.set()


def persist_word_pdf_single_use_mode():
    """持久化 Word PDF 兼容模式，避免下次启动再次探测失败。"""
    try:
        config = load_config() or {}
        app_settings = config.setdefault('app_settings', {})
        if app_settings.get('word_pdf_force_single_use', False):
            return

        app_settings['word_pdf_force_single_use'] = True
        save_config(config, immediate=False)
        logging.info("已保存Word PDF兼容模式，后续启动将直接使用单文件会话")
    except Exception as error:
        logging.warning(f"保存Word PDF兼容模式失败: {str(error)}")


def _color_to_rgba(color, alpha):
    """将 QColor 或颜色字符串转换为 RGBA CSS 字符串。"""
    qcolor = QColor(color)
    return f"rgba({qcolor.red()}, {qcolor.green()}, {qcolor.blue()}, {alpha})"


