    def _get_primary_crm_objects(self):
        """获取可作为主对象的数据源列表（始终包含部门员工内置数据源）。"""
        crm_objs = self.config.get('fxiaoke', {}).get('crm_objects', [])
        if not crm_objs:
            crm_objs = [
                {'name': '商机', 'api_name': 'NewOpportunityObj'},
                {'name': '销售订单', 'api_name': 'SalesOrderObj'},
                {'name': '发货单', 'api_name': 'DeliveryNoteObj'},
                {'name': '发货单产品', 'api_name': 'DeliveryNoteProductObj'},
            ]
        return crm_objs

    def _get_object_name_by_api_name(self, api_name):
        """根据API Name查找对象显示名称。"""
        all_primary = self._get_primary_crm_objects()
        for obj in all_primary:
            if obj['api_name'] == api_name:
                return obj['name']
        # 如果在主对象里找不到，就先用api_name作为名字
        return api_name

    def _on_source_object_selected(self, current, previous, level):
        """当用户在数据源选择器的某一级列表中选择一项时触发。"""
        if not current:
            return

        # 清理所有后续层级
        for i in range(level + 1, 4):
            self.report_source_columns[i]["list"].clear()
            self.report_source_columns[i]["group"].setVisible(False)
            self.report_source_columns[i]["list"].setVisible(False)

        # 获取当前选择
        current_list = self.report_source_columns[level]["list"]
        all_objects = current_list.property("crm_objects")
        selected_object_name = current.text()
        
        selected_object = next((obj for obj in all_objects if obj['name'] == selected_object_name), None)

        if not selected_object:
            return

        api_name = selected_object.get("api_name")
        if not api_name:
            return

        # 如果是第一列选择，填充数据范围筛选字段下拉框
        if level == 0 and hasattr(self, 'custom_report_scope_field_combo'):
            self.custom_report_scope_field_combo.blockSignals(True)
            self.custom_report_scope_field_combo.clear()
            try:
                field_options = self.get_object_field_options(api_name)
                for key, label in sorted(field_options, key=lambda x: x[1] or x[0]):
                    display = f"{label} ({key})" if label else key
                    self.custom_report_scope_field_combo.addItem(display, key)
            except Exception:
                pass
            self.custom_report_scope_field_combo.blockSignals(False)

        # 如果是最后一列，则不加载下一级
        if level >= 3:
            return

        # 获取关联字段并填充下一列
        fields = self.fetch_object_fields(api_name)
        related_objects = []
        relationship_field_types = {'reference', 'lookup', 'masterDetail'}

        for field in fields:
            print(field) # DEBUG: Inspect field metadata
            field_api_name = field.get('apiName', '')
            field_type = field.get('type', '')
            
            # 判断是否是关联字段
            if field_api_name.endswith('__r') or field_type in relationship_field_types:
                related_api_name = field.get('referenceTo') 
                if not related_api_name and field_api_name.endswith('__r'):
                     related_api_name = field_api_name.replace('__r', 'Obj').replace('_id', '').capitalize()

                if related_api_name:
                    related_name = self._get_object_name_by_api_name(related_api_name)
                    related_objects.append({'name': related_name, 'api_name': related_api_name})

        if related_objects:
            next_list = self.report_source_columns[level + 1]["list"]
            next_group = self.report_source_columns[level + 1]["group"]
            
            next_list.clear()
            next_list.addItems([obj['name'] for obj in related_objects])
            next_list.setProperty("crm_objects", related_objects)
            
            next_group.setVisible(True)
            next_list.setVisible(True)


    def _on_confirm_step1_objects(self):
        """Step 1 确认：校验对象选择，填充 Step 2 的数据源下拉，切换到 Step 2"""
        selected_objects = []
        for i, col_data in enumerate(self.report_source_columns):
            list_widget = col_data["list"]
            current_item = list_widget.currentItem()
            if current_item:
                selected_text = current_item.text()
                all_objects = list_widget.property("crm_objects")
                selected_obj = next((obj for obj in all_objects if obj['name'] == selected_text), None)
                if selected_obj:
                    selected_objects.append(selected_obj)
            else:
                break

        if not selected_objects:
            QMessageBox.warning(self, "提示", "请至少选择一个主数据对象。")
            return

        primary_obj = selected_objects[0]

        # 存储主数据源 API 名称（用于数据迭代）
        self._custom_report_main_api_name = primary_obj['api_name']
        if hasattr(self, 'custom_report_main_source_label'):
            self.custom_report_main_source_label.setText(f"主数据源: {primary_obj['name']}")

        # ===== 如果选择了多个对象，弹出匹配关系配置对话框 =====
        match_field_map = {}  # api_name -> {"main": main_field, "source": source_field}
        if len(selected_objects) > 1:
            match_field_map = self._show_matching_config_dialog(selected_objects)
            if match_field_map is None:
                return  # 用户取消了对话框

        # 更新 Step 2 的数据源下拉
        self.custom_report_main_source_combo.blockSignals(True)
        self.custom_report_main_source_combo.clear()
        for obj in selected_objects:
            self.custom_report_main_source_combo.addItem(f"{obj['name']} ({obj['api_name']})", obj['api_name'])
        self.custom_report_main_source_combo.setCurrentIndex(0)
        self.custom_report_main_source_combo.blockSignals(False)

        # 更新 Step 2 的数据对象表，携带匹配关系
        self.custom_report_source_table.setRowCount(0)
        for obj in selected_objects:
            api_name = obj['api_name']
            match_info = match_field_map.get(api_name, {})
            match_field_str = ''
            if match_info:
                try:
                    match_field_str = json.dumps(match_info, ensure_ascii=False)
                except Exception:
                    pass
            self._append_custom_report_source_row({
                'name': obj['name'],
                'api_name': api_name,
                'enabled': True,
                'match_field': match_field_str,
            })

        # 收集 Step 1 数据范围设置
        self._custom_report_scope_settings = {
            'use_filter': self.custom_report_scope_filter_radio.isChecked() if hasattr(self, 'custom_report_scope_filter_radio') else False,
            'time_check': self.custom_report_scope_time_check.isChecked() if hasattr(self, 'custom_report_scope_time_check') else False,
            'date_start': self.custom_report_scope_date_start.date().toString('yyyy-MM-dd') if hasattr(self, 'custom_report_scope_date_start') else '',
            'date_end': self.custom_report_scope_date_end.date().toString('yyyy-MM-dd') if hasattr(self, 'custom_report_scope_date_end') else '',
            'conditions': [
                self.custom_report_scope_conditions_list.item(i).data(Qt.UserRole)
                for i in range(self.custom_report_scope_conditions_list.count())
            ] if hasattr(self, 'custom_report_scope_conditions_list') else [],
        }

        # 显示 Step 2 操作按钮
        self.custom_report_step2_btns.setVisible(True)
        self.custom_report_step_label.setText("步骤 2/2：字段配置与筛选")

        # 切换到 Step 2
        self.custom_report_editor_step_stack.setCurrentIndex(1)

        # 标记为已加载并刷新候选字段
        self._custom_report_list_loaded = True
        self._refresh_candidate_field_list()

    def _show_matching_config_dialog(self, selected_objects):
        """显示匹配关系配置对话框，让用户指定各对象间的关联字段（VLOOKUP式，星型 JOIN）。"""
        if len(selected_objects) < 2:
            return {}

        from PyQt6.QtWidgets import (QDialog, QVBoxLayout, QHBoxLayout, QLabel,
                                      QComboBox, QPushButton, QGroupBox, QFormLayout,
                                      QDialogButtonBox, QFrame)

        dialog = QDialog(self)
        dialog.setWindowTitle("设置数据对象匹配关系")
        dialog.setMinimumWidth(550)
        dialog.setStyleSheet("""
            QDialog { background-color: #FAFAFA; }
            QGroupBox { font-weight: 600; font-size: 13px; border: 1px solid #E8E8E8;
                        border-radius: 6px; margin-top: 8px; padding-top: 16px; }
            QGroupBox::title { subcontrol-origin: margin; left: 12px; padding: 0 6px; }
        """)

        layout = QVBoxLayout(dialog)
        layout.setSpacing(12)
        layout.setContentsMargins(20, 16, 20, 16)

        main_obj = selected_objects[0]
        join_objects = selected_objects[1:]  # 所有非主对象

        # 顶部提示
        hint = QLabel(f"主数据对象：<b>{main_obj['name']}</b>（{main_obj['api_name']}）\n"
                      f"请为每个关联对象指定与主对象的匹配字段（类似 Excel VLOOKUP）。")
        hint.setStyleSheet("color: #666; font-size: 12px; background: #FFFBE6; padding: 8px 12px; border-radius: 4px;")
        hint.setWordWrap(True)
        layout.addWidget(hint)

        # 获取主对象的字段选项（所有 JOIN 对共用）
        main_options = self.get_object_field_options(main_obj['api_name'])

        # 为每个非主对象创建与主对象的匹配行（星型：A→B, A→C, A→D）
        match_widgets = []  # [(main_field_combo, source_field_combo, join_obj)]
        for i, join_obj in enumerate(join_objects):
            group = QGroupBox(f"关联 {i+1}：{main_obj['name']} → {join_obj['name']}")
            group_layout = QFormLayout(group)
            group_layout.setSpacing(8)
            group_layout.setContentsMargins(12, 20, 12, 12)

            join_options = self.get_object_field_options(join_obj['api_name'])

            main_combo = QComboBox()
            main_combo.setMinimumWidth(220)
            main_combo.setEditable(True)
            main_combo.setPlaceholderText(f"选择 {main_obj['name']} 的关联字段...")
            main_options_sorted = sorted(main_options, key=lambda x: x[1] or x[0])
            for key, label in main_options_sorted:
                display = f"{label} ({key})" if label else key
                main_combo.addItem(display, key)

            source_combo = QComboBox()
            source_combo.setMinimumWidth(220)
            source_combo.setEditable(True)
            source_combo.setPlaceholderText(f"选择 {join_obj['name']} 的匹配字段...")
            join_options_sorted = sorted(join_options, key=lambda x: x[1] or x[0])
            for key, label in join_options_sorted:
                display = f"{label} ({key})" if label else key
                source_combo.addItem(display, key)

            # 智能推荐匹配字段
            join_api_lower = join_obj['api_name'].lower().replace('obj', '')
            main_api_lower = main_obj['api_name'].lower().replace('obj', '')

            # 主对象推荐：找包含关联对象名的字段（如 sales_order_id）
            suggested_main = ''
            for key, label in main_options:
                key_lower = key.lower()
                if join_api_lower in key_lower and key_lower != 'name':
                    suggested_main = key
                    break
            if not suggested_main:
                for key, label in main_options:
                    key_lower = key.lower()
                    # 找外键类型的字段（_id 或 _id__r 结尾）
                    if (key_lower.endswith('_id') or key_lower.endswith('__r')) and 'name' not in key_lower:
                        if join_api_lower in key_lower or main_api_lower in key_lower:
                            suggested_main = key
                            break

            # 关联对象推荐：优先 name，其次找包含主对象名的字段
            suggested_source = ''
            for key, label in join_options:
                if key == 'name':
                    suggested_source = key
                    break
            if not suggested_source:
                for key, label in join_options:
                    key_lower = key.lower()
                    if main_api_lower in key_lower and key_lower != 'name':
                        suggested_source = key
                        break

            if suggested_main:
                idx = main_combo.findData(suggested_main)
                if idx >= 0:
                    main_combo.setCurrentIndex(idx)
            if suggested_source:
                idx = source_combo.findData(suggested_source)
                if idx >= 0:
                    source_combo.setCurrentIndex(idx)

            main_field_label = QLabel(f"「{main_obj['name']}」关联字段:")
            source_field_label = QLabel(f"「{join_obj['name']}」匹配字段:")

            group_layout.addRow(main_field_label, main_combo)
            group_layout.addRow(source_field_label, source_combo)

            hint_row = QLabel(f"用主对象「{main_obj['name']}」的关联字段值，查找「{join_obj['name']}」中匹配字段值相等的记录")
            hint_row.setStyleSheet("color: #999; font-size: 11px; font-weight: normal;")
            group_layout.addRow(hint_row)

            layout.addWidget(group)
            match_widgets.append((main_combo, source_combo, join_obj))

        # 按钮
        btn_layout = QHBoxLayout()
        btn_layout.addStretch()

        cancel_btn = QPushButton("取消")
        cancel_btn.setFixedSize(80, 30)
        cancel_btn.setStyleSheet("""
            QPushButton { border: 1px solid #D9D9D9; border-radius: 4px; background: #FFFFFF; }
            QPushButton:hover { border-color: #1890FF; color: #1890FF; }
        """)
        cancel_btn.clicked.connect(dialog.reject)
        btn_layout.addWidget(cancel_btn)

        def _validate_and_accept():
            """验证所有匹配对都已配置。"""
            missing = []
            for idx, (main_combo, source_combo, join_obj) in enumerate(match_widgets):
                main_field = main_combo.currentData() or ''
                source_field = source_combo.currentData() or ''
                if not main_field or not source_field:
                    missing.append(f"关联 {idx+1}：{main_obj['name']} → {join_obj['name']}")
            if missing:
                QMessageBox.warning(
                    dialog, "匹配字段不完整",
                    "以下关联尚未设置匹配字段，请补充：\n\n" + "\n".join(missing)
                )
                return
            dialog.accept()

        ok_btn = QPushButton("✓ 确认匹配")
        ok_btn.setFixedSize(100, 30)
        ok_btn.setStyleSheet("""
            QPushButton { background-color: #FF8C00; color: #FFFFFF; border: none;
                          border-radius: 4px; font-weight: 600; }
            QPushButton:hover { background-color: #E67A00; }
        """)
        ok_btn.clicked.connect(_validate_and_accept)
        btn_layout.addWidget(ok_btn)

        layout.addLayout(btn_layout)

        result = dialog.exec()
        if result != QDialog.DialogCode.Accepted:
            return None

        # 收集匹配关系：每个关联对象记录其与主对象的匹配字段
        match_map = {}
        for main_combo, source_combo, join_obj in match_widgets:
            main_field = main_combo.currentData() or ''
            source_field = source_combo.currentData() or ''
            match_map[join_obj['api_name']] = {
                'main': main_field,
                'source': source_field,
            }

        return match_map

    def _install_field_builder_drop_handler(self):
        """为字段拼接表安装拖放事件过滤器（拖放处理在 eventFilter 中统一处理）"""
        if not hasattr(self, 'custom_report_field_builder_table'):
            return
        table = self.custom_report_field_builder_table
        viewport = table.viewport()
        viewport.installEventFilter(self)
        self._field_builder_drop_viewport = viewport

    def _handle_field_drop_text(self, text):
        """根据拖放文本添加字段到拼接表"""
        # 文本格式可能是 "字段显示名 (field_key)" 或直接是 field_key
        key = text
        display = text
        if '(' in text and text.endswith(')'):
            parts = text.rsplit('(', 1)
            display = parts[0].strip()
            key = parts[1].rstrip(')').strip()
        # 在当前候选列表中查找匹配项
        source_api = self.custom_report_main_source_combo.currentData() or 'NewOpportunityObj'
        for i in range(self.custom_report_candidate_fields.count()):
            item = self.custom_report_candidate_fields.item(i)
            item_key = item.data(Qt.ItemDataRole.UserRole)
            if item_key == key or item.text().startswith(display):
                key = item_key or key
                display = item.text().split(' (')[0]
                source_api = self.custom_report_main_source_combo.currentData() or 'NewOpportunityObj'
                break
        config = {
            'display_name': display,
            'source_api_name': source_api,
            'field_name': key,
            'main_link_field': '',
            'source_link_field': '',
        }
        # 自动继承对象级匹配关系
        main_link, source_link = self._get_object_level_match_fields(source_api)
        if main_link and source_link:
            config['main_link_field'] = main_link
            config['source_link_field'] = source_link
        self._add_custom_report_field_config_row(config)
        self._save_custom_report_builder_state()

    def _get_object_level_match_fields(self, source_api_name):
        """从 Step 1 配置的对象级匹配关系中获取匹配字段。
        返回 (main_link_field, source_link_field) 元组。
        """
        if not source_api_name:
            return ('', '')
        rows = self._collect_custom_report_source_rows()
        for row in rows:
            if row.get('api_name') == source_api_name:
                match_raw = str(row.get('match_field', '') or '').strip()
                if match_raw:
                    try:
                        match_info = json.loads(match_raw)
                        if isinstance(match_info, dict):
                            return (
                                str(match_info.get('main', '') or '').strip(),
                                str(match_info.get('source', '') or '').strip(),
                            )
                    except (json.JSONDecodeError, TypeError):
                        if match_raw:
                            return ('', match_raw)
                break
        return ('', '')

    def _on_candidate_field_filter_changed(self, text):
        """根据搜索文本过滤候选字段列表"""
        text = text.strip().lower()
        for i in range(self.custom_report_candidate_fields.count()):
            item = self.custom_report_candidate_fields.item(i)
            item.setHidden(bool(text and text not in item.text().lower()))

    def _remove_selected_field_config(self):
        """删除字段拼接表中选中的行"""
        table = self.custom_report_field_builder_table
        rows = sorted(set(idx.row() for idx in table.selectedIndexes()), reverse=True)
        for row in rows:
            table.removeRow(row)
        if rows:
            self._save_custom_report_builder_state()

    def switch_to_custom_report_editor(self, report_id: str = None, folder_path: str = ""):
        """切换到编辑器页面（v2 新版）。

        Args:
            report_id: 要编辑的报表 ID。为 None 时创建新报表。
            folder_path: 新建报表时指定所属文件夹路径。
        """
        mgr = getattr(self, '_report_manager', None)
        if not mgr:
            return

        # 懒加载编辑器页面
        if not hasattr(self, 'custom_report_editor_page') or self.custom_report_editor_page is None:
            self.custom_report_editor_page = self.create_custom_report_editor()
            self.custom_report_page_stack.addWidget(self.custom_report_editor_page)

        # 加载报表配置
        if report_id:
            mgr.open_report_in_editor(report_id)
        else:
            mgr.new_report_in_editor(folder_path=folder_path)

        # 切换到编辑器
        if hasattr(self, 'custom_report_page_stack'):
            idx = self.custom_report_page_stack.indexOf(self.custom_report_editor_page)
            if idx >= 0:
                self.custom_report_page_stack.setCurrentIndex(idx)

    def switch_to_custom_report_detail(self, report_id: str):
        """切换到报表详情页（数据视图）。

        Args:
            report_id: 要查看数据的报表 ID。
        """
        mgr = getattr(self, '_report_manager', None)
        if not mgr or not report_id:
            return

        # 获取报表信息
        rpt = mgr.get_report(report_id)
        report_name = rpt.name if rpt else report_id
        filters = []
        if rpt:
            for f in rpt.filters:
                if hasattr(f, 'field_api'):
                    filters.append({
                        'field': f.field_api,
                        'field_label': f.field_label,
                        'target_object_api': f.target_object_api,
                        'operator': f.operator,
                        'value': f.value,
                        'expose': f.expose,
                        'is_date': f.is_date_field,
                    })
                elif isinstance(f, dict):
                    filters.append({
                        'field': f.get('field_api', ''),
                        'field_label': f.get('field_label', ''),
                        'target_object_api': f.get('target_object_api', ''),
                        'operator': f.get('operator', 'EQ'),
                        'value': f.get('value', ''),
                        'expose': f.get('expose', False),
                        'is_date': f.get('is_date_field', False),
                    })

        # 懒加载详情页面
        if not hasattr(self, 'custom_report_detail_page') or self.custom_report_detail_page is None:
            from custom_report.views.report_detail_page import ReportDetailPage
            db = mgr._db if hasattr(mgr, '_db') else None

            def _save_filters(report_id, conditions):
                from custom_report.models import FilterCondition
                filters = [
                    FilterCondition(
                        field_api=c.get('field', ''),
                        operator=c.get('operator', 'EQ'),
                        value=c.get('value', ''),
                        target_object_api=c.get('target_object_api', ''),
                        field_label=c.get('field_label', ''),
                        expose=c.get('expose', False),
                        is_date_field=c.get('is_date', False),
                    )
                    for c in conditions
                ]
                mgr.save_report_filters(report_id, filters)

            self.custom_report_detail_page = ReportDetailPage(
                db,
                save_config_fn=save_config,
                load_config_fn=load_config,
                app_config=self.config,
                save_filters_fn=_save_filters,
            )
            self.custom_report_detail_page.backRequested.connect(self.switch_to_custom_report_list)
            self.custom_report_detail_page.editRequested.connect(self._on_report_edit_from_detail)
            self.custom_report_detail_page.refreshDataRequested.connect(self._on_report_refresh_data)
            self.custom_report_page_stack.addWidget(self.custom_report_detail_page)

        # 查找主表 _id 字段对应的中文列名，用于同步 MySQL 时作为主键
        id_column = None
        if rpt:
            main_api = rpt.main_object_api

            # ✅ 从旧编辑器配置同步最新的字段顺序到 ReportDefinition
            # （旧编辑器保存到 config.json，v2 迁移后不会再同步，这里补齐）
            self._sync_v1_field_order_to_report(rpt, report_name)

            for col in rpt.columns:
                src_obj = col.source_object_api if hasattr(col, 'source_object_api') else col.get('source_object_api', '')
                src_field = col.source_field if hasattr(col, 'source_field') else col.get('source_field', '')
                if src_obj == main_api and src_field in ('_id', 'id', '_ID', 'Id'):
                    id_column = col.display_name if hasattr(col, 'display_name') else col.get('display_name', '')
                    break

        # 加载报表数据（含筛选条件）
        self.custom_report_detail_page.load_report(report_id, report_name, filters, id_column, report_def=rpt)

        # 切换到详情页
        if hasattr(self, 'custom_report_page_stack'):
            idx = self.custom_report_page_stack.indexOf(self.custom_report_detail_page)
            if idx >= 0:
                self.custom_report_page_stack.setCurrentIndex(idx)

    def _sync_v1_field_order_to_report(self, rpt, report_name: str):
        """将旧编辑器 (config.json) 的字段顺序同步到 ReportDefinition.columns.sort_order。

        旧编辑器保存字段配置到 config.json → custom_reports → presets，
        而详情页使用 v2 ReportDefinition。迁移只在首次运行，之后旧编辑器的
        字段顺序变更不会自动同步到 v2，导致详情页字段顺序与编辑预览不一致。
        """
        if not rpt or not report_name:
            return
        try:
            cfg = self.config or load_config()
            cr = cfg.get('custom_reports', {}) if isinstance(cfg, dict) else {}
            presets = cr.get('presets', {}) if isinstance(cr, dict) else {}
            state = presets.get(report_name)
            if not isinstance(state, dict):
                return
            field_configs = state.get('field_configs', [])
            if not field_configs:
                return

            # 按 field_configs 的索引顺序更新 sort_order
            field_order_map = {}
            for i, fc in enumerate(field_configs):
                if not isinstance(fc, dict):
                    continue
                key = (fc.get('display_name', ''), fc.get('field_name', ''))
                field_order_map[key] = i

            updated = False
            for col in rpt.columns:
                if isinstance(col, dict):
                    key = (col.get('display_name', ''), col.get('source_field', ''))
                else:
                    key = (col.display_name or '', col.source_field or '')
                if key in field_order_map:
                    new_order = field_order_map[key]
                    if isinstance(col, dict):
                        if col.get('sort_order', 0) != new_order:
                            col['sort_order'] = new_order
                            updated = True
                    else:
                        if col.sort_order != new_order:
                            col.sort_order = new_order
                            updated = True

            if updated:
                # 持久化到 v2 存储
                mgr = getattr(self, '_report_manager', None)
                if mgr:
                    mgr.save_report(rpt)
        except Exception:
            pass

    def switch_to_custom_report_list(self):
        """切换回列表页面（v2 新版）"""
        # 刷新列表
        if hasattr(self, 'custom_report_list_page'):
            try:
                self.custom_report_list_page.refresh()
            except Exception:
                pass
        if hasattr(self, 'custom_report_page_stack'):
            idx = self.custom_report_page_stack.indexOf(self.custom_report_list_page)
            if idx >= 0:
                self.custom_report_page_stack.setCurrentIndex(idx)

    # ===== 新版信号处理 =====

    def _on_new_report_edit(self, report_id: str):
        """列表页双击 → 进入报表详情页（数据视图）"""
        self.switch_to_custom_report_detail(report_id)

    def _on_new_report_create(self):
        """列表页新建 → 空白编辑器"""
        self.switch_to_custom_report_editor()

    def _on_new_report_create_in_folder(self, folder_path: str):
        """在指定文件夹中新建报表 → 空白编辑器"""
        self.switch_to_custom_report_editor(folder_path=folder_path)

    def _on_report_edit_from_detail(self, report_id: str):
        """详情页点击「编辑报表」→ 进入编辑器"""
        self.switch_to_custom_report_editor(report_id)

    def _on_report_refresh_data(self, report_id: str):
        """详情页点击「更新数据」→ CRM 同步 → 拼表 → 刷新页面（后台线程）。
        复用对象查询已有的同步逻辑（MysqlCache.replace_cleaned_all），
        写入对象-{name} 表，与 JOIN 读表一致。"""
        from PyQt6.QtWidgets import QMessageBox
        from PyQt6.QtCore import QObject, pyqtSignal

        mgr = getattr(self, '_report_manager', None)
        if not mgr:
            return
        rpt = mgr.get_report(report_id)
        if not rpt:
            return

        # 同步旧编辑器的字段顺序到 ReportDefinition（确保 MySQL 表列顺序与编辑界面一致）
        self._sync_v1_field_order_to_report(rpt, rpt.name or report_id)

        apis = rpt.get_object_apis()
        if not apis:
            QMessageBox.warning(self, "提示", "报表未配置数据对象。")
            return

        rpt_name = rpt.name or report_id

        refresh_cfg = load_config()
        self.config = refresh_cfg

        # 获取各 API 对应的中文显示名
        crm_objs = refresh_cfg.get('fxiaoke', {}).get('crm_objects', []) or []
        api_to_display = {}
        api_to_type = {}
        for obj in crm_objs:
            if isinstance(obj, dict):
                api_name = obj.get('api_name', '')
                api_to_display[api_name] = obj.get('name', '')
                api_to_type[api_name] = obj.get('object_type', 'preset')

        page = self.custom_report_detail_page
        if page and hasattr(page, '_refresh_btn'):
            page._refresh_btn.setText("⏳ 更新中...")
            page._refresh_btn.setEnabled(False)

        # 使用 pyqtSignal 跨线程通信（QTimer.singleShot 在非主线程不可靠）
        class _RefreshSignals(QObject):
            done = pyqtSignal(bool, str, int)  # success, message, row_count

        signals = _RefreshSignals()

        def _detail_filters_from_report(report_def):
            detail_filters = []
            if not report_def:
                return detail_filters
            for f in getattr(report_def, 'filters', []) or []:
                if hasattr(f, 'field_api'):
                    detail_filters.append({
                        'field': f.field_api,
                        'field_label': f.field_label,
                        'target_object_api': f.target_object_api,
                        'operator': f.operator,
                        'value': f.value,
                        'expose': f.expose,
                        'is_date': f.is_date_field,
                    })
                elif isinstance(f, dict):
                    detail_filters.append({
                        'field': f.get('field_api', ''),
                        'field_label': f.get('field_label', ''),
                        'target_object_api': f.get('target_object_api', ''),
                        'operator': f.get('operator', 'EQ'),
                        'value': f.get('value', ''),
                        'expose': f.get('expose', False),
                        'is_date': f.get('is_date_field', False),
                    })
            return detail_filters

        def _on_done(success: bool, message: str, row_count: int):
            if page and hasattr(page, '_refresh_btn'):
                page._refresh_btn.setText("🔄 更新数据")
                page._refresh_btn.setEnabled(True)
            if success:
                print(f"[更新报表] ✅ 完成！共 {row_count} 条记录",
                      file=sys.stderr, flush=True)
                if page:
                    refreshed_rpt = mgr.get_report(report_id) or rpt
                    page.load_report(report_id, rpt_name, _detail_filters_from_report(refreshed_rpt), report_def=refreshed_rpt)
            else:
                print(f"[更新报表] ❌ 失败: {message}", file=sys.stderr, flush=True)
                QMessageBox.warning(self, "更新失败", message)

        signals.done.connect(_on_done)

        print(f"\n{'='*60}", file=sys.stderr, flush=True)
        print(f"[更新报表] {rpt_name}  (ID: {report_id})", file=sys.stderr, flush=True)
        print(f"[更新报表] 涉及 {len(apis)} 个对象: {', '.join(apis)}", file=sys.stderr, flush=True)
        print(f"{'='*60}", file=sys.stderr, flush=True)

        def run_in_background():
            t0 = time.time()
            sync_errors = []
            cfg = load_config()
            self.config = cfg
            fx_cfg = cfg.get('fxiaoke', {})
            obj_settings = fx_cfg.get('obj_query_settings', {})
            crm_fields = fx_cfg.get('crm_object_fields', {})

            # --- 阶段1: CRM → 对象-{name} 表（对齐对象查询的筛选 + 条数设置）---
            fetcher = mgr._fetcher
            for i, api in enumerate(apis):
                display_name = api_to_display.get(api, api)

                # 读取该对象在对象查询中的筛选条件、加载条数、字段配置
                api_settings = obj_settings.get(api, {})
                global_load_default = int(fx_cfg.get('load_count', 10000))
                try:
                    load_count = int(api_settings.get('max_records', global_load_default))
                except (TypeError, ValueError):
                    load_count = global_load_default
                load_count = max(1, min(load_count, 10000))
                saved_filter_count = len(api_settings.get('filters', [])) if isinstance(api_settings.get('filters', []), list) else 0
                api_filters = self._build_api_filters_from_settings(api)
                api_fields = crm_fields.get(api, {})
                field_projection = list(dict.fromkeys(api_fields.keys())) if api_fields else None
                if field_projection and '_id' not in field_projection:
                    field_projection.insert(0, '_id')
                if field_projection:
                    for f in list(field_projection):
                        if not f.endswith('__r') and f'{f}__r' not in field_projection:
                            field_projection.append(f'{f}__r')
                if not field_projection:
                    # 非 CRM 对象（Excel 导入 / MySQL 直连 / 部门员工等）不通过 CRM API 获取，静默跳过
                    if api not in api_to_display:
                        print(f"  [同步] ⏭ {api} 非 CRM 对象，跳过 API 获取", file=sys.stderr, flush=True)
                    else:
                        sync_errors.append(f"{api}: 未配置字段，请先在 设置→CRM设置→对象管理→字段配置 中添加字段")
                        print(f"  [同步] ❌ {api} 未配置字段，跳过", file=sys.stderr, flush=True)
                    continue

                converted_filter_count = len(api_filters) if api_filters else 0
                filter_desc = f"筛选{saved_filter_count}个→CRM条件{converted_filter_count}个" if saved_filter_count else "无筛选"
                print(f"  [同步] ({i+1}/{len(apis)}) {api} | {filter_desc} | 最多{load_count}条",
                      file=sys.stderr, flush=True)
                rows, total, err = fetcher.fetch_object(
                    api,
                    max_records=load_count,
                    batch_size=min(100, load_count),
                    filters=api_filters,
                    field_projection=field_projection,
                    is_custom=api_to_type.get(api, 'preset') == 'custom',
                )
                if err:
                    sync_errors.append(f"{api}: {err}")
                    print(f"  [同步] ❌ {api} 获取失败: {err}", file=sys.stderr, flush=True)
                    continue
                if not rows:
                    print(f"  [同步] ⚠️ {api} 无数据，跳过", file=sys.stderr, flush=True)
                    continue

                print(f"  [同步] ({i+1}/{len(apis)}) {api} 获取 {len(rows)} 条，正在清洗并写入 MySQL...",
                      file=sys.stderr, flush=True)

                # 按当前 API 独立加载字段映射并清洗（不使用 _get_obj_query_cleaned_data_bg，
                # 因为它缓存了上一次对象查询的字段映射，多 API 时会用错映射）
                cleaned_rows, cleaned_headers, display_type_map = self._clean_for_sync(api, rows)
                if cleaned_rows and cleaned_headers:
                    mc = MysqlCache()
                    table_name = f"对象-{display_name}"
                    ok, msg = mc.replace_cleaned_all(table_name, cleaned_rows, cleaned_headers,
                                                      cleanup_old=False, field_type_map=display_type_map)
                    mc.close()
                    if ok:
                        print(f"  [同步] ✅ {display_name}: {msg}", file=sys.stderr, flush=True)
                    else:
                        sync_errors.append(f"{api}: {msg}")
                        print(f"  [同步] ❌ {display_name}: {msg}", file=sys.stderr, flush=True)
                else:
                    print(f"  [同步] ⚠️ {api} 清洗后无数据（可能字段映射缺失），跳过", file=sys.stderr, flush=True)

            if sync_errors:
                signals.done.emit(False, f"以下对象同步出错：\n" + '\n'.join(sync_errors), 0)
                return

            # --- 阶段2: 拼表（对齐编辑器：清空筛选 → 拼表 → 恢复筛选）---
            print(f"  [拼表] 正在执行拼表（不带筛选条件）...", file=sys.stderr, flush=True)
            saved_filters = list(rpt.filters)
            rpt.filters = []
            try:
                result = mgr.refresh_report(rpt)
            except Exception as e:
                import traceback
                traceback.print_exc()
                rpt.filters = saved_filters
                signals.done.emit(False, f"拼表异常: {e}", 0)
                return
            finally:
                rpt.filters = saved_filters

            # 恢复筛选条件后保存到磁盘，确保重启后不清空
            # （refresh_report 内部不再自动保存，由调用者显式控制保存时机）
            try:
                mgr.save_report(rpt)
            except Exception:
                pass

            elapsed = time.time() - t0
            if result['success']:
                print(f"[更新报表] ✅ 完成！共 {result['row_count']} 条记录，耗时 {elapsed:.1f}s",
                      file=sys.stderr, flush=True)
                signals.done.emit(True, "", result['row_count'])
            else:
                signals.done.emit(False, f"拼表出错：\n{result.get('error', '未知错误')}", 0)

        threading.Thread(target=run_in_background, daemon=True).start()

    def fetch_object_fields(self, object_api_name):
        """调用CRM元数据接口获取对象字段清单（字段Key、名称、类型等）- 带缓存"""
        if object_api_name in self.crm_object_fields_cache:
            return self.crm_object_fields_cache[object_api_name]

        # ✅【性能优化】使用已有的异步方法，避免主线程阻塞
        return self._get_crm_object_fields_api(object_api_name)

    def fetch_object_fields_async(self, object_api_name, callback=None):
        """
        异步获取对象字段列表（不阻塞主线程）

        【关键改进】：
        - 在后台线程执行网络请求，避免界面卡顿
        - 通过回调函数返回结果
        - 自动处理缓存和错误情况

        Args:
            object_api_name: 对象API名称
            callback: 回调函数 callback(fields, error)
        """
        # 先检查缓存
        if object_api_name in getattr(self, 'crm_object_fields_cache', {}):
            cached_fields = self.crm_object_fields_cache[object_api_name]
            if callback:
                callback(cached_fields, None)
            return cached_fields

        # 显示加载状态（如果有状态标签）
        if hasattr(self, 'obj_query_status_label'):
            from PyQt6.QtCore import QTimer
            QTimer.singleShot(0, lambda: self.obj_query_status_label.setText(
                f"⏳ 正在获取 {object_api_name} 字段定义..."))

        import threading
        def _async_fetch():
            try:
                fields = self._get_crm_object_fields_api(object_api_name)
                if callback:
                    from PyQt6.QtCore import QTimer
                    QTimer.singleShot(0, lambda: callback(fields, None))

                # 更新状态
                if hasattr(self, 'obj_query_status_label') and fields:
                    from PyQt6.QtCore import QTimer
                    QTimer.singleShot(0, lambda f=fields: self.obj_query_status_label.setText(
                        f"✅ 已获取 {len(f)} 个字段"))
            except Exception as e:
                error_msg = f"获取字段失败: {str(e)}"
                print(f"[ERROR] {error_msg}")
                if callback:
                    from PyQt6.QtCore import QTimer
                    QTimer.singleShot(0, lambda: callback([], error_msg))

                # 更新错误状态
                if hasattr(self, 'obj_query_status_label'):
                    from PyQt6.QtCore import QTimer
                    QTimer.singleShot(0, lambda em=error_msg: self.obj_query_status_label.setText(
                        f"❌ {em[:30]}"))

        thread = threading.Thread(target=_async_fetch, daemon=True)
        thread.start()
        return None  # 异步返回None，结果通过回调获取

    def get_object_field_options(self, object_api_name):
        """返回字段下拉选项（[(key, label)]），优先使用自定义字段管理配置。

        遍历 CRM 元数据字段 + 自定义配置中独有的字段，确保对象查询新增的字段
        在自定义报表待选列表中立即生效，无需重启程序。
        """
        fields = self.fetch_object_fields(object_api_name)
        # 检查是否有自定义字段管理配置
        fx_cfg = getattr(self, 'config', {}).get('fxiaoke', {})
        custom_fields = fx_cfg.get('crm_object_fields', {}).get(object_api_name, {})
        if custom_fields:
            result = []
            seen_keys = set()
            for f in fields:
                api_name = f.get('apiName', '')
                # ✅【新增】处理关联字段：去除API名称中的 __r 后缀
                if api_name and api_name.endswith('__r'):
                    original_name = api_name
                    api_name = api_name[:-2]
                    print(f"[DEBUG-字段选项] 🔧 关联字段转换 | 原始: '{original_name}' → 转换后: '{api_name}'")
                if not api_name:
                    continue
                seen_keys.add(api_name)
                # 如果自定义配置中存在该字段（检查原始名称和转换后的名称）
                field_cfg = custom_fields.get(api_name) or custom_fields.get(api_name + '__r')
                if field_cfg:
                    if isinstance(field_cfg, dict):
                        if field_cfg.get('enabled', True):
                            label = field_cfg.get('label', '') or f.get('label', api_name)
                            result.append((api_name, label))
                    else:
                        result.append((api_name, f.get('label', api_name)))
                else:
                    result.append((api_name, f.get('label', api_name)))
            # 补上仅在自定义配置中存在、但 CRM 元数据未返回的字段（对象查询新增字段立即生效）
            for cfg_key, field_cfg in custom_fields.items():
                base_key = cfg_key[:-2] if cfg_key.endswith('__r') else cfg_key
                if base_key in seen_keys:
                    continue
                if isinstance(field_cfg, dict):
                    if field_cfg.get('enabled', True):
                        label = field_cfg.get('label', '') or base_key
                        result.append((base_key, label))
                elif isinstance(field_cfg, str):
                    result.append((base_key, field_cfg))
            return result
        # 没有自定义配置，使用CRM原始字段（同样需要处理 __r）
        result = []
        for f in fields:
            api_name = f.get('apiName', '')
            if api_name and api_name.endswith('__r'):
                original_name = api_name
                api_name = api_name[:-2]
            if api_name:
                result.append((api_name, f.get('label', api_name)))
        return result

    def _get_default_custom_report_state(self):
        """构建自定义报表默认配置。"""
        sources = []
        for source in self._get_custom_report_sources():
            api_name = str(source.get('api_name', '')).strip()
            if not api_name:
                continue
            sources.append({
                'name': str(source.get('name', api_name)).strip() or api_name,
                'api_name': api_name,
                'enabled': True,
            })
        if not sources:
            sources = [{'name': '商机', 'api_name': 'NewOpportunityObj', 'enabled': True}]
        main_source = sources[0]['api_name']
        return {
            'data_objects': sources,
            'main_source': main_source,
            'field_configs': self._get_custom_report_default_field_configs(main_source),
            'filter_conditions': [],
            'visible_headers': [],
            'header_order': [],
        }

    def _load_custom_report_builder_state(self):
        """加载自定义报表页面配置。"""
        config = load_config()
        self.config = config
        custom_reports = config.get('custom_reports', {})
        state = custom_reports.get('last_state', {}) if isinstance(custom_reports, dict) else {}
        if not isinstance(state, dict) or not state:
            state = self._get_default_custom_report_state()
        self._apply_custom_report_builder_state(state)
        self._refresh_custom_report_preset_combo()

    def _apply_custom_report_builder_state(self, state):
        """将保存的状态应用到自定义报表页面。"""
        if not isinstance(state, dict):
            state = self._get_default_custom_report_state()

        data_objects = state.get('data_objects')
        if not isinstance(data_objects, list) or not data_objects:
            data_objects = self._get_default_custom_report_state().get('data_objects', [])

        if hasattr(self, 'custom_report_source_table'):
            self.custom_report_source_table.blockSignals(True)
            self.custom_report_source_table.setRowCount(0)
            for source in data_objects:
                self._append_custom_report_source_row(source)
            self.custom_report_source_table.blockSignals(False)

        main_source = state.get('main_source', '')
        self._custom_report_main_api_name = main_source or (data_objects[0].get('api_name', '') if data_objects else '')
        if hasattr(self, 'custom_report_main_source_label'):
            main_name = next((s.get('name', s.get('api_name', '')) for s in data_objects if s.get('api_name') == self._custom_report_main_api_name), self._custom_report_main_api_name)
            self.custom_report_main_source_label.setText(f"主数据源: {main_name}")
        if hasattr(self, 'custom_report_main_source_combo'):
            self._refresh_custom_report_main_source_options(main_source)
            self._populate_custom_report_field_config_table(
                state.get('field_configs') or self._get_custom_report_default_field_configs(
                    self._custom_report_main_api_name or 'NewOpportunityObj'
                )
            )

        start_text = str(state.get('date_start', '')).strip()
        end_text = str(state.get('date_end', '')).strip()
        start_date = QDate.fromString(start_text, 'yyyy-MM-dd') if start_text else QDate.currentDate().addDays(-30)
        end_date = QDate.fromString(end_text, 'yyyy-MM-dd') if end_text else QDate.currentDate()
        if not start_date.isValid():
            start_date = QDate.currentDate().addDays(-30)
        if not end_date.isValid():
            end_date = QDate.currentDate()
        self.custom_report_date_start = start_date
        self.custom_report_date_end = end_date
        if hasattr(self, 'custom_report_date_filter_btn'):
            self.custom_report_date_filter_btn.setText(
                f"{self.custom_report_date_start.toString('yyyy-MM-dd')} ~ "
                f"{self.custom_report_date_end.toString('yyyy-MM-dd')}"
            )

        self.custom_report_filter_conditions = copy.deepcopy(state.get('filter_conditions', []))
        self.custom_report_visible_headers = list(state.get('visible_headers', []))
        self.custom_report_header_order = list(state.get('header_order', []))

        if hasattr(self, 'custom_report_source_summary'):
            self._update_custom_report_source_summary()
        self._update_custom_report_filter_summary()
        self._refresh_quick_filter_field_combo()

    def _append_custom_report_source_row(self, source):
        """在来源表中追加一行对象配置。"""
        source = source or {}
        name = str(source.get('name') or source.get('api_name') or '').strip()
        api_name = str(source.get('api_name') or source.get('value') or '').strip()
        enabled = bool(source.get('enabled', True))

        row = self.custom_report_source_table.rowCount()
        self.custom_report_source_table.insertRow(row)

        check_item = QTableWidgetItem()
        check_item.setFlags(
            Qt.ItemFlag.ItemIsEnabled
            | Qt.ItemFlag.ItemIsSelectable
            | Qt.ItemFlag.ItemIsUserCheckable
        )
        check_item.setCheckState(Qt.CheckState.Checked if enabled else Qt.CheckState.Unchecked)
        match_field = str(source.get('match_field') or '').strip()
        self.custom_report_source_table.setItem(row, 0, check_item)
        self.custom_report_source_table.setItem(row, 1, QTableWidgetItem(name or api_name))
        self.custom_report_source_table.setItem(row, 2, QTableWidgetItem(api_name))
        self.custom_report_source_table.setItem(row, 3, QTableWidgetItem(match_field))

    def _collect_custom_report_source_rows(self):
        """收集来源表中的对象配置。"""
        if not hasattr(self, 'custom_report_source_table'):
            sources = self._get_custom_report_sources()
            return [{'name': s['name'], 'api_name': s['api_name'], 'enabled': True} for s in sources]
        rows = []
        for row in range(self.custom_report_source_table.rowCount()):
            check_item = self.custom_report_source_table.item(row, 0)
            name_item = self.custom_report_source_table.item(row, 1)
            api_item = self.custom_report_source_table.item(row, 2)
            match_item = self.custom_report_source_table.item(row, 3) if self.custom_report_source_table.columnCount() > 3 else None
            name = name_item.text().strip() if name_item else ''
            api_name = api_item.text().strip() if api_item else ''
            if not api_name:
                continue
            rows.append({
                'name': name or api_name,
                'api_name': api_name,
                'enabled': bool(check_item and check_item.checkState() == Qt.CheckState.Checked),
                'match_field': match_item.text().strip() if match_item else '',
            })
        return rows

    def _get_custom_report_source_option_pairs(self, enabled_only=False):
        """获取来源对象下拉选项。"""
        rows = self._collect_custom_report_source_rows()
        if enabled_only:
            enabled_rows = [(row['name'], row['api_name']) for row in rows if row.get('enabled') and row.get('api_name')]
            if enabled_rows:
                return enabled_rows
        return [(row['name'], row['api_name']) for row in rows if row.get('api_name')]

    def _refresh_custom_report_main_source_options(self, selected_api=None):
        """刷新主表对象下拉框。"""
        if not hasattr(self, 'custom_report_main_source_combo'):
            return

        options = self._get_custom_report_source_option_pairs(enabled_only=True)
        if not options:
            options = self._get_custom_report_source_option_pairs(enabled_only=False)
        if not options:
            default_state = self._get_default_custom_report_state()
            options = [
                (item.get('name', item.get('api_name', '')), item.get('api_name', ''))
                for item in default_state.get('data_objects', [])
                if item.get('api_name')
            ]

        current_api = str(selected_api or self.custom_report_main_source_combo.currentData() or '').strip()
        self.custom_report_main_source_combo.blockSignals(True)
        self.custom_report_main_source_combo.clear()
        for name, api_name in options:
            self.custom_report_main_source_combo.addItem(name, api_name)
        target_index = self.custom_report_main_source_combo.findData(current_api)
        if target_index < 0 and self.custom_report_main_source_combo.count() > 0:
            target_index = 0
        if target_index >= 0:
            self.custom_report_main_source_combo.setCurrentIndex(target_index)
        self.custom_report_main_source_combo.blockSignals(False)
        self._refresh_custom_report_field_source_options()
        # 更新候选字段列表
        try:
            if hasattr(self, '_refresh_candidate_field_list'):
                self._refresh_candidate_field_list()
        except Exception:
            pass

    def _add_custom_report_source(self):
        """添加一个自定义 CRM 对象。"""
        name, ok = QInputDialog.getText(self, '添加对象', '请输入对象名称:')
        if not ok:
            return
        api_name, ok = QInputDialog.getText(self, '添加对象', '请输入对象 API 名称:')
        if not ok:
            return

        name = str(name or '').strip()
        api_name = str(api_name or '').strip()
        if not api_name:
            show_warning('提示', '对象 API 名称不能为空。', self)
            return
        existing_apis = {row.get('api_name') for row in self._collect_custom_report_source_rows()}
        if api_name in existing_apis:
            show_warning('提示', '该对象已存在，请勿重复添加。', self)
            return

        self.custom_report_source_table.blockSignals(True)
        self._append_custom_report_source_row({'name': name or api_name, 'api_name': api_name, 'enabled': True})
        self.custom_report_source_table.blockSignals(False)
        self._refresh_custom_report_main_source_options(api_name)
        self._update_custom_report_source_summary()
        self._save_custom_report_builder_state()

    def _remove_custom_report_source(self):
        """删除选中的来源对象。"""
        selected_rows = sorted({index.row() for index in self.custom_report_source_table.selectedIndexes()}, reverse=True)
        if not selected_rows:
            show_info('提示', '请先选择要删除的对象。', self)
            return

        self.custom_report_source_table.blockSignals(True)
        for row in selected_rows:
            self.custom_report_source_table.removeRow(row)
        if self.custom_report_source_table.rowCount() == 0:
            default_row = self._get_default_custom_report_state().get('data_objects', [])[0]
            self._append_custom_report_source_row(default_row)
        self.custom_report_source_table.blockSignals(False)
        self._refresh_custom_report_main_source_options()
        self._update_custom_report_source_summary()
        self._save_custom_report_builder_state()
        self.on_custom_report_source_changed()

    def _reset_custom_report_sources(self):
        """恢复默认来源对象和字段配置。"""
        default_state = self._get_default_custom_report_state()
        self._apply_custom_report_builder_state(default_state)
        self._save_custom_report_builder_state()
        self.on_custom_report_source_changed()

    def _on_field_source_combo_changed(self):
        """字段来源对象下拉框变化时：同步主数据源 + 刷新候选字段 + 保存状态。

        确保用户在下拉框中选择 A 表时，候选字段和数据加载都对应 A 表，
        避免出现"选择A表，实际内容是B表"的问题。
        """
        if not hasattr(self, 'custom_report_main_source_combo'):
            return
        api = str(self.custom_report_main_source_combo.currentData() or '').strip()
        if not api:
            return
        # 同步主数据源 API 名称
        self._custom_report_main_api_name = api
        # 更新主数据源标签
        if hasattr(self, 'custom_report_main_source_label'):
            name = self.custom_report_main_source_combo.currentText().strip()
            self.custom_report_main_source_label.setText(f"主数据源: {name}")
        # 刷新候选字段列表
        self._refresh_candidate_field_list()
        # 保存状态
        self._save_custom_report_builder_state()

    def _refresh_candidate_field_list(self):
        """刷新主表候选字段列表和筛选字段下拉框（基于当前主表对象）。"""
        if not hasattr(self, 'custom_report_candidate_fields'):
            return
        
        # ===== 优化：启动时不执行网络请求，避免卡住 =====
        if not getattr(self, '_custom_report_list_loaded', False):
            # 启动阶段：显示占位符，不加载真实数据
            self.custom_report_candidate_fields.blockSignals(True)
            self.custom_report_candidate_fields.clear()
            placeholder = QListWidgetItem("⏳ 请等待页面完全加载...")
            placeholder.setForeground(Qt.GlobalColor.gray)
            self.custom_report_candidate_fields.addItem(placeholder)
            self.custom_report_candidate_fields.blockSignals(False)
            return
        
        api = str(self.custom_report_main_source_combo.currentData() or '').strip() or 'NewOpportunityObj'
        try:
            options = self.get_object_field_options(api)
        except Exception:
            options = []

        # 更新候选字段列表（按 CRM/header_order 优先排序，其余按 label 字母序）
        # 选择排序来源：优先使用 CRM 的 header_order，其次使用当前报表的 header_order，最后尝试从配置的 last_state 读取
        order_source = []
        if getattr(self, 'crm_header_order', None):
            order_source = list(self.crm_header_order)
        elif getattr(self, 'custom_report_header_order', None):
            order_source = list(self.custom_report_header_order)
        else:
            try:
                cfg = getattr(self, 'config', None) or load_config()
                custom_reports_cfg = cfg.get('custom_reports', {}) if isinstance(cfg, dict) else {}
                last_state = custom_reports_cfg.get('last_state', {}) if isinstance(custom_reports_cfg.get('last_state', {}), dict) else {}
                order_source = list(last_state.get('header_order', []))
            except Exception:
                order_source = []

        order_map = {k: i for i, k in enumerate(order_source)} if order_source else {}

        def option_sort_key(kv):
            key, label = kv
            primary = order_map.get(key, len(order_map))
            return (primary, (label or '').lower())

        sorted_options = sorted(options, key=option_sort_key)

        self.custom_report_candidate_fields.blockSignals(True)
        self.custom_report_candidate_fields.clear()
        for key, label in sorted_options:
            text = f"{label} ({key})"
            item = QListWidgetItem(text)
            item.setData(Qt.UserRole, key)
            self.custom_report_candidate_fields.addItem(item)
        self.custom_report_candidate_fields.blockSignals(False)

        # 同时更新快速筛选字段下拉框（仅显示已勾选的报表列字段）
        self._refresh_quick_filter_field_combo()

    def _refresh_quick_filter_field_combo(self):
        """刷新快速筛选字段下拉框，仅显示已添加到报表列（字段拼接表）的字段。"""
        if not hasattr(self, 'custom_report_quick_field_combo'):
            return

        # 从字段拼接表收集已勾选的字段
        field_configs = self._collect_custom_report_field_configs()
        seen = set()
        options = []
        for config in field_configs:
            key = str(config.get('field_name', '')).strip()
            label = str(config.get('display_name', '')).strip()
            if not key:
                continue
            if not label:
                label = self._guess_custom_report_field_label(key) or key
            if key in seen:
                continue
            seen.add(key)
            options.append((key, label))

        self.custom_report_quick_field_combo.blockSignals(True)
        current_text = self.custom_report_quick_field_combo.currentText()
        self.custom_report_quick_field_combo.clear()
        for key, label in options:
            display_text = f"{label}"
            self.custom_report_quick_field_combo.addItem(display_text, key)
            self.custom_report_quick_field_combo.setItemData(
                self.custom_report_quick_field_combo.count() - 1,
                f"({key})",
                Qt.ItemDataRole.ToolTipRole
            )
        # 恢复之前的选择
        if current_text:
            idx = self.custom_report_quick_field_combo.findText(current_text)
            if idx >= 0:
                self.custom_report_quick_field_combo.setCurrentIndex(idx)
        self.custom_report_quick_field_combo.blockSignals(False)

    def _on_candidate_field_double_click(self, item):
        """候选字段双击：添加到字段拼接表并保存状态。"""
        if not item:
            return
        key = item.data(Qt.UserRole)
        label = str(item.text()).split(' (')[0]
        source_api_name = self.custom_report_main_source_combo.currentData() or 'NewOpportunityObj'
        # 自动继承对象级匹配关系
        main_link, source_link = self._get_object_level_match_fields(source_api_name)
        config = {
            'display_name': label,
            'source_api_name': source_api_name,
            'field_name': key,
            'main_link_field': main_link,
            'source_link_field': source_link,
        }
        self._add_custom_report_field_config_row(config)
        self._save_custom_report_builder_state()
        self._update_custom_report_filter_summary()
        self._refresh_quick_filter_field_combo()

    def _add_selected_candidate_fields(self):
        """将候选字段中选中的字段添加到字段拼接表。"""
        items = list(self.custom_report_candidate_fields.selectedItems())
        if not items:
            show_info('提示', '请先选择候选字段。', self)
            return
        for item in items:
            self._on_candidate_field_double_click(item)

    def _add_all_candidate_fields(self):
        """将所有候选字段添加到字段拼接表。"""
        items = [self.custom_report_candidate_fields.item(i) for i in range(self.custom_report_candidate_fields.count())]
        for item in items:
            self._on_candidate_field_double_click(item)

    def _on_quick_add_date_part(self):
        """快捷添加时间成分字段：弹出对话框，勾选年/月/周/季度后批量添加。"""
        main_api = getattr(self, '_custom_report_main_api_name', '') or \
                   self.custom_report_main_source_combo.currentData() or 'NewOpportunityObj'

        # 收集主表字段（仅限 source_api == main_api）
        field_configs = self._collect_custom_report_field_configs()
        available_fields = []
        for config in field_configs:
            fn = str(config.get('field_name', '')).strip()
            dn = str(config.get('display_name', '')).strip() or fn
            src_api = str(config.get('source_api_name') or main_api).strip()
            if src_api == main_api and fn:
                # 跳过已有时间成分标记，避免递归嵌套
                if any(fn.startswith(p) for p in ('__year__:', '__month__:', '__week__:', '__quarter__:')):
                    continue
                available_fields.append((dn, fn))

        if not available_fields:
            show_warning('提示', '请先在字段拼接表中添加至少一个主表日期字段。', self)
            return

        dlg = DatePartPickerDialog(available_fields=available_fields, parent=self)
        if dlg.exec() == QDialog.DialogCode.Accepted:
            for unit_info in dlg.selected_units:
                unit = unit_info['unit']
                display_name = unit_info['display_name']
                marker_field = f"__{unit}__:{dlg.source_field_name}"
                self._add_custom_report_field_config_row({
                    'display_name': display_name,
                    'source_api_name': main_api,
                    'field_name': marker_field,
                    'main_link_field': '',
                    'source_link_field': '',
                })
            self._save_custom_report_builder_state()
            self._update_custom_report_filter_summary()

    def _add_custom_report_scope_condition(self):
        """添加 Step 1 数据范围筛选条件。"""
        field = self.custom_report_scope_field_combo.currentText().strip()
        operator = self.custom_report_scope_op_combo.currentText().strip()
        value = self.custom_report_scope_value_input.text().strip()

        if not field:
            show_warning('提示', '请先选择筛选字段。', self)
            return

        # 检查是否有首选的 API 名称
        field_key = self.custom_report_scope_field_combo.currentData() or field

        condition_text = f"{field} {operator} {value if value else '(空)'}"
        item = QListWidgetItem(condition_text)
        item.setData(Qt.UserRole, {
            'field': field_key,
            'operator': operator,
            'value': value
        })
        self.custom_report_scope_conditions_list.addItem(item)
        self.custom_report_scope_value_input.clear()

    def _add_custom_report_quick_condition(self):
        """添加快速筛选条件到条件列表。"""
        field_display = self.custom_report_quick_field_combo.currentText().strip()
        operator = self.custom_report_quick_op_combo.currentText().strip()
        value = self.custom_report_quick_value_input.text().strip()

        if not field_display:
            show_warning('提示', '请先选择筛选字段。', self)
            return

        # 使用 API key 作为字段标识（itemData），显示名用于展示
        field_key = self.custom_report_quick_field_combo.currentData() or field_display

        condition_text = f"{field_display} {operator} {value if value else '(空)'}"
        item = QListWidgetItem(condition_text)
        item.setData(Qt.UserRole, {
            'field': field_key,
            'operator': operator,
            'value': value
        })
        self.custom_report_conditions_list.addItem(item)

        # 清空输入
        self.custom_report_quick_value_input.clear()
        self._update_filter_summary_from_conditions()

    def _clear_custom_report_quick_conditions(self):
        """清除所有快速筛选条件。"""
        self.custom_report_conditions_list.clear()
        self._update_filter_summary_from_conditions()

    def _on_custom_report_quick_op_changed(self):
        """操作符切换时：显示/隐藏多选按钮（仅"属于/不属于"显示）。"""
        if not hasattr(self, 'custom_report_quick_picker_btn'):
            return
        op_text = self.custom_report_quick_op_combo.currentText().strip()
        self.custom_report_quick_picker_btn.setVisible(op_text in ('属于', '不属于'))

    def _on_custom_report_quick_picker_clicked(self):
        """打开多选弹窗，从配置或数据中获取可选值。"""
        field_display = self.custom_report_quick_field_combo.currentText().strip()
        if not field_display:
            show_warning('提示', '请先选择筛选字段。', self)
            return

        # 获取字段 key
        idx = self.custom_report_quick_field_combo.currentIndex()
        field_key = self.custom_report_quick_field_combo.itemData(idx) or field_display

        # 获取映射字典 {value_display: value_id} 或 {value: value}
        mappings = self._get_custom_report_field_value_options(field_key, field_display)

        if not mappings:
            show_info('提示', f'字段「{field_display}」暂无候选值。\n请先刷新数据，或手动输入筛选值。', self)
            return

        current_value = self.custom_report_quick_value_input.text().strip()
        show_multi_select_dropdown(self, mappings, current_value,
                                   anchor=self.custom_report_quick_value_input,
                                   target_input=self.custom_report_quick_value_input)

    def _get_custom_report_field_value_options(self, field_key, field_display=''):
        """获取字段的候选值映射 {display: value}。
        优先从配置 crm_option_mappings 获取，其次从已加载数据中提取去重值。
        """
        mappings = {}

        # 1) 优先从配置文件获取
        try:
            config = self.config or load_config()
            fx_cfg = config.get('fxiaoke', {}) if isinstance(config, dict) else {}
            api = str(getattr(self, '_custom_report_main_api_name', '') or '').strip()
            if not api and hasattr(self, 'custom_report_main_source_combo'):
                api = str(self.custom_report_main_source_combo.currentData() or '').strip()

            if api:
                option_mappings = fx_cfg.get('crm_option_mappings', {}).get(api, {})
                # 尝试直接用 field_key 匹配
                field_mappings = option_mappings.get(field_key, {})
                if not field_mappings:
                    # 反向查找：通过显示名找到字段 key，再取映射
                    field_config = fx_cfg.get('crm_object_fields', {}).get(api, {})
                    for fk, fi in field_config.items():
                        label = (fi.get('label', fk) if isinstance(fi, dict) else str(fi)) if fi else fk
                        if str(label).strip() == str(field_display).strip():
                            field_mappings = option_mappings.get(fk, {})
                            break
                if isinstance(field_mappings, dict) and field_mappings:
                    # crm_option_mappings 格式: {option_id: display_text}
                    # 转为 {display_text: display_text}（用户选中文显示文本，用逗号拼接）
                    mappings = {str(v): str(v) for v in field_mappings.values() if str(v).strip()}
        except Exception:
            pass

        # 2) 其次从已加载数据中提取去重值
        if not mappings:
            try:
                all_data = getattr(self, 'custom_report_all_data', None)
                if all_data:
                    values_seen = set()
                    for row in all_data:
                        if not isinstance(row, dict):
                            continue
                        val = self._format_custom_report_value(row.get(field_key, '')).strip()
                        if val and val not in values_seen:
                            values_seen.add(val)
                            mappings[val] = val
            except Exception:
                pass

        return mappings

    def _remove_selected_display_fields(self):
        """从已选显示字段列表中移除选中的字段。"""
        selected_items = self.custom_report_selected_fields.selectedItems()
        if not selected_items:
            show_info('提示', '请先选择要移除的字段。', self)
            return
        for item in selected_items:
            row = self.custom_report_selected_fields.row(item)
            self.custom_report_selected_fields.takeItem(row)
        self._refresh_quick_filter_field_combo()
        self._update_filter_summary_from_conditions()

    def _move_field_config_row(self, direction='up'):
        """上移/下移/置顶选中的字段配置行，并同步更新预览界面。"""
        configs = self._collect_custom_report_field_configs()
        if not configs:
            return
        selected_rows = sorted({index.row() for index in self.custom_report_field_builder_table.selectedIndexes()})
        if not selected_rows:
            show_info('提示', '请先选择要移动的行。', self)
            return
        if direction == 'up':
            for r in selected_rows:
                if r <= 0:
                    continue
                configs[r-1], configs[r] = configs[r], configs[r-1]
            new_selection = [max(0, r - 1) for r in selected_rows]
        elif direction == 'down':
            for r in reversed(selected_rows):
                if r >= len(configs) - 1:
                    continue
                configs[r+1], configs[r] = configs[r], configs[r+1]
            new_selection = [min(len(configs) - 1, r + 1) for r in selected_rows]
        else:  # top
            if selected_rows[0] == 0:
                return
            moved = []
            for r in selected_rows:
                moved.append(configs.pop(r - len(moved)))
            configs = moved + configs
            new_selection = list(range(len(moved)))

        # 重新填充字段拼接表
        self._populate_custom_report_field_config_table(configs)

        # 恢复选中行
        if hasattr(self, 'custom_report_field_builder_table'):
            table = self.custom_report_field_builder_table
            table.clearSelection()
            for r in new_selection:
                if 0 <= r < table.rowCount():
                    table.selectRow(r)

        # 重建预览数据，使列顺序与字段配置一致
        self._rebuild_custom_report_preview_from_field_configs(configs)

        self._save_custom_report_builder_state()
        self._update_custom_report_filter_summary()

    def _rebuild_custom_report_preview_from_field_configs(self, field_configs):
        """根据字段配置顺序重建预览数据的列顺序，保持「报表列」与「预览界面」同步。"""
        if not field_configs:
            return
        # 收集新的表头顺序（按 field_configs 中的 display_name）
        new_headers = []
        for config in field_configs:
            display_name = str(config.get('display_name', '')).strip()
            if not display_name:
                field_name = str(config.get('field_name', '')).strip()
                display_name = self._guess_custom_report_field_label(field_name) or field_name
            if display_name and display_name not in new_headers:
                new_headers.append(display_name)

        if not new_headers:
            return

        # 如果已有预览数据，按新顺序重建 headers
        if self.custom_report_all_data:
            # 用新 headers 重建预览数据（data 中 key 已是 display_name）
            old_data = self.custom_report_all_data
            rebuilt_rows = []
            for row in old_data:
                new_row = {}
                for h in new_headers:
                    new_row[h] = row.get(h, '')
                # 保留特殊字段
                for k in ('__create_time__', '__created_by__', '__owner__'):
                    if k in row:
                        new_row[k] = row[k]
                rebuilt_rows.append(new_row)
            self.custom_report_all_data = rebuilt_rows

        self.custom_report_headers = new_headers
        self.custom_report_visible_headers = new_headers
        self.custom_report_header_order = new_headers

        # 刷新预览表格（设置标志防止 sectionMoved 触发回同步）
        try:
            self._preview_reorder_syncing = True
            self._apply_custom_report_filters()
            self._populate_custom_report_table()
        finally:
            self._preview_reorder_syncing = False

    def _sync_field_builder_from_preview_order(self, display_headers):
        """预览表列被拖拽后，同步顺序回字段拼接表。"""
        if not display_headers:
            return
        configs = self._collect_custom_report_field_configs()
        if not configs:
            return

        # 建立 display_name → config 的映射
        config_map = {}
        for config in configs:
            display_name = str(config.get('display_name', '')).strip()
            if not display_name:
                field_name = str(config.get('field_name', '')).strip()
                display_name = self._guess_custom_report_field_label(field_name) or field_name
            if display_name not in config_map:
                config_map[display_name] = config

        # 按预览表头顺序重排 configs
        reordered = []
        for h in display_headers:
            if h in config_map:
                reordered.append(config_map.pop(h))
        # 追加预览表中不存在的字段（可能是新增的）
        for config in configs:
            display_name = str(config.get('display_name', '')).strip()
            if not display_name:
                field_name = str(config.get('field_name', '')).strip()
                display_name = self._guess_custom_report_field_label(field_name) or field_name
            if display_name not in display_headers:
                reordered.append(config)

        if reordered and reordered != configs:
            self._populate_custom_report_field_config_table(reordered)
            self._save_custom_report_builder_state()

    def _on_custom_report_preview_column_moved(self, logical_index, old_visual_index, new_visual_index):
        """预览表列被用户拖拽排序后，同步顺序回报表字段拼接表。"""
        # 避免程序化刷新预览表时触发无限循环
        if getattr(self, '_preview_reorder_syncing', False):
            return
        try:
            self._preview_reorder_syncing = True
            preview_table = getattr(self, 'custom_report_preview_table', None)
            if not preview_table:
                return
            header_view = preview_table.horizontalHeader()
            # 读取当前列的可视顺序
            order = [header_view.logicalIndex(vis) for vis in range(preview_table.columnCount())]
            # 获取表头文本
            display_headers = []
            for logical_idx in order:
                if logical_idx >= 0 and logical_idx < len(self.custom_report_visible_headers):
                    display_headers.append(self.custom_report_visible_headers[logical_idx])
            if display_headers:
                self.custom_report_visible_headers = display_headers
                self.custom_report_headers = display_headers
                self.custom_report_header_order = display_headers
                self._sync_field_builder_from_preview_order(display_headers)
        finally:
            self._preview_reorder_syncing = False

    def _refresh_single_custom_report_field_source_combo(self, combo, selected_api=None):
        """刷新单个字段来源下拉框。"""
        options = self._get_custom_report_source_option_pairs(enabled_only=True)
        if not options:
            options = self._get_custom_report_source_option_pairs(enabled_only=False)
        fallback_api = self.custom_report_main_source_combo.currentData() or 'NewOpportunityObj'
        target_api = str(selected_api or combo.currentData() or fallback_api).strip()

        combo.blockSignals(True)
        combo.clear()
        for name, api_name in options:
            combo.addItem(name, api_name)
        target_index = combo.findData(target_api)
        if target_index < 0 and combo.count() > 0:
            target_index = 0
        if target_index >= 0:
            combo.setCurrentIndex(target_index)
        combo.blockSignals(False)

    def _refresh_custom_report_field_source_options(self):
        """刷新字段拼接表中的来源对象选项。"""
        if not hasattr(self, 'custom_report_field_builder_table'):
            return
        for row in range(self.custom_report_field_builder_table.rowCount()):
            combo = self.custom_report_field_builder_table.cellWidget(row, 1)
            if combo is not None:
                self._refresh_single_custom_report_field_source_combo(combo)

    def _add_custom_report_field_config_row(self, config=None):
        """在字段拼接表中添加一行配置（5列布局：显示名|来源对象|字段名|主表关联字段|源表匹配字段）。"""
        config = config or {}
        row = self.custom_report_field_builder_table.rowCount()
        self.custom_report_field_builder_table.insertRow(row)

        display_name = str(config.get('display_name', '')).strip()
        field_name = str(config.get('field_name', '')).strip()
        if not display_name and field_name:
            display_name = self._guess_custom_report_field_label(field_name)

        # 列0: 显示名
        self.custom_report_field_builder_table.setItem(row, 0, QTableWidgetItem(display_name))

        # 列1: 来源对象（下拉框）
        source_combo = QComboBox()
        source_combo.setMinimumWidth(100)
        self.custom_report_field_builder_table.setCellWidget(row, 1, source_combo)
        source_api = str(config.get('source_api_name', '')).strip() or self.custom_report_main_source_combo.currentData() or 'NewOpportunityObj'
        self._refresh_single_custom_report_field_source_combo(source_combo, source_api)

        # 列2: 字段名
        self.custom_report_field_builder_table.setItem(row, 2, QTableWidgetItem(field_name))

        # 列3: 主表关联字段（原始值，非显示文本）
        main_link = str(config.get('main_link_field', '')).strip()
        self.custom_report_field_builder_table.setItem(row, 3, QTableWidgetItem(main_link))

        # 列4: 源表匹配字段（原始值，非显示文本）
        source_link = str(config.get('source_link_field', '')).strip()
        self.custom_report_field_builder_table.setItem(row, 4, QTableWidgetItem(source_link))

        # 连接 source_combo 信号：切换来源对象时自动更新 JOIN 字段
        source_combo.currentIndexChanged.connect(
            lambda idx, r=row: self._on_field_row_source_changed(r)
        )

    def _on_field_row_source_changed(self, row):
        """字段行来源对象切换时，自动更新 JOIN 匹配字段。"""
        if row < 0 or row >= self.custom_report_field_builder_table.rowCount():
            return
        source_combo = self.custom_report_field_builder_table.cellWidget(row, 1)
        if not source_combo:
            return
        source_api = source_combo.currentData() or ''
        main_api = getattr(self, '_custom_report_main_api_name', '') or ''
        if source_api == main_api:
            # 主表字段不需要 JOIN
            self.custom_report_field_builder_table.setItem(row, 3, QTableWidgetItem(''))
            self.custom_report_field_builder_table.setItem(row, 4, QTableWidgetItem(''))
        else:
            main_link, source_link = self._get_object_level_match_fields(source_api)
            self.custom_report_field_builder_table.setItem(row, 3, QTableWidgetItem(main_link))
            self.custom_report_field_builder_table.setItem(row, 4, QTableWidgetItem(source_link))
        self._save_custom_report_builder_state()

    def _remove_custom_report_field_config_row(self):
        """删除选中的字段拼接配置。"""
        selected_rows = sorted({index.row() for index in self.custom_report_field_builder_table.selectedIndexes()}, reverse=True)
        if not selected_rows:
            show_info('提示', '请先选择要删除的字段配置。', self)
            return
        for row in selected_rows:
            self.custom_report_field_builder_table.removeRow(row)
        self._update_custom_report_filter_summary()
        self._save_custom_report_builder_state()

    def _populate_custom_report_field_config_table(self, field_configs):
        """按配置填充字段拼接表（5列布局）。"""
        self.custom_report_field_builder_table.setRowCount(0)
        for config in field_configs or []:
            self._add_custom_report_field_config_row(config)
        if self.custom_report_field_builder_table.rowCount() == 0:
            main_api = getattr(self, '_custom_report_main_api_name', '') or self.custom_report_main_source_combo.currentData() or 'NewOpportunityObj'
            for config in self._get_custom_report_default_field_configs(main_api):
                self._add_custom_report_field_config_row(config)
        self._refresh_custom_report_field_source_options()
        self._refresh_quick_filter_field_combo()

    def _collect_custom_report_field_configs(self):
        """收集字段拼接表中的配置。"""
        configs = []
        for row in range(self.custom_report_field_builder_table.rowCount()):
            display_item = self.custom_report_field_builder_table.item(row, 0)
            field_item = self.custom_report_field_builder_table.item(row, 2)
            main_link_item = self.custom_report_field_builder_table.item(row, 3)
            source_link_item = self.custom_report_field_builder_table.item(row, 4)
            source_combo = self.custom_report_field_builder_table.cellWidget(row, 1)

            display_name = display_item.text().strip() if display_item else ''
            field_name = field_item.text().strip() if field_item else ''
            if not field_name and not display_name:
                continue
            if not display_name:
                display_name = self._guess_custom_report_field_label(field_name) or field_name

            configs.append({
                'display_name': display_name,
                'source_api_name': source_combo.currentData() if source_combo else (self.custom_report_main_source_combo.currentData() or ''),
                'field_name': field_name,
                'main_link_field': main_link_item.text().strip() if main_link_item else '',
                'source_link_field': source_link_item.text().strip() if source_link_item else '',
            })
        return configs

    def _get_custom_report_default_field_configs(self, main_source_api=None):
        """生成主表的默认字段配置。"""
        main_source_api = str(main_source_api or 'NewOpportunityObj').strip() or 'NewOpportunityObj'
        defaults = [
                ('创建时间', 'create_time'),
                ('名称', 'name'),
                ('创建人', 'created_by__r'),
                ('负责人', 'owner__r'),
                ('客户名称', 'account_id__r'),
                ('备注', 'remark'),
            ]
        return [
            {
                'display_name': display_name,
                'source_api_name': main_source_api,
                'field_name': field_name,
                'main_link_field': '',
                'source_link_field': '',
            }
            for display_name, field_name in defaults
        ]

    def _reset_custom_report_field_configs_to_default(self):
        """恢复主表默认字段配置。"""
        main_api = getattr(self, '_custom_report_main_api_name', '') or self.custom_report_main_source_combo.currentData() or 'NewOpportunityObj'
        self._populate_custom_report_field_config_table(
            self._get_custom_report_default_field_configs(main_api)
        )
        self._refresh_quick_filter_field_combo()
        self._update_custom_report_filter_summary()
        self._save_custom_report_builder_state()

    def _serialize_custom_report_builder_state(self):
        """序列化当前自定义报表配置。"""
        main_api = getattr(self, '_custom_report_main_api_name', '') or self.custom_report_main_source_combo.currentData() or 'NewOpportunityObj'
        return {
            'data_objects': self._collect_custom_report_source_rows(),
            'main_source': main_api,
            'field_configs': self._collect_custom_report_field_configs(),
            'date_start': self.custom_report_date_start.toString('yyyy-MM-dd') if hasattr(self, 'custom_report_date_start') and self.custom_report_date_start else '',
            'date_end': self.custom_report_date_end.toString('yyyy-MM-dd') if hasattr(self, 'custom_report_date_end') and self.custom_report_date_end else '',
            'filter_conditions': copy.deepcopy(self.custom_report_filter_conditions),
            'visible_headers': list(self.custom_report_visible_headers),
            'header_order': list(self.custom_report_header_order),
        }

    def _save_custom_report_builder_state(self, preset_name=None):
        """保存当前自定义报表配置。"""
        config = load_config()
        custom_reports = config.get('custom_reports', {})
        if not isinstance(custom_reports, dict):
            custom_reports = {}
        config['custom_reports'] = custom_reports

        state = self._serialize_custom_report_builder_state()
        custom_reports['last_state'] = copy.deepcopy(state)
        custom_reports['data_objects'] = [
            {
                'name': row.get('name', row.get('api_name', '')),
                'api_name': row.get('api_name', ''),
            }
            for row in state.get('data_objects', [])
            if row.get('api_name')
        ]

        if preset_name:
            presets = custom_reports.get('presets', {})
            if not isinstance(presets, dict):
                presets = {}
            presets[preset_name] = copy.deepcopy(state)
            custom_reports['presets'] = presets

        save_config(config, immediate=False)
        self.config = config
        return state

    def _refresh_custom_report_preset_combo(self, selected_name=None):
        """刷新预设下拉框。"""
        if not hasattr(self, 'custom_report_preset_combo'):
            return
        config = load_config()
        self.config = config
        custom_reports = config.get('custom_reports', {})
        presets = custom_reports.get('presets', {}) if isinstance(custom_reports, dict) else {}
        current_name = str(selected_name or self.custom_report_preset_combo.currentData() or '').strip()

        self.custom_report_preset_combo.blockSignals(True)
        self.custom_report_preset_combo.clear()
        self.custom_report_preset_combo.addItem('未选择预设', '')
        for name in sorted(presets.keys()):
            self.custom_report_preset_combo.addItem(name, name)
        target_index = self.custom_report_preset_combo.findData(current_name)
        if target_index >= 0:
            self.custom_report_preset_combo.setCurrentIndex(target_index)
        self.custom_report_preset_combo.blockSignals(False)

    def _on_custom_report_search_changed(self, text):
        """搜索框变化：空文字即刷新全部，有文字即过滤搜索"""
        self.custom_report_list_current_page = 1
        self._refresh_custom_report_list()

    def _on_custom_report_list_manual_refresh(self):
        """手动刷新：清空搜索框并重新加载"""
        if hasattr(self, 'custom_report_list_search'):
            self.custom_report_list_search.clear()
        self.custom_report_list_current_page = 1
        self._refresh_custom_report_list()

    def _populate_custom_report_sidebar_table(self, filter_text=None):
        """将配置中的预设填充到报表表格中（支持分页）。"""
        config = load_config()
        custom_reports = config.get('custom_reports', {}) if isinstance(config, dict) else {}
        presets = custom_reports.get('presets', {}) if isinstance(custom_reports.get('presets', {}), dict) else {}

        rows = []
        for name, state in presets.items():
            if not isinstance(state, dict):
                continue
            report_type = state.get('type', '报表')
            if report_type == 'folder':
                report_type = '文件夹'
            elif report_type == 'dashboard':
                report_type = '驾驶舱'
            rows.append({
                'name': name,
                'type': report_type,
                'modifier': state.get('modifier', state.get('owner', '')),
                'modified': state.get('modified', state.get('created', datetime.now().strftime('%Y-%m-%d %H:%M:%S'))),
                'status': state.get('status', '已启用'),
                'key': name,
            })

        last_state = custom_reports.get('last_state')
        if last_state:
            rows.insert(0, {
                'name': '[上次配置]',
                'type': '临时',
                'modifier': '',
                'modified': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                'status': '',
                'key': '__last_state__',
            })

        # 获取搜索文本：优先使用 filter_text，否则从搜索框获取
        if filter_text is not None:
            ft = filter_text.lower()
        else:
            search_widget = getattr(self, 'custom_report_list_search', None)
            ft = search_widget.text().strip().lower() if search_widget else ''
        if ft:
            rows = [r for r in rows if ft in (r.get('name','')).lower()]

        # 存储全部过滤后的行
        self.custom_report_list_all_rows = rows
        total = len(rows)

        # 分页
        page_size = getattr(self, 'custom_report_list_page_size', 20)
        page_count = max(1, (total + page_size - 1) // page_size)
        current_page = getattr(self, 'custom_report_list_current_page', 1)
        current_page = max(1, min(current_page, page_count))
        self.custom_report_list_current_page = current_page
        start = (current_page - 1) * page_size
        page_rows = rows[start:start + page_size]

        self.custom_report_table.setRowCount(0)
        for r in page_rows:
            row = self.custom_report_table.rowCount()
            self.custom_report_table.insertRow(row)
            self.custom_report_table.setItem(row, 0, QTableWidgetItem(r['name']))
            self.custom_report_table.setItem(row, 1, QTableWidgetItem(r['type']))
            self.custom_report_table.setItem(row, 2, QTableWidgetItem(r['modifier']))
            self.custom_report_table.setItem(row, 3, QTableWidgetItem(r['modified']))
            self.custom_report_table.setItem(row, 4, QTableWidgetItem(r['status']))

            # === 操作列：编辑 / 复制 / 删除 按钮 ===
            key = r['key']
            action_widget = QWidget()
            action_layout = QHBoxLayout(action_widget)
            action_layout.setContentsMargins(4, 3, 4, 3)
            action_layout.setSpacing(4)

            edit_btn = QPushButton("✏ 编辑")
            edit_btn.setFixedSize(52, 24)
            edit_btn.setCursor(Qt.CursorShape.PointingHandCursor)
            edit_btn.setStyleSheet("""
                QPushButton { border: 1px solid #D9D9D9; border-radius: 3px;
                              padding: 2px 8px; font-size: 11px; background: #FFFFFF; color: #333; }
                QPushButton:hover { border-color: #FF8C00; color: #FF8C00; background-color: #FFF7E6; }
            """)
            edit_btn.clicked.connect(lambda checked, k=key, r=row:
                self._on_old_report_edit(k, r))

            copy_btn = QPushButton("📋 复制")
            copy_btn.setFixedSize(52, 24)
            copy_btn.setCursor(Qt.CursorShape.PointingHandCursor)
            copy_btn.setStyleSheet("""
                QPushButton { border: 1px solid #D9D9D9; border-radius: 3px;
                              padding: 2px 8px; font-size: 11px; background: #FFFFFF; color: #333; }
                QPushButton:hover { border-color: #52C41A; color: #52C41A; background-color: #F6FFED; }
            """)
            copy_btn.clicked.connect(lambda checked, k=key: self._on_old_report_copy(k))

            delete_btn = QPushButton("🗑 删除")
            delete_btn.setFixedSize(52, 24)
            delete_btn.setCursor(Qt.CursorShape.PointingHandCursor)
            delete_btn.setStyleSheet("""
                QPushButton { border: 1px solid #FFCCC7; border-radius: 3px;
                              padding: 2px 8px; font-size: 11px; background: #FFFFFF; color: #FF4D4F; }
                QPushButton:hover { background-color: #FFF1F0; border-color: #FF4D4F; }
            """)
            delete_btn.clicked.connect(lambda checked, k=key: self._on_old_report_delete(k))

            action_layout.addWidget(edit_btn)
            action_layout.addWidget(copy_btn)
            action_layout.addWidget(delete_btn)
            self.custom_report_table.setCellWidget(row, 5, action_widget)

        # 更新分页控件
        if hasattr(self, 'custom_report_list_record_label'):
            self.custom_report_list_record_label.setText(f"共 {total} 条记录")
        if hasattr(self, 'custom_report_list_page_label'):
            self.custom_report_list_page_label.setText(f"{current_page}/{page_count}")
        if hasattr(self, 'custom_report_list_prev_btn'):
            self.custom_report_list_prev_btn.setEnabled(current_page > 1)
        if hasattr(self, 'custom_report_list_next_btn'):
            self.custom_report_list_next_btn.setEnabled(current_page < page_count)


    def _on_custom_report_table_cell_clicked(self, row, col):
        """点击表格行，加载对应报表配置到右侧编辑区。"""
        item = self.custom_report_table.item(row, 0)
        if not item:
            return
        key = item.text()
        # 若是上次配置，使用特殊 key
        if key == '[上次配置]':
            key = '__last_state__'
        # 选中侧栏时加载
        self._load_custom_report_by_key(key)

    def _load_custom_report_by_key(self, key):
        config = load_config()
        custom_reports = config.get('custom_reports', {}) if isinstance(config, dict) else {}
        presets = custom_reports.get('presets', {}) if isinstance(custom_reports.get('presets', {}), dict) else {}
        if key == '__last_state__':
            state = custom_reports.get('last_state')
        else:
            state = presets.get(key)
        if not isinstance(state, dict):
            show_warning('提示', '未找到该配置。', self)
            return
        self._apply_custom_report_builder_state(copy.deepcopy(state))
        self._refresh_custom_report_preset_combo(key if key != '__last_state__' else '')
        self._save_custom_report_builder_state()
        self.custom_report_current_page = 1
        self._apply_custom_report_filters()

        # 如果编辑器已创建，直接切换到 Step 2 并刷新候选字段
        if hasattr(self, 'custom_report_editor_step_stack'):
            self.custom_report_step2_btns.setVisible(True)
            self.custom_report_step_label.setText("步骤 2/2：字段配置与筛选")
            self.custom_report_editor_step_stack.setCurrentIndex(1)
            if hasattr(self, 'custom_report_editor_title') and key != '__last_state__':
                self.custom_report_editor_title.setText(f"编辑报表：{key}")
            if hasattr(self, 'custom_report_candidate_fields'):
                self._refresh_candidate_field_list()

        # 刷新右侧预览表，然后刷新左侧的报表列表
        self._populate_custom_report_table()
        self._populate_custom_report_sidebar_table()
        self._populate_custom_report_table_rows = []
        self.append_output(f"[自定义报表] 已加载报表: {key}")

    def _on_custom_report_edit(self, key):
        """编辑按钮回调：切换到编辑器页面并加载配置"""
        if key == '__last_state__':
            show_warning('提示', '临时配置不可直接编辑，请先另存为新报表。', self)
            return
        self.switch_to_custom_report_editor()
        self._load_custom_report_by_key(key)

    def _on_custom_report_copy(self, key):
        """复制预设为新报表"""
        config = load_config()
        custom_reports = config.get('custom_reports', {}) if isinstance(config, dict) else {}
        presets = custom_reports.get('presets', {}) if isinstance(custom_reports.get('presets', {}), dict) else {}
        state = presets.get(key)
        if not isinstance(state, dict):
            show_warning('提示', '未找到该配置，无法复制。', self)
            return
        new_name, ok = QInputDialog.getText(self, '复制报表', '请输入新报表名称:')
        if not ok or not new_name.strip():
            return
        presets[new_name.strip()] = copy.deepcopy(state)
        custom_reports['presets'] = presets
        config['custom_reports'] = custom_reports
        save_config(config, immediate=False)
        self._refresh_custom_report_list()
        self.append_output(f"[自定义报表] 已复制报表: {key} -> {new_name.strip()}")

    def _on_custom_report_delete(self, key):
        """表格中删除按钮回调"""
        if key == '__last_state__':
            show_warning('提示', '不能删除临时配置。', self)
            return
        ok = QMessageBox.question(self, '确认删除', f'确认删除报表: {key}?')
        if ok != QMessageBox.StandardButton.Yes:
            return
        config = load_config()
        custom_reports = config.get('custom_reports', {}) if isinstance(config, dict) else {}
        presets = custom_reports.get('presets', {}) if isinstance(custom_reports.get('presets', {}), dict) else {}
        if key in presets:
            presets.pop(key, None)
            custom_reports['presets'] = presets
            config['custom_reports'] = custom_reports
            save_config(config, immediate=False)
            self._refresh_custom_report_list()
            self._refresh_custom_report_preset_combo()
            self.append_output(f"[自定义报表] 已删除报表: {key}")

    def _on_custom_report_move(self, key):
        """移动报表到指定文件夹（重命名或分类）"""
        if key == '__last_state__':
            show_warning('提示', '不能移动临时配置，请先另存为报表。', self)
            return
        new_name, ok = QInputDialog.getText(self, '移动/重命名报表', '请输入新的报表名称（或文件夹路径）:', text=key)
        if not ok or not new_name.strip():
            return
        new_name = new_name.strip()
        if new_name == key:
            return

        config = load_config()
        custom_reports = config.get('custom_reports', {}) if isinstance(config, dict) else {}
        presets = custom_reports.get('presets', {}) if isinstance(custom_reports.get('presets', {}), dict) else {}
        state = presets.get(key)
        if not isinstance(state, dict):
            show_warning('提示', '未找到该配置，无法移动。', self)
            return

        # 检查目标名称是否已存在
        if new_name in presets and new_name != key:
            show_warning('提示', f'目标名称 "{new_name}" 已存在，请使用其他名称。', self)
            return

        # 移动/重命名
        presets.pop(key, None)
        presets[new_name] = state
        custom_reports['presets'] = presets
        config['custom_reports'] = custom_reports
        save_config(config, immediate=False)
        self._refresh_custom_report_list()
        self._refresh_custom_report_preset_combo(new_name)
        self.append_output(f"[自定义报表] 已移动报表: {key} -> {new_name}")

    def _ask_multiline_text(self, title, label, default=''):
        """弹出一个小对话框用于多行文本输入，返回文本或 None。"""
        dialog = QDialog(self)
        dialog.setWindowTitle(title)
        layout = QVBoxLayout(dialog)
        layout.addWidget(QLabel(label))
        te = QTextEdit()
        te.setPlainText(default or '')
        layout.addWidget(te)
        btn_row = QHBoxLayout()
        ok_btn = QPushButton('确定')
        cancel_btn = QPushButton('取消')
        ok_btn.clicked.connect(dialog.accept)
        cancel_btn.clicked.connect(dialog.reject)
        btn_row.addStretch()
        btn_row.addWidget(ok_btn)
        btn_row.addWidget(cancel_btn)
        layout.addLayout(btn_row)
        if dialog.exec() == QDialog.DialogCode.Accepted:
            return te.toPlainText()
        return None

    def on_add_custom_report_hook(self, hook_type):
        """添加前置或后置钩子，并保存到配置中。"""
        name, ok = QInputDialog.getText(self, '添加钩子', '请输入钩子名称:')
        if not ok or not name.strip():
            return
        code = self._ask_multiline_text('钩子代码', '请输入钩子代码（支持 Python）：')
        if code is None:
            return
        try:
            cfg = load_config()
            custom_reports = cfg.get('custom_reports', {}) if isinstance(cfg, dict) else {}
            hooks = custom_reports.get('hooks', {}) if isinstance(custom_reports.get('hooks', {}), dict) else {}
            hooks_list = hooks.get(hook_type, []) if isinstance(hooks.get(hook_type, []), list) else []
            hooks_list.append({'name': name.strip(), 'code': code})
            hooks[hook_type] = hooks_list
            custom_reports['hooks'] = hooks
            cfg['custom_reports'] = custom_reports
            save_config(cfg, immediate=False)
            self.append_output(f"[自定义报表] 已添加钩子: {hook_type} / {name.strip()}")
            show_info('提示', '钩子已保存。', self)
        except Exception as e:
            show_error('保存失败', str(e), self)

    def _on_custom_report_save(self):
        """保存当前报表配置为最近状态（不另存为）。"""
        try:
            state = self._save_custom_report_builder_state()
            self.append_output(f"[自定义报表] 已保存当前配置（最近配置）。")
            show_info('提示', '已保存当前配置。', self)
        except Exception as e:
            show_error('保存失败', str(e), self)

    def on_load_custom_report_preset(self):
        """应用选中的自定义报表预设。"""
        preset_name = str(self.custom_report_preset_combo.currentData() or '').strip()
        if not preset_name:
            show_warning('提示', '请先选择一个预设。', self)
            return

        config = load_config()
        self.config = config
        custom_reports = config.get('custom_reports', {})
        presets = custom_reports.get('presets', {}) if isinstance(custom_reports, dict) else {}
        state = presets.get(preset_name)
        if not isinstance(state, dict):
            show_warning('提示', '未找到该预设配置。', self)
            return

        self._apply_custom_report_builder_state(copy.deepcopy(state))
        self._refresh_custom_report_preset_combo(preset_name)
        self._save_custom_report_builder_state()
        self.custom_report_current_page = 1
        self._apply_custom_report_filters()
        self._populate_custom_report_table()
        self.append_output(f"[自定义报表] 已应用预设: {preset_name}")

    def on_save_custom_report_preset(self):
        """保存当前自定义报表预设。"""
        preset_name, ok = QInputDialog.getText(self, '保存预设', '请输入预设名称:')
        if not ok:
            return
        preset_name = str(preset_name or '').strip()
        if not preset_name:
            show_warning('提示', '预设名称不能为空。', self)
            return

        self._save_custom_report_builder_state(preset_name=preset_name)
        self._refresh_custom_report_preset_combo(preset_name)
        self.append_output(f"[自定义报表] 已保存预设: {preset_name}")
        self._update_custom_report_filter_summary()

    def on_generate_custom_report_bi(self):
        """生成当前预设的 BI 摘要信息。"""
        preset_name = str(self.custom_report_preset_combo.currentData() or '').strip() or '未命名预设'
        source_names = [row.get('name', row.get('api_name', '')) for row in self._collect_custom_report_source_rows() if row.get('enabled')]
        field_count = len(self._collect_custom_report_field_configs())
        row_count = len(self.custom_report_filtered_data or self.custom_report_all_data)
        summary = (
            f"BI 摘要: {preset_name} | 主表: {self.custom_report_main_source_combo.currentText() or '未设置'} | "
            f"对象数: {len(source_names)} | 字段数: {field_count} | 当前记录数: {row_count}"
        )
        self.custom_report_bi_status_label.setText(summary)
        self.custom_report_bi_status_label.setToolTip(summary)
        self.append_output(f"[自定义报表] {summary}")

    def _update_filter_summary_from_conditions(self):
        """根据左侧筛选条件列表更新摘要信息。"""
        if not hasattr(self, 'custom_report_filter_summary'):
            return
        condition_count = self.custom_report_conditions_list.count() if hasattr(self, 'custom_report_conditions_list') else 0
        selected_field_count = self.custom_report_selected_fields.count() if hasattr(self, 'custom_report_selected_fields') else 0
        candidate_count = self.custom_report_candidate_fields.count() if hasattr(self, 'custom_report_candidate_fields') else 0

        start_date = self.custom_report_start_date_edit.date().toString('yyyy-MM-dd') if hasattr(self, 'custom_report_start_date_edit') and self.custom_report_start_date_edit else ''
        end_date = self.custom_report_end_date_edit.date().toString('yyyy-MM-dd') if hasattr(self, 'custom_report_end_date_edit') and self.custom_report_end_date_edit else ''

        summary_parts = []
        if start_date and end_date:
            summary_parts.append(f"日期范围: {start_date} ~ {end_date}")
        if condition_count > 0:
            summary_parts.append(f"筛选条件: {condition_count} 条")
        if selected_field_count > 0:
            summary_parts.append(f"显示字段: {selected_field_count} 个")

        summary = " | ".join(summary_parts) if summary_parts else "尚未配置筛选条件和显示字段。"
        self.custom_report_filter_summary.setText(summary)

    def _update_custom_report_filter_summary(self):
        """更新筛选和字段配置摘要。"""
        if not hasattr(self, 'custom_report_filter_summary'):
            return
        field_configs = self._collect_custom_report_field_configs() if hasattr(self, 'custom_report_field_builder_table') else []
        visible_headers = self.custom_report_visible_headers or [
            config.get('display_name', '')
            for config in field_configs
            if config.get('display_name')
        ]
        date_text = (
            f"{self.custom_report_date_start.toString('yyyy-MM-dd')} ~ {self.custom_report_date_end.toString('yyyy-MM-dd')}"
            if hasattr(self, 'custom_report_date_start') and self.custom_report_date_start
               and hasattr(self, 'custom_report_date_end') and self.custom_report_date_end
            else '未设置'
        )
        summary = (
            f"固定日期: {date_text}；自定义条件: {len(self.custom_report_filter_conditions)} 条；"
            f"字段拼接: {len(field_configs)} 个；当前显示字段: {len([header for header in visible_headers if header])} 个"
        )
        self.custom_report_filter_summary.setText(summary)

    def open_custom_report_date_filter_dialog(self):
        """打开自定义报表日期选择弹窗。"""
        dialog = QuickDatePickerDialog(
            self.custom_report_date_start,
            self.custom_report_date_end,
            self
        )
        dialog.position_below_widget(self.custom_report_date_filter_btn)
        if dialog.exec() == QDialog.DialogCode.Accepted:
            self.custom_report_date_start = dialog.start_date
            self.custom_report_date_end = dialog.end_date
            if (
                self.custom_report_date_start and self.custom_report_date_end
                and self.custom_report_date_start.isValid() and self.custom_report_date_end.isValid()
            ):
                self.custom_report_date_filter_btn.setText(
                    f"{self.custom_report_date_start.toString('yyyy-MM-dd')} ~ "
                    f"{self.custom_report_date_end.toString('yyyy-MM-dd')}"
                )
            self.on_custom_report_local_filter_changed()

    def _get_custom_report_sources(self):
        """获取自定义报表数据源配置。优先读取 CRM 对象管理，其次 data_objects，最后默认值。"""
        sources = []

        # 优先从 CRM 对象管理读取
        fx_cfg = self.config.get('fxiaoke', {})
        crm_objects = fx_cfg.get('crm_objects', [])
        if isinstance(crm_objects, list) and crm_objects:
            for item in crm_objects:
                if isinstance(item, dict):
                    api_name = str(item.get('api_name') or '').strip()
                    name = str(item.get('name') or api_name).strip()
                    if api_name:
                        sources.append({'name': name or api_name, 'api_name': api_name})

        # 如果 CRM 对象管理为空，其次从 custom_reports.data_objects 读取
        if not sources:
            configured_sources = self.config.get('custom_reports', {}).get('data_objects', [])
            if isinstance(configured_sources, list) and configured_sources:
                for item in configured_sources:
                    if isinstance(item, dict):
                        api_name = str(item.get('api_name') or item.get('value') or '').strip()
                        name = str(item.get('name') or item.get('text') or api_name).strip()
                    else:
                        api_name = str(item).strip()
                        name = api_name
                    if api_name:
                        sources.append({'name': name or api_name, 'api_name': api_name})

        # 如果以上都为空，使用默认 CRM 对象列表
        if not sources:
            sources = [
                {'name': '商机', 'api_name': 'NewOpportunityObj'},
                {'name': '销售订单', 'api_name': 'SalesOrderObj'},
                {'name': '发货单', 'api_name': 'DeliveryNoteObj'},
                {'name': '发货单产品', 'api_name': 'DeliveryNoteProductObj'},
                {'name': '公立项目授权', 'api_name': 'public_project_authorizati__c'},
            ]


        return sources

    def _refresh_custom_report_list(self):
        """刷新侧栏中的报表预设列表。"""
        # 使用表格填充侧栏列表（支持搜索过滤和分页）
        try:
            self._populate_custom_report_sidebar_table()
        except Exception:
            # 回退为清空表格，避免异常导致界面崩溃
            try:
                self.custom_report_table.setRowCount(0)
            except Exception:
                pass

    def _on_custom_report_list_page_size_changed(self):
        """报表列表每页条数变化。"""
        self.custom_report_list_page_size = self._get_combo_page_size(self.custom_report_list_page_size_combo)
        self.custom_report_list_current_page = 1
        self._save_page_sizes()
        self._populate_custom_report_sidebar_table()

    def _on_custom_report_list_prev_page(self):
        """报表列表上一页。"""
        if self.custom_report_list_current_page > 1:
            self.custom_report_list_current_page -= 1
            self._populate_custom_report_sidebar_table()

    def _on_custom_report_list_next_page(self):
        """报表列表下一页。"""
        total = len(getattr(self, 'custom_report_list_all_rows', []))
        page_size = getattr(self, 'custom_report_list_page_size', 20)
        page_count = max(1, (total + page_size - 1) // page_size)
        if self.custom_report_list_current_page < page_count:
            self.custom_report_list_current_page += 1
            self._populate_custom_report_sidebar_table()

    def _on_custom_report_list_col_resized(self, col, old_size, new_size):
        """列宽变化时自动保存到配置"""
        self._save_custom_report_list_col_widths()

    def _save_custom_report_list_col_widths(self):
        """保存报表列表列宽到配置"""
        if not hasattr(self, 'custom_report_table'):
            return
        widths = []
        for c in range(self.custom_report_table.columnCount()):
            widths.append(self.custom_report_table.columnWidth(c))
        config = load_config()
        app_settings = config.get('app_settings', {})
        if not isinstance(app_settings, dict):
            app_settings = {}
        app_settings['custom_report_list_col_widths'] = widths
        config['app_settings'] = app_settings
        save_config(config, immediate=False)

    def show_custom_report_new_menu(self):
        """显示新建报表的下拉菜单（按CRM原版）。"""
        from PyQt6.QtWidgets import QMenu

        menu = QMenu(self)
        menu.setStyleSheet("""
            QMenu {
                background-color: #FFFFFF;
                border: 1px solid #E0E0E0;
                border-radius: 4px;
                padding: 4px 0;
            }
            QMenu::item {
                padding: 8px 20px;
                color: #333333;
                font-size: 14px;
            }
            QMenu::item:selected {
                background-color: #FFF7E6;
                color: #FF8C00;
            }
            QMenu::separator {
                height: 1px;
                background-color: #F0F0F0;
                margin: 4px 8px;
            }
        """)

        # 菜单项（按CRM原版）
        new_report_action = menu.addAction("📊 新建报表")
        new_report_action.triggered.connect(self.on_create_custom_report)

        new_chart_action = menu.addAction("📈 新建图表")
        new_chart_action.triggered.connect(lambda: show_info('提示', '新建图表功能开发中...', self))

        new_folder_action = menu.addAction("📁 新建文件夹")
        new_folder_action.triggered.connect(self.on_create_custom_report_folder)

        menu.addSeparator()

        new_global_action = menu.addAction("🌐 新建全局报表")
        new_global_action.triggered.connect(lambda: show_info('提示', '新建全局报表功能开发中...', self))

        # 显示菜单（在按钮下方）
        btn_rect = self.custom_report_new_btn.geometry()
        global_pos = self.custom_report_new_btn.mapToGlobal(btn_rect.bottomLeft())
        menu.exec(global_pos)

    def on_create_custom_report_folder(self):
        """新建文件夹。"""
        name, ok = QInputDialog.getText(self, '新建文件夹', '请输入文件夹名称:')
        if not ok or not name.strip():
            return
        state = {
            'type': 'folder',
            'name': name.strip(),
            'created': datetime.now().strftime('%Y-%m-%d'),
            'status': '已启用'
        }
        config = load_config()
        custom_reports = config.get('custom_reports', {})
        if not isinstance(custom_reports, dict):
            custom_reports = {}
        presets = custom_reports.get('presets', {}) if isinstance(custom_reports.get('presets', {}), dict) else {}
        presets[name.strip()] = state
        custom_reports['presets'] = presets
        config['custom_reports'] = custom_reports
        save_config(config, immediate=False)
        self._refresh_custom_report_list()
        self.append_output(f"[自定义报表] 已创建文件夹: {name.strip()}")

    def _on_custom_report_table_double_clicked(self, row, col):
        """双击表格行：打开报表编辑器。"""
        item = self.custom_report_table.item(row, 0)
        if not item:
            return
        key = item.text()
        if key == '[上次配置]':
            key = '__last_state__'
        # 先切换到编辑器页面，再加载配置（确保 UI 已创建）
        self.switch_to_custom_report_editor()
        self._load_custom_report_by_key(key)

    def on_create_custom_report(self):
        """新建报表：切换到编辑器页面。"""
        self.switch_to_custom_report_editor()

    def _on_old_report_edit(self, key, row):
        """旧版路径：编辑按钮 → 加载报表到编辑器"""
        if key == '[上次配置]':
            key = '__last_state__'
        self.switch_to_custom_report_editor()
        self._load_custom_report_by_key(key)

    def _on_old_report_copy(self, key):
        """旧版路径：复制按钮 → 复制报表"""
        if key == '__last_state__':
            show_info('提示', '不能复制临时配置。', self)
            return
        new_name, ok = QInputDialog.getText(self, '复制报表', '请输入新报表名称:')
        if ok and new_name.strip():
            config = load_config()
            custom_reports = config.get('custom_reports', {}) if isinstance(config, dict) else {}
            presets = custom_reports.get('presets', {}) if isinstance(custom_reports.get('presets', {}), dict) else {}
            if key in presets:
                import copy
                presets[new_name.strip()] = copy.deepcopy(presets[key])
                custom_reports['presets'] = presets
                config['custom_reports'] = custom_reports
                save_config(config, immediate=False)
                self._refresh_custom_report_list()
                self.append_output(f"[自定义报表] 已复制报表: {key} -> {new_name.strip()}")

    def _on_old_report_delete(self, key):
        """旧版路径：删除按钮 → 删除报表"""
        if key == '[上次配置]':
            show_info('提示', '不能删除临时配置。', self)
            return
        ok = QMessageBox.question(self, '确认删除', f'确认删除报表: {key}?')
        if ok != QMessageBox.StandardButton.Yes:
            return
        config = load_config()
        custom_reports = config.get('custom_reports', {}) if isinstance(config, dict) else {}
        presets = custom_reports.get('presets', {}) if isinstance(custom_reports.get('presets', {}), dict) else {}
        if key in presets:
            presets.pop(key, None)
            custom_reports['presets'] = presets
            config['custom_reports'] = custom_reports
            save_config(config, immediate=False)
            self._refresh_custom_report_list()
            self._refresh_custom_report_preset_combo()
            self.append_output(f"[自定义报表] 已删除报表: {key}")

    def on_delete_custom_report(self):
        """删除侧栏选中的预设。"""
        # 从表格中获取当前选中行并删除对应的预设
        selected = self.custom_report_table.selectionModel().selectedRows()
        if not selected:
            show_info('提示', '请先选择要删除的报表。', self)
            return
        row = selected[0].row()
        name_item = self.custom_report_table.item(row, 0)
        if not name_item:
            show_info('提示', '请选择有效的报表行。', self)
            return
        key = name_item.text()
        if key == '[上次配置]':
            show_warning('提示', '不能删除临时配置。', self)
            return
        ok = QMessageBox.question(self, '确认删除', f'确认删除报表: {key}?')
        if ok != QMessageBox.StandardButton.Yes:
            return
        config = load_config()
        custom_reports = config.get('custom_reports', {}) if isinstance(config, dict) else {}
        presets = custom_reports.get('presets', {}) if isinstance(custom_reports.get('presets', {}), dict) else {}
        if key in presets:
            presets.pop(key, None)
            custom_reports['presets'] = presets
            config['custom_reports'] = custom_reports
            save_config(config, immediate=False)
            self._refresh_custom_report_list()
            self._refresh_custom_report_preset_combo()
            self.append_output(f"[自定义报表] 已删除报表: {key}")

    def on_select_custom_report(self, item):
        """侧栏选择报表时加载并应用。"""
        if not item:
            return
        key = item.data(Qt.UserRole)
        config = load_config()
        custom_reports = config.get('custom_reports', {}) if isinstance(config, dict) else {}
        presets = custom_reports.get('presets', {}) if isinstance(custom_reports.get('presets', {}), dict) else {}
        if key == '__last_state__':
            state = custom_reports.get('last_state')
        else:
            state = presets.get(key)
        if not isinstance(state, dict):
            show_warning('提示', '未找到该配置。', self)
            return
        self._apply_custom_report_builder_state(copy.deepcopy(state))
        self._refresh_custom_report_preset_combo(key if key != '__last_state__' else '')
        self._save_custom_report_builder_state()
        self.custom_report_current_page = 1
        self._apply_custom_report_filters()
        self._populate_custom_report_table()
        self.append_output(f"[自定义报表] 已加载报表: {key}")

    def on_custom_report_source_changed(self):
        """切换自定义报表数据源。"""
        self._refresh_custom_report_main_source_options()
        self._refresh_custom_report_field_source_options()
        self._update_custom_report_source_summary()
        self.custom_report_all_data = []
        self.custom_report_filtered_data = []
        self.custom_report_source_data_map = {}
        self.custom_report_headers = []
        self.custom_report_field_labels = {}
        self.custom_report_label_to_field = {}
        self.custom_report_current_page = 1
        self._update_custom_report_filter_summary()
        self._populate_custom_report_table()
        self._save_custom_report_builder_state()

    def _get_custom_report_source_name_map(self):
        """获取自定义报表对象名称映射。"""
        return {
            source.get('name', source.get('api_name', '')): source.get('api_name', '')
            for source in self._get_custom_report_sources()
            if source.get('api_name')
        }

    def _get_custom_report_source_api_to_name_map(self):
        """获取自定义报表对象 API 到中文名映射。"""
        return {
            source.get('api_name', ''): source.get('name', source.get('api_name', ''))
            for source in self._get_custom_report_sources()
            if source.get('api_name')
        }

    def _get_selected_custom_report_sources(self):
        """获取当前选中的自定义报表对象。"""
        if hasattr(self, 'custom_report_source_table'):
            source_rows = self._collect_custom_report_source_rows()
            selected_sources = [
                {'name': row.get('name', row.get('api_name', '')), 'api_name': row.get('api_name', '')}
                for row in source_rows
                if row.get('enabled') and row.get('api_name')
            ]
            if selected_sources:
                return selected_sources
            fallback_sources = [
                {'name': row.get('name', row.get('api_name', '')), 'api_name': row.get('api_name', '')}
                for row in source_rows
                if row.get('api_name')
            ]
            if fallback_sources:
                return fallback_sources[:1]
        if not hasattr(self, 'custom_report_source_popup'):
            sources = self._get_custom_report_sources()
            return sources[:1]
        name_to_api = self._get_custom_report_source_name_map()
        selected_names = self.custom_report_source_popup.get_selected_options()
        selected_sources = [
            {'name': name, 'api_name': name_to_api.get(name, '')}
            for name in selected_names
            if name_to_api.get(name, '')
        ]
        if not selected_sources:
            sources = self._get_custom_report_sources()
            selected_sources = sources[:1]
        return selected_sources

    def _toggle_custom_report_source_popup(self):
        """切换 CRM 对象多选弹层。"""
        if not hasattr(self, 'custom_report_source_popup') or not hasattr(self, 'custom_report_source_btn'):
            return
        if self.custom_report_source_popup.isVisible():
            self.custom_report_source_popup.hide()
            return
        self.custom_report_source_popup.show_below(self.custom_report_source_btn)

    def _rebuild_custom_report_source_popup(self, select_default=False):
        """重建 CRM 对象多选弹层。"""
        if not hasattr(self, 'custom_report_source_popup'):
            return
        sources = self._get_custom_report_sources()
        options = [source.get('name', source.get('api_name', '')) for source in sources]
        selected = [options[0]] if select_default and options else self.custom_report_source_popup.get_selected_options()
        self.custom_report_source_popup.set_options(options, selected_options=selected)
        self._update_custom_report_source_summary()

    def _on_custom_report_source_selection_changed(self):
        """响应 CRM 对象选择变化。"""
        self._update_custom_report_source_summary()
        self.on_custom_report_source_changed()

    def _update_custom_report_source_summary(self):
        """更新 CRM 对象选择摘要。"""
        if not hasattr(self, 'custom_report_source_summary'):
            return
        selected_sources = self._get_selected_custom_report_sources()
        names = [source.get('name', '') for source in selected_sources if source.get('name')]
        main_source_name = self.custom_report_main_source_combo.currentText() if hasattr(self, 'custom_report_main_source_combo') else ''
        if not names:
            summary = "未选择"
        else:
            summary = f"已启用 {len(names)} 个对象"
            if len(names) <= 2:
                summary = "、".join(names)
        if main_source_name:
            summary = f"{summary} | 主表: {main_source_name}"
        self.custom_report_source_summary.setText(summary)
        self.custom_report_source_summary.setToolTip("、".join(names))

    def open_custom_report_filter_dialog(self):
        """打开自定义报表多条件筛选弹窗。"""
        # 仅从字段拼接表（报表列）获取已勾选的字段，不再合并全部 CRM 字段
        field_configs = self._collect_custom_report_field_configs()
        fields = []
        seen = set()
        for config in field_configs:
            display_name = str(config.get('display_name', '')).strip()
            field_name = str(config.get('field_name', '')).strip()
            label = display_name or self._guess_custom_report_field_label(field_name) or field_name
            if label and label not in seen:
                seen.add(label)
                fields.append(label)

        # 如果字段拼接表为空（尚未添加字段），回退使用当前报表头
        if not fields:
            available_fields = self.custom_report_headers or self._get_custom_report_fallback_fields()
            fields = list(dict.fromkeys(self._get_custom_report_display_headers(available_fields)))

        date_fields = []
        for field in fields:
            field_key = self._get_custom_report_field_key(field)
            lower_field = str(field).lower()
            lower_key = str(field_key).lower()
            if any(keyword in lower_field for keyword in ('日期', '时间', 'date', 'time')) or any(keyword in lower_key for keyword in ('date', 'time')):
                date_fields.append(field)
        display_conditions = [
            {
                **condition,
                'field': self._get_custom_report_field_label(condition.get('field', '')),
            }
            for condition in self.custom_report_filter_conditions
        ]
        dialog = CustomReportFilterDialog(fields, display_conditions, self, date_fields=date_fields)
        if dialog.exec() == QDialog.DialogCode.Accepted:
            self.custom_report_filter_conditions = [
                {
                    **condition,
                    'field': self._get_custom_report_field_key(condition.get('field', '')),
                }
                for condition in dialog.get_conditions()
            ]
            self._update_custom_report_filter_summary()
            self._save_custom_report_builder_state()
            self.on_custom_report_local_filter_changed()

    def open_custom_report_field_settings_dialog(self):
        """打开自定义报表字段设置对话框。"""
        all_headers = self.custom_report_headers or self._get_custom_report_fallback_fields()
        if not all_headers:
            show_warning("提示", "请先刷新加载报表字段。", self)
            return

        visible_headers, header_order = self._resolve_custom_report_field_settings(all_headers)
        display_headers = self._get_custom_report_display_headers(all_headers)
        display_visible_headers = self._get_custom_report_display_headers(visible_headers)
        display_header_order = self._get_custom_report_display_headers(header_order)
        dialog = ExcelFieldSettingsDialog(
            display_headers,
            visible_headers=display_visible_headers,
            header_order=display_header_order,
            parent=self
        )
        if dialog.exec() == QDialog.DialogCode.Accepted:
            new_visible_display, new_order_display = dialog.get_settings()
            new_visible = [self._get_custom_report_field_key(header) for header in new_visible_display]
            new_order = [self._get_custom_report_field_key(header) for header in new_order_display]
            self.custom_report_visible_headers = new_visible
            self.custom_report_header_order = new_order

            # ✅ 和CRM保持一致：字段设置随报表预设一起保存，不单独保存到 app_settings
            # 直接保存到 custom_reports.last_state 和当前预设中
            self._save_custom_report_builder_state()

            operation_log.info(f"自定义报表字段设置已变更 | 显示字段数:{len(new_visible)}")
            self._update_custom_report_filter_summary()
            self._populate_custom_report_table()

    def _resolve_custom_report_field_settings(self, all_headers):
        """读取并整理自定义报表字段设置。
        
        ✅ 和CRM保持一致：从 custom_reports.last_state 或当前预设读取字段配置，
        不再从 app_settings.custom_report_table_settings 单独读取。
        """
        all_headers = [str(header).strip() for header in all_headers if str(header).strip()]
        
        # 优先从 custom_reports 中读取
        config = self.config or load_config()
        custom_reports = config.get('custom_reports', {})
        
        # 尝试从 last_state 读取
        saved_order = []
        saved_visible = []
        
        last_state = custom_reports.get('last_state', {})
        if isinstance(last_state, dict):
            saved_order = [header for header in last_state.get('header_order', []) if header in all_headers]
            saved_visible = [header for header in last_state.get('visible_headers', []) if header in all_headers]
        
        # 如果 last_state 中没有，使用完整顺序
        if not saved_order:
            saved_order = all_headers.copy()
        else:
            # 补充新增的字段
            saved_order.extend(header for header in all_headers if header not in saved_order)
        
        # 如果没有指定可见字段，则全部显示
        if not saved_visible:
            saved_visible = saved_order.copy()
        
        return saved_visible, saved_order

    def _apply_custom_report_field_settings(self):
        """应用自定义报表字段显示设置。"""
        all_headers = self.custom_report_headers or self._get_custom_report_fallback_fields()
        visible_headers, header_order = self._resolve_custom_report_field_settings(all_headers)
        self.custom_report_visible_headers = visible_headers
        self.custom_report_header_order = header_order

    def _build_custom_report_field_labels(self, field_names, data_object_api_name=None):
        """构建自定义报表字段中文显示名。"""
        configured_labels = self.config.get('custom_reports', {}).get('field_labels', {})
        if not isinstance(configured_labels, dict):
            configured_labels = {}

        common_labels = {
            '_id': '数据ID',
            'id': 'ID',
            'name': '名称',
            'create_time': '创建时间',
            'submit_time': '提交时间',
            'last_modified_time': '最后修改时间',
            'created_by': '创建人ID',
            'created_by__r': '创建人',
            'owner': '负责人ID',
            'owner__r': '负责人',
            'account_id': '客户ID',
            'account_id__r': '客户名称',
            'customer_id': '客户ID',
            'customer_id__r': '客户名称',
            'contact_id': '联系人ID',
            'contact_id__r': '客户联系人',
            'record_type': '业务类型',
            'life_status': '生命状态',
            'remark': '备注',
            'lock_status': '锁定状态',
        }
        opportunity_labels = {
            'name': '商机名称',
            'source': '外部来源',
            'source__r': '外部来源',
            'account_id__r': '客户名称',
            'customer_name': '客户名称',
            'contact_id__r': '客户联系人',
            'contact_name': '客户联系人',
            'mobile': '客户联系人手机',
            'phone': '客户联系人手机',
            'expected_deal_date': '预计成交日期',
            'expected_close_date': '预计成交日期',
            'payment_method': '支付方式',
            'opportunity_status': '商机进展状态',
            'opportunity_stage': '商机阶段',
            'stage': '商机阶段',
            'description': '商机描述',
            'amount': '商机金额',
            'owner__r': '负责人',
            'owner_department__r': '负责人主属部门',
            'last_follow_time': '最后跟进时间',
            'win_rate': '赢率',
            'related_market_activity': '关联市场活动',
            'sales_contract': '销售合同',
        }
        account_labels = {
            'name': '客户名称',
            'phone': '电话',
            'mobile': '手机',
            'address': '地址',
            'owner__r': '负责人',
        }
        contact_labels = {
            'name': '联系人姓名',
            'mobile': '手机',
            'phone': '电话',
            'account_id__r': '所属客户',
            'owner__r': '负责人',
        }
        delivery_note_product_labels = {
            'name': '发货单产品名称',
            'delivery_note_id': '发货单ID',
            'delivery_note_id__r': '发货单',
            'product_id': '产品ID',
            'product_id__r': '产品名称',
            'product_name': '产品名称',
            'product_code': '产品编码',
            'specification': '规格型号',
            'model': '型号',
            'unit': '单位',
            'quantity': '数量',
            'price': '单价',
            'amount': '金额',
            'remark': '备注',
            'owner__r': '负责人',
            'created_by__r': '创建人',
        }
        object_labels = {}
        if data_object_api_name == 'NewOpportunityObj':
            object_labels = opportunity_labels
        elif data_object_api_name == 'AccountObj':
            object_labels = account_labels
        elif data_object_api_name == 'ContactObj':
            object_labels = contact_labels
        elif data_object_api_name == 'DeliveryNoteProductObj':
            object_labels = delivery_note_product_labels
        # 获取CRM字段管理中的自定义标签（最高优先级）
        crm_field_mgmt_labels = {}
        if data_object_api_name:
            fx_cfg = self.config.get('fxiaoke', {})
            custom_fields = fx_cfg.get('crm_object_fields', {}).get(data_object_api_name, {})
            if isinstance(custom_fields, dict):
                for field_key, field_cfg in custom_fields.items():
                    if isinstance(field_cfg, dict) and field_cfg.get('label'):
                        crm_field_mgmt_labels[field_key] = field_cfg['label']

        labels = {}
        label_counts = {}
        for field_name in field_names or []:
            label = (
                crm_field_mgmt_labels.get(field_name)          # 1. CRM字段管理自定义标签（最高）
                or configured_labels.get(field_name)            # 2. 旧的自定义标签
                or object_labels.get(field_name)                # 3. 对象特定默认标签
                or common_labels.get(field_name)                # 4. 通用默认标签
                or self._guess_custom_report_field_label(field_name)  # 5. 猜测标签
            )
            labels[field_name] = label
            label_counts[label] = label_counts.get(label, 0) + 1

        for field_name, label in list(labels.items()):
            if label_counts.get(label, 0) > 1:
                labels[field_name] = f"{label}（{field_name}）"

        self.custom_report_field_labels = labels
        self.custom_report_label_to_field = {label: field for field, label in labels.items()}

    def _guess_custom_report_field_label(self, field_name):
        """根据字段 key 推断一个尽量友好的中文显示名。"""
        field_name = str(field_name or '').strip()
        if not field_name:
            return ""
        normalized = field_name
        for suffix in ('__r', '__c'):
            if normalized.endswith(suffix):
                normalized = normalized[:-len(suffix)]
        keyword_labels = [
            ('create', '创建'),
            ('modified', '修改'),
            ('submit', '提交'),
            ('owner', '负责人'),
            ('account', '客户'),
            ('customer', '客户'),
            ('contact', '联系人'),
            ('mobile', '手机'),
            ('phone', '电话'),
            ('address', '地址'),
            ('amount', '金额'),
            ('price', '价格'),
            ('status', '状态'),
            ('stage', '阶段'),
            ('type', '类型'),
            ('source', '来源'),
            ('remark', '备注'),
            ('description', '描述'),
            ('date', '日期'),
            ('time', '时间'),
        ]
        lower_name = normalized.lower()
        for keyword, label in keyword_labels:
            if keyword in lower_name:
                return label
        if field_name.startswith('field_'):
            return f"自定义字段（{field_name}）"
        return field_name

    def _get_custom_report_field_label(self, field_name):
        """获取字段中文显示名。"""
        if not getattr(self, 'custom_report_field_labels', None):
            self._build_custom_report_field_labels(
                self.custom_report_headers or self._get_custom_report_fallback_fields(),
                getattr(self, '_custom_report_current_api_name', None),
            )
        return self.custom_report_field_labels.get(field_name, field_name)

    def _get_custom_report_field_key(self, label_or_key):
        """将中文显示名转换回接口字段 key。"""
        if not getattr(self, 'custom_report_label_to_field', None):
            self._build_custom_report_field_labels(
                self.custom_report_headers or self._get_custom_report_fallback_fields(),
                getattr(self, '_custom_report_current_api_name', None),
            )
        return self.custom_report_label_to_field.get(label_or_key, label_or_key)

    def _get_custom_report_display_headers(self, headers):
        """将字段 key 列表转换为中文表头列表。"""
        return [self._get_custom_report_field_label(header) for header in headers or []]

    @staticmethod
    def _parse_date_value(raw_value):
        """解析各种日期格式 → datetime，失败返回 None。"""
        if raw_value is None:
            return None
        from datetime import datetime
        if isinstance(raw_value, datetime):
            return raw_value
        if isinstance(raw_value, (int, float)):
            try:
                ts = float(raw_value)
                if ts > 1e12:
                    return datetime.fromtimestamp(ts / 1000)
                else:
                    return datetime.fromtimestamp(ts)
            except (ValueError, OSError):
                pass
        if isinstance(raw_value, str):
            raw_value = raw_value.strip()
            if not raw_value:
                return None
            for fmt in ('%Y-%m-%d %H:%M:%S', '%Y-%m-%d', '%Y-%m-%dT%H:%M:%S',
                         '%Y/%m/%d %H:%M:%S', '%Y/%m/%d', '%Y年%m月%d日'):
                try:
                    return datetime.strptime(raw_value, fmt)
                except ValueError:
                    continue
        return None

    @classmethod
    def _compute_date_part(cls, raw_value, unit):
        """从原始值计算年/月/周/季度，返回字符串。"""
        dt = cls._parse_date_value(raw_value)
        if dt is None:
            return ''
        if unit == 'year':
            return str(dt.year)
        elif unit == 'month':
            return str(dt.month)
        elif unit == 'week':
            return str(dt.isocalendar()[1])
        elif unit == 'quarter':
            return str((dt.month - 1) // 3 + 1)
        return ''

    @classmethod
    def _extract_time_part(cls, field_name, main_row):
        """检测 field_name 是否为 __year__: / __month__: / __week__: / __quarter__: 标记。
        是 → 提取对应日期成分并返回字符串；否 → 返回 None。"""
        if not field_name or not isinstance(main_row, dict):
            return None
        field_name = str(field_name)
        PREFIX_MAP = {
            '__year__:': 'year',
            '__month__:': 'month',
            '__week__:': 'week',
            '__quarter__:': 'quarter',
        }
        for prefix, unit in PREFIX_MAP.items():
            if field_name.startswith(prefix):
                source_field = field_name[len(prefix):]
                raw_value = main_row.get(source_field, '')
                return cls._compute_date_part(raw_value, unit)
        return None

    @staticmethod
    def _resolve_time_part_source_field(field_name):
        """__year__:create_time → create_time；非标记原样返回。"""
        if not field_name:
            return field_name
        field_name = str(field_name)
        for prefix in ('__year__:', '__month__:', '__week__:', '__quarter__:'):
            if field_name.startswith(prefix):
                return field_name[len(prefix):]
        return field_name

    def _build_custom_report_field_projection(self, source_api_name, field_configs, main_source_api_name):
        """为指定对象生成字段投影，避免无关字段全量拉取。"""
        projection = set()
        source_api_name = str(source_api_name or '').strip()
        main_source_api_name = str(main_source_api_name or '').strip()
        if source_api_name == main_source_api_name:
            projection.update(['create_time', 'submit_time', 'last_modified_time', 'created_by__r', 'owner__r'])

        for config in field_configs or []:
            config_source = str(config.get('source_api_name') or main_source_api_name).strip()
            if config_source != source_api_name:
                # 即使 config 不属于当前源，但它的 main_link_field 可能指向当前主表字段
                if source_api_name == main_source_api_name:
                    main_link_field = str(config.get('main_link_field', '')).strip()
                    if main_link_field:
                        projection.add(main_link_field)
                continue
            for key in ('field_name', 'source_link_field'):
                field_name = str(config.get(key, '')).strip()
                if field_name:
                    projection.add(self._resolve_time_part_source_field(field_name))
            if source_api_name == main_source_api_name:
                main_link_field = str(config.get('main_link_field', '')).strip()
                if main_link_field:
                    projection.add(main_link_field)

        return sorted(projection) if projection else None

    def _normalize_custom_report_match_value(self, value):
        """将关联匹配值统一为可比较的字符串。"""
        normalized = self._format_custom_report_value(value).strip().lower()
        return normalized

    def _index_custom_report_rows_by_field(self, rows, field_name):
        """按字段构建多值索引。"""
        index = {}
        for row in rows or []:
            if not isinstance(row, dict):
                continue
            key = self._normalize_custom_report_match_value(row.get(field_name, ''))
            if not key:
                continue
            index.setdefault(key, []).append(row)
        return index

    def _resolve_custom_report_join_value(self, main_row, main_source_api_name, source_data_map, index_cache, field_config):
        """根据字段配置从主表或关联对象解析字段值。"""
        source_api_name = str(field_config.get('source_api_name') or main_source_api_name).strip()
        field_name = str(field_config.get('field_name', '')).strip()
        if not field_name:
            return ''

        if source_api_name == main_source_api_name:
            time_part = self._extract_time_part(field_name, main_row)
            if time_part is not None:
                return time_part
            return self._format_custom_report_value(main_row.get(field_name, ''))

        main_link_field = str(field_config.get('main_link_field', '')).strip()
        source_link_field = str(field_config.get('source_link_field', '')).strip()
        if not main_link_field or not source_link_field:
            return ''

        match_key = self._normalize_custom_report_match_value(main_row.get(main_link_field, ''))
        if not match_key:
            return ''

        matched_rows = index_cache.get((source_api_name, source_link_field), {}).get(match_key, [])
        values = []
        for row in matched_rows:
            value = self._format_custom_report_value(row.get(field_name, ''))
            if value:
                values.append(value)
        if not values:
            return ''
        return '、'.join(dict.fromkeys(values))

    def _assemble_custom_report_preview_rows(self, source_data_map, main_source_api_name, field_configs):
        """将多对象数据组装为自定义报表预览行。"""
        main_rows = source_data_map.get(main_source_api_name, []) or []
        normalized_configs = []
        for config in field_configs or []:
            field_name = str(config.get('field_name', '')).strip()
            display_name = str(config.get('display_name', '')).strip()
            if not field_name and not display_name:
                continue
            normalized_configs.append({
                **config,
                'display_name': display_name or self._guess_custom_report_field_label(field_name) or field_name,
                'source_api_name': str(config.get('source_api_name') or main_source_api_name).strip() or main_source_api_name,
            })

        if not normalized_configs:
            normalized_configs = self._get_custom_report_default_field_configs(main_source_api_name)

        headers = []
        index_cache = {}
        for config in normalized_configs:
            display_name = str(config.get('display_name', '')).strip()
            if display_name and display_name not in headers:
                headers.append(display_name)

            source_api_name = str(config.get('source_api_name') or main_source_api_name).strip()
            source_link_field = str(config.get('source_link_field', '')).strip()
            if source_api_name != main_source_api_name and source_link_field:
                cache_key = (source_api_name, source_link_field)
                if cache_key not in index_cache:
                    index_cache[cache_key] = self._index_custom_report_rows_by_field(
                        source_data_map.get(source_api_name, []),
                        source_link_field,
                    )

        preview_rows = []
        for main_row in main_rows:
            preview_row = {
                '__create_time__': main_row.get('create_time', ''),
                '__created_by__': self._format_custom_report_value(main_row.get('created_by__r', '')),
                '__owner__': self._format_custom_report_value(main_row.get('owner__r', '')),
            }
            for config in normalized_configs:
                display_name = str(config.get('display_name', '')).strip()
                if not display_name:
                    continue
                preview_row[display_name] = self._resolve_custom_report_join_value(
                    main_row,
                    main_source_api_name,
                    source_data_map,
                    index_cache,
                    config,
                )
            preview_rows.append(preview_row)

        return preview_rows, headers

    def on_custom_report_manual_refresh(self):
        """刷新自定义报表数据。"""
        if getattr(self, '_custom_report_is_loading', False):
            return

        selected_sources = self._get_selected_custom_report_sources()
        if not selected_sources:
            show_warning('提示', '请先至少启用一个 CRM 对象。', self)
            return

        self.config = load_config()
        AppConfig.reload_config()

        self._custom_report_is_loading = True
        self._custom_report_current_api_name = getattr(self, '_custom_report_main_api_name', '') or selected_sources[0].get('api_name', '') or 'NewOpportunityObj'
        self._custom_report_selected_sources_snapshot = copy.deepcopy(selected_sources)
        self._custom_report_field_configs_snapshot = copy.deepcopy(
            self._collect_custom_report_field_configs() or self._get_custom_report_default_field_configs(self._custom_report_current_api_name)
        )
        self._save_custom_report_builder_state()
        self.custom_report_refresh_btn.setText("加载中...")
        self.custom_report_record_label.setText("从API加载数据...")
        operation_log.info("--- 自定义报表查询开始 ---")

        import threading
        t = threading.Thread(target=self._custom_report_fetch_worker, daemon=True)
        t.start()

    def _custom_report_fetch_worker(self):
        """自定义报表数据加载线程。"""
        try:
            cfg = load_config()
            self.config = cfg
            fx_cfg = cfg.get('fxiaoke', {})
            data_object_api_name = getattr(self, '_custom_report_current_api_name', '') or 'NewOpportunityObj'
            selected_sources = copy.deepcopy(getattr(self, '_custom_report_selected_sources_snapshot', []))
            field_configs = copy.deepcopy(getattr(self, '_custom_report_field_configs_snapshot', []))
            if not selected_sources:
                selected_sources = [{'name': data_object_api_name, 'api_name': data_object_api_name}]
            if not field_configs:
                field_configs = self._get_custom_report_default_field_configs(data_object_api_name)

            crm = FXiaokeCRM(
                app_id=fx_cfg.get('app_id', 'FSAID_1323c1a'),
                app_secret=fx_cfg.get('app_secret', 'e7f4188d14704299b375c91ddda92cb0'),
                permanent_code=fx_cfg.get('permanent_code', 'E8B8D8536B0385D035657AC2528928F0'),
                admin_mobile=fx_cfg.get('admin_mobile', '15889740213')
            )

            raw_load_count = fx_cfg.get('load_count', 100)
            try:
                load_count = int(raw_load_count)
            except (TypeError, ValueError):
                load_count = 100
            load_count = max(1, min(load_count, 10000))

            # 构建数据范围筛选条件（应用于主表）
            scope_filters = []
            scope_settings = getattr(self, '_custom_report_scope_settings', None) or {}
            if scope_settings.get('use_filter'):
                # 时间范围筛选
                if scope_settings.get('time_check'):
                    date_start = str(scope_settings.get('date_start', '')).strip()
                    date_end = str(scope_settings.get('date_end', '')).strip()
                    if date_start:
                        scope_filters.append({
                            'field_name': 'create_time',
                            'operator': 'GTE',
                            'values': [date_start + ' 00:00:00'],
                        })
                    if date_end:
                        scope_filters.append({
                            'field_name': 'create_time',
                            'operator': 'LTE',
                            'values': [date_end + ' 23:59:59'],
                        })
                # 自定义条件
                for cond in scope_settings.get('conditions', []) or []:
                    if not isinstance(cond, dict):
                        continue
                    field = str(cond.get('field', '')).strip()
                    operator = str(cond.get('operator', '')).strip()
                    value = str(cond.get('value', '')).strip()
                    if not field or not operator:
                        continue
                    op_map = {
                        '等于': 'EQ', '不等于': 'NEQ', '包含': 'LIKE', '不包含': 'NOT_LIKE',
                        '大于': 'GT', '小于': 'LT', '大于等于': 'GTE', '小于等于': 'LTE',
                        '为空': 'IS_NULL', '不为空': 'IS_NOT_NULL',
                    }
                    crm_op = op_map.get(operator, 'EQ')
                    scope_filters.append({
                        'field_name': field,
                        'operator': crm_op,
                        'values': [value] if crm_op not in ('IS_NULL', 'IS_NOT_NULL') else [],
                    })

            source_data_map = {}
            source_summary = []
            for source in selected_sources:
                source_api_name = str(source.get('api_name', '')).strip()
                if not source_api_name:
                    continue

                if source_api_name != data_object_api_name and not any(
                    str(config.get('source_api_name') or data_object_api_name).strip() == source_api_name
                    for config in field_configs
                ):
                    source_data_map[source_api_name] = []
                    continue

                field_projection = self._build_custom_report_field_projection(
                    source_api_name,
                    field_configs,
                    data_object_api_name,
                )
                # 主表应用 data scope 筛选，关联表不应用
                filters = scope_filters if source_api_name == data_object_api_name else []
                is_custom_source = self._lookup_crm_object_type(source_api_name) == 'custom'
                data, total, err = crm.fetch_all_data_object(
                        data_object_api_name=source_api_name,
                        max_records=load_count,
                        batch_size=100,
                        filters=filters,
                        field_projection=field_projection,
                        is_custom=is_custom_source,
                    )
                if err:
                    self.update_output.emit(f"[自定义报表] {source_api_name} API错误: {err}")
                    self.custom_report_all_data = []
                    self.custom_report_headers = []
                    operation_log.error(f"自定义报表查询失败: {source_api_name} | {err}")
                    return

                source_data_map[source_api_name] = data or []
                source_summary.append(f"{source.get('name', source_api_name)} {len(data or [])}/{total}")

            preview_rows, preview_headers = self._assemble_custom_report_preview_rows(
                source_data_map,
                data_object_api_name,
                field_configs,
            )
            self.custom_report_source_data_map = source_data_map
            self.custom_report_all_data = preview_rows
            self.custom_report_headers = preview_headers
            self.custom_report_field_labels = {header: header for header in preview_headers}
            self.custom_report_label_to_field = {header: header for header in preview_headers}
            self._apply_custom_report_field_settings()
            self.update_output.emit(
                f"[自定义报表] 缓存已更新: {len(self.custom_report_all_data)} 条 | "
                f"主表: {data_object_api_name} | 对象: {'；'.join(source_summary)}"
            )
            operation_log.info(
                f"自定义报表查询成功: 主表 {data_object_api_name}, "
                f"预览 {len(self.custom_report_all_data)} 条记录"
            )
        except Exception as e:
            self.update_output.emit(f"[自定义报表] 异常: {str(e)}")
            self.custom_report_all_data = []
            self.custom_report_headers = []
            operation_log.error(f"自定义报表查询异常: {str(e)}")

        self._custom_report_is_loading = False
        self.enable_custom_report_button.emit()

    def on_enable_custom_report_button(self):
        """自定义报表加载完成后刷新界面（v2 新版兼容）。"""
        mgr = getattr(self, '_report_manager', None)
        if mgr:
            # v2 路径：结果已写入 MySQL，直接刷新预览
            pass  # 预览刷新由 ReportEditorPage 自动处理
        # 旧版兼容路径
        if hasattr(self, 'custom_report_refresh_btn'):
            self.custom_report_refresh_btn.setText("刷新预览")
        self._custom_report_is_loading = False
        self.custom_report_current_page = 1
        try:
            self._apply_custom_report_filters()
            self._update_custom_report_filter_summary()
            self._populate_custom_report_table()
        except Exception:
            pass  # 新版 UI 组件可能不存在

    def _collect_custom_report_headers(self, rows):
        """从接口返回记录中收集全部字段。"""
        seen = []
        configured_headers = [
            str(config.get('display_name', '')).strip()
            for config in self._collect_custom_report_field_configs()
            if str(config.get('display_name', '')).strip()
        ]
        for field_name in configured_headers:
            if any(isinstance(row, dict) and field_name in row for row in rows):
                seen.append(field_name)
        for row in rows or []:
            if not isinstance(row, dict):
                continue
            for field_name in row.keys():
                if str(field_name).startswith('__'):
                    continue
                if field_name not in seen:
                    seen.append(field_name)
        return seen

    def _get_custom_report_fallback_fields(self):
        """未加载数据前提供常用筛选字段。"""
        field_configs = self._collect_custom_report_field_configs() if hasattr(self, 'custom_report_field_builder_table') else []
        fallback_headers = [
            str(config.get('display_name', '')).strip()
            for config in field_configs
            if str(config.get('display_name', '')).strip()
        ]
        if fallback_headers:
            return fallback_headers
        return [
            '创建时间', '名称', '负责人', '创建人', '客户名称', '备注',
        ]

    def on_custom_report_local_filter_changed(self):
        """响应自定义报表筛选条件变化。"""
        self.custom_report_current_page = 1
        self._apply_custom_report_filters()
        self._update_custom_report_filter_summary()
        self._populate_custom_report_table()

    def on_custom_report_table_search(self):
        """响应自定义报表关键字搜索。"""
        self.custom_report_current_page = 1
        self._apply_custom_report_filters()
        self._populate_custom_report_table()

    def _apply_custom_report_filters(self):
        """应用自定义报表本地筛选（增强版，支持快速条件和日期范围）。"""
        keyword = self.custom_report_search_input.text().strip().lower() if hasattr(self, 'custom_report_search_input') else ''
        creator = ''
        owner = ''

        # 尝试从旧的UI组件获取值（向后兼容）
        if hasattr(self, 'custom_report_creator_combo'):
            creator = (self.custom_report_creator_combo.currentData() or self.custom_report_creator_combo.currentText() or "").strip()
            if creator == "全部":
                creator = ""
        if hasattr(self, 'custom_report_owner_input'):
            owner = self.custom_report_owner_input.text().strip().lower()

        table_headers = self.custom_report_headers or self._get_custom_report_fallback_fields()

        # 收集所有筛选条件（包括快速条件列表）
        all_conditions = list(getattr(self, 'custom_report_filter_conditions', []))

        # 从快速条件列表收集条件
        if hasattr(self, 'custom_report_conditions_list') and self.custom_report_conditions_list:
            for i in range(self.custom_report_conditions_list.count()):
                item = self.custom_report_conditions_list.item(i)
                cond_data = item.data(Qt.UserRole) if item else None
                if isinstance(cond_data, dict):
                    all_conditions.append(cond_data)

        filtered_rows = []
        for row in self.custom_report_all_data:
            row_values = [self._format_custom_report_value(row.get(header, "")) for header in table_headers]
            row_text = " ".join(row_values).lower()
            if keyword and keyword not in row_text:
                continue

            # 日期范围检查（支持新旧两种日期选择器）
            if not self._check_date_range_for_row(row):
                continue

            creator_value = self._format_custom_report_value(
                row.get('__created_by__', row.get('创建人', row.get('created_by__r', '')))
            )
            owner_value = self._format_custom_report_value(
                row.get('__owner__', row.get('负责人', row.get('owner__r', '')))
            )
            if creator and creator.lower() not in creator_value.lower():
                continue
            if owner and owner not in owner_value.lower():
                continue

            # 应用所有筛选条件
            if not self._row_matches_all_conditions(row, all_conditions):
                continue

            filtered_rows.append(row)

        self.custom_report_filtered_data = filtered_rows

    def _check_date_range_for_row(self, row):
        """检查记录是否在日期范围内（支持新旧UI）。"""
        start_date = None
        end_date = None

        # 优先使用新的日期编辑器
        if hasattr(self, 'custom_report_start_date_edit') and self.custom_report_start_date_edit:
            start_date = self.custom_report_start_date_edit.date()
        elif hasattr(self, 'custom_report_date_start') and self.custom_report_date_start:
            start_date = self.custom_report_date_start

        if hasattr(self, 'custom_report_end_date_edit') and self.custom_report_end_date_edit:
            end_date = self.custom_report_end_date_edit.date()
        elif hasattr(self, 'custom_report_date_end') and self.custom_report_date_end:
            end_date = self.custom_report_date_end

        if not start_date or not end_date:
            return True

        raw_value = row.get('__create_time__') or row.get('创建时间') or row.get('create_time', '')
        if raw_value in (None, ''):
            return True
        try:
            if isinstance(raw_value, (int, float)):
                dt = datetime.fromtimestamp(float(raw_value) / 1000 if len(str(int(raw_value))) >= 12 else float(raw_value))
            else:
                text = str(raw_value).strip()
                if text.isdigit():
                    number_value = float(text)
                    dt = datetime.fromtimestamp(number_value / 1000 if len(text) >= 12 else number_value)
                else:
                    dt = datetime.strptime(text[:10], '%Y-%m-%d')
            row_date = QDate(dt.year, dt.month, dt.day)
            return start_date <= row_date <= end_date
        except Exception:
            return True

    def _row_matches_all_conditions(self, row, conditions):
        """判断记录是否满足所有筛选条件。"""
        for condition in (conditions or []):
            field = condition.get('field', '')
            operator = condition.get('operator', 'contains')
            expected = str(condition.get('value', '')).strip()
            actual = self._format_custom_report_value(row.get(field, '')).strip()
            actual_lower = actual.lower()
            expected_lower = expected.lower()
            values = [value.strip().lower() for value in re.split(r'[,，;；\n]+', expected) if value.strip()]

            # 中文操作符映射到英文
            op_map = {
                '包含': 'contains',
                '不包含': 'not_contains',
                '等于': 'eq',
                '不等于': 'ne',
                '大于': 'gt',
                '小于': 'lt',
                '为空': 'empty',
                '不为空': 'not_empty',
                '属于': 'in',
                '不属于': 'not_in'
            }
            operator = op_map.get(operator, operator)

            if operator == 'contains' and expected_lower not in actual_lower:
                return False
            if operator == 'not_contains' and expected_lower in actual_lower:
                return False
            if operator == 'in' and values and actual_lower not in values:
                return False
            if operator == 'not_in' and values and actual_lower in values:
                return False
            if operator == 'eq' and actual_lower != expected_lower:
                return False
            if operator == 'ne' and actual_lower == expected_lower:
                return False
            if operator == 'empty' and actual:
                return False
            if operator == 'not_empty' and not actual:
                return False
            if operator == 'gt':
                try:
                    if float(actual) <= float(expected):
                        return False
                except (ValueError, TypeError):
                    return False
            if operator == 'lt':
                try:
                    if float(actual) >= float(expected):
                        return False
                except (ValueError, TypeError):
                    return False
        return True

    def _custom_report_row_matches_date(self, row):
        """按创建时间筛选自定义报表记录。"""
        if not hasattr(self, 'custom_report_date_start') or not self.custom_report_date_start or not hasattr(self, 'custom_report_date_end') or not self.custom_report_date_end:
            return True
        raw_value = row.get('__create_time__') or row.get('创建时间') or row.get('create_time', '')
        if raw_value in (None, ''):
            return True
        try:
            if isinstance(raw_value, (int, float)):
                dt = datetime.fromtimestamp(float(raw_value) / 1000 if len(str(int(raw_value))) >= 12 else float(raw_value))
            else:
                text = str(raw_value).strip()
                if text.isdigit():
                    number_value = float(text)
                    dt = datetime.fromtimestamp(number_value / 1000 if len(text) >= 12 else number_value)
                else:
                    dt = datetime.strptime(text[:10], '%Y-%m-%d')
            row_date = QDate(dt.year, dt.month, dt.day)
            return self.custom_report_date_start <= row_date <= self.custom_report_date_end
        except Exception:
            return True

    def _custom_report_row_matches_conditions(self, row):
        """判断记录是否满足自定义多条件筛选。"""
        for condition in getattr(self, 'custom_report_filter_conditions', []):
            field = condition.get('field', '')
            operator = condition.get('operator', 'contains')
            expected = str(condition.get('value', '')).strip()
            actual = self._format_custom_report_value(row.get(field, '')).strip()
            actual_lower = actual.lower()
            expected_lower = expected.lower()
            values = [value.strip().lower() for value in re.split(r'[,，;；\n]+', expected) if value.strip()]

            if operator == 'contains' and expected_lower not in actual_lower:
                return False
            if operator == 'not_contains' and expected_lower in actual_lower:
                return False
            if operator == 'in' and values and actual_lower not in values:
                return False
            if operator == 'not_in' and values and actual_lower in values:
                return False
            if operator == 'eq' and actual_lower != expected_lower:
                return False
            if operator == 'ne' and actual_lower == expected_lower:
                return False
            if operator == 'empty' and actual:
                return False
            if operator == 'not_empty' and not actual:
                return False
            if operator == 'starts_with' and not actual_lower.startswith(expected_lower):
                return False
            if operator == 'ends_with' and not actual_lower.endswith(expected_lower):
                return False
            if operator in ('gt', 'lt') and not self._compare_custom_report_values(actual, expected, operator):
                return False
        return True

    def _compare_custom_report_values(self, actual, expected, operator):
        """比较数字或文本值。"""
        try:
            actual_value = float(str(actual).replace(',', ''))
            expected_value = float(str(expected).replace(',', ''))
        except (TypeError, ValueError):
            actual_value = str(actual)
            expected_value = str(expected)
        if operator == 'gt':
            return actual_value > expected_value
        if operator == 'lt':
            return actual_value < expected_value
        return True

    def _format_custom_report_value(self, value):
        """格式化自定义报表单元格显示值。"""
        if value is None:
            return ""
        if isinstance(value, dict):
            for key in ('name', 'text', 'label', 'value'):
                if key in value and value.get(key) not in (None, ''):
                    return str(value.get(key))
            return json.dumps(value, ensure_ascii=False)
        if isinstance(value, list):
            return "、".join(self._format_custom_report_value(item) for item in value)
        if isinstance(value, (int, float)) and len(str(int(value))) >= 12:
            try:
                dt = datetime.fromtimestamp(float(value) / 1000)
                return dt.strftime('%Y-%m-%d')
            except Exception:
                return str(value)
        return str(value)

    def _populate_custom_report_table(self):
        """填充自定义报表数据预览表格（增强版，支持新旧UI组件）。"""
        # 优先使用新的预览表格组件
        preview_table = getattr(self, 'custom_report_preview_table', None) or getattr(self, 'custom_report_table', None)
        if not preview_table:
            return

        if not self.custom_report_filtered_data and self.custom_report_all_data:
            self._apply_custom_report_filters()

        rows = self.custom_report_filtered_data if self.custom_report_all_data else []
        total = len(rows)
        page_size = self._get_combo_page_size(self.custom_report_page_size_combo)
        page_count = max(1, (total + page_size - 1) // page_size)
        self.custom_report_current_page = max(1, min(self.custom_report_current_page, page_count))
        start = (self.custom_report_current_page - 1) * page_size
        end = start + page_size
        page_rows = rows[start:end]

        if not getattr(self, 'custom_report_visible_headers', []):
            self._apply_custom_report_field_settings()
        table_headers = self.custom_report_visible_headers or self.custom_report_headers or self._get_custom_report_fallback_fields()
        display_headers = self._get_custom_report_display_headers(table_headers)

        # 设置表头和列宽
        preview_table.setColumnCount(len(display_headers))
        preview_table.setHorizontalHeaderLabels(display_headers)

        # 优化列宽设置（自动调整）
        header = preview_table.horizontalHeader()
        for i in range(len(display_headers)):
            header.setSectionResizeMode(i, QHeaderView.ResizeMode.ResizeToContents)
        # 第一列使用Stretch模式以填充剩余空间
        if len(display_headers) > 0:
            header.setSectionResizeMode(0, QHeaderView.ResizeMode.Stretch)

        # 填充数据行
        preview_table.setRowCount(len(page_rows))
        for row_idx, row_data in enumerate(page_rows):
            for col_idx, header_key in enumerate(table_headers):
                value = self._format_custom_report_value(row_data.get(header_key, ""))
                item = QTableWidgetItem(value)
                item.setTextAlignment(Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter)
                preview_table.setItem(row_idx, col_idx, item)

                # 隔行变色效果已通过setAlternatingRowColors实现

        # 更新分页信息
        if hasattr(self, 'custom_report_record_label'):
            self.custom_report_record_label.setText(f"共 {total} 条记录")
        if hasattr(self, 'custom_report_page_label'):
            self.custom_report_page_label.setText(f"第 {self.custom_report_current_page} 页/共 {page_count} 页")
        if hasattr(self, 'custom_report_prev_btn'):
            self.custom_report_prev_btn.setEnabled(self.custom_report_current_page > 1)
        if hasattr(self, 'custom_report_next_btn'):
            self.custom_report_next_btn.setEnabled(self.custom_report_current_page < page_count)

        # 更新筛选摘要信息
        self._update_filter_summary_from_conditions()

        operation_log.info(f"自定义报表数据已刷新 | 记录数:{total} | 当前页:{self.custom_report_current_page}/{page_count}")

    def on_custom_report_page_size_changed(self):
        """响应自定义报表每页条数变化。"""
        self.custom_report_page_size = self._get_combo_page_size(self.custom_report_page_size_combo)
        self.custom_report_current_page = 1
        self._save_page_sizes()
        self._populate_custom_report_table()

    def on_custom_report_prev_page(self):
        """切换到自定义报表上一页。"""
        if self.custom_report_current_page > 1:
            self.custom_report_current_page -= 1
            self._populate_custom_report_table()

    def on_custom_report_next_page(self):
        """切换到自定义报表下一页。"""
        total = len(self.custom_report_filtered_data)
        page_count = max(1, (total + self.custom_report_page_size - 1) // self.custom_report_page_size)
        if self.custom_report_current_page < page_count:
            self.custom_report_current_page += 1
            self._populate_custom_report_table()

    def open_crm_date_filter_dialog(self):
        """打开CRM订单日期选择弹窗"""
        dialog = QuickDatePickerDialog(
            self.crm_date_start,
            self.crm_date_end,
            self
        )
        dialog.position_below_widget(self.crm_date_filter_btn)
        if dialog.exec() == QDialog.DialogCode.Accepted:
            self.crm_date_start = dialog.start_date
            self.crm_date_end = dialog.end_date
            if (
                self.crm_date_start and self.crm_date_end
                and self.crm_date_start.isValid() and self.crm_date_end.isValid()
            ):
                self.crm_date_filter_btn.setText(
                    f"{self.crm_date_start.toString('yyyy-MM-dd')} ~ "
                    f"{self.crm_date_end.toString('yyyy-MM-dd')}"
                )
            self.on_crm_local_filter_changed()

    def _crm_initial_load(self):
        """页面初始化时不自动加载 CRM 订单。"""
        self._crm_auto_refresh_activated = False  # 标记：自动刷新是否已激活
        self._crm_first_load_completed = False   # ✅【新增】标记：首次加载是否已完成
        self._opportunity_first_load_completed = False  # 标记：招投标授权首次加载是否已完成

    def on_crm_auto_refresh_tick(self):
        """响应CRM自动刷新定时轮询相关操作。"""
        if not getattr(self, '_crm_is_loading', False):
            self.on_crm_refresh_orders()

    def _get_opp_filter_headers(self):
        """获取商机可筛选字段列表"""
        headers = getattr(self, 'opportunity_visible_columns', None) or []
        if headers:
            return [str(h).strip() for h in headers if h and str(h).strip()]
        if hasattr(self, 'opportunity_table') and self.opportunity_table.columnCount() > 0:
            result = []
            for col in range(self.opportunity_table.columnCount()):
                item = self.opportunity_table.horizontalHeaderItem(col)
                if item:
                    txt = item.text().strip()
                    if txt:
                        result.append(txt)
            return result
        return []

    def _is_opp_date_field(self, field_label):
        """判断是否为日期/时间字段"""
        if not field_label:
            return False
        label = str(field_label)
        return '日期' in label or '时间' in label

    def _toggle_opportunity_filter_panel(self):
        """切换商机筛选面板（照搬CRM订单）"""
        if not hasattr(self, 'opp_filter_panel'):
            return
        visible = not self.opp_filter_panel.isVisible()
        if visible:
            self.opp_filter_panel.setWindowFlags(Qt.WindowType.Dialog | Qt.WindowType.FramelessWindowHint)
            self.opp_filter_panel.setVisible(True)
            self.opp_filter_panel.raise_()
            self.opp_filter_panel.activateWindow()
            self._refresh_opp_search_field_combo()
            self._adjust_opp_filter_panel_size()
            search_frame = self.opp_search_stack.parent()
            panel_w = self.opp_filter_panel.width()
            panel_h = self.opp_filter_panel.height()
            if search_frame:
                pos = search_frame.mapToGlobal(QPoint(0, search_frame.height()))
                x, y = pos.x(), pos.y() + 4
            else:
                x, y = self.geometry().x() + 100, self.geometry().y() + 80
            screen = self.screen()
            if screen:
                geo = screen.availableGeometry()
                x = max(geo.x() + 10, min(x, geo.right() - panel_w - 10))
                y = max(geo.y() + 10, min(y, geo.bottom() - panel_h - 10))
            self.opp_filter_panel.move(x, y)
            self.opp_filter_panel.reject = lambda: self.opp_filter_panel.setVisible(False)
            self.opp_filter_panel._outside_close_armed = False
            pf = _DialogOutsideCloseFilter(self.opp_filter_panel)
            self.opp_filter_panel._outside_filter = pf
            QApplication.instance().installEventFilter(pf)
            QTimer.singleShot(0, lambda p=self.opp_filter_panel: setattr(p, '_outside_close_armed', True))
            self.opp_filter_panel.destroyed.connect(lambda obj, f=pf: QApplication.instance().removeEventFilter(f))
        else:
            self.opp_filter_panel.setVisible(False)
        self._update_opp_filter_toggle_btn()

    def _refresh_opp_search_field_combo(self):
        """刷新商机搜索字段下拉选项"""
        headers = self._get_opp_filter_headers()
        if hasattr(self, 'opp_search_field_combo'):
            current = self.opp_search_field_combo.currentData()
            self.opp_search_field_combo.blockSignals(True)
            self.opp_search_field_combo.clear()
            self.opp_search_field_combo.addItem("全字段", "")
            for h in headers:
                h_str = str(h or '').strip()
                if h_str:
                    self.opp_search_field_combo.addItem(h_str, h_str)
            idx = self.opp_search_field_combo.findData(current)
            self.opp_search_field_combo.setCurrentIndex(idx if idx >= 0 else 0)
            self.opp_search_field_combo.blockSignals(False)

    def _update_opp_search_field(self):
        """商机搜索字段切换：日期→时间段，其他→文本"""
        if not hasattr(self, 'opp_search_stack'):
            return
        field = self.opp_search_field_combo.currentText().strip()
        if self._is_opp_date_field(field):
            self.opp_search_stack.setCurrentIndex(1)
        else:
            self.opp_search_stack.setCurrentIndex(0)

    def _open_opp_search_date_range(self):
        """打开商机搜索栏日期范围选择"""
        btn = self.opp_search_date_btn
        dr = btn.property('date_range') or {'start': None, 'end': None}
        dlg = QuickDatePickerDialog(start_date=dr.get('start'), end_date=dr.get('end'), parent=self)
        dlg.set_popup_anchor_widget(btn)
        if dlg.exec() == QDialog.DialogCode.Accepted and dlg.start_date and dlg.end_date:
            new_range = {'start': dlg.start_date, 'end': dlg.end_date}
            btn.setProperty('date_range', new_range)
            btn.setText(f"{dlg.start_date.toString('yyyy-MM-dd')} ~ {dlg.end_date.toString('yyyy-MM-dd')}")
            self._apply_opp_filters()

    def _update_opp_filter_toggle_btn(self):
        """更新商机筛选按钮计数"""
        count = len(getattr(self, 'opp_condition_rows', []))
        if count > 0:
            self.opportunity_filter_toggle_btn.setText(f"筛选({count})")
        else:
            self.opportunity_filter_toggle_btn.setText("筛选")

    def _add_opp_condition_row(self, condition=None):
        """添加一条商机筛选条件行（照搬CRM订单）"""
        condition = condition or {}
        row_frame = QFrame()
        row_frame.setFixedHeight(32)
        row_frame.setStyleSheet("QFrame { background: #F8F8F8; border: none; border-radius: 4px; }")
        row_layout = QHBoxLayout(row_frame)
        row_layout.setContentsMargins(6, 0, 6, 0)
        row_layout.setSpacing(5)

        del_btn = QPushButton("✕")
        del_btn.setFixedSize(20, 20)
        del_btn.setCursor(Qt.CursorShape.PointingHandCursor)
        del_btn.setStyleSheet("QPushButton { font-weight: bold; color: #FF4D4F; border: 1px solid #FFCCC7; border-radius: 10px; font-size: 11px; background: #FFF2F0; } QPushButton:hover { background: #FF4D4F; color: #FFF; }")
        row_layout.addWidget(del_btn, alignment=Qt.AlignmentFlag.AlignVCenter)

        field_combo = QComboBox()
        field_combo.setEditable(True)
        field_combo.setFixedWidth(140)
        field_combo.setFixedHeight(26)
        field_combo.setPlaceholderText("搜索字段…")
        field_combo.setStyleSheet("QComboBox { font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 4px; background: #FFF; } QComboBox QAbstractItemView { font-size: 12px; }")
        headers = self._get_opp_filter_headers()
        for h in headers:
            field_combo.addItem(h, h)
        completer = QCompleter(headers, self)
        completer.setCaseSensitivity(Qt.CaseSensitivity.CaseInsensitive)
        completer.setFilterMode(Qt.MatchFlag.MatchContains)
        field_combo.setCompleter(completer)
        if condition.get('field'):
            idx = field_combo.findText(condition['field'])
            if idx >= 0:
                field_combo.setCurrentIndex(idx)
            else:
                field_combo.setEditText(condition['field'])
        row_layout.addWidget(field_combo, alignment=Qt.AlignmentFlag.AlignVCenter)

        op_combo = QComboBox()
        op_combo.setFixedWidth(95)
        op_combo.setFixedHeight(26)
        op_combo.setStyleSheet("QComboBox { font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 2px; background: #FFF; }")
        row_layout.addWidget(op_combo, alignment=Qt.AlignmentFlag.AlignVCenter)

        value_stack = QStackedWidget()
        value_stack.setFixedHeight(26)

        value_input = QLineEdit()
        value_input.setFixedHeight(26)
        value_input.setPlaceholderText("值")
        value_input.setStyleSheet("font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 4px;")
        value_input.setText(str(condition.get('value', '')))
        value_stack.addWidget(value_input)

        date_input = QDateEdit()
        date_input.setCalendarPopup(True)
        date_input.setDisplayFormat("yyyy-MM-dd")
        date_input.setFixedHeight(26)
        date_input.setDate(QDate.currentDate())
        date_input.setStyleSheet("font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 2px;")
        value_stack.addWidget(date_input)

        date_range_btn = QPushButton("选择日期范围")
        date_range_btn.setFixedHeight(26)
        date_range_btn.setStyleSheet("QPushButton { border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 6px; font-size: 12px; }")
        range_data = {'start': None, 'end': None}
        if condition.get('operator') == 'date_range' and '~' in str(condition.get('value', '')):
            parts = str(condition['value']).split('~')
            if len(parts) == 2:
                s = QDate.fromString(parts[0].strip(), "yyyy-MM-dd")
                e = QDate.fromString(parts[1].strip(), "yyyy-MM-dd")
                if s.isValid() and e.isValid():
                    range_data = {'start': s, 'end': e}
                    date_range_btn.setText(f"{s.toString('yyyy-MM-dd')} ~ {e.toString('yyyy-MM-dd')}")
        date_range_btn.setProperty('date_range', range_data)
        date_range_btn.clicked.connect(lambda checked, btn=date_range_btn: self._open_opp_date_range(btn))
        value_stack.addWidget(date_range_btn)

        value_stack.setCurrentIndex(0)
        row_layout.addWidget(value_stack, stretch=1)

        expose_check = QCheckBox("外露")
        expose_check.setChecked(bool(condition.get('expose', False)))
        expose_check.setToolTip("勾选后在表格上方显示该条件")
        expose_check.setStyleSheet("QCheckBox { font-size: 11px; color: #666; spacing: 1px; }")
        expose_check.toggled.connect(lambda checked: self._refresh_opp_exposed_tags())
        row_layout.addWidget(expose_check, alignment=Qt.AlignmentFlag.AlignVCenter)

        self.opp_conditions_layout.addWidget(row_frame)

        row_info = {
            'frame': row_frame, 'field_combo': field_combo, 'op_combo': op_combo,
            'value_stack': value_stack, 'value_input': value_input,
            'date_input': date_input, 'date_range_btn': date_range_btn,
            'expose_check': expose_check,
            '_saved_operator': condition.get('operator', ''),
        }
        self.opp_condition_rows.append(row_info)
        del_btn.clicked.connect(lambda: self._remove_opp_condition_row(row_info))

        def _on_opp_field_changed(ri):
            ri['value_input'].clear()
            ri['date_input'].setDate(QDate.currentDate())
            ri['date_range_btn'].setText("选择日期范围")
            ri['date_range_btn'].setProperty('date_range', {'start': None, 'end': None})
            self._update_opp_condition_input_mode(ri)
            _schedule_opp_filter()

        # ✅ 所有筛选条件变更统一走防抖定时器（300ms），避免每次按键都重建表格
        def _schedule_opp_filter():
            if hasattr(self, '_opp_filter_debounce_timer'):
                self._opp_filter_debounce_timer.stop()
                self._opp_filter_debounce_timer.start(300)

        field_combo.currentIndexChanged.connect(lambda idx, ri=row_info: _on_opp_field_changed(ri))
        field_combo.editTextChanged.connect(lambda text, ri=row_info: _on_opp_field_changed(ri))
        op_combo.currentIndexChanged.connect(lambda idx, ri=row_info: (self._update_opp_condition_input_mode(ri), _schedule_opp_filter()))
        value_input.textChanged.connect(lambda: _schedule_opp_filter())
        date_input.dateChanged.connect(lambda d: _schedule_opp_filter())

        self._update_opp_condition_input_mode(row_info)
        _schedule_opp_filter()
        self._update_opp_filter_toggle_btn()
        self._adjust_opp_filter_panel_size()

    def _update_opp_condition_input_mode(self, row_info):
        """根据字段类型切换操作符和输入模式"""
        field_label = row_info['field_combo'].currentText().strip()
        is_date = self._is_opp_date_field(field_label)
        op_combo = row_info['op_combo']
        current_op = op_combo.currentData() or row_info.get('_saved_operator', '')

        op_combo.blockSignals(True)
        op_combo.clear()
        if is_date:
            ops = [("等于", "eq"), ("不等于", "ne"), ("早于", "date_before"), ("晚于", "date_after"),
                   ("为空", "empty"), ("不为空", "not_empty"), ("时间段", "date_range")]
        else:
            ops = [("包含", "contains"), ("等于", "eq"), ("不等于", "ne"),
                   ("开头是", "starts_with"), ("结尾是", "ends_with"),
                   ("为空", "empty"), ("不为空", "not_empty")]
        for label, key in ops:
            op_combo.addItem(label, key)
        idx = op_combo.findData(current_op)
        if idx < 0 and is_date:
            idx = op_combo.findData('date_range')
        op_combo.setCurrentIndex(idx if idx >= 0 else 0)
        op_combo.blockSignals(False)

        operator = op_combo.currentData()
        vs = row_info['value_stack']
        if operator in ('empty', 'not_empty'):
            vs.setVisible(False)
        else:
            vs.setVisible(True)
            if is_date and operator == 'date_range':
                vs.setCurrentIndex(2)
            elif is_date:
                vs.setCurrentIndex(1)
            else:
                vs.setCurrentIndex(0)

    def _open_opp_date_range(self, btn):
        """打开商机日期范围选择弹窗"""
        dr = btn.property('date_range') or {'start': None, 'end': None}
        dlg = QuickDatePickerDialog(start_date=dr.get('start'), end_date=dr.get('end'), parent=self)
        dlg.set_popup_anchor_widget(btn)
        if dlg.exec() == QDialog.DialogCode.Accepted and dlg.start_date and dlg.end_date:
            new_range = {'start': dlg.start_date, 'end': dlg.end_date}
            btn.setProperty('date_range', new_range)
            btn.setText(f"{dlg.start_date.toString('yyyy-MM-dd')} ~ {dlg.end_date.toString('yyyy-MM-dd')}")
            self._apply_opp_filters()

    def _adjust_opp_filter_panel_size(self):
        """动态调整商机筛选面板高度"""
        if not hasattr(self, 'opp_filter_panel'):
            return
        row_count = len(getattr(self, 'opp_condition_rows', []))
        h = 36 + row_count * 32 + max(0, row_count - 1) * 4 + 44 + 24
        h = max(140, min(h, 500))
        self.opp_filter_panel.setFixedHeight(h)

    def _apply_opp_filter_and_close(self):
        """应用商机筛选并关闭弹窗"""
        self._apply_opp_filters()
        self._refresh_opp_exposed_tags()
        if hasattr(self, 'opp_filter_panel'):
            self.opp_filter_panel.setVisible(False)
        self._update_opp_filter_toggle_btn()

    def _remove_opp_condition_row(self, row_info):
        """移除一条商机筛选条件行"""
        if row_info in self.opp_condition_rows:
            self.opp_condition_rows.remove(row_info)
        try:
            row_info['frame'].hide()
            self.opp_conditions_layout.removeWidget(row_info['frame'])
            row_info['frame'].setParent(None)
            row_info['frame'].deleteLater()
        except RuntimeError:
            pass
        self._update_opp_filter_toggle_btn()
        self._adjust_opp_filter_panel_size()
        self._refresh_opp_exposed_tags()
        self._apply_opp_filters()

    def _collect_opp_filter_conditions(self):
        """收集商机筛选条件"""
        conditions = []
        for row_info in getattr(self, 'opp_condition_rows', []):
            field = row_info['field_combo'].currentText().strip()
            operator = row_info['op_combo'].currentData()
            is_date = self._is_opp_date_field(field)
            expose = row_info.get('expose_check') and row_info['expose_check'].isChecked()
            if not field:
                continue
            if operator in ('empty', 'not_empty'):
                value = ''
            elif is_date and operator == 'date_range':
                dr = row_info['date_range_btn'].property('date_range') or {}
                if dr.get('start') and dr.get('end'):
                    value = f"{dr['start'].toString('yyyy-MM-dd')}~{dr['end'].toString('yyyy-MM-dd')}"
                else:
                    continue
            elif is_date:
                value = row_info['date_input'].date().toString('yyyy-MM-dd')
            else:
                value = row_info['value_input'].text().strip()
                if not value:
                    continue
            conditions.append({'field': field, 'operator': operator, 'value': value, 'expose': expose})
        return conditions

    def _apply_opp_condition_filter(self, headers, data_rows):
        """应用商机多条件筛选（照搬CRM订单引擎）"""
        conditions = self._collect_opp_filter_conditions()
        if not conditions:
            return data_rows
        col_map = {}
        for idx, h in enumerate(headers):
            if h is not None:
                col_map[str(h).strip()] = idx
        filtered = []
        for entry in data_rows:
            if isinstance(entry, tuple) and len(entry) == 2:
                row_idx, row_values = entry
            else:
                row_values = entry
            match = True
            for cond in conditions:
                field = cond['field']
                op = cond['operator']
                val = cond['value'].lower()
                col_idx = col_map.get(field, -1)
                if col_idx < 0 or col_idx >= len(row_values):
                    continue
                cell_val = str(row_values[col_idx] if row_values[col_idx] is not None else '').strip().lower()
                date_val = cell_val[:10]
                if op == 'contains' and val not in cell_val:
                    match = False
                elif op == 'eq' and cell_val != val:
                    match = False
                elif op == 'ne' and cell_val == val:
                    match = False
                elif op == 'starts_with' and not cell_val.startswith(val):
                    match = False
                elif op == 'ends_with' and not cell_val.endswith(val):
                    match = False
                elif op == 'empty' and cell_val:
                    match = False
                elif op == 'not_empty' and not cell_val:
                    match = False
                elif op == 'date_before' and date_val >= val:
                    match = False
                elif op == 'date_after' and date_val <= val:
                    match = False
                elif op == 'date_range' and '~' in val:
                    parts = val.split('~')
                    if not (parts[0].strip() <= date_val <= parts[1].strip()):
                        match = False
                if not match:
                    break
            if match:
                filtered.append(entry)
        return filtered

    def on_opp_search_changed(self, text):
        """商机搜索框输入变化 → 防抖后重新筛选（300ms）"""
        if hasattr(self, '_opp_search_debounce_timer'):
            if self._opp_search_debounce_timer.isActive():
                self._opp_search_debounce_timer.stop()
            self._opp_search_debounce_timer.start(300)

    def _apply_opp_filters(self):
        """应用商机筛选条件，通过临时数据集交给 _populate_opportunity_table 渲染（复用所有格式化逻辑）"""
        if not hasattr(self, 'opportunity_all_data') or not self.opportunity_all_data:
            return
        if not hasattr(self, 'opportunity_table'):
            return

        visible_columns = getattr(self, 'opportunity_visible_columns', None) or []
        opp_map = getattr(self, 'opportunity_field_map', {})

        # 收集条件筛选
        conditions = self._collect_opp_filter_conditions() if hasattr(self, 'opp_condition_rows') else []
        col_map = {}
        for idx, h in enumerate(visible_columns):
            if h is not None:
                col_map[str(h).strip()] = idx

        # 搜索文本
        search_text = getattr(self, 'opp_search_input', None)
        search_text = search_text.text().strip().lower() if search_text else ""
        search_field = getattr(self, 'opp_search_field_combo', None)
        search_field = search_field.currentData() if search_field else ""

        # ✅ 预加载选项值映射，用于将原始 API 值转换为显示文本
        opp_mappings = getattr(self, 'opp_option_mappings', {})

        def _to_display_val(api_name, raw_val):
            """将原始 API 值转换为显示文本（应用选项值映射）"""
            raw_str = str(raw_val or '')
            field_mapping = opp_mappings.get(api_name, {})
            mappings = field_mapping.get('mappings', {}) if isinstance(field_mapping, dict) else {}
            if mappings:
                # 处理多值字段（逗号分隔）
                if ', ' in raw_str or raw_str.startswith('['):
                    parts = [p.strip() for p in raw_str.replace('[', '').replace(']', '').replace("'", '').replace('"', '').split(',')]
                    return ', '.join(str(mappings.get(p, p)) for p in parts)
                else:
                    return str(mappings.get(raw_str, raw_str))
            return raw_str

        filtered_opps = []
        for opp in self.opportunity_all_data:
            # 构建行值用于筛选（应用选项值映射后与用户输入比较）
            row_vals = []
            for header in visible_columns:
                api_name = opp_map.get(header, header)
                raw_val = opp.get(api_name, '')
                display_val = _to_display_val(api_name, raw_val)
                row_vals.append(display_val)

            # 搜索过滤
            if search_text:
                if search_field:
                    sf_idx = col_map.get(search_field, -1)
                    if sf_idx >= 0 and sf_idx < len(row_vals):
                        if search_text not in row_vals[sf_idx].lower():
                            continue
                else:
                    if not any(search_text in str(v).lower() for v in row_vals):
                        continue

            # 条件筛选
            if conditions:
                match = True
                for cond in conditions:
                    field = cond['field']
                    op = cond['operator']
                    val = cond['value'].lower()
                    col_idx = col_map.get(field, -1)
                    if col_idx < 0 or col_idx >= len(row_vals):
                        continue
                    cell_val = str(row_vals[col_idx] if row_vals[col_idx] is not None else '').strip().lower()
                    date_val = cell_val[:10]
                    if op == 'contains' and val not in cell_val:
                        match = False
                    elif op == 'eq' and cell_val != val:
                        match = False
                    elif op == 'ne' and cell_val == val:
                        match = False
                    elif op == 'starts_with' and not cell_val.startswith(val):
                        match = False
                    elif op == 'ends_with' and not cell_val.endswith(val):
                        match = False
                    elif op == 'empty' and cell_val:
                        match = False
                    elif op == 'not_empty' and not cell_val:
                        match = False
                    elif op == 'date_before' and date_val >= val:
                        match = False
                    elif op == 'date_after' and date_val <= val:
                        match = False
                    elif op == 'date_range' and '~' in val:
                        parts = val.split('~')
                        if not (parts[0].strip() <= date_val <= parts[1].strip()):
                            match = False
                    if not match:
                        break
                if not match:
                    continue

            filtered_opps.append(opp)

        # 暂存原数据，用筛选结果渲染，然后恢复
        self.opportunity_current_page = 1
        saved = self.opportunity_all_data
        self.opportunity_all_data = filtered_opps
        try:
            self._populate_opportunity_table(data=filtered_opps)
        finally:
            self.opportunity_all_data = saved

    def _clear_all_opp_conditions(self):
        """清除所有商机筛选条件"""
        for row_info in list(getattr(self, 'opp_condition_rows', [])):
            try:
                row_info['frame'].setParent(None)
                row_info['frame'].deleteLater()
            except RuntimeError:
                pass
        self.opp_condition_rows = []
        self._update_opp_filter_toggle_btn()
        self._adjust_opp_filter_panel_size()
        self._refresh_opp_exposed_tags()

    def _show_opportunity_preset_popup(self):
        """弹出商机方案选择面板（含加载/修改/设为默认/删除按钮）"""
        presets = self.config.get('opp_filter_presets', [])
        if not isinstance(presets, list):
            presets = []
        default_name = self.config.get('opp_filter_default_preset', '')

        popup = QFrame()
        popup.setWindowFlags(Qt.WindowType.Popup | Qt.WindowType.FramelessWindowHint)
        popup.setStyleSheet("QFrame { border: 1px solid #D9D9D9; border-radius: 4px; background: #FFF; }")
        popup_layout = QVBoxLayout(popup)
        popup_layout.setContentsMargins(4, 4, 4, 4)
        popup_layout.setSpacing(2)

        none_btn = QPushButton("(未选择)")
        none_btn.setFixedHeight(28)
        none_btn.setCursor(Qt.CursorShape.PointingHandCursor)
        none_btn.setStyleSheet("QPushButton { border: none; text-align: left; padding: 4px 8px; font-size: 12px; color: #999; background: transparent; } QPushButton:hover { background: #F5F5F5; }")
        none_btn.clicked.connect(lambda: [self._clear_all_opp_conditions(), self._apply_opp_filters(), setattr(self, '_opp_active_preset_name', None), self._update_opp_preset_btn_label(), popup.close()])
        popup_layout.addWidget(none_btn)

        icon_style = """
            QPushButton { border: none; border-radius: 2px; font-size: 13px; background: transparent; color: #999; }
            QPushButton:hover { background: #E6F7FF; color: #1890FF; }
        """
        for preset in presets:
            name = preset.get('name', '')
            display = f"★ {name}" if name == default_name else name
            row = QFrame()
            row.setFixedHeight(30)
            row.setStyleSheet("QFrame { border: none; background: transparent; }")
            row_layout = QHBoxLayout(row)
            row_layout.setContentsMargins(0, 0, 0, 0)
            row_layout.setSpacing(4)
            load_btn = QPushButton(display)
            load_btn.setCursor(Qt.CursorShape.PointingHandCursor)
            load_btn.setStyleSheet("QPushButton { border: none; text-align: left; padding: 4px 8px; font-size: 12px; color: #333; background: transparent; } QPushButton:hover { background: #E6F7FF; color: #1890FF; }")
            load_btn.clicked.connect(lambda checked, n=name: [setattr(self, '_opp_active_preset_name', n), self._load_opp_filter_preset(n), self._update_opp_preset_btn_label(), popup.close()])
            row_layout.addWidget(load_btn, stretch=1)
            # 修改按钮（✎）— 用当前条件覆盖方案
            mod_btn = QPushButton("✎")
            mod_btn.setFixedSize(22, 22)
            mod_btn.setStyleSheet(icon_style)
            mod_btn.setToolTip(f"用当前筛选条件覆盖「{name}」")
            mod_btn.clicked.connect(lambda checked, n=name: [self._update_opp_filter_preset(n), popup.close(), self._update_opp_preset_btn_label()])
            row_layout.addWidget(mod_btn)
            # 默认按钮（★）
            def_btn = QPushButton("★")
            def_btn.setFixedSize(22, 22)
            if name == default_name:
                def_btn.setStyleSheet("QPushButton { border: none; border-radius: 2px; font-size: 13px; background: transparent; color: #FA8C16; } QPushButton:hover { background: #FFF7E6; color: #FA8C16; }")
            else:
                def_btn.setStyleSheet(icon_style)
            def_btn.setToolTip(f"设置/取消「{name}」为默认方案")
            def_btn.clicked.connect(lambda checked, n=name: [self._set_opp_filter_default_preset(n), popup.close(), self._update_opp_preset_btn_label()])
            row_layout.addWidget(def_btn)
            # 删除按钮（✕）
            del_btn = QPushButton("✕")
            del_btn.setFixedSize(22, 22)
            del_btn.setStyleSheet(icon_style + "QPushButton:hover { background: #FFF2F0; color: #FF4D4F; }")
            del_btn.setToolTip(f"删除「{name}」")
            del_btn.clicked.connect(lambda checked, n=name: [self._delete_opp_filter_preset(n), popup.close(), self._update_opp_preset_btn_label()])
            row_layout.addWidget(del_btn)
            popup_layout.addWidget(row)

        popup.adjustSize()
        btn_pos = self.opportunity_preset_btn.mapToGlobal(QPoint(0, self.opportunity_preset_btn.height()))
        popup.move(btn_pos.x(), btn_pos.y() + 2)
        popup.reject = popup.close
        popup._outside_close_armed = False
        pf = _DialogOutsideCloseFilter(popup)
        QApplication.instance().installEventFilter(pf)
        QTimer.singleShot(0, lambda p=popup: setattr(p, '_outside_close_armed', True))
        popup.destroyed.connect(lambda obj, f=pf: QApplication.instance().removeEventFilter(f))
        popup.show()

    def _load_opp_filter_preset(self, name):
        """加载商机筛选方案"""
        presets = self.config.get('opp_filter_presets', [])
        if not isinstance(presets, list):
            return
        target = next((p for p in presets if p.get('name') == name), None)
        if not target:
            return
        conditions = target.get('conditions', [])
        self._clear_all_opp_conditions()
        for cond in conditions:
            self._add_opp_condition_row(cond)
        self._apply_opp_filters()

    def _delete_opp_filter_preset(self, name):
        """删除商机筛选方案"""
        presets = self.config.get('opp_filter_presets', [])
        if not isinstance(presets, list):
            return
        reply = QMessageBox.question(self, '确认删除', f'确定删除方案「{name}」吗？')
        if reply != QMessageBox.StandardButton.Yes:
            return
        self.config['opp_filter_presets'] = [p for p in presets if p.get('name') != name]
        # 如果删除的是默认方案，清除默认设置
        if self.config.get('opp_filter_default_preset') == name:
            self.config['opp_filter_default_preset'] = ''
        save_config(self.config)

    def _save_opp_filter_preset(self):
        """保存商机筛选条件为方案"""
        conditions = self._collect_opp_filter_conditions()
        name, ok = QInputDialog.getText(self, "保存筛选方案", "请输入方案名称：")
        if not ok or not name or not name.strip():
            return
        name = name.strip()
        presets = self.config.get('opp_filter_presets', [])
        if not isinstance(presets, list):
            presets = []
        existing = next((i for i, p in enumerate(presets) if p.get('name') == name), None)
        if existing is not None:
            reply = QMessageBox.question(self, '确认覆盖', f'方案「{name}」已存在，是否覆盖？')
            if reply != QMessageBox.StandardButton.Yes:
                return
            presets[existing] = {'name': name, 'conditions': conditions}
        else:
            presets.append({'name': name, 'conditions': conditions})
        self.config['opp_filter_presets'] = presets
        save_config(self.config)
        QMessageBox.information(self, "成功", f"方案「{name}」已保存。")

    def _update_opp_filter_preset(self, preset_name):
        """用当前筛选条件覆盖指定方案"""
        if not preset_name:
            return
        presets = self.config.get('opp_filter_presets', [])
        if not isinstance(presets, list):
            return
        idx = next((i for i, p in enumerate(presets) if p.get('name') == preset_name), None)
        if idx is None:
            return
        conditions = self._collect_opp_filter_conditions()
        presets[idx] = {'name': preset_name, 'conditions': conditions}
        self.config['opp_filter_presets'] = presets
        save_config(self.config)

    def _set_opp_filter_default_preset(self, preset_name):
        """切换默认方案：已是默认则取消，否则设为默认"""
        if not preset_name:
            return
        current_default = self.config.get('opp_filter_default_preset', '')
        if current_default == preset_name:
            self.config['opp_filter_default_preset'] = ''
            save_config(self.config)
            self._update_opp_preset_btn_label()
        else:
            presets = self.config.get('opp_filter_presets', [])
            if not isinstance(presets, list) or not any(p.get('name') == preset_name for p in presets):
                return
            self.config['opp_filter_default_preset'] = preset_name
            save_config(self.config)
            self._update_opp_preset_btn_label()

    def _update_opp_preset_btn_label(self):
        """更新方案按钮标签为当前激活的方案名"""
        active = getattr(self, '_opp_active_preset_name', None)
        if active:
            self.opportunity_preset_btn.setText(f"方案: {active} ▼")
        else:
            self.opportunity_preset_btn.setText("方案 ▼")

    def _refresh_opp_exposed_tags(self):
        """刷新商机外露标签"""
        if not hasattr(self, 'opp_exposed_tags'):
            return
        layout = self.opp_exposed_tags.layout()
        if not layout:
            return
        while layout.count() > 0:
            item = layout.takeAt(0)
            if item.widget():
                item.widget().deleteLater()
        exposed = []
        for row_info in getattr(self, 'opp_condition_rows', []):
            if row_info.get('expose_check') and row_info['expose_check'].isChecked():
                field = row_info['field_combo'].currentText().strip()
                op = row_info['op_combo'].currentData()
                is_date = self._is_opp_date_field(field)
                if not field:
                    continue
                if op in ('empty', 'not_empty'):
                    value = row_info['op_combo'].currentText()
                elif is_date and op == 'date_range':
                    dr = row_info['date_range_btn'].property('date_range') or {}
                    if dr.get('start') and dr.get('end'):
                        value = f"{dr['start'].toString('yyyy-MM-dd')}~{dr['end'].toString('yyyy-MM-dd')}"
                    else:
                        continue
                elif is_date:
                    value = row_info['date_input'].date().toString('yyyy-MM-dd')
                else:
                    value = row_info['value_input'].text().strip()
                    if not value:
                        continue
                exposed.append({'field': field, 'value': value, 'row_info': row_info})
        if not exposed:
            self.opp_exposed_tags.setVisible(False)
            return
        for cond in exposed:
            tag = QFrame()
            tag.setStyleSheet("QFrame { background: #E6F7FF; border: 1px solid #91D5FF; border-radius: 3px; }")
            tag_layout = QHBoxLayout(tag)
            tag_layout.setContentsMargins(6, 1, 1, 1)
            tag_layout.setSpacing(2)
            lbl = QLabel(f"{cond['field']}: {cond['value']}")
            lbl.setStyleSheet("font-size: 11px; color: #1890FF; border: none; background: transparent;")
            tag_layout.addWidget(lbl)
            close = QPushButton("×")
            close.setFixedSize(14, 14)
            close.setCursor(Qt.CursorShape.PointingHandCursor)
            close.setStyleSheet("QPushButton { border: none; color: #91D5FF; font-size: 10px; } QPushButton:hover { color: #FF4D4F; }")
            close.clicked.connect(lambda checked, r=cond['row_info']: self._remove_opp_condition_row(r))
            tag_layout.addWidget(close)
            layout.addWidget(tag)
        layout.addStretch()
        self.opp_exposed_tags.setVisible(True)
        self.opp_exposed_tags.updateGeometry()
        if self.opp_exposed_tags.parentWidget():
            self.opp_exposed_tags.parentWidget().updateGeometry()
            if self.opp_exposed_tags.parentWidget().layout():
                self.opp_exposed_tags.parentWidget().layout().invalidate()
                self.opp_exposed_tags.parentWidget().layout().activate()
    def open_opportunity_field_settings_dialog(self):
        """打开商机字段显示设置对话框（与CRM订单保持一致）"""
        operation_log.info("打开商机字段设置对话框")

        # ✅ 从设置中动态获取商机字段列表
        cfg = load_config()
        opp_field_mapping_list = cfg.get('opportunity', {}).get('field_mapping_list', [])
        if opp_field_mapping_list:
            all_headers = [m.get('display_name', m.get('api_name', '')) for m in opp_field_mapping_list if m.get('api_name')]
        else:
            all_headers = [
                "商机名称", "意向产品（多选）", "报价（元/台）", "竞争对手（多选）", "终端客户省份",
                "是否招投标项目", "医院等级", "授权类型", "招标日期",
                "项目号", "项目名称", "授权开始日期", "授权结束日期",
                "是否邮寄原件", "授权备注", "竞争对手产品型号", "把握性百分比(%)",
                "终端用户所在省", "终端用户准确名称", "该项目授权代理商名称",
                "授权经销商资质文件", "招标公告", "创建时间", "创建人",
                "负责人", "业务类型",
            ]
        # 非CRM自定义字段（保持不变）
        for extra in ["模板选择", "产品名称", "规格型号"]:
            if extra not in all_headers:
                all_headers.append(extra)

        visible_headers = getattr(self, 'opportunity_visible_columns', None)
        if visible_headers is None:
            # ✅ 默认显示字段映射列表中的所有字段 + 非CRM字段
            visible_headers = list(all_headers)

        # ✅ 过滤掉已不在字段映射列表中的旧表头
        visible_headers = [h for h in visible_headers if h in all_headers]

        header_order = getattr(self, 'opportunity_header_order', None)
        if header_order is None:
            header_order = visible_headers[:]
        # ✅ 过滤掉已不在字段映射列表中的旧表头
        header_order = [h for h in header_order if h in all_headers]

        dialog = ExcelFieldSettingsDialog(
            headers=all_headers,
            visible_headers=visible_headers[:],
            header_order=header_order[:],
            parent=self
        )
        result = dialog.exec()

        if result == QDialog.DialogCode.Accepted:
            new_vis, new_order = dialog.get_settings()
            self.opportunity_visible_columns = new_vis
            self.opportunity_header_order = new_order

            config = load_config()
            app_set = config.setdefault('app_settings', {})
            opportunity_table_settings = app_set.setdefault('opportunity_table_settings', {})
            opportunity_table_settings['visible_columns'] = new_vis
            opportunity_table_settings['header_order'] = new_order
            save_config(config, immediate=True)
            self.config = config

            operation_log.info(f"商机字段设置已变更 | 显示字段数:{len(new_vis)} | 字段顺序已更新")

            # 重置列宽应用标记，以便新列布局重新应用保存的列宽
            self._opportunity_column_widths_applied = False

            # ✅ 延迟重建表格，避免阻塞 UI 线程导致卡顿
            if hasattr(self, 'opportunity_all_data') and self.opportunity_all_data:
                from PyQt6.QtCore import QTimer
                QTimer.singleShot(50, self._populate_opportunity_table)

    def _on_opp_refresh_btn_clicked(self):
        """商机刷新按钮点击：从CRM API获取最新数据"""
        flush_pending_config()
        self._force_opp_api_refresh = True
        self.on_refresh_opportunity_data()

    def on_refresh_opportunity_data(self):
        """刷新商机明细数据 — 始终从 CRM API 获取，不使用本地缓存"""
        if getattr(self, '_opportunity_is_loading', False):
            return

        # ✅ 确保待保存的配置已写入磁盘，并加载最新配置（与 CRM on_crm_refresh_orders 一致）
        flush_pending_config()
        self.config = load_config()

        self._force_opp_api_refresh = False
        self._opportunity_is_loading = True
        self.opportunity_refresh_btn.setText("加载中...")
        self.opportunity_status_label.setText("从CRM加载数据...")
        self.update_output.emit("[商机] 🌐 从CRM API获取数据...")

        import threading
        t = threading.Thread(target=self._opportunity_fetch_worker, daemon=True)
        t.start()

    def _opportunity_fetch_worker(self):
        """商机数据加载工作线程"""
        try:
            cfg = load_config()
            fx_cfg = cfg.get('fxiaoke', {})
            crm = FXiaokeCRM(
                app_id=fx_cfg.get('app_id', 'FSAID_1323c1a'),
                app_secret=fx_cfg.get('app_secret', 'e7f4188d14704299b375c91ddda92cb0'),
                permanent_code=fx_cfg.get('permanent_code', 'E8B8D8536B0385D035657AC2528928F0'),
                admin_mobile=fx_cfg.get('admin_mobile', '15889740213')
            )

            # 商机筛选条件：根据招标映射值的业务类型动态过滤
            filters = []

            # 从 opp 选项映射中读取 record_type 的业务类型选项
            # 优先使用用户选择的筛选类型，否则使用全部已配置的映射值
            opp_query_record_types = fx_cfg.get('opp_query_record_types', [])
            opp_option_mappings = cfg.get('opportunity', {}).get('option_mappings', {})
            record_type_mapping = opp_option_mappings.get('record_type', {})
            if isinstance(record_type_mapping, dict):
                if opp_query_record_types:
                    # 用户选择了特定业务类型
                    filters.append({
                        "field_name": "record_type",
                        "operator": "IN",
                        "field_values": opp_query_record_types,
                    })
                else:
                    # 默认加载全部已配置映射的业务类型
                    record_type_mappings = record_type_mapping.get('mappings', {})
                    if record_type_mappings:
                        filters.append({
                            "field_name": "record_type",
                            "operator": "IN",
                            "field_values": list(record_type_mappings.keys()),
                        })

            # 合并用户设置的筛选条件
            user_filters = getattr(self, 'opportunity_current_filters', [])
            if user_filters:
                filters.extend(user_filters)

            raw_load_count = fx_cfg.get('opportunity_load_count', 100)
            try:
                load_count = int(raw_load_count)
            except (TypeError, ValueError):
                load_count = 100

            if load_count > 10000:
                load_count = 10000
            elif load_count < 1:
                load_count = 100

            # 从设置中获取要加载的商机字段（招标设置-字段映射列表的API名称）
            opp_field_mapping_list = cfg.get('opportunity', {}).get('field_mapping_list', [])
            opp_api_field_keys = [m.get('api_name', '') for m in opp_field_mapping_list if m.get('api_name')]

            # 确保基础必要字段始终加载
            opp_essential = ['_id', 'name', 'owner__r', 'created_by__r', 'life_status', 'record_type', 'owner', 'created_by']
            opportunity_field_projection = list(dict.fromkeys(opp_essential + opp_api_field_keys))
            # ✅ 自动补充 __r 关联字段，确保名称解析有数据来源
            for f in list(opportunity_field_projection):
                if not f.endswith('__r') and f'{f}__r' not in opportunity_field_projection:
                    opportunity_field_projection.append(f'{f}__r')

            # 使用fetch_all_data_object获取商机数据（指定字段投影）
            data, total, err = crm.fetch_all_data_object(
                data_object_api_name='NewOpportunityObj',
                max_records=load_count,
                batch_size=100,
                filters=filters,
                field_projection=opportunity_field_projection
            )

            if err:
                self.update_output.emit(f"[商机] API错误: {err}")
                self.opportunity_all_data = []
            else:
                # 直接从 API 数据过滤 invalid，不使用本地缓存
                self.opportunity_all_data = [r for r in (data or []) if str(r.get('life_status', '')).lower() != 'invalid']
                self.opportunity_current_page = 1

                self.update_output.emit(f"[商机] 数据加载完成: {len(self.opportunity_all_data)} 条 (API总计: {total})")

            # 在主线程中更新表格
            self.opportunity_data_ready.emit()

        except Exception as e:
            self.update_output.emit(f"[商机] 异常: {str(e)}")
            self.opportunity_all_data = []

        self._opportunity_is_loading = False

    def _populate_opportunity_table(self, data=None):
        """填充商机表格。可传入筛选后的数据子集。"""
        if not hasattr(self, 'opportunity_all_data'):
            return

        # ✅ 首次加载数据后自动应用默认筛选方案
        if not getattr(self, '_opp_default_preset_applied', False) and self.opportunity_all_data:
            self._opp_default_preset_applied = True
            default_name = self.config.get('opp_filter_default_preset', '')
            if default_name:
                self._load_opp_filter_preset(default_name)
                setattr(self, '_opp_active_preset_name', default_name)
                self._update_opp_preset_btn_label()

        if data is None:
            data = self.opportunity_all_data or []
        table = self.opportunity_table

        # ✅ 从设置中动态获取商机字段映射（招标设置-字段映射列表）
        cfg = load_config()
        opp_field_mapping_list = cfg.get('opportunity', {}).get('field_mapping_list', [])
        opportunity_field_map = {}
        for m in opp_field_mapping_list:
            api_name = m.get('api_name', '')
            display_name = m.get('display_name', api_name)
            if api_name:
                opportunity_field_map[display_name] = api_name
        # 非CRM自定义字段保持不变
        opportunity_field_map["模板选择"] = "_template_"
        opportunity_field_map["产品名称"] = "_product_name_"
        opportunity_field_map["规格型号"] = "_model_spec_"
        self.opportunity_field_map = opportunity_field_map

        # ✅ 从设置中动态获取字段映射列表的显示名称
        cfg = load_config()
        opp_field_mapping_list = cfg.get('opportunity', {}).get('field_mapping_list', [])
        if opp_field_mapping_list:
            dynamic_field_headers = [m.get('display_name', m.get('api_name', '')) for m in opp_field_mapping_list if m.get('api_name')]
        else:
            dynamic_field_headers = [k for k in opportunity_field_map.keys() if not k.startswith('_')]

        # 获取当前显示的列
        visible_columns = getattr(self, 'opportunity_visible_columns', None)
        if visible_columns is None:
            visible_columns = list(dynamic_field_headers)
        # ✅ 过滤掉已不在字段映射列表中的旧表头
        valid_headers = set(dynamic_field_headers)
        visible_columns = [c for c in visible_columns if c in valid_headers]
        # ✅ 模板选择固定在第二列（复选框后），产品名称/规格型号确保存在即可自由排序
        if "模板选择" in visible_columns:
            visible_columns = [c for c in visible_columns if c != "模板选择"]
        visible_columns = ["模板选择"] + list(visible_columns)
        for extra_col in ("产品名称", "规格型号"):
            if extra_col not in visible_columns:
                visible_columns.append(extra_col)

        # 设置表头（col 0 为复选框列）
        display_headers = [""] + list(visible_columns)
        table.setColumnCount(len(display_headers))
        table.setHorizontalHeaderLabels(display_headers)

        # 保存过滤后全量数据，按页切片展示
        self.opportunity_filtered_data = list(data)
        total = len(data)
        max_page = max(1, (total + self.opportunity_page_size - 1) // self.opportunity_page_size) if total else 1
        if self.opportunity_current_page > max_page:
            self.opportunity_current_page = max_page
        start = (self.opportunity_current_page - 1) * self.opportunity_page_size
        end = min(start + self.opportunity_page_size, total)
        page_data = data[start:end]

        table.setUpdatesEnabled(False)
        table.setRowCount(len(page_data))
        _cached_template_names = self._get_opp_template_names()
        _cached_default_template = self.config.get('app_settings', {}).get('default_bid_template', '')
        opp_column_alignments = cfg.get('app_settings', {}).get('opportunity_table_settings', {}).get('column_alignments', {})
        try:
            for row_idx, opp in enumerate(page_data):
                row_id = self._get_opportunity_row_id(opp, row_idx)

                # col 0: 复选框
                checkbox_item = QTableWidgetItem()
                checkbox_item.setFlags(Qt.ItemFlag.ItemIsEnabled)
                checkbox_item.setData(Qt.ItemDataRole.UserRole, row_id)
                table.setItem(row_idx, 0, checkbox_item)

                checkbox_widget = TableRowCheckBox(row_id=row_id)
                checkbox_widget.blockSignals(True)
                checkbox_widget.setChecked(row_id in self.opportunity_selected_row_ids)
                checkbox_widget.blockSignals(False)
                checkbox_widget.toggled_with_row_id.connect(self.on_opportunity_row_checkbox_toggled)

                checkbox_container = QWidget()
                checkbox_layout = QHBoxLayout(checkbox_container)
                checkbox_layout.setContentsMargins(0, 0, 0, 0)
                checkbox_layout.setAlignment(Qt.AlignmentFlag.AlignCenter)
                checkbox_layout.addWidget(checkbox_widget)
                table.setCellWidget(row_idx, 0, checkbox_container)

                # cols 1..N: 数据
                for col_idx, header in enumerate(visible_columns):
                    api_field = opportunity_field_map.get(header, '')

                    # 模板选择列（QComboBox，使用招标设置中的模板）—— 与 CRM 订单逻辑一致
                    if header == '模板选择':
                        template_combo = QComboBox()
                        template_combo.addItem("-", "")
                        for tpl_name in _cached_template_names:
                            template_combo.addItem(tpl_name, tpl_name)
                        preferred = self._get_opp_template_name(row_id) or _cached_default_template
                        if preferred:
                            idx = template_combo.findData(preferred)
                            if idx >= 0:
                                template_combo.setCurrentIndex(idx)
                        template_combo.currentIndexChanged.connect(
                            lambda index, rid=row_id: self._on_opp_template_changed(rid, index))
                        self.opportunity_table.setCellWidget(row_idx, col_idx + 1, template_combo)
                        continue

                    # 产品名称 — 从意向产品字段映射查找
                    if header == '产品名称':
                        pn, _ = self._get_opp_product_info(opp)
                        item = QTableWidgetItem(pn)
                        item.setFlags(item.flags() & ~Qt.ItemFlag.ItemIsEditable)
                        table.setItem(row_idx, col_idx + 1, item)
                        continue

                    # 规格型号 — 从意向产品字段映射查找
                    if header == '规格型号':
                        _, ms = self._get_opp_product_info(opp)
                        item = QTableWidgetItem(ms)
                        item.setFlags(item.flags() & ~Qt.ItemFlag.ItemIsEditable)
                        table.setItem(row_idx, col_idx + 1, item)
                        continue

                    # ✅ 使用通用方法获取字段值（自动 __r 名称解析）
                    value = self._resolve_crm_ref_value(opp, api_field)

                    # 日期字段：统一转为 YYYY-MM-DD
                    _opp_date_fields = {
                        'create_time', 'authorization_start_date__c',
                        'authorization_end_date__c', 'tender_date__c'
                    }
                    if api_field in _opp_date_fields and value:
                        try:
                            if isinstance(value, (int, float)):
                                ts = value / 1000 if value > 1e12 else value
                                value = datetime.fromtimestamp(ts).strftime('%Y-%m-%d')
                            elif isinstance(value, str) and value.strip().isdigit():
                                ts = int(value.strip())
                                ts = ts / 1000 if ts > 1e12 else ts
                                value = datetime.fromtimestamp(ts).strftime('%Y-%m-%d')
                        except Exception:
                            value = str(value)

                    # 多选字段：展平为逗号分隔
                    if api_field in ('field_fEKk5__c', 'field_8A8tZ__c'):
                        if isinstance(value, list):
                            value = ', '.join(str(v) for v in value)
                        elif isinstance(value, str) and value.startswith('[') and value.endswith(']'):
                            try:
                                import ast
                                parsed = ast.literal_eval(value)
                                if isinstance(parsed, list):
                                    value = ', '.join(str(v) for v in parsed)
                            except (ValueError, SyntaxError):
                                pass
                    elif api_field == 'field_fQr3j__c':
                        try:
                            value = f"{float(value):,.2f}" if value else ""
                        except (ValueError, TypeError):
                            value = str(value) if value else ""
                    elif api_field == 'confidence_percentage__c':
                        try:
                            value = f"{float(value)}%" if value else ""
                        except (ValueError, TypeError):
                            value = str(value) if value else ""

                    # ✅ 从招投标映射值查找显示名称（优先于原始值）
                    opp_mappings = getattr(self, 'opp_option_mappings', {})
                    field_mapping = opp_mappings.get(api_field, {})
                    if isinstance(field_mapping, dict) and isinstance(field_mapping.get('mappings'), dict):
                        raw_str = str(value)
                        # 处理多选字段（逗号分隔）
                        if ', ' in raw_str or raw_str.startswith('['):
                            parts = [p.strip() for p in raw_str.replace('[', '').replace(']', '').replace("'", '').replace('"', '').split(',')]
                            mapped_parts = []
                            for part in parts:
                                part = part.strip()
                                if part:
                                    mapped = field_mapping['mappings'].get(part, part)
                                    mapped_parts.append(mapped)
                            value = ', '.join(mapped_parts)
                        else:
                            value = field_mapping['mappings'].get(raw_str, raw_str)

                    item = QTableWidgetItem(str(value))
                    user_align = opp_column_alignments.get(header, '')
                    if user_align == 'right':
                        item.setTextAlignment(Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter)
                    elif user_align == 'center':
                        item.setTextAlignment(Qt.AlignmentFlag.AlignCenter)
                    elif user_align == 'left':
                        item.setTextAlignment(Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter)
                    elif api_field in ('field_fQr3j__c',):
                        item.setTextAlignment(Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter)
                    elif api_field in _opp_date_fields:
                        item.setTextAlignment(Qt.AlignmentFlag.AlignCenter)
                    table.setItem(row_idx, col_idx + 1, item)
        finally:
            table.setUpdatesEnabled(True)

        # 更新分页标签
        self.opportunity_pagination_label.setText(f"{self.opportunity_current_page}/{max_page}")

        # 更新表头复选框状态
        self._update_opportunity_header_checkbox_state()

        # 刷新勾选行的备注和水印显示
        self._refresh_opportunity_checked_display()

        # 应用保存的列宽（重置标记以覆盖 setColumnCount 导致的宽度重置）
        self._opportunity_column_widths_applied = False
        self._delayed_apply_opportunity_column_widths()

        # 更新状态栏
        total_count = len(data)
        self.opportunity_status_label.setText(f"共 {total_count} 条记录")
        page_count = max(1, (total_count + 19) // 20)
        self.opportunity_pagination_label.setText(f"1/{page_count}")

    def _on_opportunity_selection_changed(self):
        """商机表格选中行变化时（备注/水印已改为复选框驱动，此处仅保留接口兼容）"""
        pass

    def _get_opportunity_row_id(self, opp, fallback_index=None):
        """获取商机行唯一标识"""
        rid = opp.get('_id') if isinstance(opp, dict) else None
        if rid is not None:
            return rid
        return fallback_index if fallback_index is not None else 0

    def _get_opp_template_names(self):
        """获取招标设置中的Word模板名称列表（始终读取最新配置）"""
        config = load_config()
        templates = config.get('pdf_watermark', {}).get('word_templates', {})
        return list(templates.keys()) if isinstance(templates, dict) else []

    def _get_opp_product_info(self, opp):
        """从意向产品字段映射中获取产品名称和规格型号
        返回 (product_name_str, model_spec_str) 用 ',' 连接多个值"""
        config = getattr(self, 'config', None) or load_config()
        product_names = []
        model_specs = []
        seen_pn = set()

        opp_option_mappings = config.get('opportunity', {}).get('option_mappings', {})

        # 从 field_fEKk5__c（意向产品（多选））读取选中的产品ID
        raw_val = opp.get('field_fEKk5__c', '')
        if raw_val:
            # 展平多选字段
            ids = []
            if isinstance(raw_val, list):
                ids = [str(v).strip() for v in raw_val if str(v).strip()]
            elif isinstance(raw_val, str):
                if raw_val.startswith('['):
                    try:
                        import ast
                        parsed = ast.literal_eval(raw_val)
                        if isinstance(parsed, list):
                            ids = [str(v).strip() for v in parsed if str(v).strip()]
                    except (ValueError, SyntaxError):
                        ids = [p.strip() for p in raw_val.strip('[]').replace("'", '').replace('"', '').split(',') if p.strip()]
                else:
                    ids = [p.strip() for p in raw_val.split(',') if p.strip()]

            if ids:
                # 只取第一个意向产品ID匹配招投标映射值
                first_id = ids[0]

                # 加载 product_match_rows（招投标映射值），匹配产品名称和规格型号
                product_match_rows = config.get('opportunity', {}).get('product_match_rows', [])
                if not isinstance(product_match_rows, list):
                    product_match_rows = []
                match_map = {}
                for pm in product_match_rows:
                    if isinstance(pm, dict):
                        pid = str(pm.get('order_product', '')).strip()
                        if pid:
                            match_map[pid] = pm

                pm = match_map.get(first_id, {})
                pn = str(pm.get('product_name', '') or '').strip()
                if pn:
                    product_names.append(pn)

                ms = str(pm.get('model_spec', '') or '').strip()
                if ms:
                    model_specs.append(ms)

        return ','.join(product_names), ','.join(model_specs)

    def _get_opp_template_name(self, row_id):
        """获取指定商机行的模板选择"""
        if not hasattr(self, '_opp_row_templates'):
            self._opp_row_templates = {}
        return self._opp_row_templates.get(row_id, '')

    def _on_opp_template_changed(self, row_id, index):
        """商机模板选择变更"""
        if not hasattr(self, '_opp_row_templates'):
            self._opp_row_templates = {}
        combo = self.sender()
        if combo and index >= 0:
            template_name = combo.itemData(index) or ""
            if template_name:
                self._opp_row_templates[row_id] = template_name
            else:
                self._opp_row_templates.pop(row_id, None)

    def _get_opp_first_subdir(self):
        """获取第一个勾选商机对应的子目录名（与文件命名规则一致）"""
        selected_ids = getattr(self, 'opportunity_selected_row_ids', set())
        if not selected_ids:
            return ''
        opp_data = getattr(self, 'opportunity_all_data', [])
        from datetime import date
        today_str = date.today().strftime('%Y%m%d')
        for opp in opp_data:
            rid = self._get_opportunity_row_id(opp)
            if rid not in selected_ids:
                continue
            agent_name = str(opp.get('this_project_authorized_ag__c', '') or '').strip()
            end_user = str(opp.get('end_user_accurate_name__c', '') or '').strip()
            pn, ms = self._get_opp_product_info(opp)
            name_parts = [today_str]
            if agent_name:
                name_parts.append(agent_name)
            if end_user or ms:
                detail = f"{end_user} {ms}".strip()
                if detail:
                    name_parts.append(f"({detail})")
            return '-'.join(name_parts)
        return ''

    def _update_opp_target_preview(self):
        """根据勾选的商机更新目标路径输入框（仅预览，不影响实际存储路径）"""
        if not hasattr(self, 'pdf_target_dir_text'):
            return
        selected_ids = getattr(self, 'opportunity_selected_row_ids', set())
        if not selected_ids:
            config = load_config()
            default_dir = config.get('path_config', {}).get('opp_output_dir', '') or config.get('pdf_watermark', {}).get('target_dir', '')
            self.pdf_target_dir_text.setText(default_dir)
            self.pdf_target_dir_text.setStyleSheet("")
            return
        opp_data = getattr(self, 'opportunity_all_data', [])
        from datetime import date
        today_str = date.today().strftime('%Y%m%d')
        config = load_config()
        base_dir = config.get('path_config', {}).get('opp_output_dir', '') or config.get('pdf_watermark', {}).get('target_dir', '')
        if not base_dir:
            base_dir = str(resolve_app_path('output'))
        first_path = ""
        for opp in opp_data:
            rid = self._get_opportunity_row_id(opp)
            if rid not in selected_ids:
                continue
            agent_name = str(opp.get('this_project_authorized_ag__c', '') or '').strip()
            end_user = str(opp.get('end_user_accurate_name__c', '') or '').strip()
            pn, ms = self._get_opp_product_info(opp)
            name_parts = [today_str]
            if agent_name:
                name_parts.append(agent_name)
            if end_user or ms:
                detail = f"{end_user} {ms}".strip()
                if detail:
                    name_parts.append(f"({detail})")
            first_path = f"{base_dir}\\{'-'.join(name_parts)}"
            break
        if first_path:
            self.pdf_target_dir_text.setText(first_path)
            self.pdf_target_dir_text.setStyleSheet("color: #1890FF;")
        else:
            self.pdf_target_dir_text.setStyleSheet("")

    def _on_company_qual_toggled(self, checked):
        """公司资质复选框切换：加载/清空资质PDF文件"""
        config = load_config()
        if 'pdf_watermark' not in config:
            config['pdf_watermark'] = {}
        config['pdf_watermark']['load_company_qual'] = bool(checked)
        save_config(config, immediate=True)
        if checked:
            self._load_company_qual_files()
        else:
            self._remove_company_qual_files()

    def _load_company_qual_files(self):
        """从资质存放路径加载PDF到已选中列表"""
        config = load_config()
        qual_dir = config.get('path_config', {}).get('qualification_dir', '')
        if not qual_dir or not os.path.isdir(qual_dir):
            return
        existing = set()
        if hasattr(self, 'selected_files_widget'):
            for i in range(self.selected_files_widget.count()):
                item = self.selected_files_widget.item(i)
                if item:
                    existing.add(item.text())
        for f in os.listdir(qual_dir):
            if f.lower().endswith('.pdf') and f not in existing:
                if hasattr(self, 'selected_files_widget'):
                    full_path = os.path.join(qual_dir, f)
                    list_item = QListWidgetItem(f)
                    list_item.setData(Qt.ItemDataRole.UserRole, full_path)
                    self.selected_files_widget.addItem(list_item)

    def _remove_company_qual_files(self):
        """从已选中列表移除资质PDF文件"""
        config = load_config()
        qual_dir = config.get('path_config', {}).get('qualification_dir', '')
        if not qual_dir or not hasattr(self, 'selected_files_widget'):
            return
        qual_files = set()
        if os.path.isdir(qual_dir):
            for f in os.listdir(qual_dir):
                if f.lower().endswith('.pdf'):
                    qual_files.add(f)
        i = 0
        while i < self.selected_files_widget.count():
            item = self.selected_files_widget.item(i)
            if item and item.text() in qual_files:
                self.selected_files_widget.takeItem(i)
            else:
                i += 1

    def _match_opp_product_to_files(self, product_name):
        """根据意向产品智能匹配源文件列表中的PDF（匹配文件名包含产品名的）"""
        if not product_name or not hasattr(self, 'file_list_widget'):
            return
        # 支持多选产品名（逗号/顿号分隔），取第一个匹配的文件
        product_list = [p.strip() for p in product_name.replace('、', ',').split(',') if p.strip()]
        if not product_list:
            return
        # 在源文件列表中查找匹配的文件
        matched_items = []
        for i in range(self.file_list_widget.count()):
            item = self.file_list_widget.item(i)
            if item:
                item_lower = item.text().lower()
                for pn in product_list:
                    if pn.lower() in item_lower:
                        matched_items.append(item)
                        break
        self.file_list_widget.clearSelection()
        if matched_items:
            # 自动选中匹配的文件
            for item in matched_items:
                item.setSelected(True)
            self.file_list_widget.scrollToItem(matched_items[0])

    def _on_opp_keep_format_changed(self, index):
        """商机页面输出格式变更"""
        fmt_map = {0: 'word_pdf', 1: 'word', 2: 'pdf'}
        fmt = fmt_map.get(index, 'word_pdf')
        config = load_config()
        if 'app_settings' not in config:
            config['app_settings'] = {}
        config['app_settings']['keep_opp_output_format'] = fmt
        save_config(config, immediate=False)
        self.config = config

    def _do_opp_generate_files(self):
        """商机文件生成（后台线程），使用 opportunity_selected_row_ids 获取勾选数据"""
        self.update_output.emit("开始生成招标授权文件...")
        import threading
        t = threading.Thread(target=self._opp_generate_worker, daemon=True)
        t.start()

    def _opp_generate_worker(self):
        try:
            self.pdf_watermark_btn.setEnabled(False)
            self.pdf_watermark_btn.setText("执行中...")

            config = load_config()
            bid_templates = config.get('pdf_watermark', {}).get('word_templates', {})
            bid_template_dir = config.get('path_config', {}).get('bid_template_dir', '')
            if not bid_template_dir:
                bid_template_dir = config.get('path_config', {}).get('template_dir', 'template')

            if not bid_templates:
                self.update_output.emit("[招标授权] 未配置模板，请在招标设置中添加模板。")
                return

            opp_field_mapping = load_common_config().get('opportunity', {}).get('word_field_mapping', {})
            opp_output_dir = config.get('path_config', {}).get('opp_output_dir', '')
            if not opp_output_dir:
                opp_output_dir = config.get('path_config', {}).get('target_roots', {}).get('1', './output/opportunity')

            output_dir = resolve_app_path(opp_output_dir)
            output_dir.mkdir(parents=True, exist_ok=True)

            keep_fmt = config.get('app_settings', {}).get('keep_opp_output_format', 'word_pdf')
            global _keep_word_override
            _keep_word_override = keep_fmt

            from docxtpl import DocxTemplate
            from datetime import date
            today_str = date.today().strftime('%Y%m%d')

            # 安全方案：先在缓存文件夹生成，再按需移动到目标目录
            cache_dir = output_dir / f'_cache_{today_str}'
            cache_dir.mkdir(parents=True, exist_ok=True)

            generated_count = 0
            _last_generated_subdir = None
            generated_files = []  # [{word_path, pdf_path, pdf_success, base_name, target_subdir}]

            selected_ids = getattr(self, 'opportunity_selected_row_ids', set())
            all_data = getattr(self, 'opportunity_all_data', [])

            for opp in all_data:
                row_id = self._get_opportunity_row_id(opp)
                if row_id not in selected_ids:
                    continue

                template_name = self._get_opp_template_name(row_id)
                if not template_name:
                    template_name = config.get('app_settings', {}).get('default_bid_template', '')
                if not template_name:
                    template_name = list(bid_templates.keys())[0] if bid_templates else ''
                if not template_name:
                    continue

                template_path = bid_templates.get(template_name, '')
                if not template_path:
                    continue

                template_full = resolve_app_path(bid_template_dir) / template_path
                if not template_full.exists():
                    self.update_output.emit(f"[招标授权] 模板不存在: {template_full}")
                    continue

                try:
                    agent_name = str(opp.get('this_project_authorized_ag__c', '') or '').strip()
                    end_user = str(opp.get('end_user_accurate_name__c', '') or '').strip()
                    pn, ms = self._get_opp_product_info(opp)
                    name_parts = [today_str]
                    if agent_name:
                        name_parts.append(agent_name)
                    if end_user or ms:
                        detail = f"{end_user} {ms}".strip()
                        if detail:
                            name_parts.append(f"({detail})")
                    base_name = sanitize_output_name('-'.join(name_parts))

                    # 构建 source_values（显示名称 → 值），参考 CRM 映射逻辑
                    opp_field_map = getattr(self, 'opportunity_field_map', {})
                    source_values = {}
                    _date_api_fields = {
                        'create_time', 'authorization_start_date__c',
                        'authorization_end_date__c', 'tender_date__c'
                    }
                    special_fmts = {}
                    for sc in load_common_config().get('opportunity', {}).get('word_special_columns', []):
                        if isinstance(sc, dict):
                            special_fmts[sc.get('name', '')] = sc.get('format', '')
                    for display_name, api_field in opp_field_map.items():
                        if api_field == '_template_' or api_field == '_product_name_' or api_field == '_model_spec_':
                            continue
                        val = opp.get(api_field, '')
                        if val is None:
                            val = ''
                        if isinstance(val, dict):
                            val = val.get('name', str(val))
                        if api_field in _date_api_fields and isinstance(val, (int, float)) and val > 0:
                            try:
                                if val > 1e12:
                                    dt = datetime.fromtimestamp(val / 1000)
                                else:
                                    dt = datetime.fromtimestamp(val)
                                fmt_key = special_fmts.get(display_name, '')
                                if fmt_key and fmt_key not in ('{}', ''):
                                    import re
                                    m = re.match(r'\{:(.+)\}', fmt_key)
                                    if m:
                                        val = dt.strftime(m.group(1))
                                    else:
                                        val = dt.strftime('%Y-%m-%d')
                                else:
                                    val = dt.strftime('%Y-%m-%d')
                            except Exception:
                                val = str(val)
                        source_values[display_name] = val
                    source_values['产品名称'] = pn
                    source_values['规格型号'] = ms
                    source_values['代理商名称'] = agent_name
                    source_values['终端用户准确名称'] = end_user

                    doc = DocxTemplate(str(template_full))
                    ctx_special_fmts = {
                        k: v for k, v in special_fmts.items()
                        if not (k in opp_field_map and opp_field_map.get(k, '') in _date_api_fields)
                    }
                    context = build_context_from_mapping_values(
                        source_values, opp_field_mapping, ctx_special_fmts)

                    # 先输出到缓存文件夹（不与历史文件混在一起）
                    result = render_document_files(doc, context, base_name, output_dir=str(cache_dir))
                    generated_files.append({
                        **result,
                        'base_name': base_name,
                        'target_subdir': base_name,
                    })
                    generated_count += 1
                    _last_generated_subdir = output_dir / base_name
                except Exception as e:
                    self.update_output.emit(f"[招标授权] 生成失败: {e}")

            if generated_count > 0:
                keep_word = keep_fmt in ('word', 'word_pdf')
                keep_pdf = keep_fmt in ('pdf', 'word_pdf')

                # 从缓存文件夹按需移动到目标子目录
                for fi in generated_files:
                    target_dir = output_dir / fi['target_subdir']
                    target_dir.mkdir(parents=True, exist_ok=True)
                    word_path = fi.get('word_path')
                    pdf_path = fi.get('pdf_path')
                    pdf_success = fi.get('pdf_success', False)

                    if keep_word and word_path:
                        _safe_move_to_dir(Path(word_path), target_dir)
                    if keep_pdf and pdf_success and pdf_path:
                        _safe_move_to_dir(Path(pdf_path), target_dir)

                # 清理缓存文件夹（剩余未移动的文件直接删除）
                try:
                    shutil.rmtree(str(cache_dir), ignore_errors=True)
                except Exception:
                    pass

                self.update_output.emit(f"[招标授权] ✅ 合同生成完成: {generated_count} 个")
                if config.get('app_settings', {}).get('open_output_folder', True):
                    open_target = str(_last_generated_subdir) if generated_count == 1 and _last_generated_subdir else str(output_dir)
                    open_folder(open_target)
            else:
                self.update_output.emit("[招标授权] ⚠️ 没有生成任何合同")
                # 无生成时也清理缓存
                try:
                    shutil.rmtree(str(cache_dir), ignore_errors=True)
                except Exception:
                    pass

        except Exception as e:
            self.update_output.emit(f"[招标授权] 异常: {str(e)}")
        finally:
            self.pdf_watermark_btn.setEnabled(True)
            self.pdf_watermark_btn.setText("确认生成")

    def on_opportunity_row_checkbox_toggled(self, row_id, checked):
        """商机行复选框状态变化（单选模式 + 更新授权备注 + 更新水印文本）"""
        if not hasattr(self, 'opportunity_selected_row_ids'):
            self.opportunity_selected_row_ids = set()

        table = self.opportunity_table
        opp_data = getattr(self, 'opportunity_all_data', [])

        if checked:
            # 单选模式：先取消所有其他行的选中
            for row in range(table.rowCount()):
                checkbox_container = table.cellWidget(row, 0)
                checkbox = checkbox_container.findChild(TableRowCheckBox) if checkbox_container else None
                if checkbox and checkbox.row_id != row_id and checkbox.isChecked():
                    checkbox.blockSignals(True)
                    checkbox.setChecked(False)
                    checkbox.blockSignals(False)
            self.opportunity_selected_row_ids = {row_id}

            # 更新授权备注显示
            remark = ''
            watermark_target = ''
            for idx, opp in enumerate(opp_data):
                rid = self._get_opportunity_row_id(opp, idx)
                if rid == row_id:
                    remark = opp.get('authorization_remark__c', '') or ''
                    watermark_target = opp.get('end_user_accurate_name__c', '') or ''
                    break
            if hasattr(self, 'opportunity_remark_text'):
                self.opportunity_remark_text.setText(str(remark))

            # 提取当前商机的意向产品 + 规格型号
            # pn（意向产品）→ 用于匹配产品预设下拉框
            # ms（规格型号）→ PDF 文件名匹配
            pn = ''
            ms = ''
            opp = None
            for idx, o in enumerate(opp_data):
                rid = self._get_opportunity_row_id(o, idx)
                if rid == row_id:
                    opp = o
                    pn, ms = self._get_opp_product_info(opp)
                    break

            # 1) 根据意向产品自动切换招标设置的产品型号
            if hasattr(self, 'product_combo') and self.product_combo.count() > 0:
                pn_list = [s.strip() for s in pn.replace('、', ',').split(',') if s.strip()] if pn else []
                product_matched = False
                for keyword in pn_list:
                    idx = self.product_combo.findText(keyword)
                    if idx >= 0:
                        operation_log.info(f"[产品匹配] 意向产品 '{keyword}' 匹配产品预设，切换 product_combo 到索引 {idx}")
                        self.product_combo.setCurrentIndex(idx)
                        product_matched = True
                        break
                if not product_matched:
                    # fallback: 用 field_fEKk5__c（意向产品多选）原始值通过 option_mappings 映射后匹配
                    raw_ids = []
                    if opp:
                        raw_val = opp.get('field_fEKk5__c', '')
                        if raw_val:
                            if isinstance(raw_val, list):
                                raw_ids = [str(v).strip() for v in raw_val if str(v).strip()]
                            elif isinstance(raw_val, str):
                                if raw_val.startswith('['):
                                    try:
                                        import ast
                                        raw_ids = [str(v).strip() for v in ast.literal_eval(raw_val) if str(v).strip()]
                                    except Exception:
                                        raw_ids = [p.strip() for p in raw_val.strip('[]').replace("'", '').replace('"', '').split(',') if p.strip()]
                                else:
                                    raw_ids = [p.strip() for p in raw_val.split(',') if p.strip()]
                    if raw_ids:
                        config = load_config()
                        opp_mappings = config.get('opportunity', {}).get('option_mappings', {}).get('field_fEKk5__c', {}).get('mappings', {})
                        if not isinstance(opp_mappings, dict):
                            opp_mappings = {}
                        for rid_val in raw_ids:
                            # 查映射文本，映射文本和原始值都尝试匹配
                            display_name = str(opp_mappings.get(rid_val, '')).strip()
                            candidates = [rid_val]
                            if display_name:
                                candidates.insert(0, display_name)
                            for kw in candidates:
                                if kw:
                                    idx = self.product_combo.findText(kw)
                                    if idx >= 0:
                                        operation_log.info(f"[产品匹配] 意向产品原始值 '{kw}' 匹配产品预设，切换 product_combo 到索引 {idx}")
                                        self.product_combo.setCurrentIndex(idx)
                                        product_matched = True
                                        break
                            if product_matched:
                                break
                if not product_matched:
                    operation_log.info(f"[产品匹配] 意向产品 '{pn}' 未匹配任何产品预设，跳转到自定义并清空路径")
                    if hasattr(self, 'product_path_text'):
                        self.product_path_text.clear()
                    if hasattr(self, 'file_list_widget'):
                        self.file_list_widget.clear()
                    self.product_combo.setCurrentIndex(0)

            # 2) 再根据意向产品匹配已加载的文件列表（必须在 combo 切换之后，确保文件列表已刷新）
            if hasattr(self, 'file_list_widget'):
                if pn:
                    self._match_opp_product_to_files(pn)
                else:
                    self.file_list_widget.clearSelection()

            # 更新水印文本（放在最后，避免被 combo 切换触发的 Qt 事件循环打断）
            has_wm = hasattr(self, 'watermark_text')
            print(f"[DEBUG-WM] hasattr watermark_text={has_wm}, watermark_target='{watermark_target}'")
            if has_wm:
                wm = self.watermark_text
                print(f"[DEBUG-WM] watermark_text type={type(wm).__name__}, isVisible={wm.isVisible()}, currentText='{wm.text()}'")
                if watermark_target:
                    new_text = f"仅供{watermark_target}招投标使用，他用无效。"
                    wm.setText(new_text)
                    print(f"[DEBUG-WM] setText done, verify='{wm.text()}'")
                else:
                    wm.setText('')
                    print(f"[DEBUG-WM] cleared (empty watermark_target)")
            else:
                print("[DEBUG-WM] ERROR: self.watermark_text does NOT exist!")
            # 选中商机时自动勾选公司资质并加载
            if hasattr(self, 'company_qual_checkbox') and not self.company_qual_checkbox.isChecked():
                self.company_qual_checkbox.setChecked(True)
        else:
            self.opportunity_selected_row_ids.discard(row_id)
            # 如果取消后没有选中的行，清空显示
            if not self.opportunity_selected_row_ids:
                if hasattr(self, 'opportunity_remark_text'):
                    self.opportunity_remark_text.setText('')
                if hasattr(self, 'watermark_text'):
                    self.watermark_text.setText('')
                # 取消所有商机选中时，取消公司资质勾选并清空资质文件
                if hasattr(self, 'company_qual_checkbox') and self.company_qual_checkbox.isChecked():
                    self.company_qual_checkbox.setChecked(False)
                if hasattr(self, 'file_list_widget'):
                    self.file_list_widget.clearSelection()
                # 恢复招标设置产品型号为自定义
                if hasattr(self, 'product_combo'):
                    self.product_combo.setCurrentIndex(0)

        self._update_opp_target_preview()
        self._update_opportunity_header_checkbox_state()

    def on_opportunity_header_select_all_toggled(self, state):
        """商机表头复选框（单选模式：点击全选按钮清除所有选中）"""
        is_checked = bool(state)
        if not hasattr(self, 'opportunity_selected_row_ids'):
            self.opportunity_selected_row_ids = set()

        table = self.opportunity_table
        if is_checked:
            # 单选模式不支持全选，改为清除所有选中
            for row in range(table.rowCount()):
                checkbox_container = table.cellWidget(row, 0)
                checkbox = checkbox_container.findChild(TableRowCheckBox) if checkbox_container else None
                if checkbox and checkbox.isChecked():
                    checkbox.blockSignals(True)
                    checkbox.setChecked(False)
                    checkbox.blockSignals(False)
            self.opportunity_selected_row_ids.clear()
            if hasattr(self, 'opportunity_remark_text'):
                self.opportunity_remark_text.setText('')
            if hasattr(self, 'watermark_text'):
                self.watermark_text.setText('')
            # 取消所有商机选中时，取消公司资质勾选并清空资质文件
            if hasattr(self, 'company_qual_checkbox') and self.company_qual_checkbox.isChecked():
                self.company_qual_checkbox.setChecked(False)
            if hasattr(self, 'file_list_widget'):
                self.file_list_widget.clearSelection()
            # 恢复招标设置产品型号为自定义
            if hasattr(self, 'product_combo'):
                self.product_combo.setCurrentIndex(0)

        # 始终将表头设为未选中状态（单选模式无全选概念）
        self.opportunity_table_header.set_check_state(Qt.CheckState.Unchecked)
        self.opportunity_table_header.viewport().update()

    def _update_opportunity_header_checkbox_state(self):
        """更新商机表头复选框状态（全选/部分选/未选）"""
        if not hasattr(self, 'opportunity_table_header'):
            return
        table = self.opportunity_table
        if table.rowCount() == 0:
            self.opportunity_table_header.set_check_state(Qt.CheckState.Unchecked)
            return

        selected_ids = getattr(self, 'opportunity_selected_row_ids', set())
        checked_count = 0
        total_count = table.rowCount()
        for row in range(total_count):
            checkbox_container = table.cellWidget(row, 0)
            checkbox = checkbox_container.findChild(TableRowCheckBox) if checkbox_container else None
            if checkbox and checkbox.row_id in selected_ids:
                checked_count += 1

        if checked_count == 0:
            self.opportunity_table_header.set_check_state(Qt.CheckState.Unchecked)
        elif checked_count == total_count:
            self.opportunity_table_header.set_check_state(Qt.CheckState.Checked)
        else:
            self.opportunity_table_header.set_check_state(Qt.CheckState.PartiallyChecked)

    def _refresh_opportunity_checked_display(self):
        """根据当前勾选行刷新授权备注和水印文本"""
        if not hasattr(self, 'opportunity_selected_row_ids'):
            return
        opp_data = getattr(self, 'opportunity_all_data', [])
        checked_id = None
        for rid in self.opportunity_selected_row_ids:
            checked_id = rid
            break  # 单选模式，取第一个

        if checked_id is None:
            if hasattr(self, 'opportunity_remark_text'):
                self.opportunity_remark_text.setText('')
            if hasattr(self, 'watermark_text'):
                self.watermark_text.setText('')
            return

        remark = ''
        watermark_target = ''
        for idx, opp in enumerate(opp_data):
            rid = self._get_opportunity_row_id(opp, idx)
            if rid == checked_id:
                remark = opp.get('authorization_remark__c', '') or ''
                watermark_target = opp.get('end_user_accurate_name__c', '') or ''
                break

        if hasattr(self, 'opportunity_remark_text'):
            self.opportunity_remark_text.setText(str(remark))
        if hasattr(self, 'watermark_text'):
            if watermark_target:
                self.watermark_text.setText(f"仅供{watermark_target}招投标使用，他用无效。")
            else:
                self.watermark_text.setText('')

    # ========== 商机表格列宽持久化 ==========

