    def on_crm_local_filter_changed(self):
        """响应CRM本地过滤changed相关操作。"""
        self.crm_current_page = 1
        self._populate_crm_table()

    def on_crm_table_search(self):
        """响应CRM表格搜索相关操作。"""
        self._update_crm_filter_toggle_badge()
        self.crm_current_page = 1
        self._populate_crm_table()

    def _update_crm_search_input_mode(self):
        """根据搜索字段类型切换输入模式：日期→时间段，其他→文本"""
        if not hasattr(self, 'crm_search_stack'):
            return
        field_label = self.crm_search_field_combo.currentText().strip()
        is_date = self._is_crm_date_field(field_label)
        if is_date:
            self.crm_search_stack.setCurrentIndex(1)  # 日期范围选择
        else:
            self.crm_search_stack.setCurrentIndex(0)  # 文本输入
            self.crm_search_input.clear()

    def _open_crm_search_date_range(self):
        """打开搜索栏的日期范围选择弹窗"""
        btn = self.crm_search_date_btn
        dr = btn.property('crm_date_range') or {'start': None, 'end': None}
        dlg = QuickDatePickerDialog(
            start_date=dr.get('start'),
            end_date=dr.get('end'),
            parent=self
        )
        dlg.set_popup_anchor_widget(btn)
        if dlg.exec() == QDialog.DialogCode.Accepted and dlg.start_date and dlg.end_date:
            new_range = {'start': dlg.start_date, 'end': dlg.end_date}
            btn.setProperty('crm_date_range', new_range)
            btn.setText(f"{dlg.start_date.toString('yyyy-MM-dd')} ~ {dlg.end_date.toString('yyyy-MM-dd')}")
            self.on_crm_table_search()

    # ===== CRM 多条件筛选辅助方法 =====

    @staticmethod
    def _get_crm_text_operators():
        """非日期字段的筛选操作符"""
        return [
            ("等于", "eq"),
            ("不等于", "ne"),
            ("包含", "contains"),
            ("不包含", "not_contains"),
            ("属于", "in"),
            ("不属于", "not_in"),
            ("为空（未填写）", "empty"),
            ("不为空", "not_empty"),
            ("开头是", "starts_with"),
            ("结尾是", "ends_with"),
        ]

    @staticmethod
    def _get_crm_date_operators():
        """日期字段的筛选操作符"""
        return [
            ("等于", "eq"),
            ("不等于", "ne"),
            ("早于", "date_before"),
            ("晚于", "date_after"),
            ("早于等于", "date_before_eq"),
            ("晚于等于", "date_after_eq"),
            ("为空（未填写）", "empty"),
            ("不为空", "not_empty"),
            ("时间段", "date_range"),
            ("过去N天内(不含当天)", "past_n_days_exclusive"),
            ("未来N天内(不含当天)", "future_n_days_exclusive"),
            ("过去N月内(不含当月)", "past_n_months_exclusive"),
            ("未来N月内(不含当月)", "future_n_months_exclusive"),
            ("过去N周内(不含当周)", "past_n_weeks_exclusive"),
            ("未来N周内(不含当周)", "future_n_weeks_exclusive"),
            ("过去N天内(含当天)", "past_n_days_inclusive"),
            ("未来N天内(含当天)", "future_n_days_inclusive"),
            ("过去N周内(含当周)", "past_n_weeks_inclusive"),
            ("未来N周内(含当周)", "future_n_weeks_inclusive"),
            ("过去N月内(含当月)", "past_n_months_inclusive"),
            ("未来N月内(含当月)", "future_n_months_inclusive"),
            ("N天前", "n_days_ago"),
            ("N天后", "n_days_later"),
            ("N周前", "n_weeks_ago"),
            ("N周后", "n_weeks_later"),
            ("过去N季度内(含当季度)", "past_n_quarters_inclusive"),
        ]

    def _is_crm_date_field(self, field_label):
        """判断字段名是否为日期/时间字段"""
        if not field_label:
            return False
        for key, label, is_time in getattr(self, 'CRM_ALL_FIELDS', []):
            if label == field_label and is_time:
                return True
        return False

    def _build_crm_field_label_list(self):
        """构建所有可用字段标签列表（特殊头 + CRM_ALL_FIELDS 标签去重）"""
        labels = []
        seen = set()
        for h in getattr(self, 'crm_special_headers', []):
            if h and h not in seen:
                labels.append(h)
                seen.add(h)
        for key, label, is_time in getattr(self, 'CRM_ALL_FIELDS', []):
            if label and label not in seen:
                labels.append(label)
                seen.add(label)
        return labels

    def _get_crm_api_key_for_label(self, label):
        """字段显示名 → API key"""
        for key, lbl, is_time in getattr(self, 'CRM_ALL_FIELDS', []):
            if lbl == label:
                return key
        if label in getattr(self, 'crm_special_headers', []):
            return label
        return label

    def _build_crm_row_search_text(self, row):
        """收集一行的所有字段值（含计算字段），用于全字段模糊搜索"""
        parts = []
        for key, label, is_time in getattr(self, 'CRM_ALL_FIELDS', []):
            val = self._crm_extract_field(row, key)
            parts.append(str(val) if val is not None else '')
        computed = []
        try:
            computed.append(str(self._get_crm_model_spec(row) or ''))
            computed.append(str(self._get_crm_customer_type(row) or ''))
            computed.append(str(self._get_crm_matched_price(row) or ''))
            computed.append(str(self._get_crm_discount_unit_price(row) or ''))
            computed.append(str(self._get_crm_product_remark(row) or ''))
            computed.append(str(self._convert_amount_to_rmb_upper(row.get('product_amount', '')) or ''))
            computed.append(str(self._get_crm_option_text('record_type', row.get('record_type', '')) or ''))
            computed.append(str(self._get_crm_option_text('life_status', row.get('life_status', '')) or ''))
        except Exception:
            pass
        parts.extend(computed)
        return ' '.join(parts).lower()

    @staticmethod
    def _crm_date_value_to_qdate(raw_value):
        """将 CRM 日期值（时间戳/字符串）归一化为 QDate"""
        if raw_value in (None, ''):
            return None
        try:
            from PyQt6.QtCore import QDate
            from datetime import datetime
            if isinstance(raw_value, (int, float)):
                raw_str = str(int(raw_value))
                ts = float(raw_value)
                if len(raw_str) >= 12:
                    ts = ts / 1000
                dt = datetime.fromtimestamp(ts)
                return QDate(dt.year, dt.month, dt.day)
            text = str(raw_value).strip()
            if text.isdigit():
                ts = float(text)
                if len(text) >= 12:
                    ts = ts / 1000
                dt = datetime.fromtimestamp(ts)
                return QDate(dt.year, dt.month, dt.day)
            dt = datetime.strptime(text[:10], '%Y-%m-%d')
            return QDate(dt.year, dt.month, dt.day)
        except Exception:
            return None

    def _crm_row_matches_all_conditions(self, row, conditions):
        """判断 CRM 记录是否满足所有筛选条件（AND 逻辑）"""
        from PyQt6.QtCore import QDate
        import re
        for cond in (conditions or []):
            api_key = cond.get('api_key', cond.get('field', ''))
            operator = cond.get('operator', 'contains')
            expected = str(cond.get('value', '')).strip()

            # 获取实际值（特殊 header 使用计算值）
            if api_key in getattr(self, 'crm_special_headers', []):
                special_map = {
                    "模板选择": str(self._get_crm_model_spec(row) or ''),
                    "规格型号": str(self._get_crm_model_spec(row) or ''),
                    "客户类型": str(self._get_crm_customer_type(row) or ''),
                    "匹配价格": str(self._get_crm_matched_price(row) or ''),
                    "折扣单价": str(self._get_crm_discount_unit_price(row) or ''),
                    "产品备注": str(self._get_crm_product_remark(row) or ''),
                    "大写": str(self._convert_amount_to_rmb_upper(row.get('product_amount', '')) or ''),
                }
                actual = special_map.get(api_key, '')
            else:
                actual = str(self._crm_extract_field(row, api_key) or '')
                # 选项字段解析为显示文本
                if api_key in getattr(self, 'CRM_OPTION_FIELDS', {}):
                    actual = str(self._get_crm_option_text(api_key, row.get(api_key, '')) or actual)

            actual_stripped = actual.strip()
            actual_lower = actual_stripped.lower()
            expected_lower = expected.lower()
            values = [v.strip().lower() for v in re.split(r'[,，;；\n]+', expected) if v.strip()]

            # --- 文本/数值操作符 ---
            if operator == 'contains' and expected_lower not in actual_lower:
                return False
            if operator == 'not_contains' and expected_lower in actual_lower:
                return False
            if operator == 'in' and values and actual_lower not in values:
                return False
            if operator == 'not_in' and values and actual_lower in values:
                return False
            if operator == 'eq' and actual_lower != expected_lower:
                return False
            if operator == 'ne' and actual_lower == expected_lower:
                return False
            if operator == 'empty' and actual_stripped:
                return False
            if operator == 'not_empty' and not actual_stripped:
                return False
            if operator == 'starts_with' and not actual_lower.startswith(expected_lower):
                return False
            if operator == 'ends_with' and not actual_lower.endswith(expected_lower):
                return False
            if operator in ('gt', 'lt'):
                try:
                    a = float(actual_stripped.replace(',', ''))
                    e = float(expected.replace(',', ''))
                    if operator == 'gt' and a <= e:
                        return False
                    if operator == 'lt' and a >= e:
                        return False
                except (ValueError, TypeError):
                    return False

            # --- 日期操作符 ---
            if operator in ('eq', 'ne', 'date_before', 'date_after', 'date_before_eq', 'date_after_eq', 'date_range'):
                row_qdate = self._crm_date_value_to_qdate(actual_stripped)
                if row_qdate is None:
                    if operator == 'ne':
                        continue
                    return False

                if operator == 'date_range':
                    if '~' in expected:
                        parts = expected.split('~')
                        start_qdate = QDate.fromString(parts[0].strip(), "yyyy-MM-dd")
                        end_qdate = QDate.fromString(parts[1].strip(), "yyyy-MM-dd")
                        if start_qdate.isValid() and end_qdate.isValid():
                            if not (start_qdate <= row_qdate <= end_qdate):
                                return False
                else:
                    filter_qdate = QDate.fromString(expected[:10], "yyyy-MM-dd")
                    if not filter_qdate.isValid():
                        return False
                    if operator == 'eq' and row_qdate != filter_qdate:
                        return False
                    if operator == 'date_before' and not (row_qdate < filter_qdate):
                        return False
                    if operator == 'date_after' and not (row_qdate > filter_qdate):
                        return False
                    if operator == 'date_before_eq' and not (row_qdate <= filter_qdate):
                        return False
                    if operator == 'date_after_eq' and not (row_qdate >= filter_qdate):
                        return False

            # --- N天/N周/N月/季度相对日期操作符 ---
            n_type_ops = (
                'past_n_days_exclusive', 'future_n_days_exclusive',
                'past_n_months_exclusive', 'future_n_months_exclusive',
                'past_n_weeks_exclusive', 'future_n_weeks_exclusive',
                'past_n_days_inclusive', 'future_n_days_inclusive',
                'past_n_weeks_inclusive', 'future_n_weeks_inclusive',
                'past_n_months_inclusive', 'future_n_months_inclusive',
                'n_days_ago', 'n_days_later',
                'n_weeks_ago', 'n_weeks_later',
                'past_n_quarters_inclusive',
            )
            if operator in n_type_ops:
                row_qdate = self._crm_date_value_to_qdate(actual_stripped)
                if row_qdate is None:
                    return False
                try:
                    n = int(expected)
                except (ValueError, TypeError):
                    return False
                today = QDate.currentDate()

                if operator == 'past_n_days_exclusive':
                    start = today.addDays(-n)
                    if not (start <= row_qdate < today):
                        return False
                elif operator == 'future_n_days_exclusive':
                    end = today.addDays(n)
                    if not (today < row_qdate <= end):
                        return False
                elif operator == 'past_n_days_inclusive':
                    start = today.addDays(-n)
                    if not (start <= row_qdate <= today):
                        return False
                elif operator == 'future_n_days_inclusive':
                    end = today.addDays(n)
                    if not (today <= row_qdate <= end):
                        return False
                elif operator == 'n_days_ago':
                    target = today.addDays(-n)
                    if not (row_qdate <= target):
                        return False
                elif operator == 'n_days_later':
                    target = today.addDays(n)
                    if not (row_qdate >= target):
                        return False
                elif operator in ('past_n_months_exclusive',):
                    start = today.addMonths(-n)
                    if not (start <= row_qdate < today):
                        return False
                elif operator in ('future_n_months_exclusive',):
                    end = today.addMonths(n)
                    if not (today < row_qdate <= end):
                        return False
                elif operator in ('past_n_months_inclusive',):
                    start = today.addMonths(-n)
                    if not (start <= row_qdate <= today):
                        return False
                elif operator in ('future_n_months_inclusive',):
                    end = today.addMonths(n)
                    if not (today <= row_qdate <= end):
                        return False
                elif operator in ('past_n_weeks_exclusive',):
                    start = today.addDays(-n * 7)
                    if not (start <= row_qdate < today):
                        return False
                elif operator in ('future_n_weeks_exclusive',):
                    end = today.addDays(n * 7)
                    if not (today < row_qdate <= end):
                        return False
                elif operator in ('past_n_weeks_inclusive',):
                    start = today.addDays(-n * 7)
                    if not (start <= row_qdate <= today):
                        return False
                elif operator in ('future_n_weeks_inclusive',):
                    end = today.addDays(n * 7)
                    if not (today <= row_qdate <= end):
                        return False
                elif operator == 'n_weeks_ago':
                    target = today.addDays(-n * 7)
                    if not (row_qdate <= target):
                        return False
                elif operator == 'n_weeks_later':
                    target = today.addDays(n * 7)
                    if not (row_qdate >= target):
                        return False
                elif operator == 'past_n_quarters_inclusive':
                    start = today.addMonths(-n * 3)
                    if not (start <= row_qdate <= today):
                        return False

        return True

    # ===== CRM 多条件筛选行管理 =====

    def _add_crm_condition_row(self, condition=None):
        """新增一条筛选条件行（field_combo + op_combo + value_stack + 外露）"""
        from PyQt6.QtWidgets import QFrame, QStackedWidget, QDateEdit, QSpinBox, QCheckBox, QSizePolicy
        condition = condition or {}
        if hasattr(self, 'crm_conditions_placeholder'):
            self.crm_conditions_placeholder.setVisible(False)

        row_frame = QFrame()
        row_frame.setFixedHeight(32)
        row_frame.setStyleSheet("QFrame { background-color: #F8F8F8; border: none; border-radius: 4px; }")
        row_layout = QHBoxLayout(row_frame)
        row_layout.setContentsMargins(6, 0, 6, 0)
        row_layout.setSpacing(5)

        remove_btn = QPushButton("✕")
        remove_btn.setFixedSize(20, 20)
        remove_btn.setCursor(Qt.CursorShape.PointingHandCursor)
        remove_btn.setToolTip("删除此条件")
        remove_btn.setStyleSheet("""
            QPushButton {
                font-weight: bold; color: #FF4D4F; border: 1px solid #FFCCC7;
                border-radius: 10px; font-size: 11px; background-color: #FFF2F0;
            }
            QPushButton:hover { background-color: #FF4D4F; color: #FFFFFF; border-color: #FF4D4F; }
        """)
        row_layout.addWidget(remove_btn, alignment=Qt.AlignmentFlag.AlignVCenter)

        field_combo = QComboBox()
        field_combo.setEditable(True)
        field_combo.setFixedWidth(150)
        field_combo.setFixedHeight(26)
        field_combo.setPlaceholderText("选择字段")
        field_combo.setStyleSheet("QComboBox { font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 4px; background: #FFF; } QComboBox QAbstractItemView { font-size: 12px; }")
        # 添加所有字段选项
        all_fields = self._build_crm_field_label_list()
        for label in all_fields:
            field_combo.addItem(label, label)
        # 模糊匹配补全器（PopupCompletion 避免 inline 补全干扰输入法 IME 组合）
        completer = QCompleter(all_fields, self)
        completer.setCaseSensitivity(Qt.CaseSensitivity.CaseInsensitive)
        completer.setFilterMode(Qt.MatchFlag.MatchContains)
        completer.setCompletionMode(QCompleter.CompletionMode.PopupCompletion)
        field_combo.setCompleter(completer)
        selected_field = str(condition.get('field', '')).strip()
        if selected_field:
            idx = field_combo.findText(selected_field)
            if idx >= 0:
                field_combo.setCurrentIndex(idx)
            else:
                field_combo.setEditText(selected_field)
        row_layout.addWidget(field_combo, alignment=Qt.AlignmentFlag.AlignVCenter)

        op_combo = QComboBox()
        op_combo.setFixedWidth(105)
        op_combo.setFixedHeight(26)
        op_combo.setStyleSheet("QComboBox { font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 2px; background: #FFF; } QComboBox QAbstractItemView { font-size: 12px; }")
        selected_op = str(condition.get('operator', 'contains')).strip()
        # 判断是否为日期操作符，选择正确的操作符列表
        date_ops = {key for _, key in self._get_crm_date_operators()}
        text_ops = {key for _, key in self._get_crm_text_operators()}
        if selected_op in date_ops and selected_op not in text_ops:
            operators = self._get_crm_date_operators()
        else:
            operators = self._get_crm_text_operators()
        for label, key in operators:
            op_combo.addItem(label, key)
        op_idx = op_combo.findData(selected_op)
        if op_idx >= 0:
            op_combo.setCurrentIndex(op_idx)
        row_layout.addWidget(op_combo, alignment=Qt.AlignmentFlag.AlignVCenter)

        value_stack = QStackedWidget()
        value_stack.setFixedWidth(140)
        value_stack.setFixedHeight(26)

        # Page 0: 文本输入
        value_input = QLineEdit()
        value_input.setPlaceholderText("值")
        value_input.setFixedHeight(26)
        value_input.setStyleSheet("font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 4px;")
        value_input.setText(str(condition.get('value', '')))
        # 防抖：避免每次按键都触发本地过滤刷新，干扰 IME 输入法组合
        _crm_value_change_timer = QTimer()
        _crm_value_change_timer.setSingleShot(True)
        _crm_value_change_timer.setInterval(200)
        _crm_value_change_timer.timeout.connect(lambda: self.on_crm_local_filter_changed())
        value_input.textChanged.connect(lambda: _crm_value_change_timer.start())
        value_stack.addWidget(value_input)

        # Page 1: 单日期选择器
        date_input = QDateEdit()
        date_input.setCalendarPopup(True)
        date_input.setDisplayFormat("yyyy-MM-dd")
        date_input.setDate(QDate.currentDate())
        date_input.setFixedHeight(26)
        date_input.setStyleSheet("font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 2px;")
        raw_value = str(condition.get('value', '')).strip()
        if raw_value:
            parsed = QDate.fromString(raw_value[:10], "yyyy-MM-dd")
            if parsed.isValid():
                date_input.setDate(parsed)
        date_input.dateChanged.connect(lambda: self.on_crm_local_filter_changed())
        value_stack.addWidget(date_input)

        # Page 2: 日期范围按钮
        date_range_btn = QPushButton("选择日期范围")
        date_range_btn.setFixedHeight(26)
        date_range_btn.setStyleSheet("QPushButton { border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 6px; font-size: 12px; }")
        range_data = {'start': None, 'end': None}
        if condition.get('operator') == 'date_range' and '~' in str(condition.get('value', '')):
            parts = str(condition['value']).split('~')
            if len(parts) == 2:
                s = QDate.fromString(parts[0].strip(), "yyyy-MM-dd")
                e = QDate.fromString(parts[1].strip(), "yyyy-MM-dd")
                if s.isValid() and e.isValid():
                    range_data = {'start': s, 'end': e}
                    date_range_btn.setText(f"{s.toString('yyyy-MM-dd')} ~ {e.toString('yyyy-MM-dd')}")
        date_range_btn.setProperty('crm_date_range', range_data)
        date_range_btn.clicked.connect(lambda checked, btn=date_range_btn: self._open_crm_condition_date_range(btn))
        value_stack.addWidget(date_range_btn)

        # Page 3: 数字输入（N天/N周/N月/季度）
        n_input = QSpinBox()
        n_input.setFixedHeight(26)
        n_input.setMinimumWidth(50)
        n_input.setStyleSheet("font-size: 12px;")
        n_input.setRange(1, 999)
        n_input.setValue(int(condition.get('value', '1')) if str(condition.get('value', '')).isdigit() else 1)
        n_input.valueChanged.connect(lambda: self.on_crm_local_filter_changed())
        value_stack.addWidget(n_input)

        value_stack.setCurrentIndex(0)
        row_layout.addWidget(value_stack, alignment=Qt.AlignmentFlag.AlignVCenter)

        # 外露 checkbox（仿纷享销客）
        expose_check = QCheckBox("外露")
        expose_check.setChecked(bool(condition.get('expose', False)))
        expose_check.setToolTip("勾选后可在搜索栏下方显示该筛选条件")
        expose_check.setStyleSheet("QCheckBox { font-size: 12px; color: #666; spacing: 2px; }")
        expose_check.toggled.connect(lambda checked: self._refresh_crm_exposed_tags())
        row_layout.addWidget(expose_check, alignment=Qt.AlignmentFlag.AlignVCenter)

        self.crm_conditions_layout.addWidget(row_frame)

        row_info = {
            'frame': row_frame,
            'field_combo': field_combo,
            'op_combo': op_combo,
            'value_stack': value_stack,
            'value_input': value_input,
            'date_input': date_input,
            'date_range_btn': date_range_btn,
            'n_input': n_input,
            'expose_check': expose_check,
            '_saved_operator': condition.get('operator', ''),
        }
        self.crm_condition_rows.append(row_info)
        self._update_crm_filter_toggle_badge()

        remove_btn.clicked.connect(lambda: self._remove_crm_condition_row(row_info))

        def _on_crm_field_changed(info):
            info['value_input'].clear()
            info['date_input'].setDate(QDate.currentDate())
            info['date_range_btn'].setText("选择日期范围")
            info['date_range_btn'].setProperty('crm_date_range', {'start': None, 'end': None})
            info['n_input'].setValue(1)
            self._update_crm_condition_input_mode(info)
            self.on_crm_local_filter_changed()

        # editTextChanged 使用防抖延迟，避免在 IME 组合输入过程中频繁触发
        _crm_field_change_timer = QTimer()
        _crm_field_change_timer.setSingleShot(True)
        _crm_field_change_timer.setInterval(200)

        def _on_crm_edit_text_changed(text, info=row_info, timer=_crm_field_change_timer):
            timer.start()

        _crm_field_change_timer.timeout.connect(lambda info=row_info: _on_crm_field_changed(info))

        field_combo.currentIndexChanged.connect(lambda idx, info=row_info: _on_crm_field_changed(info))
        field_combo.editTextChanged.connect(_on_crm_edit_text_changed)
        field_combo.lineEdit().editingFinished.connect(
            lambda info=row_info: self._update_crm_condition_input_mode(info)
        )
        op_combo.currentIndexChanged.connect(lambda idx, info=row_info: (self._update_crm_condition_input_mode(info), self.on_crm_local_filter_changed()))

        self._update_crm_condition_input_mode(row_info)
        self._refresh_crm_exposed_tags()
        self._adjust_filter_panel_size()

    def _remove_crm_condition_row(self, row_info):
        """移除一条筛选条件行"""
        if row_info in self.crm_condition_rows:
            self.crm_condition_rows.remove(row_info)
        frame = row_info.get('frame')
        if frame is not None:
            try:
                frame.hide()
                self.crm_conditions_layout.removeWidget(frame)
                frame.setParent(None)
                frame.deleteLater()
            except RuntimeError:
                pass  # C++ 对象已销毁
        if not self.crm_condition_rows and hasattr(self, 'crm_conditions_placeholder'):
            self.crm_conditions_placeholder.setVisible(True)
        self._update_crm_filter_toggle_badge()
        self._refresh_crm_exposed_tags()
        self._adjust_filter_panel_size()
        self.on_crm_local_filter_changed()

    def _adjust_filter_panel_size(self):
        """根据条件数量调整面板高度"""
        if not hasattr(self, 'crm_filter_panel'):
            return
        row_count = len(getattr(self, 'crm_condition_rows', []))
        # 估算高度：标题36 + 每条件行32 + 间距4*(row-1) + 底部44 + 边距24
        h = 36 + row_count * 32 + max(0, row_count - 1) * 4 + 44 + 24
        h = max(160, min(h, 550))
        self.crm_filter_panel.setFixedHeight(h)
        if self.crm_filter_panel.isVisible():
            self.crm_filter_panel.updateGeometry()

    def _update_crm_condition_input_mode(self, row_info):
        """根据字段类型重建操作符列表并切换输入组件"""
        field_label = row_info['field_combo'].currentText().strip()
        is_date = self._is_crm_date_field(field_label)

        op_combo = row_info['op_combo']
        current_op = op_combo.currentData() or row_info.get('_saved_operator', '')
        op_combo.blockSignals(True)
        op_combo.clear()
        operators = self._get_crm_date_operators() if is_date else self._get_crm_text_operators()
        for label, key in operators:
            op_combo.addItem(label, key)
        idx = op_combo.findData(current_op)
        if idx < 0 and is_date:
            # 日期字段默认选中"时间段"
            idx = op_combo.findData('date_range')
        op_combo.setCurrentIndex(idx if idx >= 0 else 0)
        op_combo.blockSignals(False)

        operator = op_combo.currentData()
        requires_value = operator not in ('empty', 'not_empty')
        row_info['value_stack'].setVisible(requires_value)

        if not requires_value:
            return

        # N天/N周/N月/季度类操作符 → 数字输入
        n_type_ops = (
            'past_n_days_exclusive', 'future_n_days_exclusive',
            'past_n_months_exclusive', 'future_n_months_exclusive',
            'past_n_weeks_exclusive', 'future_n_weeks_exclusive',
            'past_n_days_inclusive', 'future_n_days_inclusive',
            'past_n_weeks_inclusive', 'future_n_weeks_inclusive',
            'past_n_months_inclusive', 'future_n_months_inclusive',
            'n_days_ago', 'n_days_later',
            'n_weeks_ago', 'n_weeks_later',
            'past_n_quarters_inclusive',
        )
        if is_date and operator == 'date_range':
            row_info['value_stack'].setCurrentIndex(2)
        elif is_date and operator in n_type_ops:
            row_info['value_stack'].setCurrentIndex(3)
        elif is_date:
            row_info['value_stack'].setCurrentIndex(1)
        else:
            row_info['value_stack'].setCurrentIndex(0)

    def _collect_crm_filter_conditions(self):
        """收集当前所有筛选条件行，返回 [{field, api_key, operator, value, expose}]"""
        conditions = []
        n_type_ops = (
            'past_n_days_exclusive', 'future_n_days_exclusive',
            'past_n_months_exclusive', 'future_n_months_exclusive',
            'past_n_weeks_exclusive', 'future_n_weeks_exclusive',
            'past_n_days_inclusive', 'future_n_days_inclusive',
            'past_n_weeks_inclusive', 'future_n_weeks_inclusive',
            'past_n_months_inclusive', 'future_n_months_inclusive',
            'n_days_ago', 'n_days_later',
            'n_weeks_ago', 'n_weeks_later',
            'past_n_quarters_inclusive',
        )
        for row_info in getattr(self, 'crm_condition_rows', []):
            field_label = row_info['field_combo'].currentText().strip()
            operator = row_info['op_combo'].currentData()
            if not field_label:
                continue

            if operator in ('empty', 'not_empty'):
                value = ''
            elif self._is_crm_date_field(field_label) and operator == 'date_range':
                dr = row_info['date_range_btn'].property('crm_date_range')
                if dr and dr.get('start') and dr.get('end'):
                    value = f"{dr['start'].toString('yyyy-MM-dd')}~{dr['end'].toString('yyyy-MM-dd')}"
                else:
                    continue
            elif self._is_crm_date_field(field_label) and operator in n_type_ops:
                value = str(row_info['n_input'].value())
            elif self._is_crm_date_field(field_label):
                value = row_info['date_input'].date().toString('yyyy-MM-dd')
            else:
                value = row_info['value_input'].text().strip()
                if not value:
                    continue

            api_key = self._get_crm_api_key_for_label(field_label)
            conditions.append({
                'field': field_label,
                'api_key': api_key,
                'operator': operator,
                'value': value,
                'expose': row_info['expose_check'].isChecked(),
            })
        return conditions

    def _clear_all_crm_conditions(self):
        """清除所有筛选条件行"""
        for row_info in list(getattr(self, 'crm_condition_rows', [])):
            row_info['frame'].setParent(None)
            row_info['frame'].deleteLater()
        self.crm_condition_rows = []
        if hasattr(self, 'crm_conditions_placeholder'):
            self.crm_conditions_placeholder.setVisible(True)
        self._adjust_filter_panel_size()

    def _clear_all_crm_conditions_and_search(self):
        """清除筛选条件 + 搜索框"""
        self._clear_all_crm_conditions()
        if hasattr(self, 'crm_search_input'):
            self.crm_search_input.clear()
        if hasattr(self, 'crm_search_field_combo'):
            self.crm_search_field_combo.setCurrentIndex(0)
        self._update_crm_filter_toggle_badge()
        self._refresh_crm_exposed_tags()
        self.on_crm_local_filter_changed()

    def _refresh_crm_exposed_tags(self):
        """刷新外露筛选条件标签栏（显示在搜索框下方）"""
        if not hasattr(self, 'crm_exposed_tags_frame'):
            return
        # 清除现有标签
        for i in reversed(range(self.crm_exposed_tags_layout.count())):
            item = self.crm_exposed_tags_layout.itemAt(i)
            if item:
                w = item.widget()
                if w:
                    w.setParent(None)
                    w.deleteLater()
        # 收集外露条件
        exposed_conds = []
        for row_info in getattr(self, 'crm_condition_rows', []):
            if row_info.get('expose_check') and row_info['expose_check'].isChecked():
                field_label = row_info['field_combo'].currentText().strip()
                if not field_label:
                    continue
                operator = row_info['op_combo'].currentData()
                if operator in ('empty', 'not_empty'):
                    value = row_info['op_combo'].currentText()
                elif operator == 'date_range':
                    dr = row_info['date_range_btn'].property('crm_date_range') or {}
                    if dr.get('start') and dr.get('end'):
                        value = f"{dr['start'].toString('yyyy-MM-dd')}~{dr['end'].toString('yyyy-MM-dd')}"
                    else:
                        continue
                elif self._is_crm_date_field(field_label):
                    value = row_info['date_input'].date().toString('yyyy-MM-dd')
                else:
                    value = row_info['value_input'].text().strip()
                    if not value:
                        continue
                exposed_conds.append({
                    'field': field_label,
                    'value': value,
                    'row_info': row_info,
                })
        if not exposed_conds:
            self.crm_exposed_tags_frame.setVisible(False)
            return
        self.crm_exposed_tags_frame.setVisible(True)
        # 移除旧的 stretch spacer
        for i in range(self.crm_exposed_tags_layout.count()):
            item = self.crm_exposed_tags_layout.itemAt(i)
            if item and item.spacerItem():
                self.crm_exposed_tags_layout.removeItem(item)
                break
        for cond in exposed_conds:
            row_info = cond['row_info']
            field_label = cond['field']
            is_date = self._is_crm_date_field(field_label)
            operator = row_info['op_combo'].currentData()
            is_date_range = is_date and operator == 'date_range'

            # 截断过长的值文本
            display_value = cond['value']
            if len(display_value) > 12:
                display_value = display_value[:11] + "…"

            # 截断过长的值文本
            display_value = cond['value']
            if len(display_value) > 8:
                display_value = display_value[:7] + "…"
            # 截断过长的字段名
            short_label = field_label if len(field_label) <= 4 else field_label[:4]

            tag = QFrame()
            tag.setMaximumHeight(36)
            tag.setMaximumWidth(200)
            tag.setStyleSheet("""
                QFrame#exposedTag {
                    background-color: #E6F7FF; border: 1px solid #91D5FF;
                    border-radius: 3px;
                }
                QFrame#exposedTag:hover { background-color: #BAE7FF; border-color: #69C0FF; }
            """)
            tag.setObjectName("exposedTag")
            tag_layout = QHBoxLayout(tag)
            tag_layout.setContentsMargins(4, 2, 2, 2)
            tag_layout.setSpacing(2)

            # 值显示/编辑栈（先创建，供下方按钮引用）
            value_stack = QStackedWidget()
            value_stack.setMaximumHeight(32)
            value_stack.setMaximumWidth(140)

            # 字段名按钮（点击取消编辑）
            field_btn = QPushButton(f"{short_label}:")
            field_btn.setMaximumHeight(32)
            field_btn.setMaximumWidth(55)
            field_btn.setCursor(Qt.CursorShape.PointingHandCursor)
            field_btn.setToolTip("取消编辑")
            field_btn.setStyleSheet("""
                QPushButton {
                    font-size: 10px; color: #1890FF; border: none;
                    background: transparent; font-weight: 600; padding: 0px;
                }
                QPushButton:hover { color: #FF4D4F; }
            """)
            field_btn.clicked.connect(lambda checked, vs=value_stack: vs.setCurrentIndex(0))
            tag_layout.addWidget(field_btn)

            # Page 0: 显示值（点击进入编辑）
            value_display = QPushButton(display_value)
            value_display.setMaximumHeight(32)
            value_display.setMaximumWidth(120)
            value_display.setCursor(Qt.CursorShape.PointingHandCursor)
            value_display.setToolTip("点击编辑")
            value_display.setStyleSheet("""
                QPushButton {
                    font-size: 10px; color: #1890FF; border: none;
                    background: transparent; padding: 0px;
                }
                QPushButton:hover { text-decoration: underline; }
            """)
            value_stack.addWidget(value_display)

            # Page 1: 编辑控件
            edit_widget = None
            if is_date_range:
                edit_btn = QPushButton(display_value if display_value else "选日期")
                edit_btn.setMaximumHeight(32)
                edit_btn.setMaximumWidth(120)
                edit_btn.setCursor(Qt.CursorShape.PointingHandCursor)
                edit_btn.setStyleSheet("""
                    QPushButton {
                        border: 1px solid #91D5FF; border-radius: 2px;
                        padding: 0px 4px; font-size: 10px; color: #1890FF;
                        background-color: #FFFFFF;
                    }
                    QPushButton:hover { border-color: #1890FF; }
                """)
                edit_btn.clicked.connect(lambda checked, ri=row_info, btn=edit_btn, vs=value_stack:
                    self._edit_exposed_date_range(ri, btn, vs))
                value_stack.addWidget(edit_btn)
                edit_widget = edit_btn
            elif is_date:
                edit_date = QDateEdit()
                edit_date.setCalendarPopup(True)
                edit_date.setDisplayFormat("yyyy-MM-dd")
                edit_date.setMaximumHeight(32)
                edit_date.setMaximumWidth(100)
                edit_date.setStyleSheet("""
                    QDateEdit {
                        border: 1px solid #91D5FF; border-radius: 2px;
                        padding: 0px 2px; font-size: 10px; color: #1890FF;
                        background-color: #FFFFFF;
                    }
                """)
                parsed = QDate.fromString(cond['value'], "yyyy-MM-dd")
                if parsed.isValid():
                    edit_date.setDate(parsed)
                edit_date.dateChanged.connect(lambda d, ri=row_info, vs=value_stack:
                    self._apply_exposed_edit(ri, vs))
                value_stack.addWidget(edit_date)
                edit_widget = edit_date
            else:
                edit_input = QLineEdit(cond['value'])
                edit_input.setMaximumHeight(32)
                edit_input.setMaximumWidth(100)
                edit_input.setStyleSheet("""
                    QLineEdit {
                        border: 1px solid #91D5FF; border-radius: 2px;
                        padding: 0px 2px; font-size: 10px; color: #1890FF;
                        background-color: #FFFFFF;
                    }
                """)
                edit_input.returnPressed.connect(lambda ri=row_info, vs=value_stack:
                    self._apply_exposed_edit(ri, vs))
                value_stack.addWidget(edit_input)
                edit_widget = edit_input

            # 点击显示值进入编辑模式，自动聚焦编辑器
            value_display.clicked.connect(
                lambda checked, vs=value_stack, ew=edit_widget: (
                    vs.setCurrentIndex(1), ew.setFocus() if ew else None
                )
            )

            tag_layout.addWidget(value_stack)

            # 关闭按钮
            close_btn = QPushButton("×")
            close_btn.setFixedSize(14, 14)
            close_btn.setCursor(Qt.CursorShape.PointingHandCursor)
            close_btn.setToolTip("移除此筛选条件")
            close_btn.setStyleSheet("""
                QPushButton {
                    border: none; color: #91D5FF; font-size: 10px; font-weight: bold;
                    background: transparent; padding: 0px;
                }
                QPushButton:hover { color: #FF4D4F; }
            """)
            close_btn.clicked.connect(lambda checked, ri=row_info: self._remove_crm_condition_row(ri))
            tag_layout.addWidget(close_btn)

            self.crm_exposed_tags_layout.addWidget(tag)
        self.crm_exposed_tags_layout.addStretch()

    def _apply_exposed_edit(self, row_info, value_stack):
        """应用外露标签的内联编辑，同步回条件行并刷新"""
        if row_info not in getattr(self, 'crm_condition_rows', []):
            return
        editor = value_stack.currentWidget()
        field_label = row_info['field_combo'].currentText().strip()
        is_date = self._is_crm_date_field(field_label)
        operator = row_info['op_combo'].currentData()
        is_date_range = is_date and operator == 'date_range'

        if is_date_range:
            # 日期范围：从按钮属性读取
            btn = value_stack.widget(1)
            if btn:
                dr = btn.property('crm_date_range') or {}
                if dr.get('start') and dr.get('end'):
                    new_val = f"{dr['start'].toString('yyyy-MM-dd')}~{dr['end'].toString('yyyy-MM-dd')}"
                    # 更新条件行的 date_range_btn
                    row_info['date_range_btn'].setProperty('crm_date_range', dr)
                    row_info['date_range_btn'].setText(new_val)
                    # 更新显示
                    value_stack.widget(0).setText(new_val)
        elif is_date:
            # 单日期
            if isinstance(editor, QDateEdit):
                new_val = editor.date().toString('yyyy-MM-dd')
                row_info['date_input'].setDate(editor.date())
                value_stack.widget(0).setText(new_val)
        else:
            # 文本
            if isinstance(editor, QLineEdit):
                new_val = editor.text().strip()
                row_info['value_input'].setText(new_val)
                value_stack.widget(0).setText(new_val)

        value_stack.setCurrentIndex(0)
        self.on_crm_local_filter_changed()

    def _edit_exposed_date_range(self, row_info, btn, value_stack):
        """在外露标签中打开日期范围选择"""
        dr = btn.property('crm_date_range') or {'start': None, 'end': None}
        dlg = QuickDatePickerDialog(
            start_date=dr.get('start'),
            end_date=dr.get('end'),
            parent=self
        )
        dlg.set_popup_anchor_widget(btn)
        if dlg.exec() == QDialog.DialogCode.Accepted and dlg.start_date and dlg.end_date:
            new_range = {'start': dlg.start_date, 'end': dlg.end_date}
            btn.setProperty('crm_date_range', new_range)
            new_val = f"{dlg.start_date.toString('yyyy-MM-dd')} ~ {dlg.end_date.toString('yyyy-MM-dd')}"
            btn.setText(new_val)
            # 同步到条件行
            row_info['date_range_btn'].setProperty('crm_date_range', new_range)
            row_info['date_range_btn'].setText(new_val)
            # 更新显示标签
            value_stack.widget(0).setText(new_val)
            value_stack.setCurrentIndex(0)
            self.on_crm_local_filter_changed()

    def _apply_quick_date_preset(self, preset_key):
        """应用快捷日期预设（仿纷享销客快捷时间筛选）"""
        from datetime import datetime, timedelta
        from PyQt6.QtCore import QDate

        today = datetime.now().date()
        start_date = None
        end_date = None

        if preset_key == "today":
            start_date = end_date = today
        elif preset_key == "yesterday":
            yesterday = today - timedelta(days=1)
            start_date = end_date = yesterday
        elif preset_key == "this_week":
            start_date = today - timedelta(days=today.weekday())
            end_date = today
        elif preset_key == "last_week":
            last_week_end = today - timedelta(days=today.weekday() + 1)
            start_date = last_week_end - timedelta(days=6)
            end_date = last_week_end
        elif preset_key == "this_month":
            start_date = today.replace(day=1)
            end_date = today
        elif preset_key == "last_month":
            if today.month == 1:
                start_date = today.replace(year=today.year - 1, month=12, day=1)
                end_date = today.replace(year=today.year - 1, month=12, day=31)
            else:
                last_month = today.replace(month=today.month - 1, day=1)
                if today.month == 3:
                    end_date = today.replace(day=1) - timedelta(days=1)
                else:
                    try:
                        end_date = today.replace(month=today.month - 1, day=28)
                        while True:
                            next_day = end_date + timedelta(days=1)
                            if next_day.month != end_date.month:
                                break
                            end_date = next_day
                    except ValueError:
                        end_date = today.replace(month=today.month - 1, day=28)
                start_date = last_month
        elif preset_key == "this_quarter":
            quarter = (today.month - 1) // 3
            start_date = today.replace(month=quarter * 3 + 1, day=1)
            end_date = today
        elif preset_key == "this_year":
            start_date = today.replace(month=1, day=1)
            end_date = today

        if start_date and end_date:
            q_start = QDate(start_date.year, start_date.month, start_date.day)
            q_end = QDate(end_date.year, end_date.month, end_date.day)

            # 查找或添加"创建时间"条件行
            found = False
            for row_info in getattr(self, 'crm_condition_rows', []):
                field_label = row_info['field_combo'].currentText().strip()
                if field_label == "创建时间":
                    # 设置操作符为"时间段"
                    op_idx = row_info['op_combo'].findData("date_range")
                    if op_idx >= 0:
                        row_info['op_combo'].setCurrentIndex(op_idx)
                    # 设置日期范围
                    range_data = {'start': q_start, 'end': q_end}
                    row_info['date_range_btn'].setProperty('crm_date_range', range_data)
                    row_info['date_range_btn'].setText(f"{q_start.toString('yyyy-MM-dd')} ~ {q_end.toString('yyyy-MM-dd')}")
                    found = True
                    break

            if not found:
                # 添加新的创建时间条件行
                self._add_crm_condition_row({
                    'field': '创建时间',
                    'operator': 'date_range',
                    'value': f"{q_start.toString('yyyy-MM-dd')}~{q_end.toString('yyyy-MM-dd')}",
                })
                # 设置日期范围按钮的值
                if self.crm_condition_rows:
                    last_row = self.crm_condition_rows[-1]
                    range_data = {'start': q_start, 'end': q_end}
                    last_row['date_range_btn'].setProperty('crm_date_range', range_data)
                    last_row['date_range_btn'].setText(f"{q_start.toString('yyyy-MM-dd')} ~ {q_end.toString('yyyy-MM-dd')}")

            self.on_crm_local_filter_changed()

    def _apply_crm_filter_and_close(self):
        """应用筛选条件并关闭弹窗"""
        self.on_crm_local_filter_changed()
        self._refresh_crm_exposed_tags()
        if hasattr(self, 'crm_filter_panel'):
            self.crm_filter_panel.setVisible(False)
        self._update_crm_filter_toggle_badge()



    def _toggle_crm_filter_panel(self):
        """切换筛选面板显示/隐藏（独立窗口弹窗）"""
        if not hasattr(self, 'crm_filter_panel'):
            return

        visible = not self.crm_filter_panel.isVisible()

        if visible:
            # 显示面板：作为独立窗口，在搜索框下方弹出
            self.crm_filter_panel.setWindowFlags(Qt.WindowType.Dialog | Qt.WindowType.FramelessWindowHint)
            self.crm_filter_panel.setVisible(True)
            self.crm_filter_panel.raise_()
            self.crm_filter_panel.activateWindow()

            # 根据内容自动调整高度，再定位
            self._adjust_filter_panel_size()
            panel_width = self.crm_filter_panel.width()
            panel_height = self.crm_filter_panel.height()

            # 定位在搜索框正下方
            search_frame = self.crm_search_stack.parent()
            if search_frame:
                search_bottom_left = search_frame.mapToGlobal(QPoint(0, search_frame.height()))
                x = search_bottom_left.x()
                y = search_bottom_left.y() + 4
            else:
                x = self.geometry().x() + 100
                y = self.geometry().y() + 80

            # 确保不超出屏幕边界
            screen = self.screen()
            if screen:
                screen_rect = screen.availableGeometry()
                x = max(screen_rect.x() + 10, min(x, screen_rect.right() - panel_width - 10))
                y = max(screen_rect.y() + 10, min(y, screen_rect.bottom() - panel_height - 10))

            self.crm_filter_panel.move(x, y)
            # 点击外部关闭弹窗
            self._install_crm_filter_outside_close()
        else:
            self.crm_filter_panel.setVisible(False)
            self._remove_crm_filter_outside_close()

        self._update_crm_filter_toggle_badge()

    def _install_crm_filter_outside_close(self):
        """安装点击外部关闭筛选面板的事件过滤器"""
        if not hasattr(self, 'crm_filter_outside_filter'):
            # QFrame 没有 reject()，补一个供 _DialogOutsideCloseFilter 调用
            self.crm_filter_panel.reject = lambda: self.crm_filter_panel.setVisible(False)
            self.crm_filter_outside_filter = _DialogOutsideCloseFilter(self.crm_filter_panel)
        app = QApplication.instance()
        if app and not getattr(self, '_crm_filter_outside_installed', False):
            app.installEventFilter(self.crm_filter_outside_filter)
            self._crm_filter_outside_installed = True
            # 延迟激活，避免当前点击事件立即关闭面板
            self.crm_filter_panel._outside_close_armed = False
            QTimer.singleShot(0, lambda: setattr(self.crm_filter_panel, '_outside_close_armed', True))

    def _remove_crm_filter_outside_close(self):
        """移除点击外部关闭筛选面板的事件过滤器"""
        app = QApplication.instance()
        if app and getattr(self, '_crm_filter_outside_installed', False) and hasattr(self, 'crm_filter_outside_filter'):
            app.removeEventFilter(self.crm_filter_outside_filter)
            self._crm_filter_outside_installed = False
        if hasattr(self, 'crm_filter_panel'):
            self.crm_filter_panel._outside_close_armed = False

    def _update_crm_filter_toggle_badge(self):
        """更新筛选按钮上的计数徽标"""
        if not hasattr(self, 'crm_filter_toggle_btn'):
            return
        count = len(getattr(self, 'crm_condition_rows', []))
        has_search = bool(getattr(self, 'crm_search_input', None) and self.crm_search_input.text().strip())
        total = count + (1 if has_search else 0)
        if total > 0:
            self.crm_filter_toggle_btn.setText(f"筛选({total})")
        else:
            self.crm_filter_toggle_btn.setText("筛选")

    def _open_crm_condition_date_range(self, btn):
        """点击条件行中的时间段按钮，打开日期范围选择弹窗"""
        dr = btn.property('crm_date_range') or {'start': None, 'end': None}
        dlg = QuickDatePickerDialog(
            start_date=dr.get('start'),
            end_date=dr.get('end'),
            parent=self
        )
        dlg.set_popup_anchor_widget(btn)
        if dlg.exec() == QDialog.DialogCode.Accepted and dlg.start_date and dlg.end_date:
            new_range = {'start': dlg.start_date, 'end': dlg.end_date}
            btn.setProperty('crm_date_range', new_range)
            btn.setText(f"{dlg.start_date.toString('yyyy-MM-dd')} ~ {dlg.end_date.toString('yyyy-MM-dd')}")
            self.on_crm_local_filter_changed()

    # ===== CRM 筛选方案管理 =====

    def _save_crm_filter_preset(self, name=None):
        """保存当前筛选条件和字段显示设置为方案"""
        # clicked 信号会传 checked:bool，忽略非字符串的 name
        if not isinstance(name, str):
            name = None
        conditions = self._collect_crm_filter_conditions()
        if name is None:
            name, ok = QInputDialog.getText(self, "保存筛选方案", "请输入方案名称：")
            if not ok or not name or not name.strip():
                return
        name = name.strip()
        # 收集当前可见列和顺序（排除固定列如复选框）
        column_visibility = {}  # {col_name: True/False}
        column_order = []       # [col_name, ...] 按当前顺序
        fixed_headers = set(getattr(self, 'crm_fixed_headers', [""]))
        if hasattr(self, 'crm_table'):
            header = self.crm_table.horizontalHeader()
            for vis_idx in range(header.count()):
                logical_idx = header.logicalIndex(vis_idx)
                header_item = self.crm_table.horizontalHeaderItem(logical_idx)
                if header_item:
                    col_name = header_item.text().strip()
                    if col_name in fixed_headers:
                        continue
                    is_hidden = self.crm_table.isColumnHidden(logical_idx)
                    column_visibility[col_name] = not is_hidden
                    column_order.append(col_name)
        preset_data = {
            'name': name,
            'conditions': conditions,
            'column_visibility': column_visibility,
            'column_order': column_order,
        }
        fx_cfg = self.config.setdefault('fxiaoke', {})
        presets = fx_cfg.get('crm_filter_presets', [])
        if not isinstance(presets, list):
            presets = []
        existing_idx = next((i for i, p in enumerate(presets) if p.get('name') == name), None)
        if existing_idx is not None:
            presets[existing_idx] = preset_data
        else:
            presets.append(preset_data)
        fx_cfg['crm_filter_presets'] = presets
        save_config(self.config)
        self._crm_active_preset_name = name
        self._update_crm_preset_btn_label()
        if name is None:
            QMessageBox.information(self, '成功', f'方案「{name}」已保存。')

    def _load_crm_filter_preset(self, preset_name=None):
        """加载选中的筛选方案（筛选条件 + 字段显示设置）"""
        if not isinstance(preset_name, str) or not preset_name:
            return
        presets = self.config.get('fxiaoke', {}).get('crm_filter_presets', [])
        if not isinstance(presets, list):
            return
        target = next((p for p in presets if p.get('name') == preset_name), None)
        if not target:
            return
        conditions = target.get('conditions', [])
        self._clear_all_crm_conditions()
        for cond in conditions:
            self._add_crm_condition_row(cond)
        # 恢复字段显示设置和顺序：直接更新运行时状态并重建表格列
        column_visibility = target.get('column_visibility', {})
        column_order = target.get('column_order', [])
        if column_order and hasattr(self, 'crm_table'):
            # 更新运行时状态（排除固定列如复选框列）
            fixed = getattr(self, 'crm_fixed_headers', [""])
            self.crm_header_order = list(column_order)
            self.crm_visible_headers = [n for n in column_order
                                        if n not in fixed and column_visibility.get(n, True)]
            # 重建表格列（包含正确的顺序和可见性）
            self._apply_crm_table_columns()
        elif column_visibility and hasattr(self, 'crm_table'):
            for col in range(self.crm_table.columnCount()):
                header_item = self.crm_table.horizontalHeaderItem(col)
                if header_item:
                    col_name = header_item.text().strip()
                    if col_name in column_visibility:
                        self.crm_table.setColumnHidden(col, not column_visibility[col_name])
        self.on_crm_local_filter_changed()

    def _delete_crm_filter_preset(self, preset_name=None):
        """删除指定筛选方案"""
        if not preset_name:
            preset_name = getattr(self, '_crm_active_preset_name', None)
        if not preset_name:
            QMessageBox.warning(self, "提示", "请先在方案列表中选择一个方案。")
            return
        presets = self.config.get('fxiaoke', {}).get('crm_filter_presets', [])
        if not isinstance(presets, list):
            return
        idx = next((i for i, p in enumerate(presets) if p.get('name') == preset_name), None)
        if idx is None:
            return
        reply = QMessageBox.question(self, '确认删除', f'确定删除方案「{preset_name}」吗？')
        if reply != QMessageBox.StandardButton.Yes:
            return
        presets.pop(idx)
        self.config.setdefault('fxiaoke', {})['crm_filter_presets'] = presets
        # 如果删除的是默认方案，清除默认
        if self.config.get('fxiaoke', {}).get('crm_filter_default_preset') == preset_name:
            self.config['fxiaoke']['crm_filter_default_preset'] = ''
        save_config(self.config)
        self._crm_active_preset_name = None
        self._update_crm_preset_btn_label()

    def _update_crm_preset_btn_label(self):
        """更新方案按钮文字"""
        if not hasattr(self, 'crm_filter_preset_btn'):
            return
        name = getattr(self, '_crm_active_preset_name', None)
        if name:
            self.crm_filter_preset_btn.setText(f"{name} ▼")
        else:
            self.crm_filter_preset_btn.setText("方案 ▼")

    def _show_crm_filter_preset_popup(self):
        """弹出方案选择面板（含操作按钮）"""
        presets = self.config.get('fxiaoke', {}).get('crm_filter_presets', [])
        if not isinstance(presets, list):
            presets = []
        default_name = self.config.get('fxiaoke', {}).get('crm_filter_default_preset', '')

        popup = QFrame()
        popup.setWindowFlags(Qt.WindowType.Popup | Qt.WindowType.FramelessWindowHint)
        popup.setStyleSheet("QFrame { border: 1px solid #D9D9D9; border-radius: 4px; background: #FFF; }")
        popup_layout = QVBoxLayout(popup)
        popup_layout.setContentsMargins(4, 4, 4, 4)
        popup_layout.setSpacing(2)

        # "(未选择)" 项
        none_btn = QPushButton("(未选择)")
        none_btn.setFixedHeight(28)
        none_btn.setCursor(Qt.CursorShape.PointingHandCursor)
        none_btn.setStyleSheet("QPushButton { border: none; text-align: left; padding: 4px 8px; font-size: 12px; color: #999; background: transparent; } QPushButton:hover { background: #F5F5F5; }")
        none_btn.clicked.connect(lambda: [self._clear_all_crm_conditions(), self.on_crm_local_filter_changed(), setattr(self, '_crm_active_preset_name', None), self._update_crm_preset_btn_label(), popup.close()])
        popup_layout.addWidget(none_btn)

        for preset in presets:
            name = preset.get('name', '')
            display = f"★ {name}" if name == default_name else name
            row = QFrame()
            row.setFixedHeight(30)
            row.setStyleSheet("QFrame { border: none; background: transparent; }")
            row_layout = QHBoxLayout(row)
            row_layout.setContentsMargins(0, 0, 0, 0)
            row_layout.setSpacing(4)

            # 方案名按钮（点击加载）
            load_btn = QPushButton(display)
            load_btn.setCursor(Qt.CursorShape.PointingHandCursor)
            load_btn.setStyleSheet("QPushButton { border: none; text-align: left; padding: 4px 8px; font-size: 12px; color: #333; background: transparent; } QPushButton:hover { background: #E6F7FF; color: #1890FF; }")
            load_btn.clicked.connect(lambda checked, n=name: [setattr(self, '_crm_active_preset_name', n), self._load_crm_filter_preset(n), self._update_crm_preset_btn_label(), popup.close()])
            row_layout.addWidget(load_btn, stretch=1)

            icon_style = """
                QPushButton { border: none; border-radius: 2px; font-size: 13px; background: transparent; color: #999; }
                QPushButton:hover { background: #E6F7FF; color: #1890FF; }
            """
            # 修改按钮（✎）
            mod_btn = QPushButton("✎")
            mod_btn.setFixedSize(22, 22)
            mod_btn.setStyleSheet(icon_style)
            mod_btn.setToolTip(f"用当前筛选+字段覆盖「{name}」")
            mod_btn.clicked.connect(lambda checked, n=name: [self._update_crm_filter_preset(n), popup.close()])
            row_layout.addWidget(mod_btn)
            # 默认按钮（★）
            def_btn = QPushButton("★")
            def_btn.setFixedSize(22, 22)
            if name == default_name:
                def_btn.setStyleSheet("QPushButton { border: none; border-radius: 2px; font-size: 13px; background: transparent; color: #FA8C16; } QPushButton:hover { background: #FFF7E6; color: #FA8C16; }")
            else:
                def_btn.setStyleSheet(icon_style)
            def_btn.setToolTip(f"设置/取消「{name}」为默认方案")
            def_btn.clicked.connect(lambda checked, n=name: [self._set_crm_filter_default_preset(n), popup.close(), self._update_crm_preset_btn_label()])
            row_layout.addWidget(def_btn)
            # 删除按钮（✕）
            del_btn = QPushButton("✕")
            del_btn.setFixedSize(22, 22)
            del_btn.setStyleSheet(icon_style + "QPushButton:hover { background: #FFF2F0; color: #FF4D4F; }")
            del_btn.setToolTip(f"删除「{name}」")
            del_btn.clicked.connect(lambda checked, n=name: [self._delete_crm_filter_preset(n), popup.close(), self._update_crm_preset_btn_label()])
            row_layout.addWidget(del_btn)

            popup_layout.addWidget(row)

        popup.adjustSize()
        # 定位在按钮下方
        btn_pos = self.crm_filter_preset_btn.mapToGlobal(QPoint(0, self.crm_filter_preset_btn.height()))
        popup.move(btn_pos.x(), btn_pos.y() + 2)
        # 点击外部关闭
        popup.reject = popup.close
        popup._outside_close_armed = False
        pf = _DialogOutsideCloseFilter(popup)
        popup._outside_filter = pf
        QApplication.instance().installEventFilter(pf)
        QTimer.singleShot(0, lambda p=popup: setattr(p, '_outside_close_armed', True))
        popup.destroyed.connect(lambda obj, f=pf: QApplication.instance().removeEventFilter(f))
        popup.show()
        self._crm_preset_popup = popup

    def _update_crm_filter_preset(self, preset_name=None):
        """用当前筛选条件和字段设置覆盖指定方案"""
        if not preset_name:
            preset_name = getattr(self, '_crm_active_preset_name', None)
        if not preset_name:
            QMessageBox.warning(self, "提示", "请先在方案列表中选择一个方案。")
            return
        presets = self.config.get('fxiaoke', {}).get('crm_filter_presets', [])
        if not isinstance(presets, list):
            return
        old_idx = next((i for i, p in enumerate(presets) if p.get('name') == preset_name), None)
        if old_idx is None:
            return
        # 收集当前条件
        conditions = self._collect_crm_filter_conditions()
        # 收集当前字段设置
        column_visibility = {}
        column_order = []
        fixed_headers = set(getattr(self, 'crm_fixed_headers', [""]))
        if hasattr(self, 'crm_table'):
            header = self.crm_table.horizontalHeader()
            for vis_idx in range(header.count()):
                logical_idx = header.logicalIndex(vis_idx)
                header_item = self.crm_table.horizontalHeaderItem(logical_idx)
                if header_item:
                    col_name = header_item.text().strip()
                    if col_name in fixed_headers:
                        continue
                    is_hidden = self.crm_table.isColumnHidden(logical_idx)
                    column_visibility[col_name] = not is_hidden
                    column_order.append(col_name)
        # 覆盖保存
        presets[old_idx] = {
            'name': preset_name,
            'conditions': conditions,
            'column_visibility': column_visibility,
            'column_order': column_order,
        }
        self.config.setdefault('fxiaoke', {})['crm_filter_presets'] = presets
        save_config(self.config)
        QMessageBox.information(self, "成功", f"方案「{preset_name}」已更新。")

    def _set_crm_filter_default_preset(self, preset_name=None):
        """切换默认方案：已是默认则取消，否则设为默认"""
        if not preset_name:
            preset_name = getattr(self, '_crm_active_preset_name', None)
        if not preset_name:
            QMessageBox.information(self, "提示", "请先在方案列表中选择一个方案。")
            return
        current_default = self.config.get('fxiaoke', {}).get('crm_filter_default_preset', '')
        if current_default == preset_name:
            self.config.setdefault('fxiaoke', {})['crm_filter_default_preset'] = ''
            save_config(self.config)
            self._update_crm_preset_btn_label()
        else:
            presets = self.config.get('fxiaoke', {}).get('crm_filter_presets', [])
            if not isinstance(presets, list) or not any(p.get('name') == preset_name for p in presets):
                QMessageBox.information(self, "提示", "请先在方案列表中选择一个方案。")
                return
            self.config.setdefault('fxiaoke', {})['crm_filter_default_preset'] = preset_name
            save_config(self.config)
            self._update_crm_preset_btn_label()

    def _rename_crm_filter_preset(self, preset_name=None):
        """重命名指定方案"""
        if not preset_name:
            preset_name = getattr(self, '_crm_active_preset_name', None)
        if not preset_name:
            QMessageBox.information(self, "提示", "请先在方案列表中选择一个方案。")
            return
        presets = self.config.get('fxiaoke', {}).get('crm_filter_presets', [])
        if not isinstance(presets, list):
            return
        idx = next((i for i, p in enumerate(presets) if p.get('name') == preset_name), None)
        if idx is None:
            return
        old_name = presets[idx].get('name', '')
        new_name, ok = QInputDialog.getText(self, "重命名方案", "请输入新名称：", text=old_name)
        if not ok or not new_name or not new_name.strip():
            return
        new_name = new_name.strip()
        # 更新方案名
        presets[idx]['name'] = new_name
        self.config.setdefault('fxiaoke', {})['crm_filter_presets'] = presets
        # 更新默认方案引用
        if self.config.get('fxiaoke', {}).get('crm_filter_default_preset') == old_name:
            self.config['fxiaoke']['crm_filter_default_preset'] = new_name
        save_config(self.config)
        self._crm_active_preset_name = new_name
        self._update_crm_preset_btn_label()  # was _refresh_crm_filter_preset_combo(new_name)

    # ===== 构建新筛选栏 UI =====

    def _build_crm_filter_bar(self):
        """构建 CRM 多条件筛选栏，返回 QVBoxLayout"""
        from PyQt6.QtWidgets import QGraphicsDropShadowEffect
        from PyQt6.QtCore import Qt

        filter_bar_layout = QVBoxLayout()
        filter_bar_layout.setSpacing(6)

        # ===== 第一行：筛选按钮 + 全字段搜索 + 方案管理 + 操作按钮 =====
        top_row = QHBoxLayout()
        top_row.setSpacing(8)

        # 筛选按钮（带计数徽标）- 移到搜索框前面
        self.crm_filter_toggle_btn = QPushButton("筛选")
        self.crm_filter_toggle_btn.setFixedHeight(32)
        self.crm_filter_toggle_btn.setStyleSheet("""
            QPushButton {
                border: 1px solid #D9D9D9; border-radius: 4px;
                padding: 4px 14px; font-size: 13px;
                background-color: #FFFFFF; color: #333;
            }
            QPushButton:hover { border-color: #1890FF; color: #1890FF; }
        """)
        self.crm_filter_toggle_btn.clicked.connect(self._toggle_crm_filter_panel)

        # 方案选择按钮（点击弹出方案列表）
        self.crm_filter_preset_btn = QPushButton("方案 ▼")
        self.crm_filter_preset_btn.setFixedHeight(30)
        self.crm_filter_preset_btn.setCursor(Qt.CursorShape.PointingHandCursor)
        self.crm_filter_preset_btn.setToolTip("选择筛选方案")
        self.crm_filter_preset_btn.setStyleSheet("""
            QPushButton {
                border: 1px solid #D9D9D9; border-radius: 4px;
                padding: 2px 10px; font-size: 12px; color: #333;
                background-color: #FFFFFF;
            }
            QPushButton:hover { border-color: #1890FF; color: #1890FF; }
        """)
        self.crm_filter_preset_btn.clicked.connect(self._show_crm_filter_preset_popup)
        self._crm_active_preset_name = None
        self._update_crm_preset_btn_label()
        top_row.addWidget(self.crm_filter_preset_btn)
        top_row.addWidget(self.crm_filter_toggle_btn)

        top_row.addSpacing(6)

        # 全字段搜索框（仿纷享销客：左侧字段选择器 + 分隔线 + 搜索输入）
        search_frame = QFrame()
        search_frame.setFixedHeight(32)
        search_frame.setMaximumWidth(280)  # 限制最大宽度为原来的约1/3
        search_frame.setStyleSheet("""
            QFrame {
                border: 1px solid #D9D9D9; border-radius: 4px;
                background-color: #FFFFFF;
            }
            QFrame:focus-within { border-color: #1890FF; }
        """)
        search_layout = QHBoxLayout(search_frame)
        search_layout.setContentsMargins(0, 0, 0, 0)
        search_layout.setSpacing(0)

        # 字段选择器（默认"全字段"，支持手动输入和模糊匹配）
        self.crm_search_field_combo = QComboBox()
        self.crm_search_field_combo.setEditable(True)
        self.crm_search_field_combo.setFixedWidth(120)
        self.crm_search_field_combo.setFixedHeight(30)
        self.crm_search_field_combo.setPlaceholderText("搜索字段…")
        # 添加CRM所有字段作为选项
        all_field_labels = self._build_crm_field_label_list()
        for label in all_field_labels:
            self.crm_search_field_combo.addItem(label, label)
        self.crm_search_field_combo.setCurrentText("全字段")
        # 模糊匹配补全器（PopupCompletion 避免 inline 补全干扰输入法 IME 组合）
        search_completer = QCompleter(all_field_labels, self)
        search_completer.setCaseSensitivity(Qt.CaseSensitivity.CaseInsensitive)
        search_completer.setFilterMode(Qt.MatchFlag.MatchContains)
        search_completer.setCompletionMode(QCompleter.CompletionMode.PopupCompletion)
        self.crm_search_field_combo.setCompleter(search_completer)
        self.crm_search_field_combo.setStyleSheet("""
            QComboBox {
                border: none; background: transparent;
                padding: 2px 4px 2px 8px; font-size: 12px; color: #666;
            }
            QComboBox:hover { color: #333; }
            QComboBox::drop-down { border: none; width: 16px; }
            QComboBox QAbstractItemView {
                border: 1px solid #D9D9D9;
                border-radius: 4px;
                background-color: #FFFFFF;
                selection-background-color: #E6F7FF;
                selection-color: #1890FF;
            }
        """)
        self.crm_search_field_combo.currentIndexChanged.connect(self._update_crm_search_input_mode)
        search_layout.addWidget(self.crm_search_field_combo)

        # 分隔线
        sep = QFrame()
        sep.setFrameShape(QFrame.Shape.VLine)
        sep.setStyleSheet("border: none; background-color: #E8E8E8; min-width: 1px; max-width: 1px;")
        search_layout.addWidget(sep)

        # 搜索输入区域（文本 / 日期范围切换）
        self.crm_search_stack = QStackedWidget()
        self.crm_search_stack.setMaximumWidth(180)

        # Page 0: 文本搜索
        self.crm_search_input = QLineEdit()
        self.crm_search_input.setPlaceholderText("搜索")
        self.crm_search_input.setFixedHeight(30)
        self.crm_search_input.setMaximumWidth(180)
        self.crm_search_input.setStyleSheet("""
            QLineEdit {
                border: none; background: transparent;
                padding: 2px 8px; font-size: 13px;
            }
        """)
        self.crm_search_input.textChanged.connect(self.on_crm_table_search)
        self.crm_search_stack.addWidget(self.crm_search_input)

        # Page 1: 日期范围搜索
        self.crm_search_date_btn = QPushButton("选择日期范围")
        self.crm_search_date_btn.setFixedHeight(30)
        self.crm_search_date_btn.setMaximumWidth(180)
        self.crm_search_date_btn.setCursor(Qt.CursorShape.PointingHandCursor)
        self.crm_search_date_btn.setStyleSheet("""
            QPushButton {
                border: none; background: transparent;
                padding: 2px 8px; font-size: 12px; color: #999;
            }
            QPushButton:hover { color: #1890FF; }
        """)
        self.crm_search_date_btn.setProperty('crm_date_range', {'start': None, 'end': None})
        self.crm_search_date_btn.clicked.connect(lambda: self._open_crm_search_date_range())
        self.crm_search_stack.addWidget(self.crm_search_date_btn)

        search_layout.addWidget(self.crm_search_stack, stretch=1)

        top_row.addWidget(search_frame)
        top_row.addStretch()

        # ✅ CRM输出格式选择
        keep_crm_format = self.config.get('app_settings', {}).get('keep_crm_output_format', 'word_pdf')
        self.crm_keep_format_combo = QComboBox()
        self.crm_keep_format_combo.addItems(["Word+PDF", "Word", "PDF"])
        crm_fmt_map = {"word_pdf": "Word+PDF", "word": "Word", "pdf": "PDF"}
        self.crm_keep_format_combo.setCurrentText(crm_fmt_map.get(keep_crm_format, "Word+PDF"))
