    def _on_usergroup_search(self):
        """搜索框输入变化"""
        self._usergroup_populate_table()

    def _on_usergroup_manual_refresh(self):
        """手动刷新数据"""
        self.usergroup_refresh_btn.setText("⏳ 加载中...")
        self.usergroup_refresh_btn.setEnabled(False)
        self._usergroup_fetch_data()

    def _usergroup_fetch_data(self):
        """获取部门下成员信息"""
        dept_id_str = self.usergroup_group_id_input.text().strip() if hasattr(self, 'usergroup_group_id_input') else "999999"
        if not dept_id_str:
            self.usergroup_all_data = []
            if hasattr(self, 'usergroup_status_label'):
                self.usergroup_status_label.setText("⚠️ 请输入部门ID")
            return
        try:
            department_id = int(dept_id_str)
        except ValueError:
            self.usergroup_all_data = []
            if hasattr(self, 'usergroup_status_label'):
                self.usergroup_status_label.setText("⚠️ 部门ID必须为整数")
            return

        if hasattr(self, 'usergroup_status_label'):
            self.usergroup_status_label.setText("⏳ 正在加载...")
        if hasattr(self, 'usergroup_source_label'):
            self.usergroup_source_label.setText("☁️ CRM API 加载中...")

        # 使用 BackgroundTaskManager 确保线程安全（替代原始 threading.Thread）
        self.task_manager.start(
            'usergroup_fetch',
            '部门员工加载',
            self._usergroup_fetch_worker,
            department_id
        )

    def _usergroup_fetch_worker(self, department_id):
        """后台线程：获取部门成员和部门列表（不直接操作 GUI）"""
        cfg = load_config()
        fx_cfg = cfg.get('fxiaoke', {})

        crm = FXiaokeCRM(
            app_id=fx_cfg.get('app_id', 'FSAID_1323c1a'),
            app_secret=fx_cfg.get('app_secret', 'e7f4188d14704299b375c91ddda92cb0'),
            permanent_code=fx_cfg.get('permanent_code', 'E8B8D8536B0385D035657AC2528928F0'),
            admin_mobile=fx_cfg.get('admin_mobile', '15889740213')
        )

        # 并行获取用户列表和部门列表
        rows, err = crm.query_user_list(department_id=department_id, fetch_child=True, show_department_detail=True)
        dept_list, dept_err = crm.query_department_list(department_id=999999, fetch_child=True)

        if err:
            self.usergroup_all_data = []
            self.usergroup_dept_map = {}
            self._usergroup_error_msg = str(err)
            self.usergroup_data_ready.emit('usergroup')
            self.update_output.emit(f"[部门员工] 加载失败: {err}")
            return

        # 构建 部门ID → 部门名称 映射
        dept_map = {}
        if dept_err:
            self.update_output.emit(f"[部门员工] 部门列表加载失败: {dept_err}")
        elif dept_list:
            for d in dept_list:
                if isinstance(d, dict):
                    did = d.get('id')
                    dname = d.get('name', '')
                    if did is not None:
                        dept_map[int(did)] = dname
            self.update_output.emit(f"[部门员工] 部门列表加载完成: {len(dept_map)} 个部门")

        self.usergroup_all_data = rows if rows else []
        self.usergroup_dept_map = dept_map
        self._usergroup_error_msg = ''
        self.usergroup_data_ready.emit('usergroup')

    def _usergroup_populate_table_safe(self, page_type):
        """在主线程中安全地填充表格"""
        if hasattr(self, 'usergroup_refresh_btn'):
            self.usergroup_refresh_btn.setText("🔄 刷新")
            self.usergroup_refresh_btn.setEnabled(True)

        data = getattr(self, 'usergroup_all_data', [])
        error_msg = getattr(self, '_usergroup_error_msg', '')

        if error_msg:
            if hasattr(self, 'usergroup_status_label'):
                self.usergroup_status_label.setText(f"❌ 加载失败")
            if hasattr(self, 'usergroup_source_label'):
                self.usergroup_source_label.setText("❌ 加载失败")
            return

        if hasattr(self, 'usergroup_status_label'):
            self.usergroup_status_label.setText(f"✅ 已加载 {len(data)} 条记录")
        if hasattr(self, 'usergroup_source_label'):
            self.usergroup_source_label.setText(f"☁️ CRM API | {len(data)} 条")

        try:
            self._usergroup_populate_table()
        except Exception as e:
            print(f"[ERROR-部门员工] ❌ 表格填充失败: {e}")
            import traceback
            traceback.print_exc()

        # 自动同步 MySQL
        if data and self._get_usergroup_sync_mode() == 'auto':
            self.update_output.emit(f"[部门员工] 自动同步 MySQL 开始: {len(data)} 条")
            self.task_manager.start(
                'mysql_sync_usergroup',
                'MySQL同步: 部门员工',
                self._do_usergroup_sync_to_mysql_bg,
                data
            )

    # 字段名 → 中文表头映射
    USER_FIELD_CN_MAP = {
        'openUserId': '员工ID',
        'account': '账号',
        'name': '姓名',
        'nickName': '昵称',
        'isStop': '状态',
        'email': '邮箱',
        'mobile': '手机',
        'gender': '性别',
        'position': '职位',
        'profileImageUrl': '头像',
        'departmentIds': '所属部门',
        'employeeNumber': '工号',
        'hireDate': '入职日期',
        'birthDate': '生日',
        'startWorkDate': '参加工作日期',
        'createTime': '创建时间',
        'leaderId': '汇报对象',
        'qq': 'QQ',
        'weixin': '微信',
        'mainDepartmentId': '主属部门',
        'attachingDepartmentIds': '附属部门',
    }

    def _clean_user_value(self, field, val, id_name_map=None, dept_map=None):
        """清洗用户字段值"""
        if val is None:
            return ''
        if field == 'isStop':
            return '离职' if val else '在职'
        if field == 'gender':
            return '男' if val == 'M' else '女' if val == 'F' else str(val)
        if field == 'createTime' and isinstance(val, (int, float)):
            from datetime import datetime
            try:
                return datetime.fromtimestamp(val / 1000).strftime('%Y-%m-%d %H:%M')
            except Exception:
                return str(val)
        if field == 'leaderId':
            if id_name_map and val in id_name_map:
                return id_name_map[val]
            return str(val)
        if field == 'departmentIds' and isinstance(val, list):
            if dept_map:
                return ', '.join(dept_map.get(int(v), str(v)) for v in val)
            return ', '.join(str(v) for v in val)
        if field in ('mainDepartmentId', 'attachingDepartmentIds'):
            if dept_map:
                if isinstance(val, list):
                    return ', '.join(dept_map.get(int(v), str(v)) for v in val)
                return dept_map.get(int(val), str(val))
            return str(val) if not isinstance(val, list) else ', '.join(str(v) for v in val)
        if isinstance(val, list):
            return ', '.join(str(v) for v in val)
        if isinstance(val, dict):
            return val.get('name', str(val))
        return str(val)

    def _get_user_cn_header(self, field):
        """获取字段的中文表头"""
        return self.USER_FIELD_CN_MAP.get(field, field)

    def _usergroup_populate_table(self):
        """填充用户组表格（中文表头 + 数据清洗）"""
        data = getattr(self, 'usergroup_all_data', [])
        table = self.usergroup_table

        if not data:
            table.setColumnCount(0)
            table.setRowCount(0)
            return

        meta_keys = {'_id', '_from_mapped_cache', 'mapped_at'}
        all_fields = []
        for row in data:
            for key in row.keys():
                if key not in all_fields and key not in meta_keys:
                    all_fields.append(key)

        all_fields_sorted = sorted(all_fields, key=lambda f: (not f.startswith('_'), f.lower()))

        api_name = 'usergroup'
        vis, order = self._load_usergroup_field_settings(api_name)
        # 默认按常用字段顺序
        default_order = ['name', 'mobile', 'position', 'isStop', 'gender', 'email',
                         'departmentIds', 'employeeNumber', 'hireDate', 'leaderId',
                         'account', 'nickName', 'openUserId', 'birthDate', 'startWorkDate',
                         'createTime', 'profileImageUrl', 'qq', 'weixin']
        visible_labels = vis if vis else default_order
        if order:
            ordered = [f for f in order if f in all_fields_sorted]
            remaining = [f for f in all_fields_sorted if f not in ordered]
            all_fields_sorted = ordered + remaining
        else:
            ordered = [f for f in default_order if f in all_fields_sorted]
            remaining = [f for f in all_fields_sorted if f not in ordered]
            all_fields_sorted = ordered + remaining

        visible_fields = [f for f in visible_labels if f in all_fields_sorted]
        if not visible_fields:
            visible_fields = list(all_fields_sorted)

        # 搜索过滤（搜索中文显示值）
        search_text = self.usergroup_search_input.text().strip().lower()
        search_api_field = self.usergroup_search_field.currentData() or ''
        _search_id_map = {r.get('openUserId'): r.get('name', '') for r in data if r.get('openUserId')}
        _search_dept_map = getattr(self, 'usergroup_dept_map', {})
        filtered = list(data)
        if search_text:
            if search_api_field:
                filtered = [r for r in filtered if search_text in self._clean_user_value(search_api_field, r.get(search_api_field), _search_id_map, _search_dept_map).lower()]
            else:
                filtered = [r for r in filtered if any(search_text in self._clean_user_value(k, v, _search_id_map, _search_dept_map).lower() for k, v in r.items())]

        # 更新搜索字段下拉框（中文显示）
        current_search = self.usergroup_search_field.currentData()
        self.usergroup_search_field.blockSignals(True)
        self.usergroup_search_field.clear()
        self.usergroup_search_field.addItem("全字段", "")
        for f in visible_fields:
            self.usergroup_search_field.addItem(self._get_user_cn_header(f), f)
        for i in range(self.usergroup_search_field.count()):
            if self.usergroup_search_field.itemData(i) == current_search:
                self.usergroup_search_field.setCurrentIndex(i)
                break
        if self.usergroup_search_field.currentIndex() < 0:
            self.usergroup_search_field.setCurrentIndex(0)
        self.usergroup_search_field.blockSignals(False)

        # 构建 openUserId → 姓名 映射（用于转换汇报对象等）
        id_name_map = {r.get('openUserId'): r.get('name', '') for r in data if r.get('openUserId')}
        # 获取部门ID → 部门名称映射
        dept_map = getattr(self, 'usergroup_dept_map', {})

        # 填充表格（中文表头 + 清洗数据）
        cn_headers = [self._get_user_cn_header(f) for f in visible_fields]
        table.setColumnCount(len(visible_fields))
        table.setHorizontalHeaderLabels(cn_headers)
        table.setRowCount(len(filtered))

        for row_idx, row_data in enumerate(filtered):
            for col_idx, field in enumerate(visible_fields):
                val = self._clean_user_value(field, row_data.get(field), id_name_map, dept_map)
                item = QTableWidgetItem(val)
                item.setToolTip(val)
                table.setItem(row_idx, col_idx, item)

        table.resizeColumnsToContents()

    def _open_usergroup_column_settings(self):
        """打开字段显示设置（中文标签）"""
        data = getattr(self, 'usergroup_all_data', [])
        if not data:
            return

        meta_keys = {'_id', '_from_mapped_cache', 'mapped_at'}
        all_api_fields = []
        for row in data:
            for key in row.keys():
                if key not in all_api_fields and key not in meta_keys:
                    all_api_fields.append(key)

        # 用中文标签显示
        cn_labels = [self._get_user_cn_header(f) for f in all_api_fields]
        # 建立中文→API 映射
        cn_to_api = {self._get_user_cn_header(f): f for f in all_api_fields}

        api_name = 'usergroup'
        vis, order = self._load_usergroup_field_settings(api_name)
        # visible/order 存的是 API 字段名，转为中文显示
        current_visible = [self._get_user_cn_header(f) for f in vis] if vis else list(cn_labels)
        header_order = [self._get_user_cn_header(f) for f in order] if order else list(cn_labels)

        dialog = ExcelFieldSettingsDialog(cn_labels, visible_headers=current_visible, header_order=header_order, parent=self)
        if dialog.exec() == QDialog.DialogCode.Accepted:
            new_vis_cn, new_order_cn = dialog.get_settings()
            # 转回 API 字段名保存
            new_vis = [cn_to_api.get(h, h) for h in new_vis_cn if h in cn_to_api]
            new_order = [cn_to_api.get(h, h) for h in new_order_cn if h in cn_to_api]
            self._save_usergroup_field_settings(api_name, new_vis, new_order)
            self._usergroup_populate_table()

    # ===== MySQL 同步 =====
    def _get_usergroup_sync_mode(self):
        """获取当前同步模式"""
        if hasattr(self, 'usergroup_sync_mode_combo'):
            return self.usergroup_sync_mode_combo.currentData() or 'auto'
        return self.config.get('fxiaoke', {}).get('usergroup_sync_mode', 'auto')

    def _on_usergroup_sync_mode_changed(self):
        """同步模式切换"""
        mode = self._get_usergroup_sync_mode()
        cfg = load_config()
        cfg.setdefault('fxiaoke', {})['usergroup_sync_mode'] = mode
        save_config_with_delay(cfg)

    def _on_usergroup_sync_to_mysql(self):
        """手动同步到 MySQL"""
        data = getattr(self, 'usergroup_all_data', [])
        if not data:
            from PyQt6.QtWidgets import QMessageBox
            QMessageBox.information(self, "提示", "当前没有数据可同步。")
            return
        if hasattr(self, 'usergroup_sync_btn'):
            self.usergroup_sync_btn.setText("⏳")
            self.usergroup_sync_btn.setEnabled(False)
        self.update_output.emit(f"[部门员工] 手动同步 MySQL 开始: {len(data)} 条")
        self.task_manager.start(
            'mysql_sync_usergroup',
            'MySQL同步: 部门员工',
            self._do_usergroup_sync_to_mysql_bg,
            data
        )

    def _do_usergroup_sync_to_mysql_bg(self, data):
        """后台执行 MySQL 同步（清洗表）"""
        try:
            mc = MysqlCache()
            if not mc.available:
                self.update_output.emit("[部门员工] MySQL 未启用，跳过同步")
                mc.close()
                return False, "MySQL 未启用"

            # 构建清洗数据：中文表头 + 清洗值
            id_name_map = {r.get('openUserId'): r.get('name', '') for r in data if r.get('openUserId')}
            dept_map = getattr(self, 'usergroup_dept_map', {})
            fields = [f for f in data[0].keys() if f not in {'_id', '_from_mapped_cache', 'mapped_at'}] if data else []
            cn_headers = [self._get_user_cn_header(f) for f in fields]
            cleaned_rows = []
            for row in data:
                cleaned_row = {'_id': row.get('openUserId', '')}
                for f in fields:
                    cn = self._get_user_cn_header(f)
                    cleaned_row[cn] = self._clean_user_value(f, row.get(f), id_name_map, dept_map)
                cleaned_rows.append(cleaned_row)

            table_name = "部门员工"
            ok, msg = mc.replace_cleaned_all(table_name, cleaned_rows, cn_headers, cleanup_old=False)
            mc.close()
            if ok:
                self.update_output.emit(f"[部门员工] MySQL 同步完成: '{table_name}' {msg}")
                if hasattr(self, 'usergroup_sync_btn'):
                    self.usergroup_sync_btn.setText("同步")
                    self.usergroup_sync_btn.setEnabled(True)
                return True, ""
            else:
                self.update_output.emit(f"[部门员工] MySQL 同步失败: {msg}")
                if hasattr(self, 'usergroup_sync_btn'):
                    self.usergroup_sync_btn.setText("同步")
                    self.usergroup_sync_btn.setEnabled(True)
                return False, msg
        except Exception as e:
            self.update_output.emit(f"[部门员工] MySQL 同步异常: {str(e)[:80]}")
            logging.error(f"[部门员工] MySQL 同步失败: {e}")
            if hasattr(self, 'usergroup_sync_btn'):
                self.usergroup_sync_btn.setText("同步")
                self.usergroup_sync_btn.setEnabled(True)
            return False, str(e)[:200]

    def _load_usergroup_field_settings(self, api_name):
        """加载用户组页面的字段显示设置"""
        settings = self.config.get('app_settings', {}).get('usergroup_field_settings', {}).get(api_name, {})
        visible = settings.get('visible_headers', None)
        order = settings.get('header_order', None)
        return visible if visible else None, order if order else None

    def _save_usergroup_field_settings(self, api_name, visible_headers, header_order):
        """保存用户组页面的字段显示设置到配置文件"""
        config = load_config()
        config.setdefault('app_settings', {}).setdefault('usergroup_field_settings', {})
        config['app_settings']['usergroup_field_settings'][api_name] = {
            'visible_headers': list(visible_headers),
            'header_order': list(header_order),
        }
        save_config_with_delay(config)
        self.config = config

    def switch_to_page(self, index):
        """切换到指定页面"""
        # 权限检查：普通用户不能访问管理员页面
        is_admin_user = (user_type == "admin" or current_user in ("Zengjiataoadmin", "001"))
        restricted_pages = {2, 5, 7, 8}  # 自定义报表、对象查询、BI报表、部门员工（仅管理员）
        if index in restricted_pages and not is_admin_user:
            return

        flush_pending_config()

        # ✅【2026-05-12 修复】页面名称列表必须与 content_stack 的创建顺序一致
        # 创建顺序（见第6911-6917行）：
        # 0:文件生成, 1:CRM订单, 2:自定义报表, 3:文件移动, 4:PDF水印, 5:对象查询, 6:设置
        page_names = ["文件生成", "订单转合同", "自定义报表", "文件移动", "PDF水印", "对象查询", "设置", "BI 报表", "部门员工"]
        page_name = page_names[index] if index < len(page_names) else f"页面{index}"

        if index == 6:  # 设置页面
            if getattr(self, 'output_visible', False):
                self.on_toggle_output()
                self.output_auto_hidden_by_settings = True
            # ✅ 每次切换到设置页面时，刷新当前对象的加载条数等设置（确保与对象查询页面一致）
            if hasattr(self, 'settings_dialog'):
                dlg = self.settings_dialog
                api_name = dlg._get_current_settings_api_name()
                if api_name and hasattr(dlg, '_load_obj_query_settings'):
                    dlg._load_obj_query_settings(api_name)
        elif getattr(self, 'output_auto_hidden_by_settings', False):
            if not getattr(self, 'output_visible', True):
                self.on_toggle_output()
            self.output_auto_hidden_by_settings = False

        # ✅【新增】CRM订单首次自动加载检测
        if index == 1:  # CRM订单页面
            if not getattr(self, '_crm_first_load_completed', False):
                print(f"\n[DEBUG-CRM] 🎯 首次进入CRM订单页面，自动加载数据...")
                self._crm_first_load_completed = True
                from PyQt6.QtCore import QTimer
                QTimer.singleShot(100, self._crm_first_auto_load)

        # 招投标授权首次自动加载检测
        if index == 4:  # 招投标授权页面
            if not getattr(self, '_opportunity_first_load_completed', False):
                self._opportunity_first_load_completed = True
                from PyQt6.QtCore import QTimer
                QTimer.singleShot(200, self._opportunity_first_auto_load)

        # ✅【2026-05-12 修复】对象查询首次自动加载检测 - 修正为index=5
        if index == 5:  # 对象查询页面
            if not getattr(self, '_obj_query_first_auto_load_done', False):
                print(f"\n[DEBUG-对象查询] 🎯 首次进入对象查询页面，准备自动加载数据...")
                self._obj_query_first_auto_load_done = True

                # 检查是否有默认对象配置
                fx_cfg = getattr(self, 'config', {}).get('fxiaoke', {})
                default_obj_api = fx_cfg.get('default_obj_query_object', '')

                # ✅【关键修复】如果无默认对象配置，使用第一个有效对象
                if not default_obj_api:
                    print(f"[DEBUG-对象查询] ℹ️ 未配置默认对象，尝试使用第一个有效对象")
                    for i in range(1, self.obj_query_object_combo.count()):  # 跳过索引0（"请选择对象"）
                        first_api = self.obj_query_object_combo.itemData(i)
                        if first_api:
                            default_obj_api = first_api
                            print(f"[DEBUG-对象查询] ✅ 使用第一个对象: '{default_obj_api}' ({self.obj_query_object_combo.itemText(i)})")
                            break

                if default_obj_api:
                    # 有默认对象 → 延迟自动加载（确保UI完全渲染）
                    from PyQt6.QtCore import QTimer

                    def _auto_load_default_obj():
                        """延迟加载默认对象数据"""
                        print(f"[DEBUG-对象查询] 🚀 自动加载默认对象 | API: '{default_obj_api}'")

                        # 检查当前选择的对象是否是默认对象
                        current_api = self.obj_query_object_combo.currentData() or ''

                        if current_api != default_obj_api:
                            # 当前选中的不是默认对象 → 切换到默认对象（会触发_on_obj_query_object_changed）
                            for i in range(self.obj_query_object_combo.count()):
                                if self.obj_query_object_combo.itemData(i) == default_obj_api:
                                    self.obj_query_object_combo.setCurrentIndex(i)
                                    break
                        else:
                            # 已经选中默认对象 → 带筛选条件加载
                            self._pending_obj_query_api = default_obj_api
                            self._do_obj_query_load(default_obj_api)

                    # 延迟200ms确保UI完全就绪
                    QTimer.singleShot(200, _auto_load_default_obj)
                else:
                    # 无可用对象 → 提示用户
                    print(f"[DEBUG-对象查询] ⚠️ 无可用的业务对象")
                    if hasattr(self, 'obj_query_status_label'):
                        self.obj_query_status_label.setText("⚠️ 请先在设置中添加业务对象")
            elif getattr(self, '_obj_query_filters_dirty', False):
                # ✅ 筛选条件在设置中已修改 → 清除缓存并重新加载
                print(f"[DEBUG-对象查询] 🔄 检测到筛选条件变更，清除缓存并重新加载")
                self._obj_query_filters_dirty = False
                if hasattr(self, '_obj_query_mem_cache'):
                    self._obj_query_mem_cache.clear()
                current_api = self.obj_query_object_combo.currentData() or ''
                if current_api:
                    self._reset_obj_query_field_mapping()
                    self._pending_obj_query_api = current_api
                    self._do_obj_query_load(current_api)

            # ✅ 每次切换到对象查询页面时，从配置同步加载条数（确保与设置页面一致）
            self._sync_load_count_spin_from_config()
            # ✅【新增】每次切换到对象查询页面时，同步加载快捷筛选条件
            if hasattr(self, 'obj_query_object_combo'):
                current_api = self.obj_query_object_combo.currentData() or ''
                if current_api:
                    self._load_quick_filters_for_object(current_api)

        # ✅ 部门员工页面首次自动加载检测
        if index == 8:  # 部门员工页面
            if not getattr(self, '_usergroup_first_load_done', False):
                print(f"\n[DEBUG-部门员工] 🎯 首次进入部门员工页面，自动加载数据...")
                self._usergroup_first_load_done = True
                from PyQt6.QtCore import QTimer
                QTimer.singleShot(200, self._usergroup_fetch_data)

        if hasattr(self, 'content_stack'):
            self.setUpdatesEnabled(False)
            self.content_stack.setCurrentIndex(index)
            self.setUpdatesEnabled(True)
            # 切换到自定义报表时刷新列表 + 编辑器数据源
            if index == 2:
                if hasattr(self, 'custom_report_list_page'):
                    try:
                        self.custom_report_list_page.refresh()
                    except Exception:
                        pass
                # 同时刷新编辑器数据源选项（MySQL 配置变更后无需重启）
                if hasattr(self, '_refresh_custom_report_main_source_options'):
                    try:
                        self._refresh_custom_report_main_source_options()
                    except Exception:
                        pass
                if hasattr(self, '_refresh_custom_report_field_source_options'):
                    try:
                        self._refresh_custom_report_field_source_options()
                    except Exception:
                        pass
            # 切换到 BI 报表时刷新数据（同步自定义报表更新）
            if index == 7 and hasattr(self, 'bi_dashboard_page_stack'):
                try:
                    mgr = getattr(self, '_report_manager', None)
                    current_widget = self.bi_dashboard_page_stack.currentWidget()
                    if mgr and current_widget:
                        # 如果是查看页，刷新查看页数据
                        if (self.bi_dashboard_view_page
                                and current_widget is self.bi_dashboard_view_page
                                and self.bi_dashboard_view_page._dashboard):
                            dashboard = self.bi_dashboard_view_page._dashboard
                            data_map = mgr.query_all_chart_data(dashboard)
                            self.bi_dashboard_view_page.load_dashboard(dashboard, data_map)
                        # 如果是设计器，刷新设计器数据
                        elif (self.bi_dashboard_designer_page
                              and current_widget is self.bi_dashboard_designer_page
                              and self.bi_dashboard_designer_page._dashboard):
                            dashboard = self.bi_dashboard_designer_page._dashboard
                            data_map = mgr.query_all_chart_data(dashboard)
                            self.bi_dashboard_designer_page.refresh_data(data_map)
                        # 列表页刷新
                        elif hasattr(self, 'bi_dashboard_list_page'):
                            self.bi_dashboard_list_page.refresh()
                except Exception:
                    pass

        if hasattr(self, 'nav_items_info'):
            for item in self.nav_items_info:
                item['btn'].setChecked(item.get('page_idx') == index)
    
    def _crm_first_auto_load(self):
        """CRM订单首次自动加载"""
        print("[DEBUG-CRM] 🚀 执行首次自动加载...")
        self.on_crm_manual_refresh()  # 调用手动刷新方法加载数据

    def _opportunity_first_auto_load(self):
        """招投标授权首次自动加载商机数据"""
        print("[DEBUG-商机] 🚀 执行首次自动加载商机数据...")
        if hasattr(self, 'on_refresh_opportunity_data'):
            self.on_refresh_opportunity_data()
    
    def toggle_navigation(self):
        """切换导航栏的展开/折叠状态"""
        self.nav_expanded = not self.nav_expanded

        # 记录导航栏状态变更
        status = "展开" if self.nav_expanded else "折叠"
        operation_log.info(f"导航栏{status}")

        self._apply_navigation_width()

        if self.nav_expanded:
            self.toggle_nav_btn.setText("◀ ◀")
            if hasattr(self, 'nav_items_info'):
                for item in self.nav_items_info:
                    item['btn'].setText(f"{item['icon']}  {item['name']}")
            if hasattr(self, 'toggle_output_btn'):
                self.toggle_output_btn.setVisible(True)
            if hasattr(self, 'clear_btn'):
                self.clear_btn.setVisible(True)
            if hasattr(self, 'sub_output_frame'):
                self.sub_output_frame.setVisible(not self.output_visible)
        else:
            self.toggle_nav_btn.setText("▶ ▶")
            if hasattr(self, 'nav_items_info'):
                for item in self.nav_items_info:
                    item['btn'].setText(item['icon'])
            if hasattr(self, 'toggle_output_btn'):
                self.toggle_output_btn.setVisible(False)
            if hasattr(self, 'clear_btn'):
                self.clear_btn.setVisible(False)
            if hasattr(self, 'sub_output_frame'):
                self.sub_output_frame.setVisible(False)

    def set_navbar_visible(self, visible):
        """显示或隐藏导航栏"""
        if hasattr(self, 'left_panel'):
            self.left_panel.setVisible(visible)
        self._navbar_visible = visible

    def set_navbar_position(self, position):
        """切换导航栏位置：'left' 或 'right'"""
        if position == self._navbar_position:
            return
        self._navbar_position = position
        main_layout = self.centralWidget().layout()
        if not main_layout:
            return
        main_layout.removeWidget(self.left_panel)
        if position == 'left':
            main_layout.insertWidget(0, self.left_panel)
        else:
            main_layout.addWidget(self.left_panel)

    def set_navbar_default_expanded(self, expanded):
        """设置导航栏默认展开状态（立即生效）"""
        self._navbar_default_expanded = expanded
        if self.nav_expanded != expanded:
            self.toggle_navigation()

    def _rebuild_nav_buttons(self, select_first=False):
        """根据配置重建导航按钮（更新顺序和可见性）

        Args:
            select_first: True=启动时选中第一个按钮并切换页面，False=保持当前页面选中
        """
        if not hasattr(self, 'nav_buttons_layout'):
            return

        # 1. 清空按钮子布局
        while self.nav_buttons_layout.count():
            item = self.nav_buttons_layout.takeAt(0)
            if item.widget():
                item.widget().deleteLater()

        self.nav_buttons.clear()
        self.nav_items_info.clear()

        # 2. 读取配置
        app_settings = self.config.get('app_settings', {})
        button_order = list(app_settings.get('nav_button_order', [0, 1, 2, 3, 4, 5, 6, 7, 8]))
        button_visible = dict(app_settings.get('nav_button_visible', {str(i): True for i in range(9)}))

        # 兼容旧配置：确保新页面 7、8 始终存在
        for pi in (7, 8):
            if pi not in button_order:
                button_order.append(pi)
            if str(pi) not in button_visible:
                button_visible[str(pi)] = True

        is_admin = (user_type == "admin" or current_user in ("Zengjiataoadmin", "001"))

        # 3. page_idx → (icon, name) 映射
        item_map = {
            0: ("📄", "文件生成"),
            1: ("📋", "订单转合同"),
            2: ("📊", "自定义报表"),
            3: ("📁", "文件移动"),
            4: ("🔖", "招投标授权"),
            5: ("📦", "对象查询"),
            6: ("⚙️", "设   置"),
            7: ("📈", "BI 报表"),
            8: ("🏢", "部门员工"),
        }

        # 4. 按配置顺序创建按钮
        for page_idx in button_order:
            if page_idx in {2, 5, 7, 8} and not is_admin:
                continue
            if page_idx not in {6}:
                vis = button_visible.get(str(page_idx), True)
                if not vis:
                    continue

            icon, name = item_map.get(page_idx, ("?", "未知"))
            btn_text = f"{icon}  {name}" if self.nav_expanded else icon
            btn = QPushButton(btn_text)
            btn.setCheckable(True)
            btn.setMinimumHeight(10)
            btn.setCursor(Qt.CursorShape.PointingHandCursor)
            btn.setStyleSheet(get_nav_button_style(self.ui_scale_percent))
            btn.clicked.connect(lambda checked, idx=page_idx: self.switch_to_page(idx))

            self.nav_buttons_layout.addWidget(btn)
            self.nav_buttons.append(btn)
            self.nav_items_info.append({
                'icon': icon, 'name': name, 'btn': btn, 'page_idx': page_idx
            })

        # 5. 恢复选中状态
        if select_first and self.nav_items_info:
            first_page = self.nav_items_info[0]['page_idx']
            self.switch_to_page(first_page)
        else:
            current_idx = self.content_stack.currentIndex()
            for item in self.nav_items_info:
                item['btn'].setChecked(item['page_idx'] == current_idx)

        # 6. 折叠状态下按钮文本仅显示图标
        if not self.nav_expanded:
            for item in self.nav_items_info:
                item['btn'].setText(item['icon'])

    def apply_theme(self, theme_mode):
        """应用主题模式"""
        set_dialog_opacity(self)

    def on_radio_select(self, value):
        """单选按钮选择事件处理（兼容旧代码）"""
        self.selected_operation = value
        self._on_operation_changed(value)
    
    def on_operation_combo_changed(self, index):
        """下拉选项框变化事件处理"""
        if index < 0:
            return
        value = self.operation_combo.currentData()
        if value is None:
            self.selected_operation = None
            self.persist_contract_page_state()
            self._clear_data_table("请选择功能后加载数据")
            return
        self.selected_operation = value
        self.persist_contract_page_state()
        self._on_operation_changed(value)
    
    def _on_operation_changed(self, value):
        """功能选择变化的公共处理（使用缓存，不强制刷新）"""
        # ✅ 修复：切换功能时重置列宽应用标志，让新功能能正确加载自己的列宽
        self._data_table_column_widths_applied = False

        # 更新状态显示
        for option in self.gui_options:
            if option['value'] == value:
                operation_name = option['text']
                break
        else:
            operation_name = "未知操作"

        status_text = f"已选择: {operation_name}"
        self.append_output(status_text)

        # 加载Excel数据到表格（使用缓存，不强制刷新）
        self.load_excel_data_to_table(value, force_reload=False)

    def on_refresh_data(self):
        """刷新按钮 - 重新加载Excel数据（强制刷新，清除缓存）"""
        self._reset_contract_filters_and_selection()
        if hasattr(self, 'selected_operation') and self.selected_operation:
            # 清除该功能的缓存
            cache_key = str(self.selected_operation)
            if cache_key in getattr(self, '_data_cache', {}):
                del self._data_cache[cache_key]
            self.load_excel_data_to_table(self.selected_operation, force_reload=True)
            self.append_output("数据已刷新")

    def _reset_contract_filters_and_selection(self):
        """刷新文件生成时重置搜索、筛选和勾选状态"""
        if hasattr(self, '_search_timer') and self._search_timer.isActive():
            self._search_timer.stop()
        if hasattr(self, '_date_filter_timer') and self._date_filter_timer.isActive():
            self._date_filter_timer.stop()

        if hasattr(self, 'data_search_input'):
            self.data_search_input.blockSignals(True)
            self.data_search_input.clear()
            self.data_search_input.blockSignals(False)

        self.selected_filter_start_date = None
        self.selected_filter_end_date = None
        if hasattr(self, 'date_filter_button'):
            self.date_filter_button.setText("请选择日期范围")
        self._clear_all_data_conditions()
        self._refresh_data_exposed_tags()

        operation_value = getattr(self, 'selected_operation', None)
        if operation_value is not None:
            self._selected_row_ids_by_operation[str(operation_value)] = set()

        if hasattr(self, 'data_table'):
            self.data_table.clearSelection()
        if hasattr(self, 'table_header'):
            self.table_header.set_check_state(Qt.CheckState.Unchecked)

        self.current_page = 1
        self.persist_contract_page_state()

    # ===== 文件生成多条件筛选 =====

    def _get_data_filter_headers(self):
        """获取可筛选的字段列表"""
        # 优先从 current_source_headers 获取
        headers = getattr(self, 'current_source_headers', [])
        if headers:
            return [str(h).strip() for h in headers if h and str(h).strip()]
        # 回退：从表格列头获取
        result = []
        if hasattr(self, 'data_table') and self.data_table.columnCount() > 0:
            for col in range(self.data_table.columnCount()):
                item = self.data_table.horizontalHeaderItem(col)
                if item:
                    txt = item.text().strip()
                    if txt:
                        result.append(txt)
        return result

    def _is_data_date_field(self, field_label):
        """判断是否为日期/时间字段（模糊匹配：包含 日期/时间）"""
        if not field_label:
            return False
        label = str(field_label)
        return '日期' in label or '时间' in label

    def _toggle_data_filter_panel(self):
        """切换文件生成筛选面板（弹窗形式）"""
        if not hasattr(self, 'data_filter_panel'):
            return
        visible = not self.data_filter_panel.isVisible()
        if visible:
            self.data_filter_panel.setWindowFlags(Qt.WindowType.Dialog | Qt.WindowType.FramelessWindowHint)
            self.data_filter_panel.setVisible(True)
            self.data_filter_panel.raise_()
            self.data_filter_panel.activateWindow()
            # 更新字段下拉选项，调整面板高度
            self._refresh_data_search_field_combo()
            self._adjust_data_filter_panel_size()
            # 定位在搜索框下方
            search_frame = self.data_search_stack.parent()
            panel_w = self.data_filter_panel.width()
            panel_h = self.data_filter_panel.height()
            if search_frame:
                pos = search_frame.mapToGlobal(QPoint(0, search_frame.height()))
                x = pos.x()
                y = pos.y() + 4
            else:
                x = self.geometry().x() + 100
                y = self.geometry().y() + 80
            screen = self.screen()
            if screen:
                geo = screen.availableGeometry()
                x = max(geo.x() + 10, min(x, geo.right() - panel_w - 10))
                y = max(geo.y() + 10, min(y, geo.bottom() - panel_h - 10))
            self.data_filter_panel.move(x, y)
            # 外部点击关闭
            self.data_filter_panel.reject = lambda: self.data_filter_panel.setVisible(False)
            self.data_filter_panel._outside_close_armed = False
            pf = _DialogOutsideCloseFilter(self.data_filter_panel)
            self.data_filter_panel._outside_filter = pf
            QApplication.instance().installEventFilter(pf)
            QTimer.singleShot(0, lambda p=self.data_filter_panel: setattr(p, '_outside_close_armed', True))
            self.data_filter_panel.destroyed.connect(lambda obj, f=pf: QApplication.instance().removeEventFilter(f))
        else:
            self.data_filter_panel.setVisible(False)
        self._update_data_filter_toggle_btn()

    def _refresh_data_search_field_combo(self):
        """刷新搜索字段下拉选项"""
        # 优先使用 current_source_headers，回退到表格列头
        headers = getattr(self, 'current_source_headers', [])
        if not headers:
            headers = self._get_data_filter_headers()
        if hasattr(self, 'data_search_field_combo'):
            current = self.data_search_field_combo.currentData()
            self.data_search_field_combo.blockSignals(True)
            self.data_search_field_combo.clear()
            self.data_search_field_combo.addItem("全字段", "")
            for h in headers:
                h_str = str(h or '').strip()
                if h_str:
                    self.data_search_field_combo.addItem(h_str, h_str)
            idx = self.data_search_field_combo.findData(current)
            self.data_search_field_combo.setCurrentIndex(idx if idx >= 0 else 0)
            self.data_search_field_combo.blockSignals(False)

    def _update_data_search_field(self):
        """搜索字段切换：日期→时间段，其他→文本"""
        if not hasattr(self, 'data_search_stack'):
            return
        field = self.data_search_field_combo.currentText().strip()
        if self._is_data_date_field(field):
            self.data_search_stack.setCurrentIndex(1)
        else:
            self.data_search_stack.setCurrentIndex(0)

    def _open_data_search_date_range(self):
        """打开搜索栏日期范围选择"""
        btn = self.data_search_date_btn
        dr = btn.property('date_range') or {'start': None, 'end': None}
        dlg = QuickDatePickerDialog(start_date=dr.get('start'), end_date=dr.get('end'), parent=self)
        dlg.set_popup_anchor_widget(btn)
        if dlg.exec() == QDialog.DialogCode.Accepted and dlg.start_date and dlg.end_date:
            new_range = {'start': dlg.start_date, 'end': dlg.end_date}
            btn.setProperty('date_range', new_range)
            btn.setText(f"{dlg.start_date.toString('yyyy-MM-dd')} ~ {dlg.end_date.toString('yyyy-MM-dd')}")
            self.apply_search_filter_now()

    def _update_data_filter_toggle_btn(self):
        """更新筛选按钮计数"""
        count = len(getattr(self, 'data_condition_rows', []))
        if count > 0:
            self.data_filter_toggle_btn.setText(f"筛选({count})")
        else:
            self.data_filter_toggle_btn.setText("筛选")

    def _add_data_condition_row(self, condition=None):
        """添加一条数据筛选条件行（CRM 风格）"""
        condition = condition or {}
        row_frame = QFrame()
        row_frame.setFixedHeight(32)
        row_frame.setStyleSheet("QFrame { background: #F8F8F8; border: none; border-radius: 4px; }")
        row_layout = QHBoxLayout(row_frame)
        row_layout.setContentsMargins(6, 0, 6, 0)
        row_layout.setSpacing(5)

        del_btn = QPushButton("✕")
        del_btn.setFixedSize(20, 20)
        del_btn.setCursor(Qt.CursorShape.PointingHandCursor)
        del_btn.setStyleSheet("QPushButton { font-weight: bold; color: #FF4D4F; border: 1px solid #FFCCC7; border-radius: 10px; font-size: 11px; background: #FFF2F0; } QPushButton:hover { background: #FF4D4F; color: #FFF; }")
        row_layout.addWidget(del_btn, alignment=Qt.AlignmentFlag.AlignVCenter)

        field_combo = QComboBox()
        field_combo.setEditable(True)
        field_combo.setFixedWidth(140)
        field_combo.setFixedHeight(26)
        field_combo.setPlaceholderText("搜索字段…")
        field_combo.setStyleSheet("QComboBox { font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 4px; background: #FFF; } QComboBox QAbstractItemView { font-size: 12px; }")
        headers = self._get_data_filter_headers()
        for h in headers:
            field_combo.addItem(h, h)
        # 模糊匹配
        completer = QCompleter(headers, self)
        completer.setCaseSensitivity(Qt.CaseSensitivity.CaseInsensitive)
        completer.setFilterMode(Qt.MatchFlag.MatchContains)
        field_combo.setCompleter(completer)
        if condition.get('field'):
            idx = field_combo.findText(condition['field'])
            if idx >= 0:
                field_combo.setCurrentIndex(idx)
            else:
                field_combo.setEditText(condition['field'])
        row_layout.addWidget(field_combo, alignment=Qt.AlignmentFlag.AlignVCenter)

        op_combo = QComboBox()
        op_combo.setFixedWidth(95)
        op_combo.setFixedHeight(26)
        op_combo.setStyleSheet("QComboBox { font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 2px; background: #FFF; }")
        row_layout.addWidget(op_combo, alignment=Qt.AlignmentFlag.AlignVCenter)

        # 值区域：文本 / 日期切换
        value_stack = QStackedWidget()
        value_stack.setFixedHeight(26)

        value_input = QLineEdit()
        value_input.setFixedHeight(26)
        value_input.setPlaceholderText("值")
        value_input.setStyleSheet("font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 4px;")
        value_input.setText(str(condition.get('value', '')))
        value_stack.addWidget(value_input)  # Page 0: 文本

        date_input = QDateEdit()
        date_input.setCalendarPopup(True)
        date_input.setDisplayFormat("yyyy-MM-dd")
        date_input.setFixedHeight(26)
        date_input.setDate(QDate.currentDate())
        date_input.setStyleSheet("font-size: 12px; border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 2px;")
        if condition.get('value') and '~' not in str(condition['value']):
            parsed = QDate.fromString(str(condition['value'])[:10], "yyyy-MM-dd")
            if parsed.isValid():
                date_input.setDate(parsed)
        value_stack.addWidget(date_input)  # Page 1: 单日期

        date_range_btn = QPushButton("选择日期范围")
        date_range_btn.setFixedHeight(26)
        date_range_btn.setStyleSheet("QPushButton { border: 1px solid #D9D9D9; border-radius: 3px; padding: 2px 6px; font-size: 12px; }")
        range_data = {'start': None, 'end': None}
        if condition.get('operator') == 'date_range' and '~' in str(condition.get('value', '')):
            parts = str(condition['value']).split('~')
            if len(parts) == 2:
                s = QDate.fromString(parts[0].strip(), "yyyy-MM-dd")
                e = QDate.fromString(parts[1].strip(), "yyyy-MM-dd")
                if s.isValid() and e.isValid():
                    range_data = {'start': s, 'end': e}
                    date_range_btn.setText(f"{s.toString('yyyy-MM-dd')} ~ {e.toString('yyyy-MM-dd')}")
        date_range_btn.setProperty('date_range', range_data)
        date_range_btn.clicked.connect(lambda checked, btn=date_range_btn: self._open_data_date_range(btn))
        value_stack.addWidget(date_range_btn)  # Page 2: 时间段

        value_stack.setCurrentIndex(0)
        row_layout.addWidget(value_stack, stretch=1)

        # 外露 checkbox
        expose_check = QCheckBox("外露")
        expose_check.setChecked(bool(condition.get('expose', False)))
        expose_check.setToolTip("勾选后在表格上方显示该条件")
        expose_check.setStyleSheet("QCheckBox { font-size: 11px; color: #666; spacing: 1px; }")
        expose_check.toggled.connect(lambda checked: self._refresh_data_exposed_tags())
        row_layout.addWidget(expose_check, alignment=Qt.AlignmentFlag.AlignVCenter)

        self.data_conditions_layout.addWidget(row_frame)

        row_info = {
            'frame': row_frame,
            'field_combo': field_combo,
            'op_combo': op_combo,
            'value_stack': value_stack,
            'value_input': value_input,
            'date_input': date_input,
            'date_range_btn': date_range_btn,
            'expose_check': expose_check,
            '_saved_operator': condition.get('operator', ''),
        }
        self.data_condition_rows.append(row_info)
        del_btn.clicked.connect(lambda: self._remove_data_condition_row(row_info))

        def _on_data_field_changed(ri):
            ri['value_input'].clear()
            ri['date_input'].setDate(QDate.currentDate())
            ri['date_range_btn'].setText("选择日期范围")
            ri['date_range_btn'].setProperty('date_range', {'start': None, 'end': None})
            self._update_data_condition_input_mode(ri)
            self._apply_data_filters()

        field_combo.currentIndexChanged.connect(lambda idx, ri=row_info: _on_data_field_changed(ri))
        field_combo.editTextChanged.connect(lambda text, ri=row_info: _on_data_field_changed(ri))
        op_combo.currentIndexChanged.connect(lambda idx, ri=row_info: (self._update_data_condition_input_mode(ri), self._apply_data_filters()))
        value_input.textChanged.connect(lambda: self._apply_data_filters())
        date_input.dateChanged.connect(lambda d: self._apply_data_filters())

        # 首次设置操作符列表和输入模式
        self._update_data_condition_input_mode(row_info)
        self._apply_data_filters()
        self._update_data_filter_toggle_btn()
        self._adjust_data_filter_panel_size()

    def _update_data_condition_input_mode(self, row_info):
        """根据字段类型切换操作符和输入模式"""
        field_label = row_info['field_combo'].currentText().strip()
        is_date = self._is_data_date_field(field_label)
        op_combo = row_info['op_combo']
        current_op = op_combo.currentData() or row_info.get('_saved_operator', '')

        op_combo.blockSignals(True)
        op_combo.clear()
        if is_date:
            ops = [("等于", "eq"), ("不等于", "ne"), ("早于", "date_before"), ("晚于", "date_after"),
                   ("为空", "empty"), ("不为空", "not_empty"), ("时间段", "date_range")]
        else:
            ops = [("包含", "contains"), ("等于", "eq"), ("不等于", "ne"),
                   ("开头是", "starts_with"), ("结尾是", "ends_with"),
                   ("为空", "empty"), ("不为空", "not_empty")]
        for label, key in ops:
            op_combo.addItem(label, key)
        idx = op_combo.findData(current_op)
        if idx < 0 and is_date:
            idx = op_combo.findData('date_range')
        op_combo.setCurrentIndex(idx if idx >= 0 else 0)
        op_combo.blockSignals(False)

        operator = op_combo.currentData()
        vs = row_info['value_stack']
        if operator in ('empty', 'not_empty'):
            vs.setVisible(False)
        else:
            vs.setVisible(True)
            if is_date and operator == 'date_range':
                vs.setCurrentIndex(2)  # 时间段按钮
            elif is_date:
                vs.setCurrentIndex(1)  # 单日期选择器
            else:
                vs.setCurrentIndex(0)  # 文本输入

    def _open_data_date_range(self, btn):
        """打开日期范围选择弹窗"""
        dr = btn.property('date_range') or {'start': None, 'end': None}
        dlg = QuickDatePickerDialog(start_date=dr.get('start'), end_date=dr.get('end'), parent=self)
        dlg.set_popup_anchor_widget(btn)
        if dlg.exec() == QDialog.DialogCode.Accepted and dlg.start_date and dlg.end_date:
            new_range = {'start': dlg.start_date, 'end': dlg.end_date}
            btn.setProperty('date_range', new_range)
            btn.setText(f"{dlg.start_date.toString('yyyy-MM-dd')} ~ {dlg.end_date.toString('yyyy-MM-dd')}")
            self._apply_data_filters()

    def _adjust_data_filter_panel_size(self):
        """动态调整筛选面板高度"""
        if not hasattr(self, 'data_filter_panel'):
            return
        row_count = len(getattr(self, 'data_condition_rows', []))
        h = 36 + row_count * 32 + max(0, row_count - 1) * 4 + 44 + 24
        h = max(140, min(h, 500))
        self.data_filter_panel.setFixedHeight(h)

    def _apply_data_filter_and_close(self):
        """应用筛选并关闭弹窗"""
        self._apply_data_filters()
        self._refresh_data_exposed_tags()
        if hasattr(self, 'data_filter_panel'):
            self.data_filter_panel.setVisible(False)
        self._update_data_filter_toggle_btn()

    def _remove_data_condition_row(self, row_info):
        """移除一条数据筛选条件行"""
        if row_info in self.data_condition_rows:
            self.data_condition_rows.remove(row_info)
        try:
            row_info['frame'].hide()
            self.data_conditions_layout.removeWidget(row_info['frame'])
            row_info['frame'].setParent(None)
            row_info['frame'].deleteLater()
        except RuntimeError:
            pass
        self._update_data_filter_toggle_btn()
        self._adjust_data_filter_panel_size()
        self._refresh_data_exposed_tags()
        self._apply_data_filters()

    def _collect_data_filter_conditions(self):
        """收集数据筛选条件（包含外露标记，日期字段读取日期值）"""
        conditions = []
        for row_info in getattr(self, 'data_condition_rows', []):
            field = row_info['field_combo'].currentText().strip()
            operator = row_info['op_combo'].currentData()
            is_date = self._is_data_date_field(field)
            expose = row_info.get('expose_check') and row_info['expose_check'].isChecked()
            if not field:
                continue
            if operator in ('empty', 'not_empty'):
                value = ''
            elif is_date and operator == 'date_range':
                dr = row_info['date_range_btn'].property('date_range') or {}
                if dr.get('start') and dr.get('end'):
                    value = f"{dr['start'].toString('yyyy-MM-dd')}~{dr['end'].toString('yyyy-MM-dd')}"
                else:
                    continue
            elif is_date:
                value = row_info['date_input'].date().toString('yyyy-MM-dd')
            else:
                value = row_info['value_input'].text().strip()
                if not value:
                    continue
            conditions.append({'field': field, 'operator': operator, 'value': value, 'expose': expose})
        return conditions

    def _apply_condition_filter(self, headers, data_rows):
        """应用多条件筛选"""
        conditions = self._collect_data_filter_conditions()
        if not conditions:
            return data_rows
        # 建立字段名 → 列索引映射
        col_map = {}
        for idx, h in enumerate(headers):
            if h is not None:
                col_map[str(h).strip()] = idx
        filtered = []
        for entry in data_rows:
            # 兼容 (row_index, row_data) 和纯 list 两种格式
            if isinstance(entry, tuple) and len(entry) == 2:
                row_idx, row_values = entry
            else:
                row_values = entry
            match = True
            for cond in conditions:
                field = cond['field']
                op = cond['operator']
                val = cond['value'].lower()
                col_idx = col_map.get(field, -1)
                if col_idx < 0 or col_idx >= len(row_values):
                    continue
                cell_val = str(row_values[col_idx] if row_values[col_idx] is not None else '').strip().lower()
                date_val = cell_val[:10]  # 取日期部分 yyyy-MM-dd
                if op == 'contains' and val not in cell_val:
                    match = False
                elif op == 'eq' and cell_val != val:
                    match = False
                elif op == 'ne' and cell_val == val:
                    match = False
                elif op == 'starts_with' and not cell_val.startswith(val):
                    match = False
                elif op == 'ends_with' and not cell_val.endswith(val):
                    match = False
                elif op == 'empty' and cell_val:
                    match = False
                elif op == 'not_empty' and not cell_val:
                    match = False
                elif op == 'date_before' and date_val >= val:
                    match = False
                elif op == 'date_after' and date_val <= val:
                    match = False
                elif op == 'date_range' and '~' in val:
                    parts = val.split('~')
                    if not (parts[0].strip() <= date_val <= parts[1].strip()):
                        match = False
                if not match:
                    break
            if match:
                filtered.append(entry)
        return filtered

    def _apply_data_filters(self):
        """条件变化时重新刷新表格"""
        data_rows = getattr(self, '_current_raw_data_rows', None)
        headers = getattr(self, 'current_source_headers', None)
        if not data_rows or not headers:
            return
        self.current_page = 1
        self._update_data_table(headers, data_rows)
        self._update_pagination_controls()

    def _clear_all_data_conditions(self):
        """清除所有数据筛选条件"""
        for row_info in list(getattr(self, 'data_condition_rows', [])):
            try:
                row_info['frame'].setParent(None)
                row_info['frame'].deleteLater()
            except RuntimeError:
                pass
        self.data_condition_rows = []
        self._update_data_filter_toggle_btn()
        self._adjust_data_filter_panel_size()
        self._refresh_data_exposed_tags()

    def _show_data_preset_popup(self):
        """弹出方案选择面板"""
        presets = self.config.get('file_gen_filter_presets', [])
        if not isinstance(presets, list):
            presets = []
        default_name = self.config.get('file_gen_filter_default_preset', '')

        popup = QFrame()
        popup.setWindowFlags(Qt.WindowType.Popup | Qt.WindowType.FramelessWindowHint)
        popup.setStyleSheet("QFrame { border: 1px solid #D9D9D9; border-radius: 4px; background: #FFF; }")
        popup_layout = QVBoxLayout(popup)
        popup_layout.setContentsMargins(4, 4, 4, 4)
        popup_layout.setSpacing(2)

        none_btn = QPushButton("(未选择)")
        none_btn.setFixedHeight(28)
        none_btn.setCursor(Qt.CursorShape.PointingHandCursor)
        none_btn.setStyleSheet("QPushButton { border: none; text-align: left; padding: 4px 8px; font-size: 12px; color: #999; background: transparent; } QPushButton:hover { background: #F5F5F5; }")
        none_btn.clicked.connect(lambda: [self._clear_all_data_conditions(), self._apply_data_filters(), popup.close()])
        popup_layout.addWidget(none_btn)

        icon_style = """
            QPushButton { border: none; border-radius: 2px; font-size: 13px; background: transparent; color: #999; }
            QPushButton:hover { background: #E6F7FF; color: #1890FF; }
        """
        for preset in presets:
            name = preset.get('name', '')
            is_default = (name == default_name)
            display = f"★ {name}" if is_default else name
            row = QFrame()
            row.setFixedHeight(30)
            row.setStyleSheet("QFrame { border: none; background: transparent; }")
            row_layout = QHBoxLayout(row)
            row_layout.setContentsMargins(0, 0, 0, 0)
            row_layout.setSpacing(4)

            load_btn = QPushButton(display)
            load_btn.setCursor(Qt.CursorShape.PointingHandCursor)
            if is_default:
                load_btn.setStyleSheet("QPushButton { border: none; text-align: left; padding: 4px 8px; font-size: 12px; color: #333; background: transparent; } QPushButton:hover { background: #E6F7FF; color: #1890FF; }")
            else:
                load_btn.setStyleSheet("QPushButton { border: none; text-align: left; padding: 4px 8px; font-size: 12px; color: #333; background: transparent; } QPushButton:hover { background: #E6F7FF; color: #1890FF; }")
            load_btn.clicked.connect(lambda checked, n=name: [self._load_data_filter_preset(n), popup.close()])
            row_layout.addWidget(load_btn, stretch=1)

            def_btn = QPushButton("★")
            def_btn.setFixedSize(22, 22)
            if is_default:
                def_btn.setStyleSheet("QPushButton { border: none; border-radius: 2px; font-size: 13px; background: transparent; color: #FA8C16; } QPushButton:hover { background: #FFF7E6; color: #FA8C16; }")
            else:
                def_btn.setStyleSheet(icon_style)
            def_btn.setToolTip(f"设置/取消「{name}」为默认方案")
            def_btn.clicked.connect(lambda checked, n=name: [self._toggle_data_filter_default_preset(n), popup.close()])
            row_layout.addWidget(def_btn)

            del_btn = QPushButton("✕")
            del_btn.setFixedSize(22, 22)
            del_btn.setStyleSheet(icon_style + "QPushButton:hover { background: #FFF2F0; color: #FF4D4F; }")
            del_btn.setToolTip(f"删除「{name}」")
            del_btn.clicked.connect(lambda checked, n=name: [self._delete_data_filter_preset(n), popup.close()])
            row_layout.addWidget(del_btn)
            popup_layout.addWidget(row)

        popup.adjustSize()
        btn_pos = self.data_preset_btn.mapToGlobal(QPoint(0, self.data_preset_btn.height()))
        popup.move(btn_pos.x(), btn_pos.y() + 2)
        popup.reject = popup.close
        popup._outside_close_armed = False
        pf = _DialogOutsideCloseFilter(popup)
        QApplication.instance().installEventFilter(pf)
        QTimer.singleShot(0, lambda p=popup: setattr(p, '_outside_close_armed', True))
        popup.destroyed.connect(lambda obj, f=pf: QApplication.instance().removeEventFilter(f))
        popup.show()

    def _load_data_filter_preset(self, name):
        """加载保存的筛选方案"""
        presets = self.config.get('file_gen_filter_presets', [])
        if not isinstance(presets, list):
            return
        target = next((p for p in presets if p.get('name') == name), None)
        if not target:
            return
        conditions = target.get('conditions', [])
        self._clear_all_data_conditions()
        for cond in conditions:
            self._add_data_condition_row(cond)
        self._apply_data_filters()

    def _delete_data_filter_preset(self, name):
        """删除筛选方案"""
        presets = self.config.get('file_gen_filter_presets', [])
        if not isinstance(presets, list):
            return
        reply = QMessageBox.question(self, '确认删除', f'确定删除方案「{name}」吗？')
        if reply != QMessageBox.StandardButton.Yes:
            return
        self.config['file_gen_filter_presets'] = [p for p in presets if p.get('name') != name]
        if self.config.get('file_gen_filter_default_preset') == name:
            self.config['file_gen_filter_default_preset'] = ''
        save_config(self.config)

    def _toggle_data_filter_default_preset(self, preset_name):
        """切换默认方案：已是默认则取消，否则设为默认"""
        if not preset_name:
            return
        current_default = self.config.get('file_gen_filter_default_preset', '')
        if current_default == preset_name:
            self.config['file_gen_filter_default_preset'] = ''
        else:
            presets = self.config.get('file_gen_filter_presets', [])
            if not isinstance(presets, list) or not any(p.get('name') == preset_name for p in presets):
                return
            self.config['file_gen_filter_default_preset'] = preset_name
        save_config(self.config)

    def _save_data_filter_preset(self):
        """保存文件生成筛选条件为方案（存储在 config['file_gen_filter_presets']）"""
        conditions = self._collect_data_filter_conditions()
        name, ok = QInputDialog.getText(self, "保存筛选方案", "请输入方案名称：")
        if not ok or not name or not name.strip():
            return
        name = name.strip()
        presets = self.config.get('file_gen_filter_presets', [])
        if not isinstance(presets, list):
            presets = []
        existing = next((i for i, p in enumerate(presets) if p.get('name') == name), None)
        if existing is not None:
            reply = QMessageBox.question(self, '确认覆盖', f'方案「{name}」已存在，是否覆盖？')
            if reply != QMessageBox.StandardButton.Yes:
                return
            presets[existing] = {'name': name, 'conditions': conditions}
        else:
            presets.append({'name': name, 'conditions': conditions})
        self.config['file_gen_filter_presets'] = presets
        save_config(self.config)
        QMessageBox.information(self, "成功", f"方案「{name}」已保存。")

    def _refresh_data_exposed_tags(self):
        """刷新文件生成外露标签"""
        if not hasattr(self, 'data_exposed_tags'):
            return
        layout = self.data_exposed_tags.layout()
        if not layout:
            return
        # 清除所有现有项目（widgets + spacers）
        while layout.count() > 0:
            item = layout.takeAt(0)
            if item.widget():
                item.widget().deleteLater()
        # 收集外露条件
        exposed = []
        for row_info in getattr(self, 'data_condition_rows', []):
            if row_info.get('expose_check') and row_info['expose_check'].isChecked():
                field = row_info['field_combo'].currentText().strip()
                op = row_info['op_combo'].currentData()
                is_date = self._is_data_date_field(field)
                if not field:
                    continue
                if op in ('empty', 'not_empty'):
                    value = row_info['op_combo'].currentText()
                elif is_date and op == 'date_range':
                    dr = row_info['date_range_btn'].property('date_range') or {}
                    if dr.get('start') and dr.get('end'):
                        value = f"{dr['start'].toString('yyyy-MM-dd')}~{dr['end'].toString('yyyy-MM-dd')}"
                    else:
                        continue
                elif is_date:
                    value = row_info['date_input'].date().toString('yyyy-MM-dd')
                else:
                    value = row_info['value_input'].text().strip()
                    if not value:
                        continue
                exposed.append({'field': field, 'value': value, 'row_info': row_info})
        if not exposed:
            self.data_exposed_tags.setVisible(False)
            return
        # 创建标签
        for cond in exposed:
            tag = QFrame()
            tag.setStyleSheet("QFrame { background: #E6F7FF; border: 1px solid #91D5FF; border-radius: 3px; }")
            tag_layout = QHBoxLayout(tag)
            tag_layout.setContentsMargins(6, 1, 1, 1)
            tag_layout.setSpacing(2)
            lbl = QLabel(f"{cond['field']}: {cond['value']}")
            lbl.setStyleSheet("font-size: 11px; color: #1890FF; border: none; background: transparent;")
            tag_layout.addWidget(lbl)
            close = QPushButton("×")
            close.setFixedSize(14, 14)
            close.setCursor(Qt.CursorShape.PointingHandCursor)
            close.setStyleSheet("QPushButton { border: none; color: #91D5FF; font-size: 10px; } QPushButton:hover { color: #FF4D4F; }")
            close.clicked.connect(lambda checked, r=cond['row_info']: self._remove_data_condition_row(r))
            tag_layout.addWidget(close)
            layout.addWidget(tag)
        layout.addStretch()
        self.data_exposed_tags.setVisible(True)
        self.data_exposed_tags.updateGeometry()
        # 强制父布局刷新
        if self.data_exposed_tags.parentWidget():
            self.data_exposed_tags.parentWidget().updateGeometry()
            if self.data_exposed_tags.parentWidget().layout():
                self.data_exposed_tags.parentWidget().layout().invalidate()
                self.data_exposed_tags.parentWidget().layout().activate()

    def _reset_crm_filters_and_selection(self):
        """刷新CRM时重置搜索、筛选和勾选状态"""
        if hasattr(self, 'crm_search_input'):
            self.crm_search_input.blockSignals(True)
            self.crm_search_input.clear()
            self.crm_search_input.blockSignals(False)

        # 清除所有多条件筛选行
        self._clear_all_crm_conditions()

        # 重置方案选择
        self._crm_active_preset_name = None
        self._update_crm_preset_btn_label()

        # 重置日期范围（默认不筛选）
        self.crm_date_start = None
        self.crm_date_end = None

        self.crm_current_page = 1
        self.crm_selected_row_ids = set()

        if hasattr(self, 'crm_table'):
            self.crm_table.clearSelection()
        if hasattr(self, 'crm_table_header'):
            self.crm_table_header.set_check_state(Qt.CheckState.Unchecked)

    def _clear_data_table(self, message="请选择功能后加载数据"):
        """清空数据表格"""
        self._is_updating_data_table = True

        # ✅ 保存当前列宽（如果有）
        current_widths = {}
        if hasattr(self, 'data_table') and self.data_table.columnCount() > 0:
            for col in range(self.data_table.columnCount()):
                current_widths[col] = self.data_table.columnWidth(col)

        self.data_table.clear()
        self.data_table.setColumnCount(0)
        self.data_table.setRowCount(0)

        # ✅ 如果之前有列宽且现在列数为0，暂存起来用于后续恢复
        if current_widths and not hasattr(self, '_saved_data_table_widths'):
            self._saved_data_table_widths = current_widths

        self._is_updating_data_table = False
        self.table_raw_data = []
        self.current_all_headers = []
        self.current_visible_headers = []
        self.current_filtered_rows = []
        self.current_source_headers = []
        self.current_header_source_index_map = {}
        self.current_page = 1
        self.data_header_label.setText(message)
        if hasattr(self, 'table_header'):
            self.table_header.set_check_state(Qt.CheckState.Unchecked)
        self._update_pagination_controls()
        self._update_data_table_sort_indicator()

    def _get_excel_table_settings(self, operation_value):
        """读取当前功能的表格字段设置"""
        if not operation_value:
            return {}
        config = getattr(self, 'config', None) or load_config() or {}
        return (
            config.get('app_settings', {})
            .get('excel_table_settings', {})
            .get(str(operation_value), {})
        )

    def _save_excel_table_settings(self, operation_value, visible_headers=None, header_order=None):
        """保存当前功能的表格字段设置"""
        if not operation_value:
            return

        # ✅ 使用 load_config() 获取最新配置，避免使用旧的 self.config 缓存
        config = load_config()
        app_settings = config.setdefault('app_settings', {})
        table_settings = app_settings.setdefault('excel_table_settings', {})
        operation_settings = table_settings.setdefault(str(operation_value), {})

        changed = False
        if visible_headers is not None and operation_settings.get('visible_headers') != visible_headers:
            operation_settings['visible_headers'] = visible_headers
            changed = True
        if header_order is not None and operation_settings.get('header_order') != header_order:
            operation_settings['header_order'] = header_order
            changed = True

        if changed:
            save_config(config, immediate=False)
            # 同步更新 self.config
            self.config = config

    def _compose_full_header_order(self, visible_headers):
        """根据当前完整表头补齐隐藏字段顺序"""
        all_headers = list(getattr(self, 'current_all_headers', []))
        return list(visible_headers) + [header for header in all_headers if header not in visible_headers]

    def _build_sort_key(self, value):
        """将不同类型的值标准化为可比较的排序键"""
        if value is None:
            return None

        if isinstance(value, datetime):
            return (1, value.timestamp())

        if isinstance(value, (int, float)):
            return (0, float(value))

        text = str(value).strip()
        if not text:
            return None

        numeric_text = text.replace(',', '')
        if numeric_text.endswith('%'):
            numeric_text = numeric_text[:-1]
        if re.fullmatch(r'-?\d+(?:\.\d+)?', numeric_text):
            return (0, float(numeric_text))

        for fmt in ('%Y-%m-%d %H:%M:%S', '%Y-%m-%d %H:%M', '%Y-%m-%d'):
            try:
                return (1, datetime.strptime(text, fmt).timestamp())
            except ValueError:
                continue

        return (2, text.casefold())

    def _sort_records(self, records, value_getter, sort_order):
        """按指定取值函数对记录排序，空值始终排在末尾"""
        sortable_records = []
        empty_records = []

        for record in records:
            sort_key = self._build_sort_key(value_getter(record))
            if sort_key is None:
                empty_records.append(record)
            else:
                sortable_records.append((sort_key, record))

        sortable_records.sort(
            key=lambda item: item[0],
            reverse=(sort_order == Qt.SortOrder.DescendingOrder)
        )
        return [record for _, record in sortable_records] + empty_records

    def _get_excel_sort_value(self, entry, header_label, source_index_map):
        """内部方法：获取Excel排序值。"""
        row_id, row_data = entry
        source_index = source_index_map.get(header_label, -1)
        if 0 <= source_index < len(row_data):
            return row_data[source_index]
        return ''

    def _sort_excel_data_entries(self, data_entries, visible_headers, source_index_map):
        """内部方法：处理排序Excel数据entries逻辑。"""
        sort_header = str(getattr(self, 'data_sort_header', '') or '').strip()
        if not sort_header:
            return list(data_entries)
        if sort_header not in visible_headers:
            self.data_sort_header = ''
            return list(data_entries)

        return self._sort_records(
            list(data_entries),
            lambda entry: self._get_excel_sort_value(entry, sort_header, source_index_map),
            getattr(self, 'data_sort_order', Qt.SortOrder.AscendingOrder)
        )

    def _update_data_table_sort_indicator(self):
        """内部方法：更新数据表格排序indicator。"""
        if not hasattr(self, 'table_header'):
            return

        sort_header = str(getattr(self, 'data_sort_header', '') or '').strip()
        visible_headers = list(getattr(self, 'current_visible_headers', []))
        if not sort_header or sort_header not in visible_headers:
            self.table_header.setSortIndicatorShown(False)
            return

        logical_index = visible_headers.index(sort_header) + 1
        self.table_header.setSortIndicatorShown(True)
        self.table_header.setSortIndicator(logical_index, getattr(self, 'data_sort_order', Qt.SortOrder.AscendingOrder))

    def on_data_table_header_clicked(self, logical_index):
        """响应数据表头clicked相关操作。"""
        if logical_index <= 0 or logical_index >= self.data_table.columnCount():
            return

        header_item = self.data_table.horizontalHeaderItem(logical_index)
        if header_item is None:
            return

        header_text = header_item.text().strip()
        if not header_text:
            return

        if getattr(self, 'data_sort_header', '') == header_text:
            if getattr(self, 'data_sort_order', Qt.SortOrder.AscendingOrder) == Qt.SortOrder.AscendingOrder:
                self.data_sort_order = Qt.SortOrder.DescendingOrder
            else:
                self.data_sort_header = ''
                self.data_sort_order = Qt.SortOrder.AscendingOrder
        else:
            self.data_sort_header = header_text
            self.data_sort_order = Qt.SortOrder.AscendingOrder

        self.current_page = 1
        self._refresh_current_table_page()

    def _get_crm_sort_value(self, order, row_index, header_label, label_to_key):
        """内部方法：获取CRM排序值。"""
        row_id = self._get_crm_row_id(order, row_index)

        if header_label == '模板选择':
            return self._get_selected_crm_template_name(order, row_id)
        if header_label == '规格型号':
            return self._get_crm_model_spec(order)
        if header_label == '客户类型':
            return self._get_crm_customer_type(order, row_id)
        if header_label == '匹配价格':
            customer_type = self._get_crm_customer_type(order, row_id)
            return self._get_crm_matched_price(order, customer_type, row_id)
        if header_label == '折扣单价':
            customer_type = self._get_crm_customer_type(order, row_id)
            return self._get_crm_discount_unit_price(order, customer_type, row_id)
        if header_label == '产品备注':
            return self._get_crm_product_remark(order, row_id)
        if header_label == '大写':
            return self._convert_amount_to_rmb_upper(order.get('product_amount', ''))

        key_info = label_to_key.get(header_label)
        if not key_info:
            return ''

        key, is_time = key_info
        if is_time:
            return order.get(key, '')
        return self._crm_extract_field(order, key)

    def _sort_crm_data(self, data_rows, label_to_key):
        """内部方法：处理排序CRM数据逻辑。"""
        sort_header = str(getattr(self, 'crm_sort_header', '') or '').strip()
        available_headers = list(getattr(self, 'crm_visible_headers', []))
        if not sort_header:
            return list(data_rows)
        if sort_header not in available_headers:
            self.crm_sort_header = ''
            return list(data_rows)

        sorted_records = self._sort_records(
            list(enumerate(data_rows)),
            lambda item: self._get_crm_sort_value(item[1], item[0], sort_header, label_to_key),
            getattr(self, 'crm_sort_order', Qt.SortOrder.AscendingOrder)
        )
        return [record for _, record in sorted_records]

    def _update_crm_table_sort_indicator(self):
        """内部方法：更新CRM表格排序indicator。"""
        if not hasattr(self, 'crm_table_header'):
            return

        sort_header = str(getattr(self, 'crm_sort_header', '') or '').strip()
        available_headers = self._get_crm_display_headers()
        if not sort_header or sort_header not in available_headers:
            self.crm_table_header.setSortIndicatorShown(False)
            return

        logical_index = available_headers.index(sort_header)
        self.crm_table_header.setSortIndicatorShown(True)
        self.crm_table_header.setSortIndicator(logical_index, getattr(self, 'crm_sort_order', Qt.SortOrder.AscendingOrder))

    def on_crm_table_header_clicked(self, logical_index):
        """响应CRM表头clicked相关操作。"""
        if logical_index <= 0 or logical_index >= self.crm_table.columnCount():
            return

        header_item = self.crm_table.horizontalHeaderItem(logical_index)
        if header_item is None:
            return

        header_text = header_item.text().strip()
        if not header_text:
            return

        if getattr(self, 'crm_sort_header', '') == header_text:
            if getattr(self, 'crm_sort_order', Qt.SortOrder.AscendingOrder) == Qt.SortOrder.AscendingOrder:
                self.crm_sort_order = Qt.SortOrder.DescendingOrder
            else:
                self.crm_sort_header = ''
                self.crm_sort_order = Qt.SortOrder.AscendingOrder
        else:
            self.crm_sort_header = header_text
            self.crm_sort_order = Qt.SortOrder.AscendingOrder

        self.crm_current_page = 1
        self._populate_crm_table()

    def _resolve_excel_table_headers(self, headers):
        """根据配置解析表格需要显示的字段和顺序"""
        source_index_map = {}
        all_headers = []
        for index, header in enumerate(headers):
            header_text = str(header).strip() if header is not None else ""
            if not header_text:
                continue
            if header_text not in source_index_map:
                source_index_map[header_text] = index
                all_headers.append(header_text)

        settings = self._get_excel_table_settings(getattr(self, 'selected_operation', None))
        saved_order = [header for header in settings.get('header_order', []) if header in all_headers]
        ordered_headers = saved_order + [header for header in all_headers if header not in saved_order]
        if not ordered_headers:
            ordered_headers = all_headers.copy()

        saved_visible = settings.get('visible_headers', ordered_headers)
        visible_headers = [header for header in ordered_headers if header in saved_visible]
        if not visible_headers:
            visible_headers = ordered_headers.copy()

        return all_headers, ordered_headers, visible_headers, source_index_map

    def _get_current_visual_headers(self):
        """读取当前表格表头的视觉顺序"""
        if not hasattr(self, 'data_table') or self.data_table.columnCount() <= 1:
            return list(getattr(self, 'current_visible_headers', []))

        header = self.data_table.horizontalHeader()
        visual_headers = []
        for visual_index in range(1, self.data_table.columnCount()):
            logical_index = header.logicalIndex(visual_index)
            header_item = self.data_table.horizontalHeaderItem(logical_index)
            if not header_item:
                continue
            header_text = header_item.text().strip()
            if header_text:
                visual_headers.append(header_text)

        return visual_headers or list(getattr(self, 'current_visible_headers', []))

    def on_data_table_header_moved(self, logical_index, old_visual_index, new_visual_index):
        """拖动表头后保存字段顺序"""
        if getattr(self, '_is_updating_data_table', False):
            return
        if logical_index <= 0 or old_visual_index == new_visual_index:
            return

        visual_headers = self._get_current_visual_headers()
        if not visual_headers:
            return

        self.current_visible_headers = visual_headers
        self._save_excel_table_settings(
            getattr(self, 'selected_operation', None),
            visible_headers=visual_headers,
            header_order=self._compose_full_header_order(visual_headers)
        )

        self._force_rebuild_data_table = True
        self._refresh_current_table_page()

    def _get_operation_selected_row_ids(self, operation_value=None):
        """获取当前功能勾选的行ID集合"""
        target_operation = operation_value if operation_value is not None else getattr(self, 'selected_operation', None)
        if target_operation is None:
            return set()

        cache_key = str(target_operation)
        if cache_key not in self._selected_row_ids_by_operation:
            self._selected_row_ids_by_operation[cache_key] = set()
        return self._selected_row_ids_by_operation[cache_key]

    def _get_current_page_size(self):
        """获取当前每页显示数量"""
        return self._get_combo_page_size(getattr(self, 'page_size_combo', None))

    def _get_total_pages(self):
        """计算总页数"""
        total_rows = len(getattr(self, 'current_filtered_rows', []))
        page_size = max(1, self._get_current_page_size())
        return max(1, (total_rows + page_size - 1) // page_size)

    def _update_pagination_controls(self):
        """更新分页控件状态"""
        if not hasattr(self, 'page_label'):
            return

        total_pages = self._get_total_pages()
        if getattr(self, 'current_page', 1) < 1:
            self.current_page = 1
        if self.current_page > total_pages:
            self.current_page = total_pages

        self.page_label.setText(f"{self.current_page}/{total_pages}")

        if hasattr(self, 'prev_page_btn'):
            self.prev_page_btn.setEnabled(self.current_page > 1)
        if hasattr(self, 'next_page_btn'):
            self.next_page_btn.setEnabled(self.current_page < total_pages)

    def on_page_size_changed(self, index):
        """切换每页显示数量"""
        if index < 0:
            return
        self.current_page = 1
        self._save_page_sizes()
        self.persist_contract_page_state()
        self._refresh_current_table_page()

    def on_page_spin_changed(self, page):
        """切换页码"""
        if self._is_updating_data_table:
            return
        self.current_page = max(1, page)
        self.persist_contract_page_state()
        self._refresh_current_table_page()

    def on_prev_page(self):
        """上一页"""
        if self.current_page > 1:
            self.current_page -= 1
            self._refresh_current_table_page()

    def on_next_page(self):
        """下一页"""
        total_pages = self._get_total_pages()
        if self.current_page < total_pages:
            self.current_page += 1
            self._refresh_current_table_page()

    def on_row_checkbox_toggled(self, row_id, checked):
        """同步跨页勾选状态"""
        if self._is_updating_data_table or row_id is None or not getattr(self, 'selected_operation', None):
            return

        selected_ids = self._get_operation_selected_row_ids()
        if checked:
            selected_ids.add(row_id)
        else:
            selected_ids.discard(row_id)

        self._update_header_checkbox_state()
        self._update_data_header_summary()

    def on_data_table_item_changed(self, item):
        """同步主表首列复选框和跨页勾选状态"""
        if (
            self._is_updating_data_table
            or item is None
            or item.column() != 0
            or not getattr(self, 'selected_operation', None)
        ):
            return

        row_id = item.data(Qt.ItemDataRole.UserRole)
        if row_id is None:
            return

        selected_ids = self._get_operation_selected_row_ids()
        if item.checkState() == Qt.CheckState.Checked:
            selected_ids.add(row_id)
        else:
            selected_ids.discard(row_id)

        self._update_header_checkbox_state()
        self._update_data_header_summary()

    def _update_header_checkbox_state(self):
        """根据当前页面显示结果更新表头复选框状态"""
        if not hasattr(self, 'table_header'):
            return

        current_page_ids = [row_id for row_id, _ in getattr(self, '_current_page_rows', [])]
        if not current_page_ids:
            self.table_header.set_check_state(Qt.CheckState.Unchecked)
            return

        selected_ids = self._get_operation_selected_row_ids()
        checked_count = sum(1 for row_id in current_page_ids if row_id in selected_ids)
        if checked_count == 0:
            state = Qt.CheckState.Unchecked
        elif checked_count == len(current_page_ids):
            state = Qt.CheckState.Checked
        else:
            state = Qt.CheckState.PartiallyChecked
        self.table_header.set_check_state(state)

    def _update_data_header_summary(self):
        """更新数据区摘要文本"""
        if not hasattr(self, 'data_header_label'):
            return

        total_rows = len(getattr(self, 'current_filtered_rows', []))
        visible_headers = list(getattr(self, 'current_visible_headers', []))
        selected_row_ids = self._get_operation_selected_row_ids()
        self.data_header_label.setText(
            f"已加载 {total_rows} 条记录，显示 {len(visible_headers)} 个字段，已勾选 {len(selected_row_ids)} 条"
        )

    def on_data_table_cell_clicked(self, row, col):
        """文件生成表格单元格点击处理：第0列（复选框）选中整行，其他列只选中单元格"""
        if col == 0:
            self.data_table.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectRows)
            self.data_table.selectRow(row)
            self.data_table.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectItems)

    def on_crm_table_cell_clicked(self, row, col):
        """CRM订单表格单元格点击处理：第0列（复选框）选中整行，其他列只选中单元格"""
        if col == 0:
            self.crm_table.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectRows)
            self.crm_table.selectRow(row)
            self.crm_table.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectItems)

    def _on_opportunity_data_ready(self):
        """商机数据加载完成（主线程回调）"""
        self._opportunity_is_loading = False
        self.opportunity_refresh_btn.setText("刷新")
        if hasattr(self, 'opportunity_all_data') and self.opportunity_all_data:
            self._populate_opportunity_table()
            self.opportunity_status_label.setText(f"共 {len(self.opportunity_all_data)} 条记录")
        else:
            self.opportunity_status_label.setText("共 0 条记录")

    def _on_opp_table_cell_clicked(self, row, col):
        """商机表格：第0列（复选框）选中整行，其他列点哪选哪"""
        if col == 0:
            self.opportunity_table.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectRows)
            self.opportunity_table.selectRow(row)
            self.opportunity_table.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectItems)

    def _on_obj_query_table_cell_clicked(self, row, col):
        """对象查询表格：第0列（复选框）选中整行，其他列点哪选哪"""
        if col == 0:
            self.obj_query_table.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectRows)
            self.obj_query_table.selectRow(row)
            self.obj_query_table.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectItems)

    def on_crm_table_cell_double_clicked(self, row, col):
        """保留兼容接口，实际编辑由表格委托处理"""
        return

    def on_header_select_all_toggled(self, checked):
        """点击表头复选框，全选或全不选当前页面显示结果"""
        selected_ids = self._get_operation_selected_row_ids()
        current_page_ids = [row_id for row_id, _ in getattr(self, '_current_page_rows', [])]
        if checked:
            selected_ids.update(current_page_ids)
        else:
            for row_id in current_page_ids:
                selected_ids.discard(row_id)

        self._is_updating_data_table = True
        try:
            for row in range(self.data_table.rowCount()):
                checkbox_container = self.data_table.cellWidget(row, 0)
                checkbox = checkbox_container.findChild(QCheckBox) if checkbox_container else None
                if checkbox:
                    checkbox.setChecked(checked)
        finally:
            self._is_updating_data_table = False

        self.data_table.viewport().update()
        self._update_header_checkbox_state()
        self._update_data_header_summary()

    def on_global_search_changed(self, text):
        """搜索框输入变化 → 重新筛选"""
        self._apply_data_filters()

    def _do_data_search(self):
        self._apply_data_filters()

    def apply_search_filter_now(self):
        """应用全局搜索"""
        self._apply_data_filters()

    def open_date_filter_dialog(self, anchor_widget=None):
        """打开日期选择弹窗"""
        self.selected_filter_start_date = getattr(self, 'selected_filter_start_date', None) or QDate.currentDate()
        self.selected_filter_end_date = getattr(self, 'selected_filter_end_date', None) or QDate.currentDate()
        dialog = QuickDatePickerDialog(
            self.selected_filter_start_date,
            self.selected_filter_end_date,
            self
        )
        if anchor_widget:
            dialog.position_below_widget(anchor_widget)
        if dialog.exec() == QDialog.DialogCode.Accepted:
            self.selected_filter_start_date = dialog.start_date
            self.selected_filter_end_date = dialog.end_date
            self.current_page = 1
            self.persist_contract_page_state()
            self._trigger_date_filter_update()

    def open_column_settings_dialog(self):
        """打开字段显示设置对话框"""
        operation_log.info("打开文件生成字段设置对话框")

        if not getattr(self, 'selected_operation', None):
            show_warning("提示", "请先选择功能，再设置显示字段。", self)
            return

        headers = list(getattr(self, 'current_all_headers', []))
        if not headers:
            cache_key = str(self.selected_operation)
            if cache_key in getattr(self, '_data_cache', {}):
                cached_headers, _ = self._data_cache[cache_key]
                headers = [str(header).strip() for header in cached_headers if str(header).strip()]

        if not headers:
            self.load_excel_data_to_table(self.selected_operation, force_reload=False)
            headers = list(getattr(self, 'current_all_headers', []))

        if not headers:
            show_warning("提示", "当前功能还没有可设置的字段。", self)
            return

        _, ordered_headers, visible_headers, _ = self._resolve_excel_table_headers(headers)
        current_visual_headers = self._get_current_visual_headers()
        if current_visual_headers:
            visible_headers = current_visual_headers
            ordered_headers = self._compose_full_header_order(current_visual_headers)

        dialog = ExcelFieldSettingsDialog(
            headers=headers,
            visible_headers=visible_headers,
            header_order=ordered_headers,
            parent=self
        )

        if dialog.exec() == QDialog.DialogCode.Accepted:
            visible_headers, header_order = dialog.get_settings()
            print(f"[DEBUG-文件生成] 字段设置确认 | 新可见字段数: {len(visible_headers)} | 前5项: {visible_headers[:5]}")
            self.current_visible_headers = visible_headers
            self._save_excel_table_settings(
                self.selected_operation,
                visible_headers=visible_headers,
                header_order=header_order
            )

            # 记录字段设置变更
            operation_log.info(f"文件生成字段设置已变更 | 显示字段数:{len(visible_headers)}")

            cache_key = str(self.selected_operation)
            if cache_key in getattr(self, '_data_cache', {}):
                print(f"[DEBUG-文件生成] 调用 _refresh_current_table_page()")
                self.current_page = 1
                self._refresh_current_table_page()
                print(f"[DEBUG-文件生成] _refresh_current_table_page() 完成")
            else:
                print(f"[DEBUG-文件生成] 调用 load_excel_data_to_table()")
                self.load_excel_data_to_table(self.selected_operation, force_reload=False)
                print(f"[DEBUG-文件生成] load_excel_data_to_table() 完成")
    
    def load_excel_data_to_table(self, operation_value, force_reload=False):
        """
        加载选中功能的Excel数据到表格（支持公式计算结果和缓存机制）
        
        参数:
            operation_value: 功能值
            force_reload: 是否强制重新加载（忽略缓存），默认False
        """
        try:
            config = getattr(self, 'config', None) or load_config()
            gui_options = config.get('gui_options', [])
            excel_paths = config.get('path_config', {}).get('excel_paths', {})
            
            selected_option = None
            for opt in gui_options:
                if opt.get('value') == operation_value:
                    selected_option = opt
                    break
            
            if not selected_option:
                self.data_header_label.setText("未找到功能配置")
                self.data_table.setRowCount(0)
                return
            
            excel_path = AppConfig.get_excel_template_path(operation_value)
            if not excel_path or not excel_path.exists():
                self.data_header_label.setText(f"Excel文件不存在: {excel_path}")
                self.data_table.setRowCount(0)
                return
            
            # ===== 缓存机制 =====
            cache_key = str(operation_value)
            
            # 检查是否有有效缓存
            if not force_reload and cache_key in getattr(self, '_data_cache', {}):
                cached_headers, cached_rows = self._data_cache[cache_key]
                self.current_page = 1
                self._update_data_table(cached_headers, cached_rows)
                return
            
            # 缓存无效或强制刷新，从Excel加载
            from openpyxl import load_workbook
            # 使用data_only=True获取公式的计算结果
            workbook = load_workbook(excel_path, data_only=True, read_only=True)
            sheet_name = selected_option.get('sheet', '')
            
            if sheet_name and sheet_name in workbook.sheetnames:
                sheet = workbook[sheet_name]
            else:
                sheet = workbook.active
            
            headers = [cell.value for cell in sheet[1]]
            
            data_rows = []
            for row in sheet.iter_rows(min_row=2):
                row_data = [cell.value for cell in row]
                
                # 过滤空行
                if all(cell is None or cell == '' for cell in row_data):
                    continue
                
                data_rows.append(row_data)
            
            workbook.close()
            
            # 保存到缓存（保存原始未筛选的数据）
            if not hasattr(self, '_data_cache'):
                self._data_cache = {}
            self._data_cache[cache_key] = (headers, data_rows.copy())
            
            self.current_page = 1
            self._update_data_table(headers, data_rows)

            # 首次加载数据后自动应用默认筛选方案
            if not getattr(self, '_data_default_preset_applied', False):
                self._data_default_preset_applied = True
                default_name = self.config.get('file_gen_filter_default_preset', '')
                if default_name:
                    self._load_data_filter_preset(default_name)

        except Exception as e:
            logging.error(f"加载数据失败: {str(e)}")
            self.data_header_label.setText(f"加载数据失败: {str(e)}")
    
    def _update_data_table(self, headers, data_rows):
        """更新数据表格显示（与 CRM _populate_crm_table 逻辑一致）"""
        self.current_source_headers = list(headers)
        self._current_raw_data_rows = list(data_rows)
        # 刷新搜索字段下拉框，加载表格列名
        self._refresh_data_search_field_combo()

        # 1. 日期筛选
        date_filtered_rows = self._apply_date_filter(headers, data_rows)

        # 2. 多条件筛选
        condition_filtered_rows = self._apply_condition_filter(headers, date_filtered_rows)

        # 3. 搜索筛选（与 CRM 完全一致的逻辑）
        if hasattr(self, 'data_search_stack') and self.data_search_stack.currentIndex() == 1:
            # 日期范围搜索
            search_field = ''
            if hasattr(self, 'data_search_field_combo'):
                search_field = self.data_search_field_combo.currentData() or ''
            if search_field:
                dr = self.data_search_date_btn.property('date_range') or {}
                if dr.get('start') and dr.get('end'):
                    start_str = dr['start'].toString('yyyy-MM-dd')
                    end_str = dr['end'].toString('yyyy-MM-dd')
                    col_idx = -1
                    for idx, h in enumerate(headers):
                        if str(h or '').strip() == search_field:
                            col_idx = idx
                            break
                    if col_idx >= 0:
                        filtered = []
                        for entry in condition_filtered_rows:
                            row_data = entry[1] if isinstance(entry, tuple) else entry
                            if col_idx < len(row_data):
                                cell = str(row_data[col_idx] or '')[:10]
                                if start_str <= cell <= end_str:
                                    filtered.append(entry)
                        condition_filtered_rows = filtered
            self.current_filtered_rows = condition_filtered_rows
        else:
            search = self.data_search_input.text().strip().lower() if hasattr(self, 'data_search_input') else ''
            if search:
                search_field = ''
                if hasattr(self, 'data_search_field_combo'):
                    search_field = self.data_search_field_combo.currentData() or ''
                if search_field:
                    # 指定字段搜索
                    col_idx = -1
                    for idx, h in enumerate(headers):
                        if str(h or '').strip() == search_field:
                            col_idx = idx
                            break
                    if col_idx >= 0:
                        filtered = []
                        for entry in condition_filtered_rows:
                            row_data = entry[1] if isinstance(entry, tuple) else entry
                            if col_idx < len(row_data) and search in str(row_data[col_idx] or '').lower():
                                filtered.append(entry)
                        condition_filtered_rows = filtered
                else:
                    # 全字段搜索
                    filtered = []
                    for entry in condition_filtered_rows:
                        row_data = entry[1] if isinstance(entry, tuple) else entry
                        if any(search in str(v or '').lower() for v in row_data):
                            filtered.append(entry)
                    condition_filtered_rows = filtered
            self.current_filtered_rows = condition_filtered_rows

        self._refresh_current_table_page()

    def _refresh_current_table_page(self):
        """按当前筛选条件和分页设置刷新表格页"""
        headers = list(getattr(self, 'current_source_headers', []))
        data_entries = list(getattr(self, 'current_filtered_rows', []))

        # ✅ 优先使用内存中的 current_visible_headers（避免从配置文件重新解析导致旧值）
        current_visible = getattr(self, 'current_visible_headers', None)
        if current_visible and len(current_visible) > 0:
            print(f"[DEBUG-文件生成] ✅ 使用内存中的visible_headers: {len(current_visible)}个字段")
            all_headers, ordered_headers, visible_headers, source_index_map = self._resolve_excel_table_headers(headers)
            visible_headers = [h for h in current_visible if h in all_headers]
            if not visible_headers:
                visible_headers = all_headers[1:] if len(all_headers) > 1 else all_headers
            ordered_headers = list(visible_headers) + [h for h in all_headers if h not in visible_headers]
            print(f"[DEBUG-文件生成] 实际使用visible_headers: {len(visible_headers)}个字段 | 列表: {visible_headers[:10]}")
        else:
            print(f"[DEBUG-文件生成] 内存中无visible_headers，从配置文件解析")
            all_headers, _, visible_headers, source_index_map = self._resolve_excel_table_headers(headers)

        data_entries = self._sort_excel_data_entries(data_entries, visible_headers, source_index_map)
        display_headers = [""] + visible_headers
        total_rows = len(data_entries)
        page_size = max(1, self._get_current_page_size())
        total_pages = max(1, (total_rows + page_size - 1) // page_size)
        if self.current_page > total_pages:
            self.current_page = total_pages
        if self.current_page < 1:
            self.current_page = 1

        start_index = (self.current_page - 1) * page_size
        end_index = start_index + page_size
        page_rows = data_entries[start_index:end_index]
        self._current_page_rows = list(page_rows)
        selected_row_ids = self._get_operation_selected_row_ids()

        # ✅ 检查是否需要重建表格结构（列数变化时才重建）
        force_rebuild = getattr(self, '_force_rebuild_data_table', False)
        need_rebuild = force_rebuild or (
            self.data_table.columnCount() != len(display_headers) or
            self.data_table.horizontalHeader() is None or
            len(display_headers) == 0
        )

        if need_rebuild:
            print(f"[DEBUG-列宽] 文件生成表格 | 需要重建 | _data_table_column_widths_applied={getattr(self, '_data_table_column_widths_applied', False)}")
            # ✅ 只在结构变化时才完全重建
            self._is_updating_data_table = True

            # 保存当前列宽（如果有）
            current_widths = {}
            if self.data_table.columnCount() > 0:
                for col in range(self.data_table.columnCount()):
                    current_widths[col] = self.data_table.columnWidth(col)

            self.data_table.clear()
            self.data_table.setColumnCount(len(display_headers))
            self.data_table.setHorizontalHeaderLabels(display_headers)
            self.data_table.setRowCount(len(page_rows))

            # ✅ 关键修复：重建表格后必须重新设置ResizeMode，否则clear()/setColumnCount()会重置为默认值
            header = self.data_table.horizontalHeader()
            header.setSectionResizeMode(0, QHeaderView.ResizeMode.Fixed)
            for ci in range(1, len(display_headers)):
                header.setSectionResizeMode(ci, QHeaderView.ResizeMode.Interactive)
            header.setSectionsMovable(True)

            # ✅ 关键修复：重建表格后必须重新连接sectionResized信号！
            # 否则 setHorizontalHeaderLabels() 可能会导致原信号连接失效
            try:
                header.sectionResized.disconnect(self._on_data_table_column_resized)
            except Exception:
                pass  # 可能未连接
            header.sectionResized.connect(self._on_data_table_column_resized)
            try:
                header.sectionMoved.disconnect(self.on_data_table_header_moved)
            except Exception:
                pass
            header.sectionMoved.connect(self.on_data_table_header_moved)
            print(f"[DEBUG-列宽] [OK] 已重新连接sectionResized信号")

            config = load_config()  # 强制加载最新配置
            app_set = config.get('app_settings', {})
            data_set = app_set.get('data_table_settings', {})

            # ✅ 修复：优先从按功能选项保存的列宽中读取
            operation_value = getattr(self, 'selected_operation', None)
            saved_widths_raw = {}
            if operation_value is not None:
                by_operation = data_set.get('column_widths_by_operation', {})
                op_key = str(operation_value)
                if op_key in by_operation:
                    saved_widths_raw = by_operation[op_key]

            # 如果没有找到按功能选项保存的列宽，则使用通用位置（向后兼容）
            if not saved_widths_raw:
                saved_widths_raw = data_set.get('column_widths', {})

            # ✅ 关键修复：统一键类型为整数
            saved_widths = {}
            for k, v in saved_widths_raw.items():
                try:
                    saved_widths[int(k)] = v
                except (ValueError, TypeError):
                    pass

            print(f"[DEBUG-列宽] 文件生成表格 | 保存的列宽数量: {len(saved_widths)} | 显示列数: {len(display_headers)}")

            if saved_widths and 0 in saved_widths:
                self.data_table.setColumnWidth(0, saved_widths.get(0, 22))
            else:
                self.data_table.setColumnWidth(0, 22)

            for col_idx in range(1, len(display_headers)):
                # ✅ 如果已经应用过保存的列宽，只设置有保存值的列，不强制覆盖
                if getattr(self, '_data_table_column_widths_applied', False) and saved_widths and col_idx in saved_widths:
                    self.data_table.setColumnWidth(col_idx, saved_widths[col_idx])
                elif saved_widths and col_idx in saved_widths:
                    # 首次加载：使用保存的宽度
                    self.data_table.setColumnWidth(col_idx, saved_widths[col_idx])
                elif current_widths and col_idx in current_widths:
                    self.data_table.setColumnWidth(col_idx, current_widths[col_idx])
                else:
                    # 只在首次加载时设置默认值
                    if not getattr(self, '_data_table_column_widths_applied', False):
                        if col_idx == 1:
                            self.data_table.setColumnWidth(col_idx, 120)
                        elif col_idx <= 5:
                            self.data_table.setColumnWidth(col_idx, 100)
                        else:
                            self.data_table.setColumnWidth(col_idx, 80)

            print(f"[DEBUG-列宽] 文件生成表格 | 列宽设置完成")

            # ✅ 验证：打印实际列宽
            actual_widths = {}
            for ci in range(min(5, self.data_table.columnCount())):
                actual_widths[ci] = self.data_table.columnWidth(ci)
            print(f"[DEBUG-列宽] 验证-重建后前5列实际宽度: {actual_widths}")
        else:
            # ✅ 结构不变，只更新行数和数据内容（保持列宽不变）
            self._is_updating_data_table = True
            old_row_count = self.data_table.rowCount()
            new_row_count = len(page_rows)

            if new_row_count > old_row_count:
                self.data_table.setRowCount(new_row_count)
            elif new_row_count < old_row_count:
                for row in range(old_row_count - 1, new_row_count - 1, -1):
                    self.data_table.removeRow(row)

        self._force_rebuild_data_table = False

        self.table_raw_data = []
        self.current_all_headers = all_headers
        self.current_visible_headers = visible_headers
        self.current_header_source_index_map = dict(source_index_map)

        for row_idx, entry in enumerate(page_rows):
            row_id, row_data = entry
            checkbox_item = QTableWidgetItem()
            checkbox_item.setFlags(Qt.ItemFlag.ItemIsEnabled)
            checkbox_item.setData(Qt.ItemDataRole.UserRole, row_id)
            self.data_table.setItem(row_idx, 0, checkbox_item)

            checkbox_widget = TableRowCheckBox(row_id=row_id)
            checkbox_widget.blockSignals(True)
            checkbox_widget.setChecked(row_id in selected_row_ids)
            checkbox_widget.blockSignals(False)
            checkbox_widget.toggled_with_row_id.connect(self.on_row_checkbox_toggled)

            checkbox_container = QWidget()
            checkbox_layout = QHBoxLayout(checkbox_container)
            checkbox_layout.setContentsMargins(0, 0, 0, 0)
            checkbox_layout.setAlignment(Qt.AlignmentFlag.AlignCenter)
            checkbox_layout.addWidget(checkbox_widget)
            self.data_table.setCellWidget(row_idx, 0, checkbox_container)
            
            for col_idx, header in enumerate(visible_headers):
                source_index = source_index_map.get(header, -1)
                value = row_data[source_index] if 0 <= source_index < len(row_data) else None
                # 处理None值和公式结果
                if value is None:
                    display_value = ""
                elif isinstance(value, float):
                    # 处理浮点数，避免过长小数
                    if value == int(value):
                        display_value = str(int(value))
                    else:
                        display_value = f"{value:.2f}"
                else:
                    display_value = str(value)
                
                item = QTableWidgetItem(display_value)
                item.setFlags(item.flags() & ~Qt.ItemFlag.ItemIsEditable)
                self.data_table.setItem(row_idx, col_idx + 1, item)
            
            row_dict = {}
            for header in all_headers:
                source_index = source_index_map.get(header, -1)
                row_dict[header] = row_data[source_index] if 0 <= source_index < len(row_data) else None
            self.table_raw_data.append(row_dict)

        self._is_updating_data_table = False
        self._update_data_header_summary()
        self._update_header_checkbox_state()
        self._update_pagination_controls()
        self._update_data_table_sort_indicator()

        # ✅ 延迟应用列宽 - 确保在所有其他操作完成后执行，不会被覆盖
        from PyQt6.QtCore import QTimer
        QTimer.singleShot(10, self._delayed_apply_data_table_column_widths)
    
    def _get_active_filter_date_range(self):
        """获取当前日期范围，未选择时返回(None, None)"""
        start_date = getattr(self, 'selected_filter_start_date', None)
        end_date = getattr(self, 'selected_filter_end_date', None)
        if not start_date or not end_date:
            return None, None
        if not start_date.isValid() or not end_date.isValid():
            return None, None
        if start_date > end_date:
            start_date, end_date = end_date, start_date
        return start_date, end_date

    def _apply_date_filter(self, headers, data_rows):
        """应用日期筛选，返回筛选后的数据行"""
        start_date, end_date = self._get_active_filter_date_range()
        if not start_date or not end_date or not headers:
            return list(enumerate(data_rows))

        date_fields = ['日期', '开始日期', '结束日期', '合同日期', '签署日期', '签订日期']
        date_field_indexes = [i for i, header in enumerate(headers) if header in date_fields]
        if not date_field_indexes:
            return list(enumerate(data_rows))

        filtered_rows = []
        for row_index, row_data in enumerate(data_rows):
            for index in date_field_indexes:
                if index < len(row_data):
                    cell_val = row_data[index]
                    if cell_val:
                        try:
                            if isinstance(cell_val, datetime):
                                cell_date = QDate(cell_val.year, cell_val.month, cell_val.day)
                            else:
                                cell_text = str(cell_val)[:10].replace("/", "-").replace(".", "-")
                                cell_date = QDate.fromString(cell_text, "yyyy-MM-dd")
                            if cell_date.isValid() and start_date <= cell_date <= end_date:
                                filtered_rows.append((row_index, row_data))
                                break
                        except Exception:
                            continue

        return filtered_rows

    def _apply_search_filter(self, headers, data_entries):
        """应用搜索过滤（支持全字段 / 指定字段 / 日期时间段）"""
        if not hasattr(self, 'data_search_input'):
            return list(data_entries)

        # 日期范围搜索
        if hasattr(self, 'data_search_stack') and self.data_search_stack.currentIndex() == 1:
            search_field = ''
            if hasattr(self, 'data_search_field_combo'):
                search_field = self.data_search_field_combo.currentData() or ''
            if not search_field:
                return list(data_entries)
            dr = self.data_search_date_btn.property('date_range') or {}
            if not dr.get('start') or not dr.get('end'):
                return list(data_entries)
            start_str = dr['start'].toString('yyyy-MM-dd')
            end_str = dr['end'].toString('yyyy-MM-dd')
            col_idx = -1
            for idx, h in enumerate(headers):
                if str(h or '').strip() == search_field:
                    col_idx = idx
                    break
            if col_idx < 0:
                return list(data_entries)
            filtered = []
            for entry in data_entries:
                if isinstance(entry, tuple) and len(entry) == 2:
                    row_id, row_data = entry
                else:
                    row_data = entry
                if col_idx < len(row_data):
                    cell = str(row_data[col_idx] or '')[:10]
                    if start_str <= cell <= end_str:
                        filtered.append(entry)
            return filtered

        # 文本搜索
        keyword = self.data_search_input.text().strip().lower()
        if not keyword:
            return list(data_entries)

        search_field = ''
        if hasattr(self, 'data_search_field_combo'):
            search_field = self.data_search_field_combo.currentData() or ''

        filtered_entries = []
        for entry in data_entries:
            # 兼容 tuple (row_id, row_data) 和 list [cell1, cell2, ...] 格式
            if isinstance(entry, tuple) and len(entry) == 2:
                row_id, row_data = entry
            else:
                row_data = entry
            if search_field:
                col_idx = -1
                for idx, h in enumerate(headers):
                    if str(h or '').strip() == search_field:
                        col_idx = idx
                        break
                if col_idx >= 0 and col_idx < len(row_data):
                    if keyword in str(row_data[col_idx] or '').lower():
                        filtered_entries.append(entry)
            else:
                values = row_data
                if any(keyword in str(v or '').lower() for v in values):
                    filtered_entries.append(entry)
        return filtered_entries

    def _trigger_date_filter_update(self):
        """延迟触发日期筛选，避免连续重绘"""
        if hasattr(self, '_date_filter_timer'):
            self._date_filter_timer.start(180)

    def apply_date_filter_now(self):
        """应用日期筛选到当前缓存数据"""
        if hasattr(self, 'selected_operation') and self.selected_operation:
            cache_key = str(self.selected_operation)
            if cache_key in getattr(self, '_data_cache', {}):
                cached_headers, cached_rows = self._data_cache[cache_key]
                self.current_page = 1
                self._update_data_table(cached_headers, cached_rows)
            else:
                self.load_excel_data_to_table(self.selected_operation)

    def on_date_filter_changed(self):
        """日期变化后延迟应用筛选"""
        self._trigger_date_filter_update()

    def get_selected_rows_from_table(self):
        """从缓存中获取用户勾选的全部行数据（支持跨页）"""
        selected_rows = []
        if not getattr(self, 'selected_operation', None):
            return selected_rows

        cache_key = str(self.selected_operation)
        selected_ids = self._get_operation_selected_row_ids()
        if cache_key in getattr(self, '_data_cache', {}) and selected_ids:
            _, cached_rows = self._data_cache[cache_key]
            header_source_index_map = dict(getattr(self, 'current_header_source_index_map', {}))
            for row_id in sorted(selected_ids):
                if 0 <= row_id < len(cached_rows):
                    row_data = cached_rows[row_id]
                    row_dict = {}
                    for header in self.current_all_headers:
                        source_index = header_source_index_map.get(header, -1)
                        row_dict[header] = row_data[source_index] if 0 <= source_index < len(row_data) else None
                    selected_rows.append(row_dict)
            return selected_rows

        if not hasattr(self, 'data_table') or not hasattr(self, 'table_raw_data'):
            return selected_rows

        for row in range(self.data_table.rowCount()):
            checkbox_container = self.data_table.cellWidget(row, 0)
            checkbox = checkbox_container.findChild(QCheckBox) if checkbox_container else None
            if checkbox and checkbox.isChecked():
                if row < len(self.table_raw_data):
                    selected_rows.append(self.table_raw_data[row])

        return selected_rows

    def on_confirm_operation(self):
        """确认执行选中的操作"""
        if self.selected_operation is None:
            messagebox.showwarning("提示", "请先选择一个操作类型！")
            return
        
        # 获取用户勾选的行数据
        selected_rows = self.get_selected_rows_from_table()
        
        if len(selected_rows) == 0:
            messagebox.showwarning("提示", "请在列表中选择要生成的合同！")
            return

        # 更新状态
        status_text = f"处理中... (已选择 {len(selected_rows)} 条记录)"
        self.append_output(status_text)

        # 在后台线程中执行处理，传递选中的行数据
        thread = threading.Thread(target=self.run_process_with_choice, args=(self.selected_operation, selected_rows))
        thread.daemon = True
        thread.start()

        # 禁用按钮
        self.confirm_btn.setEnabled(False)
        self.confirm_btn.setText("执行中>>>")

    def append_output(self, text):
        """追加文本到输出窗口"""
        append_user_operation_record(text)
        # 副窗口：排除数据加载日志和过程细节，仅显示生成结果
        t = str(text)
        _show_in_sub = True
        if t.startswith('[') or t.startswith('  ') or t.startswith('\t'):
            _show_in_sub = False
        elif any(t.startswith(p) for p in ('处理页面', '原文件名', '新文件名', '页面',
                                             '水印', '当前字体', '成功设置', '尝试加载',
                                             '字体 ', '使用备用', 'MediaBox', 'CropBox',
                                             '旋转角度', '选中的文件')):
            _show_in_sub = False
        def safe_append():
            if hasattr(self, 'output_text'):
                self.output_text.append(text)
                self.output_text.ensureCursorVisible()
            if hasattr(self, 'sub_output_text') and not self.output_visible and _show_in_sub:
                self.sub_output_text.append(text)
                self.sub_output_text.ensureCursorVisible()
        from PyQt6.QtCore import QTimer
        QTimer.singleShot(0, safe_append)

    def on_clear_output(self):
        """清除输出窗口内容"""
        self.output_text.clear()
        if hasattr(self, 'sub_output_text'):
            self.sub_output_text.clear()

    # ============== 后台任务状态栏处理 ==============

    def _on_task_status_changed(self, task_id, name, status):
        """任务状态变化时刷新状态栏"""
        self._refresh_task_bar()

    def _on_task_completed(self, task_id, success, message):
        """任务完成：刷新状态栏 + 处理特定任务的 UI 恢复"""
        self._refresh_task_bar()
        # MySQL 同步完成：恢复按钮和标签
        if 'mysql_sync' in task_id:
            self._on_mysql_sync_completed(task_id, success, message)
        # MySQL 连接测试完成
        if task_id == 'mysql_test_connection':
            self._on_mysql_test_completed(task_id, success, message)

    def _on_task_error_occurred(self, task_id, error_message):
        """任务异常"""
        self.append_output(f"[后台任务] {task_id} 失败: {error_message}")
        self._refresh_task_bar()

    def _refresh_task_bar(self):
        """根据当前活跃任务刷新状态栏显示"""
        count = self.task_manager.active_count
        names = self.task_manager.active_task_names()
        if count == 0:
            self.task_status_bar.setMaximumHeight(0)
            self.task_status_label.setText("")
            self.task_count_label.setText("")
            self.task_status_icon_label.setText("")
        else:
            self.task_status_bar.setMaximumHeight(80)
            frames = ["◐", "◓", "◑", "◒"]
            idx = (int(time.time() * 2)) % len(frames)
            summary = "、".join(names[:3])
            if count > 3:
                summary += f" 等{count}个任务"
            self.task_status_icon_label.setText(f"{frames[idx]} 后台任务")
            self.task_status_label.setText(summary)
            self.task_count_label.setText(f"{count} 个运行中")

    def _on_mysql_sync_completed(self, task_id, success, message):
        """MySQL 同步任务完成：恢复按钮和更新状态标签"""
        if hasattr(self, 'obj_query_sync_btn'):
            self.obj_query_sync_btn.setText("同步")
            self.obj_query_sync_btn.setEnabled(True)
        data = getattr(self, 'obj_query_all_data', [])
        if hasattr(self, 'obj_query_status_label') and data:
            self.obj_query_status_label.setText(f"✅ 已同步 {len(data)} 条到 MySQL")

    def _on_mysql_test_completed(self, task_id, success, message):
        """MySQL 连接测试完成：更新状态标签和按钮"""
        # 查找 SettingsDialog 实例以更新其 UI
        settings_dialog = None
        if hasattr(self, 'settings_dialog') and self.settings_dialog:
            settings_dialog = self.settings_dialog

        if settings_dialog is None:
            return

        # 恢复按钮
        if hasattr(settings_dialog, 'mysql_test_btn'):
            settings_dialog.mysql_test_btn.setEnabled(True)

        if not success:
            # 超时或连接失败
            error_text = message or '连接失败'
            if hasattr(settings_dialog, 'mysql_status_label'):
                settings_dialog.mysql_status_label.setText(f"❌ {error_text}")
                settings_dialog.mysql_status_label.setStyleSheet(
                    "QLabel { color: #d13438; padding: 8px; font-size: 13px; }")
            return

        result = getattr(settings_dialog, '_mysql_test_result', None)
        if not result:
            return
        if hasattr(settings_dialog, 'mysql_status_label'):
            if result['success']:
                settings_dialog.mysql_status_label.setText(
                    f"✅ 连接成功！服务器: {result['host']}:{result['port']}\n"
                    f"数据库: {result['database']} | MySQL版本: {result['version']}")
                settings_dialog.mysql_status_label.setStyleSheet(
                    "QLabel { color: #107c10; padding: 8px; font-size: 13px; }")
            else:
                settings_dialog.mysql_status_label.setText(f"❌ 连接失败: {result['error']}")
                settings_dialog.mysql_status_label.setStyleSheet(
                    "QLabel { color: #d13438; padding: 8px; font-size: 13px; }")

    # ============== 后台任务状态栏处理结束 ==============

    def on_toggle_output(self):
        """切换输出窗口的显示/隐藏状态"""
        self.output_visible = not self.output_visible
        self.save_user_runtime_state_patch({'output_visible': self.output_visible}, immediate=True)

        if self.output_visible:
            self.output_frame.show()
            self.toggle_output_btn.setText("隐藏")
            if hasattr(self, 'sub_output_frame'):
                self.sub_output_frame.hide()
        else:
            self.output_frame.hide()
            self.toggle_output_btn.setText("显示")
            if hasattr(self, 'sub_output_frame'):
                self.sub_output_frame.show()
    
    def update_operation_buttons(self, preferred_value=None):
        """更新主界面的功能选项下拉框"""
        # 从配置文件中重新加载操作选项
        config = load_config()
        self.config = config
        gui_options = config.get('gui_options', [
            {"text": "SAAS合同", "value": 1},
            {"text": "招投标授权", "value": 2},
            {"text": "服务协议", "value": 3},
            {"text": "CRM合同", "value": 4},
            {"text": "经销协议", "value": 5}
        ])
        
        # 过滤掉PDF文件整理选项
        gui_options = [option for option in gui_options if option.get('text', '') != 'PDF文件整理']

        # 按value排序，确保顺序一致
        gui_options.sort(key=lambda x: x['value'])

        # 更新实例变量
        self.gui_options = gui_options
        self.operation_map = {i: option['value'] for i, option in enumerate(gui_options)}
        
        # 更新下拉框
        if hasattr(self, 'operation_combo'):
            # 阻止信号触发
            self.operation_combo.blockSignals(True)
            
            # 记录当前选中的值
            current_value = preferred_value if preferred_value is not None else self.operation_combo.currentData()
            
            # 清空并重新填充
            self.operation_combo.clear()

            self.operation_combo.addItem("请选择功能", None)
            
            for option in gui_options:
                text = option.get("text", "")
                value = option.get("value", 0)
                self.operation_combo.addItem(text, value)
            
            # 尝试恢复之前的选择
            if current_value is not None:
                index = self.operation_combo.findData(current_value)
                if index >= 0:
                    self.operation_combo.setCurrentIndex(index)
                    self.selected_operation = current_value
                elif self.operation_combo.count() > 0:
                    self.operation_combo.setCurrentIndex(0)
                    self.selected_operation = self.operation_combo.currentData()
            elif self.operation_combo.count() > 0:
                self.operation_combo.setCurrentIndex(0)
                self.selected_operation = self.operation_combo.currentData()
            
            # 恢复信号
            self.operation_combo.blockSignals(False)

            self.persist_contract_page_state()

    def run_process_with_choice(self, selected_choice, selected_rows=None):
        """在后台线程中执行处理，使用预选择的选项和选中的行数据"""
        try:
            global choice
            choice = selected_choice

            # 清空缓存文件夹
            self.update_output.emit("清空缓存文件夹...")
            print("清空缓存文件夹...")
            try:
                # 加载配置获取缓存文件夹路径
                config = load_config()
                log_dir = config.get('path_config', {}).get('log_dir', 'Cache')
                cache_path = Path(log_dir)
                if cache_path.exists() and cache_path.is_dir():
                    deleted_count = 0
                    skipped_count = 0
                    for f in cache_path.iterdir():
                        if f.is_file():
                            try:
                                f.unlink()
                                deleted_count += 1
                            except Exception as e:
                                print(f"跳过被占用的文件: {f.name} - {str(e)}")
                                skipped_count += 1
                    if deleted_count > 0:
                        self.update_output.emit(f"缓存文件夹已清空")
                        print(f"缓存文件夹已清空，删除了 {deleted_count} 个文件，跳过了 {skipped_count} 个被占用的文件: {cache_path}")
                    else:
                        self.update_output.emit(f"缓存文件夹为空或所有文件都被占用: {cache_path}")
                        print(f"缓存文件夹为空或所有文件都被占用: {cache_path}")
                else:
                    self.update_output.emit(f"缓存文件夹不存在: {cache_path}")
                    print(f"缓存文件夹不存在: {cache_path}")
            except Exception as e:
                self.update_output.emit(f"清空缓存文件夹失败: {str(e)}")
                print(f"清空缓存文件夹失败: {str(e)}")

            config = AppConfig()
            config.get_target_root(choice).mkdir(parents=True, exist_ok=True)

            # 核心处理流程
            self.update_output.emit("开始处理Excel模板...")
            # 检查Excel模板是否存在
            excel_template_path = AppConfig.get_excel_template_path(choice)
            if excel_template_path.exists():
                self.update_output.emit(f"Excel模板存在，开始处理: {excel_template_path}")
            else:
                self.update_output.emit(f"错误: Excel模板不存在，请检查路径: {excel_template_path}")
            process_excel_template(choice)
            self.update_output.emit("Excel模板处理完成")

            self.update_output.emit("开始生成合同...")
            generated_contracts = generate_contracts(AppConfig.get_field_mapping(), selected_rows)
            self.update_output.emit(f"✓ 合同生成完成（共 {len(generated_contracts)} 个）")

            self.update_output.emit("开始转换为PDF格式...")
            import os
            output_dir = AppConfig.OUTPUT_DIR
            pdf_count = 0
            word_count = 0
            for contract_name in generated_contracts:
                word_file = output_dir / f"{contract_name}{AppConfig.FILE_EXTENSION}"
                pdf_file = output_dir / f"{contract_name}.pdf"
                if pdf_file.exists() and pdf_file.stat().st_size > 0:
                    pdf_count += 1
                if word_file.exists():
                    word_count += 1

            if pdf_count > 0:
                self.update_output.emit(f"✓ PDF转换完成（{pdf_count}/{word_count} 个成功）")
            else:
                self.update_output.emit(f"⚠ PDF转换未成功，请检查：")
                self.update_output.emit("   1. 是否安装了Microsoft Word或LibreOffice")
                self.update_output.emit("   2. 是否安装了comtypes库（pip install comtypes）")
                self.update_output.emit("   3. 查看控制台日志了解详细错误信息")

            self.update_output.emit("开始整理输出文件...")
            organize_output_files()
            self.update_output.emit("文件整理完成")

            self.update_output.emit("打开输出文件夹...")
            open_output_folder()
            self.update_output.emit("输出文件夹已打开")

            # 检查SVN提交设置，根据设置决定是否提交SVN
            config = load_config()
            app_settings = config.get('app_settings', {})
            svn_submission = app_settings.get('svn_submission', True)
            
            if svn_submission:
                # 延时0.8秒后再提交SVN
                self.update_output.emit("准备提交SVN...")
                import time
                time.sleep(0.8)
                commit_to_svn()
                self.update_output.emit("SVN提交完成")
            else:
                self.update_output.emit("SVN提交功能已关闭，跳过提交")

            # 打印生成的合同编号
            if generated_contracts:
                self.update_output.emit("\n生成的合同编号:")
                for contract in generated_contracts:
                    self.update_output.emit(f"{contract}")
            else:
                self.update_output.emit("\n未生成任何合同")

            # 恢复确认按钮状态
            self.enable_button.emit()
            
            # 执行完成后保持上次选择的功能
        except Exception as e:
            # 处理错误
            error_msg = f"处理失败: {str(e)}"
            self.update_output.emit(error_msg)
            print(error_msg)
            # 在主线程中显示错误对话框
            from PyQt6.QtCore import QTimer
            error_str = str(e)
            QTimer.singleShot(0, lambda: self.show_error_dialog(error_str))
            # 恢复确认按钮状态
            self.enable_button.emit()
            # 错误处理后保持上次选择的功能
            logging.error(error_msg)

