    def on_organize_files(self):
        """执行文件整理操作"""
        try:
            source_dir = self.source_dir_text.text().strip()
            target_dir = self.target_dir_text.text().strip()
            file_extensions = self.file_type_text.text().strip()
            filename_contains = self.filename_text.text().strip()
            
            if not source_dir:
                show_error("错误", "请选择源文件夹")
                return
            
            if not target_dir:
                show_error("错误", "请选择目标文件夹")
                return

            if self.organize_file_table.rowCount() == 0:
                self.load_organize_file_list()

            selected_files = []
            for row in range(self.organize_file_table.rowCount()):
                item = self.organize_file_table.item(row, 0)
                path_item = self.organize_file_table.item(row, 5)
                if item and path_item and item.checkState() == Qt.CheckState.Checked:
                    selected_files.append(path_item.text())

            if not selected_files:
                show_error("提示", "请至少勾选一个文件")
                return
            
            # 执行文件整理
            self.append_output(f"\n=== 开始文件整理 ===")
            self.append_output(f"源文件夹: {source_dir}")
            self.append_output(f"目标文件夹: {target_dir}")
            self.append_output(f"文件后缀: {file_extensions if file_extensions else '所有文件'}")
            self.append_output(f"文件名包含: {filename_contains if filename_contains else '无'}")
            if self.organize_start_date and self.organize_end_date:
                self.append_output(
                    f"修改时间筛选: {self.organize_start_date.toString('yyyy-MM-dd')} ~ "
                    f"{self.organize_end_date.toString('yyyy-MM-dd')}"
                )
            self.append_output(f"勾选文件数: {len(selected_files)}")
            
            # 调用文件整理函数
            moved_count = self.move_files_to_new_folders(selected_files, target_dir)
            
            self.append_output(f"\n=== 文件整理完成 ===")
            self.append_output(f"成功移动 {moved_count} 个文件")
            self.append_output("====================")

            self.load_organize_file_list()

            # 打开目标文件夹（受通用设置控制）
            if self.config.get('app_settings', {}).get('open_output_folder', True):
                open_folder(target_dir)

            # 提交到SVN
            self.commit_to_svn(target_dir)
            
        except Exception as e:
            show_error("错误", f"文件整理失败: {str(e)}")
            self.append_output(f"\n=== 文件整理失败 ===")
            self.append_output(f"错误信息: {str(e)}")
            self.append_output("====================")

    def move_files_to_new_folders(self, selected_files, target_root):
        """将勾选文件移动到按文件名命名的新文件夹中"""
        moved_count = 0

        for file_name in selected_files:
            file_path = Path(file_name)
            if not file_path.exists() or not file_path.is_file():
                continue
            # 获取文件名（不含扩展名）
            base_name = file_path.stem
            # 在目标根目录下创建与文件名相同的新文件夹
            target_folder_path = os.path.join(target_root, base_name)
            os.makedirs(target_folder_path, exist_ok=True)  # 如果文件夹已存在，则不会抛出错误

            # 构建目标文件路径
            dst_file_path = os.path.join(target_folder_path, file_path.name)
            # 将文件从源路径移动到目标路径
            shutil.move(file_path, dst_file_path)
            # 打印移动信息
            self.append_output(f"移动文件: {file_path.name} → {base_name}")
            moved_count += 1
        
        return moved_count

    def on_exit(self):
        """退出按钮事件处理"""
        self.close()

    def switch_tab(self, index):
        """切换标签页"""
        # 切换标签页
        self.tab_widget.setCurrentIndex(index)
        
        # 更新标签按钮状态
        if index == 0:
            self.contract_tab_btn.setChecked(True)
            self.pdf_tab_btn.setChecked(False)
        elif index == 1:
            self.contract_tab_btn.setChecked(False)
            self.pdf_tab_btn.setChecked(True)
    
    def on_close(self, event=None):
        """窗口关闭事件处理"""
        # 关闭前先停止列宽相关定时器，并强制落盘最后一次调整结果
        for timer_name in ('_crm_column_width_save_timer', '_data_column_width_save_timer', '_opportunity_column_width_save_timer', '_obj_query_column_width_save_timer', '_auto_save_column_widths_timer', '_ui_scale_save_timer'):
            if hasattr(self, timer_name):
                timer = getattr(self, timer_name)
                if hasattr(timer, 'isActive') and timer.isActive():
                    timer.stop()

        # 保存窗口大小和位置，供下次启动恢复
        try:
            if self.isMaximized():
                normal_geo = self.normalGeometry()
                window_size = [normal_geo.width(), normal_geo.height()]
                window_pos = [normal_geo.x(), normal_geo.y()]
            elif not self.isMinimized():
                window_size = [self.width(), self.height()]
                window_pos = [self.x(), self.y()]
            else:
                window_size = None
                window_pos = None
            if window_size is not None:
                save_user_runtime_state({
                    'window_size': window_size,
                    'window_pos': window_pos,
                }, immediate=True, merge=True)
        except Exception as e:
            logging.error(f"关闭时保存窗口几何失败: {str(e)}")

        try:
            self._persist_ui_scale_percent()
        except Exception as e:
            logging.error(f"关闭时保存界面缩放失败: {str(e)}")

        try:
            self._remove_global_zoom_event_filter()
        except Exception as e:
            logging.error(f"关闭时移除全局缩放事件失败: {str(e)}")

        if getattr(self, 'tray_icon', None) is not None:
            try:
                self.tray_icon.hide()
            except Exception as e:
                logging.error(f"关闭时隐藏托盘图标失败: {str(e)}")

        try:
            if hasattr(self, 'crm_table') and self.crm_table.columnCount() > 0:
                self._save_crm_column_widths()
        except Exception as e:
            logging.error(f"关闭时保存CRM列宽失败: {str(e)}")

        try:
            if hasattr(self, 'data_table') and self.data_table.columnCount() > 0:
                self._save_data_table_column_widths()
        except Exception as e:
            logging.error(f"关闭时保存文件生成列宽失败: {str(e)}")

        try:
            if hasattr(self, 'opportunity_table') and self.opportunity_table.columnCount() > 0:
                self._save_opportunity_column_widths()
        except Exception as e:
            logging.error(f"关闭时保存商机列宽失败: {str(e)}")

        try:
            if hasattr(self, 'obj_query_table') and self.obj_query_table.columnCount() > 0:
                self._save_obj_query_column_widths()
        except Exception as e:
            logging.error(f"关闭时保存对象查询列宽失败: {str(e)}")

        # ✅ 性能优化：关闭前保存未保存的CRM映射数据
        if hasattr(self, 'settings_dialog') and self.settings_dialog:
            if hasattr(self.settings_dialog, '_crm_mapping_dirty') and self.settings_dialog._crm_mapping_dirty:
                try:
                    # 立即保存脏数据
                    if hasattr(self.settings_dialog, '_debounced_save_crm_option_mapping'):
                        self.settings_dialog._debounced_save_crm_option_mapping()
                except Exception as e:
                    logging.error(f"关闭时保存CRM映射失败: {str(e)}")

            # ✅ 性能优化：关闭前取消延迟刷新定时器，避免关闭后还触发刷新
            if hasattr(self.settings_dialog, '_crm_table_refresh_timer') and self.settings_dialog._crm_table_refresh_timer:
                if self.settings_dialog._crm_table_refresh_timer.isActive():
                    self.settings_dialog._crm_table_refresh_timer.stop()

            try:
                self.settings_dialog.close()
            except Exception as e:
                logging.error(f"关闭设置对话框失败: {str(e)}")
        
        # 保存所有设置（通过 save_config 确保 split_config_by_scope 将共享字段写入系统配置文件）
        config = load_config()
        if 'app_settings' not in config:
            config['app_settings'] = {}
        save_config(config, immediate=True)
        
        # 保存用户数据到本地配置文件，无论是否使用数据库
        try:
            users_data = load_users()
            users_path = CONFIG_DIR / 'users.json'
            users_path.parent.mkdir(exist_ok=True)
            with open(users_path, 'w', encoding='utf-8') as f:
                json.dump(users_data, f, ensure_ascii=False, indent=2)

        except Exception as e:
            logging.error(f"退出时，保存用户数据到本地配置文件失败: {str(e)}")
        
        if event:
            event.accept()
        else:
            self.destroy()



    def reset_to_default_selection(self):
        """重置为默认选择"""
        self.selected_operation = 1
        for i, radio_btn in enumerate(self.radio_buttons):
            if i == 0:
                radio_btn.setChecked(True)
                break
        
        # 更新状态显示
        for option in self.gui_options:
            if option['value'] == 1:
                operation_name = option['text']
                break
        else:
            operation_name = "SAAS合同"
        
        status_text = f"已选择: {operation_name}"
        self.append_output(status_text)
        self.confirm_btn.setEnabled(True)

    def show_error_dialog(self, error_msg):
        """显示错误对话框"""
