    def enable_confirm_button(self):
        """启用确认按钮"""
        self.confirm_btn.setEnabled(True)
        self.confirm_btn.setText("确认执行")

    def _enable_crm_generate_button(self):
        """恢复CRM生成按钮状态"""
        if hasattr(self, 'crm_generate_btn'):
            self.crm_generate_btn.setEnabled(True)
            self.crm_generate_btn.setText("生成合同")

    def on_splitter_moved(self, pos, index):
        """分割器位置改变事件处理 - 新布局中不再使用"""
        pass

    def showEvent(self, event):
        """窗口显示时确保不超出屏幕边界"""
        if not hasattr(self, '_first_show_done'):
            self._first_show_done = False
        is_first_show = not self._first_show_done
        if is_first_show and hasattr(self, '_startup_x'):
            # 在原生窗口创建前一次性设置完整几何参数（位置+尺寸），避免 show 后再调整触发二次重绘
            self.setGeometry(self._startup_x, self._startup_y, self._startup_width, self._startup_height)
        super().showEvent(event)
        if is_first_show:
            self._first_show_done = True

    def _ensure_fits_screen(self):
        """确保窗口大小和位置不超出当前屏幕"""
        screen = self.screen()
        if not screen:
            screen = QApplication.primaryScreen()
        if not screen:
            return

        geo = screen.availableGeometry()
        current = self.geometry()

        # 窗口尺寸超过屏幕可用区域则缩小到96%
        if current.width() > geo.width() or current.height() > geo.height():
            new_width = max(self.minimumWidth(), int(geo.width() * 0.80))
            new_height = max(self.minimumHeight(), int(geo.height() * 0.80))
            self.resize(new_width, new_height)
            current = self.geometry()

        # 水平垂直居中
        target_x = geo.left() + max(0, (geo.width() - current.width()) // 2)
        target_y = geo.top() + max(0, (geo.height() - current.height()) // 2)
        self.move(target_x, target_y)

    def resizeEvent(self, event):
        """主窗口大小改变事件处理（I/O去抖300ms）"""
        new_size = [self.width(), self.height()]
        self._pending_window_size = new_size
        if not hasattr(self, '_resize_save_timer'):
            self._resize_save_timer = QTimer(self)
            self._resize_save_timer.setSingleShot(True)
            self._resize_save_timer.timeout.connect(self._on_resize_save)
        self._resize_save_timer.start(300)
        super().resizeEvent(event)

    def _on_resize_save(self):
        """延迟保存窗口尺寸（避免resize期间I/O风暴）"""
        new_size = getattr(self, '_pending_window_size', None)
        if not new_size:
            return
        config = load_config()
        if 'app_settings' not in config:
            config['app_settings'] = {}
        config['app_settings']['window_size'] = new_size
        save_config(config, immediate=True)
        self.save_user_runtime_state_patch({'window_size': new_size}, immediate=True)

    def update_output_window_size(self, width, height):
        """更新输出窗口大小 - 新布局中自动适配，无需手动调整"""
        pass
    
