        # 确保窗口不会抢夺焦点
        self.setFocusPolicy(Qt.NoFocus)
        # 保存主窗口引用（parent 可能被 layout 重新指定，故提前保存）
        self._main_window = parent

        # 加载配置文件
        import sys; print("[DEBUG-设置初始化] SettingsDialog.__init__ 开始", flush=True, file=sys.stderr)
        self.config = load_config()
        self.runtime_state = load_user_runtime_state()
        self.crm_object_fields_cache = {}
        self._pending_setting_change_types = set()
        self._suspend_mapping_save = False
        self._mapping_save_timer = QTimer(self)
        self._mapping_save_timer.setSingleShot(True)
        self._mapping_save_timer.timeout.connect(self._flush_mapping_save)

        self.CRM_OPTION_FIELDS = {
            'field_jv2dq__c': '订单产品类型',
            'record_type': '业务类型',
            'payment_status': '付款状态',
            'life_status': '生命周期状态',

        }

        saved_option_mappings = self.config.get('business_rules', {}).get('crm_option_mappings', {})
        self.crm_option_mappings = {}
