    def create_feature_selection_tab(self):
        """创建功能配置设置标签页"""
        tab = QFrame()
        tab_layout = QVBoxLayout(tab)
        
        # 使用已加载的配置
        gui_options = self.config.get('gui_options', [
            {"text": "SAAS合同", "value": 1},
            {"text": "招投标授权", "value": 2},
            {"text": "服务协议", "value": 3},
            {"text": "CRM合同", "value": 4},
            {"text": "经销协议", "value": 5}
        ])
        
        # 按value排序
        gui_options.sort(key=lambda x: x['value'])
        
        # 功能列表表格
        feature_group = QGroupBox("功能列表")
        feature_layout = QVBoxLayout(feature_group)
        
        # 获取目标路径配置
        target_roots = self.config.get('path_config', {}).get('target_roots', {})
        
        self.feature_table = QTableWidget()
        self.feature_table.setRowCount(len(gui_options))
        self.feature_table.setColumnCount(4)
        self.feature_table.setHorizontalHeaderLabels(["Excel文件路径", "功能名称", "Excel Sheet", "生成文件路径"])
        
        # 获取Excel文件路径配置
        excel_paths = self.config.get('path_config', {}).get('excel_paths', {})
        
        # 存储Sheet下拉框的引用
        self.sheet_combos = []
        
        # 填充表格
        for i, option in enumerate(gui_options):
            # Excel文件路径列
            excel_path = excel_paths.get(str(option.get("value", i + 1)), "")
            excel_item = QTableWidgetItem(excel_path)
            self.feature_table.setItem(i, 0, excel_item)

            name_item = QTableWidgetItem(option.get("text", ""))

            # Excel Sheet列 - 使用下拉框
            sheet_combo = QComboBox()
            sheet_combo.setEditable(True)  # 允许手动输入
            current_sheet = option.get("sheet", "")

            # 如果有Excel文件路径，读取其sheet列表
            if excel_path and os.path.exists(excel_path):
                sheet_names = self._get_excel_sheets(excel_path)
                sheet_combo.addItems(sheet_names)

                # 设置当前选中的sheet
                if current_sheet:
                    index = sheet_combo.findText(current_sheet)
                    if index >= 0:
                        sheet_combo.setCurrentIndex(index)
                    else:
                        sheet_combo.setCurrentText(current_sheet)
                elif sheet_names:
                    sheet_combo.setCurrentIndex(0)
            else:
                # 没有Excel文件时，只显示当前值或空
                if current_sheet:
                    sheet_combo.addItem(current_sheet)
                    sheet_combo.setCurrentText(current_sheet)

            # 保存下拉框引用
            self.sheet_combos.append(sheet_combo)

            # Sheet变化时保存配置
            sheet_combo.currentTextChanged.connect(lambda text, row=i: self.on_sheet_changed(row, text))

            self.feature_table.setCellWidget(i, 2, sheet_combo)

            # 获取对应的路径
            path_value = target_roots.get(str(option.get("value", i + 1)), "")
            path_item = QTableWidgetItem(path_value)
            self.feature_table.setItem(i, 1, name_item)
            self.feature_table.setItem(i, 3, path_item)
        
        # 加载保存的列宽
        config = load_config()
        runtime_column_widths = self.runtime_state.get('table_column_widths', {})
        column_widths = runtime_column_widths.get('feature_table') or config.get('app_settings', {}).get('column_widths', {}).get('feature_table', [250, 120, 120, 300])
        # 确保有 4 个列宽值
        while len(column_widths) < 4:
            column_widths.append(100)
        self.feature_table.setColumnWidth(0, column_widths[0])
        self.feature_table.setColumnWidth(1, column_widths[1])
        self.feature_table.setColumnWidth(2, column_widths[2])
        self.feature_table.setColumnWidth(3, column_widths[3])
        
        feature_layout.addWidget(self.feature_table)
        tab_layout.addWidget(feature_group)
        
        # 根据用户权限设置表格和按钮的可编辑性
        has_feature_permission = self.user_permissions.get('feature_selection', False) or user_type == "admin"
        
        # 操作按钮 - 只有管理员显示
