    def create_template_tab(self):
        """创建模板管理标签页"""
        tab = QFrame()
        tab_layout = QVBoxLayout(tab)
        
        # 使用已加载的配置
        word_templates = self.config.get('file_config', {}).get('word_templates', {})
        template_dir = self.config.get('path_config', {}).get('template_dir', 'template')

        # 模板文件夹设置
        self.create_path_entry(tab_layout, "模板文件夹:", template_dir, "template_dir", is_dir=True)
        
        # 模板列表
        from PyQt6.QtWidgets import QTableWidget, QTableWidgetItem, QComboBox
        from PyQt6.QtCore import QEvent, QObject
        
        # 鼠标滚轮事件过滤器类
        class WheelEventFilter(QObject):
            """通用滚轮事件过滤器。"""
            def eventFilter(self, obj, event):
                """拦截并处理目标事件。"""
                if event.type() == QEvent.Wheel:
                    return True  # 阻止鼠标滚轮事件
                return False
        
        self.template_table = QTableWidget(len(word_templates), 2)
        self.template_table.setHorizontalHeaderLabels(["模板名称", "模板路径"])
        
        # 保存所有过滤器引用的列表
        self.template_table_wheel_filters = []
        
        # 填充表格
        for i, (name, path) in enumerate(word_templates.items()):
            # 模板名称列
            name_item = QTableWidgetItem(name)
            self.template_table.setItem(i, 0, name_item)
            
            # 模板路径列 - 使用下拉列表
            combo = QComboBox()
            # 读取模板文件夹中的word文件
            template_dir_path = resolve_app_path(template_dir)
            if template_dir_path.exists() and template_dir_path.is_dir():
                # 查找所有.docx文件
                word_files = list(template_dir_path.glob('*.docx'))
                # 添加文件路径到下拉列表
                for word_file in word_files:
                    # 使用相对路径
                    relative_path = word_file.relative_to(template_dir_path)
                    combo.addItem(str(relative_path))
            
            # 设置当前值
            combo.setCurrentText(path)
            # 连接信号
            combo.currentTextChanged.connect(lambda text, row=i: self.on_template_path_changed(row, text))
            
            # 安装鼠标滚轮事件过滤器，并保持引用防止被垃圾回收
            wheel_filter = WheelEventFilter()
            self.template_table_wheel_filters.append(wheel_filter)
            combo.installEventFilter(wheel_filter)
            
            # 添加到表格
            self.template_table.setCellWidget(i, 1, combo)
        
        # 设置表格属性
        self.template_table.horizontalHeader().setSectionResizeMode(QHeaderView.Interactive)
        # 加载保存的列宽
        config = load_config()
        runtime_column_widths = self.runtime_state.get('table_column_widths', {})
        column_widths = runtime_column_widths.get('template_table') or config.get('app_settings', {}).get('column_widths', {}).get('template_table', [150, 300])
        self.template_table.setColumnWidth(0, column_widths[0])
        self.template_table.setColumnWidth(1, column_widths[1])
        # 连接单元格编辑信号，只在编辑模板名称时保存
        def on_cell_changed(row, column):
            # 只处理模板名称列（第0列）的编辑
            """响应单元格changed相关操作。"""
            if column == 0:
                self.on_save_templates()
        
        self.template_table.cellChanged.connect(on_cell_changed)
        # 连接列宽变化信号
        self.template_table.horizontalHeader().sectionResized.connect(lambda logicalIndex, oldSize, newSize: self.save_column_widths('template_table'))
        tab_layout.addWidget(self.template_table)
        
        # 按钮
        btn_frame = QFrame()
        btn_layout = QHBoxLayout(btn_frame)
        btn_layout.setAlignment(Qt.AlignCenter)
        
        add_btn = QPushButton("添加")
        add_btn.clicked.connect(self.on_add_template)
        btn_layout.addWidget(add_btn)
        btn_layout.addSpacing(20)
        
        delete_btn = QPushButton("删除")
        delete_btn.clicked.connect(self.on_delete_template)
        btn_layout.addWidget(delete_btn)
        
        tab_layout.addWidget(btn_frame)
        
        self.notebook.addTab(tab, "模板")

    def create_crm_template_tab(self):
        """创建CRM模板管理标签页"""
        tab = QFrame()
        tab_layout = QVBoxLayout(tab)

        from PyQt6.QtWidgets import QTableWidget, QTableWidgetItem, QComboBox, QLabel, QGroupBox, QHBoxLayout, QCheckBox
        from PyQt6.QtCore import QEvent, QObject

        crm_word_templates = self.config.get('file_config', {}).get('crm_word_templates', {})
        crm_template_target_paths = self.config.get('path_config', {}).get('crm_template_target_paths', {})
        crm_template_dir = self.config.get('path_config', {}).get('crm_template_dir', 'template')
        default_crm_template = self.config.get('app_settings', {}).get('default_crm_template', '')

        self.create_path_entry(tab_layout, "CRM模板文件夹:", crm_template_dir, "crm_template_dir", is_dir=True)

        class CrmWheelEventFilter(QObject):
            """CRM下拉滚轮事件过滤器。"""
            def eventFilter(self, obj, event):
                """拦截并处理目标事件。"""
                if event.type() == QEvent.Wheel:
                    return True
                return False

        self.crm_template_table = QTableWidget(len(crm_word_templates), 4)
        self.crm_template_table.setHorizontalHeaderLabels(["默认", "模板名称", "模板路径", "目标文件路径"])

        self.crm_default_template_checkboxes = []
        self.crm_template_table_wheel_filters = []

        for i, (name, path) in enumerate(crm_word_templates.items()):
            checkbox = QCheckBox()
            checkbox.setChecked(name == default_crm_template)
            checkbox.setStyleSheet("""
                QCheckBox {
                    spacing: 0px;
                    padding: 0px;
                    margin: 0px;
                }
                QCheckBox::indicator {
                    width: 19px;
                    height: 19px;
                }
            """)
            checkbox.stateChanged.connect(lambda state, row=i: self.on_crm_default_template_changed(row, state))
            self.crm_template_table.setCellWidget(i, 0, checkbox)
            self.crm_default_template_checkboxes.append(checkbox)

            name_item = QTableWidgetItem(name)
            self.crm_template_table.setItem(i, 1, name_item)

            combo = QComboBox()
            for template_path in self._get_crm_template_file_options():
                combo.addItem(template_path)

            combo.setCurrentText(path)
            combo.currentTextChanged.connect(lambda text, row=i: self.on_crm_template_path_changed(row, text))

            wheel_filter = CrmWheelEventFilter()
            self.crm_template_table_wheel_filters.append(wheel_filter)
            combo.installEventFilter(wheel_filter)

            self.crm_template_table.setCellWidget(i, 2, combo)

            target_path = str(crm_template_target_paths.get(name, '') or '').strip()
            self.crm_template_table.setCellWidget(i, 3, self._create_crm_target_path_widget(target_path))

        self.crm_template_table.horizontalHeader().setSectionResizeMode(0, QHeaderView.ResizeMode.Fixed)
        self.crm_template_table.setColumnWidth(0, 50)
        self.crm_template_table.horizontalHeader().setSectionResizeMode(QHeaderView.Interactive)
        config = load_config()
        runtime_column_widths = self.runtime_state.get('table_column_widths', {})
        column_widths = runtime_column_widths.get('crm_template_table') or config.get('app_settings', {}).get('column_widths', {}).get('crm_template_table', [50, 150, 260, 320])
        while len(column_widths) < 4:
            column_widths.append(260)
        if len(column_widths) >= 4:
            self.crm_template_table.setColumnWidth(1, column_widths[1])
            self.crm_template_table.setColumnWidth(2, column_widths[2])
            self.crm_template_table.setColumnWidth(3, column_widths[3])

        def on_crm_cell_changed(row, column):
            """响应CRM单元格changed相关操作。"""
            if column == 1:
                self.on_save_crm_templates()

        self.crm_template_table.cellChanged.connect(on_crm_cell_changed)
        self.crm_template_table.horizontalHeader().sectionResized.connect(lambda logicalIndex, oldSize, newSize: self.save_column_widths('crm_template_table'))
        tab_layout.addWidget(self.crm_template_table)

        btn_frame = QFrame()
        btn_layout = QHBoxLayout(btn_frame)
        btn_layout.setAlignment(Qt.AlignCenter)

        add_btn = QPushButton("添加")
        add_btn.clicked.connect(self.on_add_crm_template)
        btn_layout.addWidget(add_btn)
        btn_layout.addSpacing(20)

        delete_btn = QPushButton("删除")
        delete_btn.clicked.connect(self.on_delete_crm_template)
        btn_layout.addWidget(delete_btn)

        tab_layout.addWidget(btn_frame)

