    def _get_crm_template_file_options(self):
        """读取CRM模板目录中的可选模板文件"""
        config = load_config()
        self.config = config
        crm_template_dir = config.get('path_config', {}).get('crm_template_dir', 'template')
        template_dir_path = resolve_app_path(crm_template_dir)
        if not template_dir_path.exists() or not template_dir_path.is_dir():
            return []

        word_files = sorted(template_dir_path.glob('*.docx'), key=lambda item: item.name.lower())
        options = []
        for word_file in word_files:
            try:
                options.append(str(word_file.relative_to(template_dir_path)))
            except Exception:
                options.append(word_file.name)
        return options

    def _refresh_crm_template_file_choices(self):
        """刷新CRM模板设置页的模板文件下拉框"""
        if not hasattr(self, 'crm_template_table'):
            return

        template_options = self._get_crm_template_file_options()
        for row in range(self.crm_template_table.rowCount()):
            combo = self.crm_template_table.cellWidget(row, 2)
            if not isinstance(combo, QComboBox):
                continue

            current_text = combo.currentText().strip()
            combo.blockSignals(True)
            combo.clear()
            for option in template_options:
                combo.addItem(option)

            if current_text:
                index = combo.findText(current_text)
                if index >= 0:
                    combo.setCurrentIndex(index)
                elif combo.count() > 0:
                    combo.setCurrentIndex(0)
            combo.blockSignals(False)

    def _create_crm_target_path_widget(self, initial_value=''):
        """创建CRM模板目标路径编辑控件"""
        container = QFrame()
        layout = QHBoxLayout(container)
        layout.setContentsMargins(0, 0, 0, 0)
        layout.setSpacing(4)

        line_edit = BrowseLineEdit()
        line_edit.setText(initial_value)
        line_edit.editingFinished.connect(self.on_save_crm_templates)
        line_edit.doubleClicked.connect(lambda line_edit=line_edit: self._browse_crm_template_target_dir(line_edit))
        layout.addWidget(line_edit)

        browse_btn = QPushButton("浏览")
        browse_btn.setFixedWidth(60)
        browse_btn.clicked.connect(lambda checked=False, line_edit=line_edit: self._browse_crm_template_target_dir(line_edit))
        layout.addWidget(browse_btn)

        return container

    def _browse_crm_template_target_dir(self, line_edit):
        """浏览CRM模板目标文件夹"""
        current_path = line_edit.text().strip() if line_edit else ''
        if not current_path or not os.path.exists(current_path):
            current_path = ""

        dir_path = QFileDialog.getExistingDirectory(self, "选择目标文件夹", current_path)
        if dir_path and line_edit is not None:
            line_edit.setText(dir_path)
            self.on_save_crm_templates()

