    def _on_save_opp_word_mapping(self):
        """保存商机-Word字段映射配置"""
        try:
            mappings = {}
            special_columns = []
            for row in range(self.opp_word_mapping_table.rowCount()):
                src_item = self.opp_word_mapping_table.item(row, 0)
                target_item = self.opp_word_mapping_table.item(row, 1)
                fmt_combo = self.opp_word_mapping_table.cellWidget(row, 2)
                if not src_item:
                    continue
                src_field = src_item.text().strip()
                if not src_field:
                    continue
                target_field = target_item.text().strip() if target_item else src_field
                mappings[src_field] = target_field
                if fmt_combo:
                    fmt_text = fmt_combo.currentText()
                    fmt_val = {
                        "文本": "{}", "日期(yyyy-MM-dd)": "{:%Y-%m-%d}",
                        "日期(yyyy/MM/dd)": "{:%Y/%m/%d}", "日期(yyyy年MM月dd日)": "{:%Y年%m月%d日}",
                        "人民币大写": "rmb_upper", "金额(千分位)": "{:,.2f}",
                        "数字": "{:}", "整数": "{:.0f}"
                    }.get(fmt_text, "{}")
                    if fmt_val != "{}":
                        special_columns.append({"name": src_field, "format": fmt_val})
            # 通过 save_config 保存，自动按 scope 拆分到个人/系统配置文件
            config = load_config()
            if 'opportunity' not in config:
                config['opportunity'] = {}
            config['opportunity']['word_field_mapping'] = mappings
            config['opportunity']['word_special_columns'] = special_columns
            save_config(config, immediate=True)
            self.config = load_config()
        except Exception as e:
            logging.error(f"保存商机-Word字段映射失败: {str(e)}")

    def _on_add_opp_word_mapping(self):
        """添加商机-Word字段映射行"""
        row = self.opp_word_mapping_table.rowCount()
        self.opp_word_mapping_table.insertRow(row)
        self.opp_word_mapping_table.setItem(row, 0, QTableWidgetItem(""))
        self.opp_word_mapping_table.setItem(row, 1, QTableWidgetItem(""))
        fmt_combo = QComboBox()
        fmt_list = ["文本", "日期(yyyy-MM-dd)", "日期(yyyy/MM/dd)", "日期(yyyy年MM月dd日)",
                     "人民币大写", "金额(千分位)", "数字", "整数"]
        fmt_combo.addItems(fmt_list)
        fmt_combo.currentIndexChanged.connect(lambda idx, r=row: self._on_save_opp_word_mapping())
        from PyQt6.QtCore import QEvent, QObject
        wf = QObject()
        wf.eventFilter = lambda obj, ev: ev.type() == QEvent.Wheel
        self.opp_word_mapping_wheel_filters.append(wf)
        fmt_combo.installEventFilter(wf)
        self.opp_word_mapping_table.setCellWidget(row, 2, fmt_combo)
        self._on_save_opp_word_mapping()

    def _on_delete_opp_word_mapping(self):
        """删除商机-Word字段映射行"""
        current_row = self.opp_word_mapping_table.currentRow()
        if current_row < 0:
            current_row = max(0, self.opp_word_mapping_table.rowCount() - 1)
        if self.opp_word_mapping_table.rowCount() > 0:
            self.opp_word_mapping_table.removeRow(current_row)
        self._on_save_opp_word_mapping()

