        fx_cfg = self.config.get('fxiaoke', {})
        row1.addWidget(QLabel("刷新时间:"))
        self.crm_auto_refresh_combo = QComboBox()
        refresh_items = [
            ("手动", 0),
            ("15分钟", 900000),
            ("30分钟", 1800000),
            ("1小时", 3600000)
        ]
        default_refresh = fx_cfg.get('auto_refresh_interval', 0)
        for label, val in refresh_items:
            self.crm_auto_refresh_combo.addItem(label, val)
        for i in range(self.crm_auto_refresh_combo.count()):
            if self.crm_auto_refresh_combo.itemData(i) == default_refresh:
                self.crm_auto_refresh_combo.setCurrentIndex(i)
                break
        self.crm_auto_refresh_combo.currentIndexChanged.connect(lambda: self.apply_settings_immediately({'crm'}))
        row1.addWidget(self.crm_auto_refresh_combo)

        row1.addSpacing(12)
        row1.addWidget(QLabel("加载数量:"))
        self.crm_load_count_spin = QSpinBox()
        self.crm_load_count_spin.setRange(50, 10000)
        self.crm_load_count_spin.setSingleStep(100)
        self.crm_load_count_spin.valueChanged.connect(lambda v: self._save_crm_config('load_count', v))
        # 加载已保存的值，没有则用默认值并立即写入配置
        saved = fx_cfg.get('load_count', 0)
        if saved:
            self.crm_load_count_spin.setValue(saved)
